import os
import pathlib
import logging
import re
import json
from typing import Any, Callable, Iterable, Optional, Set

SAFE_BASE_DIR: pathlib.Path = pathlib.Path.cwd().resolve(strict=True)
MAX_ITERATIONS_FACTOR: int = 5
_ALLOWED_STEM_RE = re.compile(r"^[A-Za-z0-9_-]+$")

def _ensure_dir_secure(dir_path: pathlib.Path) -> None:
    """
    Ensure that *dir_path* exists and has mode 0o750.
    Creates missing parents without altering existing ones.
    Raises OSError on failure.
    """
    try:
        os.makedirs(dir_path, mode=0o750, exist_ok=True)
        try:
            os.chmod(dir_path, 0o750)
        except OSError as exc:
            logging.error("Failed to set mode for %s: %s", dir_path, exc)
            raise
    except OSError as exc:
        logging.error("Failed to create or set mode for %s: %s", dir_path, exc)
        raise

def generate_candidates(
    generator_func: Callable[[], Iterable[Any]],
    max_size: int,
    *,
    variable_size: Optional[int] = None,
    output_file: str,
) -> Set[Any]:
    """
    Generate a set of candidates using `generator_func`, ensuring the set size
    matches the desired maximum size or variable size. The set is written to
    `output_file` for later use securely.
    """
    if not callable(generator_func):
        raise TypeError("generator_func must be callable")

    if not isinstance(max_size, int) or max_size <= 0:
        raise ValueError("max_size must be a positive integer")

    if variable_size is not None:
        if not isinstance(variable_size, int) or variable_size <= 0:
            raise ValueError("variable_size must be a positive integer")
        if variable_size > max_size:
            raise ValueError("variable_size cannot exceed max_size")

    output_path = pathlib.Path(output_file)
    if output_path.is_absolute():
        raise ValueError("output_file must be a relative path")
    if any(part in (".", "..") for part in output_path.parts):
        raise ValueError("output_file path contains disallowed components")
    if not _ALLOWED_STEM_RE.match(output_path.name):
        raise ValueError("output_file stem contains disallowed characters")

    try:
        parent = output_path.parent.resolve(strict=True)
    except FileNotFoundError as exc:
        raise ValueError(f"Parent directory of output_file does not exist: {exc}") from exc

    resolved_path = parent / output_path.name

    if not resolved_path.is_relative_to(SAFE_BASE_DIR):
        raise ValueError("output_file path escapes the safe base directory")

    _ensure_dir_secure(parent)

    desired_size = variable_size or max_size
    max_iterations = desired_size * MAX_ITERATIONS_FACTOR
    candidates: Set[Any] = set()

    count = 0
    try:
        for candidate in generator_func():
            candidates.add(candidate)
            count += 1
            if len(candidates) >= desired_size:
                break
            if count > max_iterations:
                raise RuntimeError(
                    f"Generator exceeded maximum iterations ({max_iterations}) "
                    f"without producing {desired_size} unique candidates."
                )
    except Exception as exc:
        logging.error("Error during candidate generation: %s", exc)
        raise

    if len(candidates) != desired_size:
        raise AssertionError(
            f"Expected {desired_size} candidates, but got {len(candidates)}"
        )

    try:
        with os.fdopen(
            os.open(
                str(resolved_path),
                os.O_WRONLY | os.O_CREAT | os.O_EXCL | os.O_NOFOLLOW,
                0o640,
            ),
            "w",
            encoding="utf-8",
        ) as f:
            for item in candidates:
                f.write(json.dumps(item, ensure_ascii=False) + "
")
    except PermissionError as exc:
        logging.error("Permission denied while writing to %s: %s", resolved_path, exc)
        raise
    except OSError as exc:
        logging.error("Failed to write candidates to %s: %s", resolved_path, exc)
        raise

    return candidates

#!/usr/bin/env python3
import argparse
import json
import logging
import secrets
import sys
import time
import multiprocessing
import zmq
import ipaddress

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    stream=sys.stdout,
)

UNIT_COST_PER_SECOND = 10.0
TASK_WORKLOAD_MIN = 0.5
TASK_WORKLOAD_MAX = 2.0
DEFAULT_PUSH_ADDRESS = "127.0.0.1:5557"

def parse_arguments():
    parser = argparse.ArgumentParser(description="Distribute tasks via ZeroMQ PUSH/PULL.")
    parser.add_argument(
        "-w",
        "--workers",
        type=int,
        default=4,
        help="Number of worker processes (positive integer).",
    )
    parser.add_argument(
        "-t",
        "--tasks",
        type=int,
        default=20,
        help="Number of tasks to distribute (positive integer).",
    )
    args = parser.parse_args()

    if args.workers <= 0:
        logging.error("Number of workers must be a positive integer.")
        sys.exit(1)
    if args.tasks <= 0:
        logging.error("Number of tasks must be a positive integer.")
        sys.exit(1)

    return args.workers, args.tasks

def worker(worker_id, address):
    try:
        context = zmq.Context()
        pull_socket = context.socket(zmq.PULL)
        pull_socket.connect(f"tcp://{address}")
    except zmq.ZMQError as exc:
        logging.error("Worker %s: failed to set up socket: %s", worker_id, exc)
        return

    while True:
        try:
            msg_bytes = pull_socket.recv(flags=zmq.NOBLOCK)
        except zmq.Again:
            time.sleep(0.01)
            continue
        except zmq.ZMQError:
            logging.exception("Worker %s: receive error", worker_id)
            break

        try:
            task = json.loads(msg_bytes.decode("utf-8"))
        except (ValueError, UnicodeDecodeError):
            logging.warning("Worker %s: invalid task format", worker_id)
            continue

        if task.get("shutdown"):
            break

        workload = task.get("workload")
        if not isinstance(workload, (int, float)) or workload <= 0:
            logging.warning("Worker %s: invalid workload value: %s", worker_id, workload)
            continue

        time.sleep(workload)

    pull_socket.close()
    context.term()

def create_tasks(num_tasks):
    tasks = []
    workload_range = int((TASK_WORKLOAD_MAX - TASK_WORKLOAD_MIN) * 1000)
    for i in range(num_tasks):
        workload = secrets.randbelow(workload_range) / 1000.0 + TASK_WORKLOAD_MIN
        task = {"id": i, "workload": workload}
        tasks.append(task)
    return tasks

def calculate_total_expected_cost(tasks):
    return sum(task["workload"] * UNIT_COST_PER_SECOND for task in tasks)

def validate_address(address):
    try:
        ip, _, port = address.partition(":")
        ipaddress.ip_address(ip)
        if not port.isdigit() or not 1 <= int(port) <= 65535:
            raise ValueError
    except Exception:
        logging.error("Invalid address format: %s", address)
        sys.exit(1)

def main():
    workers, tasks = parse_arguments()
    address = DEFAULT_PUSH_ADDRESS
    validate_address(address)

    process_list = []
    for i in range(workers):
        p = multiprocessing.Process(target=worker, args=(i, address))
        p.start()
        process_list.append(p)

    try:
        context = zmq.Context()
        push_socket = context.socket(zmq.PUSH)
        push_socket.bind(f"tcp://{address}")
    except zmq.ZMQError as exc:
        logging.error("Failed to bind push socket: %s", exc)
        for p in process_list:
            p.terminate()
        sys.exit(1)

    task_list = create_tasks(tasks)
    total_cost = calculate_total_expected_cost(task_list)
    logging.info("Total expected cost: %.2f", total_cost)

    try:
        for task in task_list:
            push_socket.send(json.dumps(task).encode("utf-8"))
    except zmq.ZMQError as exc:
        logging.error("Failed to send task: %s", exc)

    for _ in process_list:
        try:
            push_socket.send(json.dumps({"shutdown": True}).encode("utf-8"))
        except zmq.ZMQError:
            pass

    push_socket.close()
    context.term()

    for p in process_list:
        p.join()

if __name__ == "__main__":
    main()

import secrets
from functools import reduce
from math import prod
from typing import List, Tuple, Any


MAX_ELEMENT_LIMIT = 1_000_000
MAX_NESTING_LIMIT = 10
MAX_DIMENSION_SIZE = 1000


def _validate_dimensions(dims: List[int]) -> None:
    if not isinstance(dims, list):
        raise TypeError("Dimensions must be a list of positive integers.")
    if not dims:
        raise ValueError("Dimensions list cannot be empty.")
    if len(dims) > MAX_NESTING_LIMIT:
        raise ValueError(f"Maximum nesting depth of {MAX_NESTING_LIMIT} exceeded.")
    for d in dims:
        if not isinstance(d, int):
            raise TypeError(f"Dimension value {d!r} is not an integer.")
        if d < 1 or d > MAX_DIMENSION_SIZE:
            raise ValueError(
                f"Each dimension must be an integer between 1 and {MAX_DIMENSION_SIZE}."
            )
    if prod(dims) > MAX_ELEMENT_LIMIT:
        raise ValueError(
            f"Total number of elements {prod(dims)} exceeds the limit of {MAX_ELEMENT_LIMIT}."
        )


def _generate_array(dims: List[int]) -> Any:
    # Build from innermost dimension outward to avoid deep recursion
    if not dims:
        return None
    current_size = dims[-1]
    base = [secrets.randbelow(1000) for _ in range(current_size)]
    for size in reversed(dims[:-1]):
        base = [list(base) for _ in range(size)]
    return base


def _generate_intervals(dims: List[int]) -> List[Tuple[int, int]]:
    intervals: List[Tuple[int, int]] = []
    for size in dims:
        start = secrets.randbelow(size)
        end = secrets.randbelow(size - start) + start
        intervals.append((start, end))
    return intervals


def _extract_subarray(arr: Any, intervals: List[Tuple[int, int]], depth: int = 0) -> Any:
    start, end = intervals[depth]
    sliced = arr[start : end + 1]
    if depth + 1 < len(intervals):
        return [_extract_subarray(sub, intervals, depth + 1) for sub in sliced]
    return sliced


def generate_subarray(dims: List[int]) -> Any:
    """Generate a subarray from a randomly generated multidimensional array."""
    _validate_dimensions(dims)
    original = _generate_array(dims)
    intervals = _generate_intervals(dims)
    return _extract_subarray(original, intervals)

