from typing import Any, Callable, Dict, Type

_factory_registry: Dict[str, Callable[..., "JsonSerializable"]] = {}


def add_factory(factory_id: str, factory: Callable[..., "JsonSerializable"]) -> None:
    if not isinstance(factory_id, str):
        raise TypeError("Factory identifier must be a string.")
    if not callable(factory):
        raise TypeError("Factory must be callable.")
    _factory_registry[factory_id] = factory


def _validate_kwargs(func: Callable[..., Any], kwargs: Dict[str, Any]) -> Dict[str, Any]:
    sig = signature(func)
    allowed = set(sig.parameters.keys())
    if not set(kwargs).issubset(allowed):
        raise ValueError("Unexpected keyword arguments provided.")
    filtered = {k: v for k, v in kwargs.items() if k in allowed}
    return filtered


def create_with_factory(factory_id: str, **kwargs) -> "JsonSerializable":
    factory = _factory_registry.get(factory_id)
    if factory is None:
        raise ValueError(f"No factory registered under ID: {factory_id!r}")
    try:
        filtered_kwargs = _validate_kwargs(factory, kwargs)
        instance = factory(**filtered_kwargs)
    except Exception as exc:
        raise ValueError(f"Factory for ID {factory_id!r} raised an exception.") from None
    if not isinstance(instance, JsonSerializable):
        raise TypeError("Factory did not return a JsonSerializable instance.")
    return instance


class JsonSerializable:
    def to_json(self) -> str:
        try:
            return json.dumps(
                self.__dict__,
                separators=(",", ":"),
                ensure_ascii=False,
            )
        except (TypeError, OverflowError):
            raise ValueError("Failed to serialize object to JSON.") from None

    @classmethod
    def from_json(cls: Type["JsonSerializable"], json_str: str) -> "JsonSerializable":
        if not isinstance(json_str, str):
            raise TypeError("Input must be a JSON-formatted string.")
        try:
            data = json.loads(json_str)
        except json.JSONDecodeError:
            raise ValueError("Invalid JSON string.") from None
        if not isinstance(data, dict):
            raise ValueError("JSON root must be an object.")
        try:
            filtered_data = _validate_kwargs(cls, data)
            instance = cls(**filtered_data)
        except TypeError:
            raise ValueError("Failed to instantiate object from JSON data.") from None
        return instance


