import logging
import ipaddress
import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional

logger = logging.getLogger(__name__)

@dataclass(frozen=True)
class Bridge:
    port: int
    ip_address: str
    fingerprint: str
    pluggable_transport: Optional[Dict[str, str]] = field(default=None)

def _validate_port(port: int) -> int:
    if not isinstance(port, int):
        raise TypeError("Port must be an integer.")
    if not (0 < port <= 65535):
        raise ValueError("Port must be between 1 and 65535.")
    return port

def _validate_ip_address(ip: str) -> str:
    if not isinstance(ip, str):
        raise TypeError("IP address must be a string.")
    try:
        ipaddress.ip_address(ip)
    except ValueError:
        raise ValueError(f"Invalid IP address: {ip}")
    return ip

def _validate_fingerprint(fingerprint: str) -> str:
    if not isinstance(fingerprint, str):
        raise TypeError("Fingerprint must be a string.")
    if not re.fullmatch(r"[0-9A-Fa-f]{40,}", fingerprint):
        raise ValueError("Fingerprint must be a hexadecimal string of at least 40 characters.")
    return fingerprint

def _validate_pluggable_transport(pt: Dict[str, str]) -> Dict[str, str]:
    if not isinstance(pt, dict):
        raise TypeError("Pluggable transport must be a dictionary.")
    required_keys = {"name", "command"}
    if not required_keys.issubset(pt):
        missing = required_keys - pt.keys()
        raise ValueError(f"Pluggable transport missing required keys: {missing}")
    for k, v in pt.items():
        if not isinstance(v, str):
            raise TypeError(f"Pluggable transport key '{k}' must have a string value.")
    return pt

def add_bridge(
    port: int,
    ip_address: str,
    fingerprint: str,
    bridges: List[Bridge],
    pluggable_transport: Optional[Dict[str, str]] = None
) -> Bridge:
    """Create a Bridge object, validate inputs, add to bridges list, and return it."""
    try:
        validated_port = _validate_port(port)
        validated_ip = _validate_ip_address(ip_address)
        validated_fp = _validate_fingerprint(fingerprint)
        validated_pt = _validate_pluggable_transport(pluggable_transport) if pluggable_transport else None

        bridge = Bridge(
            port=validated_port,
            ip_address=validated_ip,
            fingerprint=validated_fp,
            pluggable_transport=validated_pt
        )
        bridges.append(bridge)
        return bridge
    except Exception as exc:
        logger.error("Error creating bridge: %s", exc)
        raise ValueError("Failed to create bridge due to invalid input.") from None

#!/usr/bin/env python3
import argparse
import re
import sys

try:
    import rospy
except ImportError as e:
    sys.stderr.write(f"Required module not found: {e}
")
    sys.exit(1)

from std_msgs.msg import String

_TOPIC_REGEX = re.compile(r"^[a-zA-Z0-9_/]+$")
_MAX_MESSAGE_LENGTH = 4096
_MAX_RATE = 1000.0
_MIN_RATE = 0.0

def _validate_topic(name: str) -> str:
    if not _TOPIC_REGEX.fullmatch(name):
        raise argparse.ArgumentTypeError(f"Invalid topic name: {name}")
    return name

def _validate_message(msg: str) -> str:
    if len(msg) > _MAX_MESSAGE_LENGTH:
        raise argparse.ArgumentTypeError(
            f"Message too long; maximum is {_MAX_MESSAGE_LENGTH} characters"
        )
    return msg

def _validate_rate(value: str) -> float:
    try:
        rate = float(value)
    except ValueError:
        raise argparse.ArgumentTypeError(f"Rate must be a number: {value}")
    if not (_MIN_RATE < rate <= _MAX_RATE):
        raise argparse.ArgumentTypeError(
            f"Rate must be > 0 and <= {_MAX_RATE} Hz"
        )
    return rate

def _parse_arguments():
    parser = argparse.ArgumentParser(
        description="Publish a string message to a ROS topic at a specified rate."
    )
    parser.add_argument(
        "-t",
        "--topic",
        required=True,
        type=_validate_topic,
        help="ROS topic name (letters, digits, underscore, slash).",
    )
    parser.add_argument(
        "-m",
        "--message",
        required=True,
        type=_validate_message,
        help="String payload to publish.",
    )
    parser.add_argument(
        "-r",
        "--rate",
        required=True,
        type=_validate_rate,
        help="Publishing rate in Hz (positive number, max 1000).",
    )
    return parser.parse_args()

def _publish_loop(topic: str, message: str, rate_hz: float):
    try:
        rospy.init_node(
            "secure_publisher",
            anonymous=True,
            log_level=rospy.WARN,
        )
    except rospy.ROSException as e:
        sys.stderr.write(f"Failed to initialize ROS node: {e}
")
        sys.exit(1)

    publisher = rospy.Publisher(topic, String, queue_size=10, latch=False)
    pub_rate = rospy.Rate(rate_hz)

    while publisher.get_num_connections() == 0:
        if rospy.is_shutdown():
            sys.exit(0)
        rospy.sleep(0.5)

    try:
        while not rospy.is_shutdown():
            publisher.publish(String(data=message))
            pub_rate.sleep()
    except rospy.ROSInterruptException:
        pass
    except Exception as exc:
        sys.stderr.write(f"Unexpected error during publishing: {exc}
")
        sys.exit(1)

def main():
    args = _parse_arguments()
    _publish_loop(args.topic, args.message, args.rate)

if __name__ == "__main__":
    main()

import re
from typing import Dict

MAX_INPUT_LENGTH = 10_000
MAX_INT_VALUE = 10**12
MAX_DIGITS = len(str(MAX_INT_VALUE))

INT_LITERAL_RE = re.compile(r"[-+]?\d+")
EXPECTED_KEYS = {"type", "intensity", "size", "generation", "choice"}

class ParsedObject:
    __slots__ = ("type", "intensity", "size", "generation", "choice")

    def __init__(self, *, type: int, intensity: int, size: int, generation: int, choice: int):
        self.type = type
        self.intensity = intensity
        self.size = size
        self.generation = generation
        self.choice = choice


def _to_int(value: str) -> int:
    if not INT_LITERAL_RE.fullmatch(value):
        raise ValueError(f"Invalid integer value: '{value}'. Must be an optional sign followed by digits.")
    digits = value.lstrip("+-")
    if len(digits) > MAX_DIGITS:
        raise ValueError(f"Integer value too long: '{value}'.")
    result = int(value)
    if abs(result) > MAX_INT_VALUE:
        raise ValueError(f"Integer value out of bounds: {result}.")
    return result


def parse_input(input_str: str) -> ParsedObject:
    if not isinstance(input_str, str):
        raise ValueError("Invalid input: expected a string.")
    if len(input_str) > MAX_INPUT_LENGTH:
        raise ValueError("Input string is too long.")

    sanitized = input_str.replace(";", ",")
    parts = [p.strip() for p in sanitized.split(",") if p.strip()]
    if not parts:
        raise ValueError("Input string is empty or malformed.")

    values: Dict[str, str] = {}
    for part in parts:
        if "=" not in part:
            raise ValueError(f"Malformed part: '{part}'. Expected key=value format.")
        key, val = [s.strip() for s in part.split("=", 1)]
        if key not in EXPECTED_KEYS:
            raise ValueError(f"Unexpected key: '{key}'.")
        if key in values:
            raise ValueError(f"Duplicate key: '{key}'.")
        values[key] = val

    missing = EXPECTED_KEYS - values.keys()
    if missing:
