import logging
import pathlib
from pathlib import Path
from typing import Dict, List, Optional, Any

import numpy as np
import tensorflow as tf


logging.basicConfig(level=logging.WARNING)
_logger = logging.getLogger(__name__)


def _validate_layer_weights(layer: tf.keras.layers.Layer, provided_weights: List[np.ndarray]) -> None:
    """Validate that the provided weights match the expected shapes for a layer."""
    expected_shapes = [w.shape for w in layer.get_weights()]
    provided_shapes = [w.shape for w in provided_weights]
    if expected_shapes != provided_shapes:
        raise ValueError(
            f"Shape mismatch in layer '{layer.name}'. "
            f"Expected shapes: {expected_shapes}, "
            f"provided shapes: {provided_shapes}"
        )


def _ensure_within_base_dir(path: Path, base: Path) -> None:
    """Raise PermissionError if path is not within base directory."""
    try:
        path.relative_to(base)
    except ValueError:
        raise PermissionError("output_path is outside the allowed base directory") from None


def _create_output_directory(path: Path) -> None:
    """Create the parent directory for the output path if it does not exist."""
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        raise RuntimeError(f"Cannot create directory for output path: {exc}") from exc


def set_and_save_weights(
    model: tf.keras.Model,
    layer_names: List[str],
    weights_dict: Dict[str, List[np.ndarray]],
    output_path: str,
    *,
    format: str = "h5",
    base_dir: Optional[str] = None,
) -> None:
    """
    Set weights for specified layers in a Keras model and save the modified model.

    Raises
    ------
    TypeError
        If an argument has an unexpected type.
    ValueError
        If a layer name is missing or weight shapes are incompatible.
    PermissionError
        If the output path is not within the allowed base directory.
    RuntimeError
        If an unexpected error occurs during processing or saving.
    """
    # Validate types
    if not isinstance(model, tf.keras.Model):
        raise TypeError("model must be an instance of tensorflow.keras.Model")
    if not isinstance(layer_names, list) or not all(isinstance(n, str) for n in layer_names):
        raise TypeError("layer_names must be a list of strings")
    if not isinstance(weights_dict, dict):
        raise TypeError("weights_dict must be a dictionary")
    if set(weights_dict.keys()) != set(layer_names):
        missing = set(layer_names) - set(weights_dict.keys())
        extra = set(weights_dict.keys()) - set(layer_names)
        errors = []
        if missing:
            errors.append(f"missing weights for layers: {missing}")
        if extra:
            errors.append(f"unrequested keys in weights_dict: {extra}")
        raise ValueError("; ".join(errors))
    for key, val in weights_dict.items():
        if not isinstance(val, list) or not all(isinstance(v, np.ndarray) for v in val):
            raise TypeError(f"weights for layer '{key}' must be a list of numpy arrays")

    # Resolve and validate output path
    try:
        output_path_obj = Path(output_path).expanduser().resolve()
    except Exception as exc:
        raise RuntimeError(f"Invalid output path: {exc}") from exc
    if base_dir:
        try:
            base_dir_obj = Path(base_dir).expanduser().resolve()
        except Exception as exc:
            raise RuntimeError(f"Invalid base_dir: {exc}") from exc
        _ensure_within_base_dir(output_path_obj, base_dir_obj)

    # Validate format
    save_format = format.lower()
    if save_format not in {"h5", "tf"}:
        raise ValueError("Unsupported format. Supported: 'h5', 'tf'")
    if save_format == "h5" and output_path_obj.suffix.lower() != ".h5":
        # Append extension if missing
        output_path_obj = output_path_obj.with_suffix(".h5")

    # Prepare output directory
    _create_output_directory(output_path_obj)

    # Update weights
    try:
        layer_map = {layer.name: layer for layer in model.layers}
        for name in layer_names:
            layer = layer_map.get(name)
            if not layer:
                raise ValueError(f"Layer '{name}' not found in the model")
            _validate_layer_weights(layer, weights_dict[name])
            layer.set_weights(weights_dict[name])
    except Exception as exc:
        _logger.warning("Error updating weights: %s", exc)
        raise RuntimeError("Failed to set weights for specified layers") from exc

    # Save the modified model
    try:
        model.save(str(output_path_obj), save_format=save_format)
    except (OSError, ValueError) as exc:
        _logger.warning("Error saving model: %s", exc)
        raise RuntimeError("Failed to save the modified model") from exc

