class SecureMockServer:
    """Threaded mock HTTP server bound to localhost on a userâspecified port."""

    def __init__(self, port: int, directory: Optional[str] = None) -> None:
        if not isinstance(port, int):
            raise TypeError("Port must be an integer")
        if not (1024 <= port <= 65535):
            raise ValueError("Port must be between 1024 and 65535")
        self.port = port

        # Resolve absolute path and ensure it exists and is a directory
        if directory is None:
            directory = os.getcwd()
        abs_path = Path(directory).expanduser().resolve()
        if not abs_path.is_dir():
            raise ValueError(f"Directory '{directory}' does not exist or is not a directory")
        self.directory = str(abs_path)

        self._server: Optional[socketserver.TCPServer] = None
        self._thread: Optional[threading.Thread] = None

    def _make_handler_class(self) -> Type[http.server.SimpleHTTPRequestHandler]:
        """Return a handler class that serves files from self.directory."""
        parent_dir = self.directory

        class CustomHandler(http.server.SimpleHTTPRequestHandler):
            def __init__(self, *args, **kwargs):
                super().__init__(*args, directory=parent_dir, **kwargs)

        return CustomHandler

    def start(self) -> None:
        """Start the mock server in a background thread."""
        if self._server is not None:
            raise RuntimeError("Server already started")

        address = ("127.0.0.1", self.port)
        handler_class = self._make_handler_class()

        try:
            # Use ThreadingMixIn to allow concurrent requests
            self._server = socketserver.ThreadingTCPServer(address, handler_class)
            # Allow address reuse to simplify restarts
            self._server.allow_reuse_address = True
        except OSError as exc:
            raise RuntimeError(f"Unable to bind to {address}: {exc}") from exc

        self._thread = threading.Thread(
            target=self._server.serve_forever,
            name="MockServerThread",
            daemon=True,
        )
        self._thread.start()
        logging.info(f"Mock server started on {address[0]}:{self.port}")

    def stop(self) -> None:
        """Stop the mock server and clean up."""
        if self._server is None:
            return

        try:
            self._server.shutdown()
            self._server.server_close()
            logging.info(f"Mock server on port {self.port} stopped")
        except Exception as exc:
            logging.error(f"Error while stopping server: {exc}")
        finally:
            self._server = None
            if self._thread:
                self._thread.join()
                self._thread = None

    def __enter__(self) -> "SecureMockServer":
        self.start()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> None:
        self.stop()


def get_mock_server(port: int, directory: Optional[str] = None) -> SecureMockServer:
    """Convenience factory returning a preâconfigured SecureMockServer."""
    return SecureMockServer(port, directory)

