def filter_blocked_ips(
    ip_ports: Dict[str, Union[int, List[int]]],
    block_countries: List[str]
) -> Dict[str, List[int]]:
    """
    Return a dictionary of IP addresses and their ports that
    should be blocked when 'cn' is present in block_countries.
    """
    # Ensure block_countries is iterable and contains 'cn' (caseâinsensitive)
    if not isinstance(block_countries, list):
        return {}
    if "cn" not in [str(c).lower() for c in block_countries]:
        return {}

    blocked: Dict[str, List[int]] = {}
    if not isinstance(ip_ports, dict):
        return blocked

    for raw_ip, raw_ports in ip_ports.items():
        # Convert raw_ip to a valid IP string
        try:
            ip = str(ipaddress.ip_address(raw_ip))
        except (ValueError, TypeError):
            # Skip invalid IP representations
            continue

        # Normalise ports to a list of ints
        if isinstance(raw_ports, int):
            ports = [raw_ports]
        elif isinstance(raw_ports, (list, tuple)):
            ports = [p for p in raw_ports if isinstance(p, int) and 0 <= p <= 65535]
        else:
            # Unsupported port format
            continue

        if ports:
            blocked[ip] = ports

    return blocked

