def generate_and_visualize_random_graph(
    num_nodes: int,
    edge_density: float,
    output_file: str,
    node_types: list[str] | None = None,
) -> None:
    """
    Generates a random undirected graph, assigns random types and weights,
    and saves a HivePlot as a PDF.
    """
    if not isinstance(num_nodes, int) or num_nodes <= 0:
        raise ValueError("num_nodes must be a strictly positive integer.")
    if not isinstance(edge_density, (float, int)) or not (0 <= edge_density <= 1):
        raise ValueError("edge_density must be a float between 0 and 1 inclusive.")
    out_path = Path(output_file)
    if out_path.suffix.lower() != ".pdf":
        raise ValueError("output_file must have a .pdf extension.")
    try:
        out_path.resolve(strict=False)
    except Exception as exc:
        raise ValueError(f"Invalid output_file path: {exc}") from exc
    out_path.parent.mkdir(parents=True, exist_ok=True)

