        G.add_node(node_id, type=rng.choice(node_types))

    max_possible_edges = num_nodes * (num_nodes - 1) // 2
    target_edges = math.floor(max_possible_edges * edge_density)

    edges_created = 0
    max_attempts = target_edges * 10
    attempt = 0
    while edges_created < target_edges and attempt < max_attempts:
        u, v = rng.sample(range(num_nodes), 2)
        if not G.has_edge(u, v):
            G.add_edge(u, v, weight=rng.random())
            edges_created += 1
