    stream=sys.stdout,
)

ALLOWED_SCHEMES = {"https"}

PRIVATE_IP_BLOCKS = [
    ipaddress.IPv4Network("127.0.0.0/8"),
    ipaddress.IPv4Network("10.0.0.0/8"),
    ipaddress.IPv4Network("172.16.0.0/12"),
    ipaddress.IPv4Network("192.168.0.0/16"),
    ipaddress.IPv6Network("::1/128"),
    ipaddress.IPv6Network("fe80::/10"),
]

# ---------------------------------------

def _is_public_ip(ip_str: str) -> bool:
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        return False
    for net in PRIVATE_IP_BLOCKS:
        if ip in net:
            return False
    return True

def _resolve_hostname(hostname: str) -> bool:
    try:
        addrinfo = socket.getaddrinfo(hostname, None, family=socket.AF_UNSPEC, type=socket.SOCK_STREAM)
    except socket.gaierror:
        return False
    for _, _, _, _, sockaddr in addrinfo:
        if isinstance(sockaddr, (tuple, list)):
            ip_str = sockaddr[0]
            if not _is_public_ip(ip_str):
                return False
    return True

def is_valid_url(url: str) -> bool:
    """Validate that the URL has a proper secure scheme, netloc, and does not resolve to private IPs."""
    try:
        result = parse.urlparse(url)
    except Exception:
        return False
    if result.scheme not in ALLOWED_SCHEMES:
        return False
    if not result.netloc:
        return False
    hostname = result.hostname
    if not hostname:
        return False
    try:
        ipaddress.ip_address(hostname)
        if not _is_public_ip(hostname):
            return False
    except ValueError:
        if not _resolve_hostname(hostname):
            return False
    return True

# ---------------------------------------

class StrictRedirectHandler(request.HTTPRedirectHandler):
    """Prevent redirects to disallowed hosts or schemes."""
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        result = super().redirect_request(req, fp, code, msg, hdrs, newurl)
        if result is None:
            return None
        if not is_valid_url(result.full_url):
            return None
        return result

# ---------------------------------------

def fetch_feed_content(url: str, timeout: int = 10) -> bytes:
    if not is_valid_url(url):
        raise ValueError(f"URL scheme or host not allowed: {url}")
    ctx = ssl.create_default_context()
    ctx.check_hostname = True
    ctx.verify_mode = ssl.CERT_REQUIRED
    opener = request.build_opener(
        StrictRedirectHandler(),
        request.HTTPSHandler(context=ctx)
    )
    req = request.Request(url, headers={"User-Agent": "SecureFeedFetcher/1.0"})
    with opener.open(req, timeout=timeout) as resp:
        return resp.read()

# ---------------------------------------

def parse_feed(content: bytes) -> feedparser.FeedParserDict:
    """
    Parse feed with defusedxml to guard against XXE.
    """
    try:
        root = ET.fromstring(content)
    except ET.ParseError as exc:
        raise ValueError(f"XML parsing error: {exc}") from None
    sanitized = ET.tostring(root, encoding="utf-8")
    return feedparser.parse(sanitized)

def safe_parse(url: str) -> feedparser.FeedParserDict:
    try:
        content = fetch_feed_content(url)
    except (error.URLError, error.HTTPError, ssl.SSLError, ValueError) as exc:
        raise ValueError(f"Failed to fetch URL: {exc}") from None
    feed = parse_feed(content)
    if feed.bozo:
        raise ValueError(f"Feed parsing error: {feed.bozo_exception}")
