import numpy as np
import scipy.stats as stats
import scipy.optimize as optimize
import inspect
import re
from typing import Optional

class InvalidDistributionError(ValueError):
    """Raised when the provided distribution name is invalid or unsupported."""
    pass

class InvalidDataError(ValueError):
    """Raised when the provided data array is invalid."""
    pass

# Precompile the regular expression to improve performance and safety.
_VALID_DIST_NAME_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

def _sanitize_distribution_name(name: str) -> str:
    if not isinstance(name, str) or not _VALID_DIST_NAME_RE.fullmatch(name):
        raise InvalidDistributionError("Distribution name must be a valid identifier.")
    return name

def _validate_data(data):
    try:
        arr = np.asarray(data, dtype=float)
    except Exception as exc:
        raise InvalidDataError(f"Data could not be converted to a numeric array: {exc}") from exc
    if arr.ndim != 1:
        raise InvalidDataError("Data must be a one-dimensional array.")
    if np.isnan(arr).any() or np.isinf(arr).any():
        raise InvalidDataError("Data contains NaN or infinite values.")
    if arr.size == 0:
        raise InvalidDataError("Data array is empty.")
    if arr.size > 10_000_000:
        raise InvalidDataError("Data array is too large.")
    return arr

def _has_default_loc_scale(dist) -> bool:
    try:
        sig = inspect.signature(dist.ppf)
        loc_param = sig.parameters.get("loc")
        scale_param = sig.parameters.get("scale")
        loc_default = loc_param.default if loc_param else 0.0
        scale_default = scale_param.default if scale_param else 1.0
        return loc_default == 0.0 and scale_default == 1.0
    except (AttributeError, TypeError):
        return False

def _compute_correlation(dist, shape, data):
    n = data.size
    ps = (np.arange(1, n + 1, dtype=float) - 0.5) / n
    try:
        theoretical = dist.ppf(ps, shape, loc=0, scale=1)
    except Exception:
        theoretical = np.full_like(data, np.nan, dtype=float)
    return np.corrcoef(data, theoretical)[0, 1]

def maximize_pfc(dist_name: str, data) -> Optional[float]:
    """
    Return the shape parameter that maximizes the probability plot correlation coefficient
    for the specified one-parameter distribution and data.

    Parameters
    ----------
    dist_name : str
        Name of the scipy.stats distribution.
    data : array-like
        Observed data values.

    Returns
    -------
    shape : float or None
        Optimal shape parameter or None if calculation fails.
    """
    dist_name = _sanitize_distribution_name(dist_name)
    data = _validate_data(data)

    if not hasattr(stats, dist_name):
        raise InvalidDistributionError(f"Distribution '{dist_name}' not found in scipy.stats.")
    dist = getattr(stats, dist_name)
    # Accept both frozen and continuous distribution instances.
    if not (isinstance(dist, stats.rv_continuous) or isinstance(dist, stats.rv_frozen)):
        raise InvalidDistributionError(f"'{dist_name}' is not a valid continuous distribution.")

    try:
        shape_count = int(dist.shape)
    except (AttributeError, TypeError):
        raise InvalidDistributionError(f"Distribution '{dist_name}' does not expose a shape attribute.") from None
    if shape_count != 1:
        raise InvalidDistributionError(f"Distribution '{dist_name}' is not a one-parameter family.")

    if not _has_default_loc_scale(dist):
        raise InvalidDistributionError(f"Distribution '{dist_name}' does not have default loc=0 and scale=1.")

    def objective(shape):
        if not isinstance(shape, (int, float)) or shape <= 0:
            return np.inf
        try:
            corr = _compute_correlation(dist, shape, data)
            return -corr if np.isfinite(corr) else np.inf
        except Exception:
            return np.inf

    result = optimize.minimize_scalar(objective, bounds=(1e-6, 1e6), method='bounded')
    if not result.success or not np.isfinite(result.x):
        return None
    return float(result.x)

from dataclasses import dataclass, field
from typing import Dict, Any, Union
from uuid import uuid4
from math import isfinite

@dataclass(frozen=True)
class Plan:
    identifier: str = field(default_factory=lambda: str(uuid4()))
    features: Dict[str, float] = field(default_factory=dict)

def _validate_features(features: Dict[Any, Any]) -> Dict[str, float]:
    if not isinstance(features, dict):
        raise ValueError("Features must be a dictionary.")
    if not features:
        raise ValueError("Features dictionary cannot be empty.")
    sanitized: Dict[str, float] = {}
    for key, value in features.items():
        if not isinstance(key, str):
            raise ValueError("Feature names must be strings.")
        if not isinstance(value, (int, float)):
            raise ValueError("Feature values must be numeric.")
        if not isfinite(float(value)):
            raise ValueError("Feature values must be finite numbers.")
        sanitized[key] = float(value)
    return sanitized

def create_and_modify_plan(features: Dict[Any, Any]) -> None:
    sanitized_features: Dict[str, float] = _validate_features(features)
    original_plan: Plan = Plan(features=sanitized_features)
    modified_features: Dict[str, float] = {k: v * 1.1 for k, v in original_plan.features.items()}
    modified_plan: Plan = Plan(identifier=original_plan.identifier, features=modified_features)
    if modified_plan.identifier != original_plan.identifier:
        raise ValueError("Identifier mismatch")

