def _get_safe_path(path_spec: str | Path | Sequence[str | Path]) -> Path | None:
    """Resolve a path and ensure it points inside BASE_DIR."""
    try:
        if isinstance(path_spec, (str, Path)):
            candidate = Path(path_spec)
        elif isinstance(path_spec, Sequence) and not isinstance(path_spec, (str, Path)):
            if not path_spec:
                return None
            candidate = Path(path_spec[0])
        else:
            return None

        resolved = candidate.resolve(strict=True)
        if not resolved.is_relative_to(BASE_DIR):
            return None
        return resolved
    except Exception:
        return None


def _load_words_from_file(file_path: Path) -> Set[str]:
    if not file_path.is_file():
        logging.error(f"Failed to load words: {file_path.name}")
        return set()
    try:
        words = set()
        with file_path.open("r", encoding="utf-8", errors="replace") as f:
            for line in f:
                word = line.strip().lower()
                if word:
                    words.add(word)
        return words
    except Exception:
        logging.error(f"Failed to load words: {file_path.name}")
        return set()


def extract_words_from_html(
    html_text: str,
    stopwords_path: Sequence[str | Path],
    dictionary_path: Sequence[str | Path] | None = None,
) -> Tuple[Set[str], Dict[str, int]]:
    if not isinstance(html_text, str):
        logging.error("html_text must be a string")
        return set(), {}

    stopwords_file = _get_safe_path(stopwords_path)
    if stopwords_file is None:
