    word_counter: Counter = Counter()
    word_pattern = re.compile(r" [a-zA-Z]+ ", re.UNICODE)

    class WordExtractor(HTMLParser):
        def handle_data(self, data: str) -> None:
            for match in word_pattern.finditer(data):
                word = match.group().lower()
                if word in stopwords:
                    continue
                if dictionary is not None and word not in dictionary:
                    continue
                word_counter[word] += 1

    try:
        extractor = WordExtractor()
        extractor.feed(html.unescape(html_text))
        extractor.close()
    except Exception:
        logging.error("Error parsing HTML content")
        return set(), {}

    unique_words: Set[str] = set(word_counter.keys())
    frequencies: Dict[str, int] = dict(word_counter)
    return unique_words, frequencies

