_host_name_re = re.compile(
    r"^(?=.{1,253}$)(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)(?:\.(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?))*$"
)
_username_password_re = re.compile(r"^[A-Za-z0-9@._\-!$%&*()]+$")


def _is_valid_host(host: str) -> bool:
    # Reject empty host
    if not host:
        return False
    # Reject localhost and loopback addresses
    try:
        ip = ipaddress.ip_address(host)
        if ip.is_private or ip.is_loopback:
            return False
    except ValueError:
        # Not an IP address; validate DNS name
        if not _host_name_re.fullmatch(host):
            return False
    return True


def login_to_server(
    host: str,
    port: int,
    username: str,
    password: str,
    timeout: int = 5,
) -> Dict[str, Any]:
    """
    Connect to the specified HTTPS server, send a login request with the given username
    and password, parse the JSON response, and return it as a dictionary.
    """
    # Input validation
    if not isinstance(host, str) or not _is_valid_host(host):
        raise ValueError("Invalid host")
    if not isinstance(port, int) or not (0 < port < 65536):
        raise ValueError("Invalid port")
    if not isinstance(username, str) or not username:
        raise ValueError("Username must be a non-empty string")
    if not isinstance(password, str) or not password:
        raise ValueError("Password must be a non-empty string")
    if len(username) > 255 or len(password) > 255:
        raise ValueError("Username or password is too long")
    if not _username_password_re.fullmatch(username):
        raise ValueError("Username contains invalid characters")
    if not _username_password_re.fullmatch(password):
        raise ValueError("Password contains invalid characters")

    payload = json.dumps({"username": username, "password": password})
    headers = {"Content-Type": "application/json", "Accept": "application/json"}
    context = ssl.create_default_context()

    try:
        with http.client.HTTPSConnection(
            host=host,
            port=port,
            context=context,
            timeout=timeout,
        ) as conn:
            conn.request("POST", "/login", body=payload, headers=headers)
            response = conn.getresponse()
            if response.status != 200:
                return {"error": "Login failed"}
            data = response.read().decode("utf-8")
            try:
                resp_json = json.loads(data)
            except (ValueError, json.JSONDecodeError):
                return {"error": "Invalid response from server"}
            if not isinstance(resp_json, dict):
                return {"error": "Unexpected response format"}
            return resp_json
    except (http.client.HTTPException, ssl.SSLError, OSError):
        return {"error": "Unable to connect to server"}

