logging.basicConfig(level=logging.WARNING, format="%(levelname)s: %(message)s")

def get_current_date_str() -> str:
    """Return current UTC date as YYYY-MM-DD."""
    return datetime.utcnow().strftime("%Y-%m-%d")

def get_previous_date_str(days_passed: int) -> str:
    """Return UTC date string for the day that is `days_passed` days ago."""
    return (datetime.utcnow() - timedelta(days=days_passed)).strftime("%Y-%m-%d")

def get_current_date_components() -> Tuple[int, int, int]:
    """Return current year, month, and day as integers."""
    now = datetime.utcnow()
    return now.year, now.month, now.day

def get_previous_date_components(days_passed: int) -> Tuple[int, int, int]:
    """Return previous date components by subtracting days_passed from today."""
    prev = datetime.utcnow() - timedelta(days=days_passed)
    return prev.year, prev.month, prev.day

def read_last_entry() -> Optional[str]:
    """Read and return the last non-empty line from data/last_entry."""
    base_dir = Path(__file__).resolve().parent
    file_path = base_dir / "data" / "last_entry"
    if not file_path.is_file():
        logging.warning(f"File not found: {file_path}")
        return None
    try:
        lines = [ln for ln in file_path.read_text(encoding="utf-8").splitlines() if ln.strip()]
        return lines[-1] if lines else None
    except (OSError, UnicodeDecodeError) as exc:
        logging.error(f"Error reading the last entry file: {exc}")
        return None

def validate_days_passed(arg: str) -> int:
    """Validate that the argument represents a non-negative integer."""
    try:
        days = int(arg)
        if days < 0:
            raise ValueError
        return days
    except ValueError:
        logging.error("Days passed must be a non-negative integer.")
        sys.exit(1)

def main() -> None:
    if len(sys.argv) != 2:
        logging.error("Usage: python script.py <days_passed>")
        sys.exit(1)

    days_passed = validate_days_passed(sys.argv[1])

    current_date_str = get_current_date_str()
    prev_date_str = get_previous_date_str(days_passed)

    cur_year, cur_month, cur_day = get_current_date_components()
    prev_year, prev_month, prev_day = get_previous_date_components(days_passed)

    last_entry = read_last_entry()

    print(f"Current date (YYYY-MM-DD): {current_date_str}")
    print(f"Previous date (YYYY-MM-DD, {days_passed} days ago): {prev_date_str}")
