import random
import datetime
from typing import List, Dict, Any, Optional


class FakeRing:
    def __init__(self, containers: List[Dict[str, Any]]) -> None:
        self._containers = containers

    def get_container_policy_indexes(
        self, policy_index: int, limit: int = 10
    ) -> List[Dict[str, Any]]:
        res = [
            c
            for c in self._containers
            if c.get("policy_index") == policy_index
        ]
        return res[:limit]


def _validate_policy_index(value: Any) -> Optional[int]:
    if not isinstance(value, int) or isinstance(value, bool) or value < 0:
        return None
    return value


def get_oldest_non_default_policy_index(policy_index: int) -> Optional[int]:
    validated_index = _validate_policy_index(policy_index)
    if validated_index is None:
        return None

    fake_containers = [
        {"policy_index": 1, "creation_time": datetime.datetime(2023, 1, 1)},
        {"policy_index": 2, "creation_time": datetime.datetime(2023, 6, 1)},
        {"policy_index": 0, "creation_time": datetime.datetime(2022, 12, 1)},
        {"policy_index": 3, "creation_time": datetime.datetime(2021, 3, 1)},
    ]

    ring = FakeRing(fake_containers)

    policy_records = ring.get_container_policy_indexes(validated_index)
    # Append the special policy record
    policy_records.append(
        {"policy_index": 99, "creation_time": datetime.datetime(2024, 1, 1)}
    )

    random.shuffle(policy_records)

    non_default_records = [
        rec for rec in policy_records if rec.get("policy_index") != 0
    ]

    if not non_default_records:
        return None

    oldest_record = min(
        non_default_records, key=lambda r: r.get("creation_time")
    )
    return oldest_record.get("policy_index") if oldest_record else None


if __name__ == "__main__":
