import sys
import importlib
import logging
import re
import threading
from typing import Iterable, List, Union, Optional, Set

__all__ = ["load_modules_with_dlopen_flags"]

logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())

# the pattern requires components to start with letter or underscore,
# and disallows relative import syntax (e.g. .module or ..module)
_module_name_pattern = re.compile(
    r"^(?!\.)(?!.*\.\.)([A-Za-z_][A-Za-z0-9_]*)(\.[A-Za-z_][A-Za-z0-9_]*)*$"
)

_lock = threading.Lock()


def _validate_module_name(name: str, whitelist: Optional[Set[str]] = None) -> None:
    if not isinstance(name, str) or not name:
        raise ValueError("Module name must be a non-empty string")
    if not _module_name_pattern.match(name):
        raise ValueError(f"Invalid module name: {name!r}")
    if whitelist is not None and name not in whitelist:
        raise ValueError(f"Module {name!r} is not in the allowed whitelist")


def _validate_flags(flags: Union[int, None]) -> int:
    if flags is None:
        return getattr(sys, "dlopenflags", 0)
    if not isinstance(flags, int) or flags < 0:
        raise ValueError("Flags must be a non-negative integer")
    return flags


class _DlopenFlagsContext:
    def __init__(self, flags: int):
        self.flags = flags
        self.original = getattr(sys, "getdlopenflags", lambda: None)()

    def __enter__(self):
        if hasattr(sys, "setdlopenflags"):
            sys.setdlopenflags(self.flags)

    def __exit__(self, exc_type, exc_value, traceback):
        if self.original is not None and hasattr(sys, "setdlopenflags"):
            try:
                sys.setdlopenflags(self.original)
            except Exception:
                logger.warning("Failed to restore original dlopenflags")


def load_modules_with_dlopen_flags(
    modules: Iterable[str],
    flags: Union[int, None] = None,
    *,
    whitelist: Optional[Iterable[str]] = None,
) -> List[object]:
    """
    Set dynamic loading flags, import modules, and restore original flags.

    Parameters
    ----------
    modules : Iterable[str]
        Iterable of absolute module names to import.
    flags : int or None
        Integer flags passed to sys.setdlopenflags. If None, existing flags are used.
    whitelist : Iterable[str] or None
        Optional iterable of module names that are allowed to be imported. If provided,
        every module in ``modules`` must be present in this whitelist.

    Returns
    -------
    List[object]
        List of imported module objects in the order provided.
    """
    if not isinstance(modules, Iterable):
        raise ValueError("modules must be an iterable of module names")

    whitelist_set: Optional[Set[str]] = set(whitelist) if whitelist is not None else None
    module_list: List[str] = []

    for name in modules:
        _validate_module_name(name, whitelist=whitelist_set)
        module_list.append(name)

    use_flags = _validate_flags(flags)

    with _lock, _DlopenFlagsContext(use_flags):
        imported_modules: List[object] = []
        for name in module_list:
            try:
                imported_modules.append(importlib.import_module(name))
            except Exception as exc:
                logger.warning("Failed to import module %s: %s", name, exc)
                raise ImportError(f"Unable to import module {name!r}") from exc
        return imported_modules

