# Base directory where JWT files are expected to reside
TOKEN_BASE_DIR = Path.home() / ".config" / "myapp" / "tokens"


def load_jwt_token(rel_path: str) -> Tuple[Optional[str], None]:
    """
    Load a JWT token from a JSON file located relative to TOKEN_BASE_DIR.
    Accepts either a JSON object containing a "token" field or a JSON string.
    Returns a tuple (token, None) on success; otherwise (None, None).
    """
    # Construct a Path object from the provided relative path
    candidate_path = Path(rel_path)

    # Reject absolute paths
    if candidate_path.is_absolute():
        return None, None

    # Reject paths that try to traverse upward (". .")
    if any(part == ".." for part in candidate_path.parts):
        return None, None

    # Resolve the full path inside the token directory
    candidate = TOKEN_BASE_DIR / candidate_path
    try:
        resolved = candidate.resolve(strict=True)
    except (FileNotFoundError, PermissionError, OSError):
        return None, None

    # Ensure the resolved path refers to a regular file
    if not resolved.is_file():
        return None, None

    # Verify that the resolved file is still within the allowed directory
    try:
        if not resolved.is_relative_to(TOKEN_BASE_DIR):
            return None, None
    except AttributeError:
        # For Python < 3.9, emulate is_relative_to
        if TOKEN_BASE_DIR not in resolved.parents:
            return None, None

    # Read and parse the JSON content safely
    try:
        with resolved.open("r", encoding="utf-8") as f:
            content = json.load(f)
    except (json.JSONDecodeError, UnicodeDecodeError, OSError):
        return None, None

