import ast
import io
import json
import multiprocessing
import queue
import sys
import token
import traceback
import tokenize

try:
    import resource  # May be unavailable on nonâUnix platforms
    RESOURCE_AVAILABLE = True
except ImportError:
    RESOURCE_AVAILABLE = False

# Configuration
MAX_CODE_LENGTH = 5000  # characters
CPU_LIMIT_SECONDS = 1   # CPU time
MEMORY_LIMIT_BYTES = 64 * 1024 * 1024  # 64 MB
MAX_RESULT_BYTES = 1_048_576  # 1 MB for JSON result

# Disallowed identifiers
DISALLOWED_TOKENS = {
    'import', 'from', 'exec', 'eval', 'system', 'subprocess',
    'open', 'call', 'execfile', '__import__'
}

# Allowed AST nodes
ALLOWED_AST_TYPES = (
    ast.Module, ast.Expr, ast.Assign, ast.AugAssign,
    ast.Name, ast.Constant,
    ast.BinOp, ast.UnaryOp, ast.BoolOp, ast.Compare,
    ast.operator, ast.unaryop, ast.boolop, ast.cmpop,
    ast.Load, ast.Store, ast.Del, ast.AugLoad, ast.AugStore, ast.AugDel
)

SAFE_GLOBALS = {'__builtins__': None}


def _is_code_safe(code: str) -> bool:
    if not isinstance(code, str) or len(code) > MAX_CODE_LENGTH:
        return False
    try:
        for tok in tokenize.generate_tokens(io.StringIO(code).readline):
            if tok.type == token.NAME and tok.string in DISALLOWED_TOKENS:
                return False
    except tokenize.TokenError:
        return False
    return True


def _validate_ast(tree: ast.AST) -> bool:
    for node in ast.walk(tree):
        if not isinstance(node, ALLOWED_AST_TYPES):
            return False
        if isinstance(node, ast.Name) and node.id in DISALLOWED_TOKENS:
            return False
    return True


def _apply_resource_limits():
    if not RESOURCE_AVAILABLE:
        return
    try:
        resource.setrlimit(resource.RLIMIT_CPU, (CPU_LIMIT_SECONDS, CPU_LIMIT_SECONDS))
        resource.setrlimit(resource.RLIMIT_AS, (MEMORY_LIMIT_BYTES, MEMORY_LIMIT_BYTES))
    except Exception:
        # Log failure but continue execution
        print("Failed to set resource limits", file=sys.stderr)


def _execute_user_code(code: str, output_queue: multiprocessing.Queue):
    try:
        _apply_resource_limits()
        tree = ast.parse(code, mode='exec')

        if not _validate_ast(tree):
            output_queue.put(json.dumps(None))
            return

        compiled = compile(tree, '<user_code>', 'exec')
        local_ns = {}
        exec(compiled, SAFE_GLOBALS, local_ns)
        result = local_ns.get('result', None)

        try:
            serialized = json.dumps(result)
        except (TypeError, OverflowError):
            serialized = json.dumps(None)

        if len(serialized) > MAX_RESULT_BYTES:
            serialized = json.dumps(None)
        output_queue.put(serialized)

    except Exception:
        output_queue.put(json.dumps(None))


def validate_code(user_code: str, reference_func, timeout_seconds: int = 2) -> bool:
    if not _is_code_safe(user_code):
        return False
    if not callable(reference_func):
        return False

    result_queue = multiprocessing.Queue()
    process = multiprocessing.Process(
        target=_execute_user_code, args=(user_code, result_queue)
    )

    try:
        process.start()
        process.join(timeout_seconds)

        if process.is_alive():
            process.terminate()
            return False

        try:
            json_result = result_queue.get_nowait()
        except queue.Empty:
            return False

        try:
            user_result = json.loads(json_result)
        except json.JSONDecodeError:
            return False

        try:
            reference_result = reference_func()
        except Exception:
            return False

        return user_result == reference_result

    except Exception:
        traceback.print_exc(limit=1, file=sys.stderr)
        return False

    finally:
        if process.is_alive():
            process.terminate()
        process.join()

