from typing import List


class SecureCommandExecutor:
    """
    Execute a limited set of system commands from predefined absolute paths.
    Validates command names and arguments strictly to mitigate command injection
    and output exposure risks.
    """

    # Map allowed command names to their absolute system paths
    _ALLOWED_COMMANDS = {
        "echo": "/usr/bin/echo",
        "date": "/usr/bin/date",
        "whoami": "/usr/bin/whoami",
        "uname": "/usr/bin/uname",
        "id": "/usr/bin/id",
        "cal": "/usr/bin/cal",
        "uptime": "/usr/bin/uptime",
        "hostname": "/usr/bin/hostname",
    }

    # Directories considered trusted for command execution
    _TRUSTED_DIRECTORIES = {"/usr/bin", "/bin"}

    # Maximum number of characters to expose from command output
    _MAX_OUTPUT_LENGTH = 200

    @staticmethod
    def _validate_command(cmd: str) -> bool:
        """
        Ensure the command is a non-empty string and is in the whitelist.
        """
        return isinstance(cmd, str) and bool(cmd.strip()) and cmd.strip() in SecureCommandExecutor._ALLOWED_COMMANDS

    @staticmethod
    def _validate_args(args: List[str]) -> bool:
        """
        Ensure all arguments are valid ASCII, non-empty, <=256 chars and contain
        only letters, digits, underscore, or hyphen.
        """
        pattern = re.compile(r"^[A-Za-z0-9_\-]+$")  # alphanumeric, underscore, hyphen
        for arg in args:
            if not isinstance(arg, str):
                return False
            if not arg:
                return False
            if len(arg) > 256:
                return False
            if not pattern.match(arg):
                return False
        return True

    def execute(self, command: str, *args: str) -> str:
        """
        Execute the specified command with validated arguments.
        Returns a truncated string representation of the command's stdout.
        """
        cmd_clean = command.strip()
        if not self._validate_command(cmd_clean):
            return "Error: Invalid or disallowed command."
        if not self._validate_args(args):
            return "Error: Invalid arguments."

        # Resolve to absolute path and confirm it is in a trusted directory
        cmd_path = SecureCommandExecutor._ALLOWED_COMMANDS[cmd_clean]
        if not (
            os.path.isfile(cmd_path)
            and os.access(cmd_path, os.X_OK)
            and os.path.abspath(cmd_path).startswith(tuple(SecureCommandExecutor._TRUSTED_DIRECTORIES))
        ):
            return "Error: Command not available."

        command_list = [cmd_path] + list(args)

        try:
            result = subprocess.run(
                command_list,
                capture_output=True,
                text=True,
                check=True,
                timeout=10,
                shell=False,
            )
            output = result.stdout.strip()
            if len(output) > self._MAX_OUTPUT_LENGTH:
                output = output[: self._MAX_OUTPUT_LENGTH] + "..."
            return output
        except subprocess.TimeoutExpired:
            return "Error: Command timed out."
        except subprocess.CalledProcessError as e:
            return f"Error: Command exited with status {e.returncode}."
        except FileNotFoundError:
            return "Error: Command not found."
        except PermissionError:
            return "Error: Permission denied."
        except OSError as e:
            return f"Error: OS error: {e.strerror}."
        except Exception:
            return "Error: Failed to execute command."

    @staticmethod
    def generate_random_string(length: int) -> str:
        """
        Generate a cryptographically secure random string of the given length.
        """
        if not isinstance(length, int) or length <= 0:
            raise ValueError("Length must be a positive integer.")
        alphabet = string.ascii_letters + string.digits
        return "".join(secrets.choice(alphabet) for _ in range(length))

    @staticmethod
    def is_integer(value: str) -> bool:
        """
        Check whether the provided string represents an integer.
        """
        if not isinstance(value, str):
            return False
        try:
            int(value)
            return True
        except ValueError:
            return False


