class Quantity:
    """
    Represents a quantity with an amount, unit, and error bounds.
    """

    __slots__ = ("amount", "unit", "error_lower", "error_upper")

    def __init__(
        self,
        amount: float,
        unit: str,
        error_lower: float,
        error_upper: float,
    ) -> None:
        self.amount = self._validate_number(amount, "amount")
        self.unit = self._validate_unit(unit)
        self.error_lower = self._validate_number(error_lower, "error_lower")
        self.error_upper = self._validate_number(error_upper, "error_upper")

        if self.error_lower > self.error_upper:
            raise ValueError("error_lower cannot be greater than error_upper")

    @staticmethod
    def _validate_number(value: Any, field_name: str) -> float:
        if isinstance(value, (int, float)):
            num = float(value)
        elif isinstance(value, str):
            try:
                num = float(value)
            except ValueError as exc:
                raise ValueError(
                    f"Invalid numeric value for '{field_name}': '{value}'"
                ) from exc
        else:
            raise ValueError(
                f"Unsupported type for '{field_name}': {type(value).__name__}"
            )

        if not math.isfinite(num):
            raise ValueError(f"'{field_name}' must be a finite number, got {value}")

        return num

    @staticmethod
    def _validate_unit(unit: Any) -> str:
        if not isinstance(unit, str):
            raise ValueError(f"Unit must be a string, got {type(unit).__name__}")
        unit = unit.strip()
        if not unit:
            raise ValueError("Unit cannot be empty")
        if any(ord(c) > 127 for c in unit):
            raise ValueError("Unit must contain only ASCII characters")
        if len(unit) > 50:
            raise ValueError("Unit string is too long")
        return unit

    @classmethod
    def from_json(cls, data: Dict[str, Any]) -> "Quantity":
        """
        Create a Quantity instance from a dictionary optionally loaded from JSON.
        """
        if not isinstance(data, dict):
            raise ValueError("Input must be a dictionary")

        required_keys = ("amount", "unit", "error_lower", "error_upper")
        missing = [k for k in required_keys if k not in data]
        if missing:
            raise ValueError(f"Missing required fields: {', '.join(missing)}")

        return cls(
            data["amount"],
            data["unit"],
            data["error_lower"],
            data["error_upper"],
        )

    def to_json(self) -> Dict[str, Any]:
        """
        Serialize the Quantity instance to a JSON-friendly dictionary.
        """
        return {
            "amount": self.amount,
            "unit": self.unit,
            "error_lower": self.error_lower,
            "error_upper": self.error_upper,
        }

    def __str__(self) -> str:
        return (
            f"{self.amount:.6g} {self.unit} "
            f"(+{self.error_upper:.6g}/-{self.error_lower:.6g})"
        )

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, Quantity):
            return NotImplemented
        return (
            math.isclose(self.amount, other.amount, rel_tol=1e-9, abs_tol=0.0)
            and self.unit == other.unit
            and math.isclose(
