            )
            and math.isclose(
                self.error_upper, other.error_upper, rel_tol=1e-9, abs_tol=0.0
            )
        )

    def __repr__(self) -> str:
        return (
            f"Quantity(amount={self.amount!r}, unit={self.unit!r}, "
            f"error_lower={self.error_lower!r}, error_upper={self.error_upper!r})"
