from typing import Tuple, Optional


class User:
    """Simple user data container."""

    def __init__(self, username: str, age: int, email: str) -> None:
        self.username = username
        self.age = age
        self.email = email


def generate_random_username(length: int = 8) -> str:
    """Generate a cryptographically secure random username."""
    alphabet = string.ascii_letters + string.digits
    return "".join(secrets.choice(alphabet) for _ in range(length))


def generate_random_email() -> str:
    """Generate a cryptographically secure random email address."""
    local_part = generate_random_username(6)
    domain = generate_random_username(5)
    tld = secrets.choice(["com", "net", "org"])
    return f"{local_part}@{domain}.{tld}"


def validate_user_input(username: str, age: int, email: str) -> Tuple[str, int, str]:
    """Validate and sanitize user input."""
    if not isinstance(username, str):
        raise ValueError("Username must be a string.")
    if not username:
        raise ValueError("Username cannot be empty.")
    if not re.fullmatch(r"[A-Za-z0-9_]{3,32}", username):
        raise ValueError(
            "Username must be 3-32 characters long and contain only letters, digits, or underscores."
        )

    if not isinstance(age, int):
        raise ValueError("Age must be an integer.")
    if age < 0 or age > 150:
        raise ValueError("Age must be between 0 and 150.")

    if not isinstance(email, str):
