import ast
import itertools
import numpy as np
import types

_MAX_LAMBDA_LENGTH = 200
_MAX_AST_NODES = 50
_ALLOWED_OPERATORS = (
    ast.Add,
    ast.Sub,
    ast.Mult,
    ast.Div,
    ast.FloorDiv,
    ast.Mod,
    ast.Pow,
    ast.LShift,
    ast.RShift,
    ast.BitOr,
    ast.BitAnd,
    ast.BitXor,
    ast.UAdd,
    ast.USub,
    ast.Not,
    ast.Invert,
)
_ALLOWED_COMPARISONS = (
    ast.Eq,
    ast.NotEq,
    ast.Lt,
    ast.LtE,
    ast.Gt,
    ast.GtE,
)


class _SafeLambdaValidator(ast.NodeVisitor):
    def __init__(self, allowed_names):
        self.node_count = 0
        self.errors = []
        self.allowed_names = allowed_names

    def generic_visit(self, node):
        self.node_count += 1
        if self.node_count > _MAX_AST_NODES:
            raise ValueError("Lambda expression too complex")
        super().generic_visit(node)

    def visit_Module(self, node):
        if len(node.body) != 1 or not isinstance(node.body[0], ast.Expr):
            raise ValueError("Lambda expression not in evaluable form")
        return super().visit(node.body[0].value)

    def visit_Lambda(self, node):
        return super().visit(node.body)

    def visit_Name(self, node):
        if not isinstance(node.ctx, ast.Load):
            raise ValueError("Invalid context for name")
        if node.id not in self.allowed_names:
            raise ValueError(f"Disallowed name: {node.id}")
        return super().visit(node)

    def visit_Constant(self, node):
        return

    def visit_BoolOp(self, node):
        for value in node.values:
            self.visit(value)

    def visit_UnaryOp(self, node):
        if not isinstance(node.op, _ALLOWED_OPERATORS):
            raise ValueError(f"Disallowed unary operator: {node.op}")
        self.visit(node.operand)

    def visit_BinOp(self, node):
        if not isinstance(node.op, _ALLOWED_OPERATORS):
            raise ValueError(f"Disallowed binary operator: {node.op}")
        self.visit(node.left)
        self.visit(node.right)

    def visit_Compare(self, node):
        self.visit(node.left)
        for op in node.ops:
            if not isinstance(op, _ALLOWED_COMPARISONS):
                raise ValueError(f"Disallowed comparison: {op}")
        for comp in node.comparators:
            self.visit(comp)

    def visit_Call(self, node):
        raise ValueError("Function calls are not allowed")

    def visit_Attribute(self, node):
        raise ValueError("Attribute access is not allowed")

    def visit_Subscript(self, node):
        raise ValueError("Subscript access is not allowed")

    def visit_ListComp(self, node):
        raise ValueError("Comprehensions are not allowed")

    def visit_DictComp(self, node):
        raise ValueError("Comprehensions are not allowed")

    def visit_SetComp(self, node):
        raise ValueError("Comprehensions are not allowed")

    def visit_GeneratorExp(self, node):
        raise ValueError("Comprehensions are not allowed")


def _validate_lambda_expression(method: str) -> bool:
    if not isinstance(method, str) or not method or len(method) > _MAX_LAMBDA_LENGTH:
        return False
    try:
        tree = ast.parse(method, mode="eval")
    except SyntaxError:
        return False
    if not isinstance(tree.body, ast.Lambda):
        return False
    args = tree.body.args
    if len(args.args) != 4:
        return False
    arg_names = {arg.arg for arg in args.args}
    if any(not arg.isidentifier() for arg in arg_names):
        return False
    validator = _SafeLambdaValidator(arg_names)
    try:
        validator.visit(tree)
    except ValueError:
        return False
    return True


def _compile_exclude_lambda(method: str):
    try:
        code_obj = compile(method, "<lambda>", "eval")
    except Exception as exc:
        raise ValueError("Failed to compile method lambda expression") from exc
    safe_globals = {"__builtins__": None}
    try:
        lambda_func = eval(code_obj, safe_globals, {})
    except Exception as exc:
        raise ValueError("Failed to instantiate method lambda expression") from exc
    if not callable(lambda_func):
        raise ValueError("Provided method is not a callable lambda")
    return lambda_func


def curve(data: np.ndarray, values: np.ndarray) -> np.ndarray:
    if values is None:
        return np.array(data, copy=True)
    if not isinstance(values, np.ndarray):
        raise TypeError("values must be a NumPy array or None")
    if values.shape != data.shape:
        raise ValueError("values array must match shape of data")
    return np.array(values, copy=True)


def sum_filtered(data: np.ndarray, method: str) -> float:
    if not isinstance(data, np.ndarray):
        raise TypeError("data must be a NumPy array")
    if not _validate_lambda_expression(method):
        raise ValueError("method is not a safe lambda expression with four arguments")
    exclude = _compile_exclude_lambda(method)
    processed_data = curve(data, None)
    total = 0.0
    for idx in itertools.product(*(range(d) for d in processed_data.shape)):
        args = (*idx, 0, 0)[:4]
        try:
            if not exclude(*args):
                continue
        except Exception:
            continue
        total += float(processed_data[idx])
    return total

