import argparse
import logging
import os
import sys
import pathlib
import re
from typing import List

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s:%(message)s",
    stream=sys.stderr,
)

def _resolve_path(given_path: str, base_dir: pathlib.Path) -> pathlib.Path:
    """Resolve a path and ensure it is within the base directory."""
    resolved = pathlib.Path(given_path).resolve()
    try:
        resolved.relative_to(base_dir.resolve())
    except ValueError as exc:
        raise ValueError(
            f"'{given_path}' is not a valid path within the expected base directory."
        ) from exc
    return resolved

def _validate_package_name(name: str) -> None:
    pattern = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*(?:\.[A-Za-z_][A-Za-z0-9_]*)*$")
    if not pattern.match(name):
        raise ValueError(f"Invalid package name: {name!r}")

def _discover_modules(package_name: str, base_dir: pathlib.Path) -> List[str]:
    """Discover all submodules of a top-level package without importing it."""
    _validate_package_name(package_name)
    package_path = base_dir.joinpath(*package_name.split(".")).resolve()
    if not package_path.is_dir():
        raise RuntimeError(f"Package directory for '{package_name}' not found at {package_path}.")

    modules: List[str] = []
    base_module = package_name

    for root, dirs, files in os.walk(str(package_path)):
        dirs[:] = [d for d in dirs if d != "__pycache__"]
        rel_dir = pathlib.Path(root).relative_to(package_path)
        if "__init__.py" in files:
            module_name = ".".join([base_module] + list(rel_dir.parts))
            modules.append(module_name)
        for filename in files:
            if filename.endswith(".py") and filename != "__init__.py":
                rel_file = pathlib.Path(root) / filename
                rel_parts = rel_file.relative_to(package_path).with_suffix("").parts
                module_name = ".".join([base_module] + list(rel_parts))
                modules.append(module_name)
    return sorted(set(modules))

def _read_template(path: pathlib.Path) -> str:
    try:
        with open(path, "r", encoding="utf-8") as fh:
            return fh.read()
    except OSError as exc:
        raise RuntimeError(f"Failed to read template file: {exc}") from exc

def _write_file(path: pathlib.Path, content: str) -> None:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        with open(path, "w", encoding="utf-8") as fh:
            fh.write(content)
    except OSError as exc:
        raise RuntimeError(f"Failed to write output file: {exc}") from exc

def _build_modules_list(modules: List[str]) -> str:
    return "
".join(f"- {m}" for m in modules)

def _parse_arguments() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Generate a README from a template.")
    parser.add_argument(
        "--template",
        required=True,
        help="Path to the README template file.",
    )
    parser.add_argument(
        "--output",
        required=True,
        help="Path where the generated README will be written.",
    )
    parser.add_argument(
        "--package",
        required=True,
        help="Top-level package name to introspect for modules.",
    )
    return parser.parse_args()

def main() -> None:
    try:
        args = _parse_arguments()
        base = pathlib.Path.cwd()

        template_path = _resolve_path(args.template, base)
        output_path = _resolve_path(args.output, base)

        modules = _discover_modules(args.package, base)
        modules_section = _build_modules_list(modules)

        template = _read_template(template_path)
        readme_content = template.replace("{{MODULES}}", modules_section)

        _write_file(output_path, readme_content)

        logging.info("README generated at %s", output_path)
    except Exception as exc:
        logging.error("An error occurred: %s", exc)
        sys.exit(1)

if __name__ == "__main__":
    main()

