def validate_org_name(name: str) -> str:
    if not name:
        raise ValueError("Organization name cannot be empty.")
    if len(name) > 100:
        raise ValueError("Organization name must not exceed 100 characters.")
    pattern = re.compile(r"^[A-Za-z0-9\-.]+$")
    if not pattern.match(name):
        raise ValueError("Invalid organization name format.")
    return name.strip()


def validate_username(username: str) -> str:
    if not username:
        raise ValueError("Username cannot be empty.")
    sanitized = username.strip()
    if not sanitized:
        raise ValueError("Username cannot be solely whitespace.")
    if len(sanitized) > 30:
        raise ValueError("Username must not exceed 30 characters.")
    return sanitized


def main():
    parser = argparse.ArgumentParser(description="Fetch GitHub organization information.")
    parser.add_argument(
        "org",
        type=str,
        help="GitHub organization name (alphanumeric, dashes, periods).",
    )
    parser.add_argument(
        "-u",
        "--username",
        type=str,
        required=True,
        help="GitHub username.",
    )
    args = parser.parse_args()

    try:
        org_name = validate_org_name(args.org)
    except ValueError as e:
        logging.error("Organization name validation failed: %s", e)
        sys.exit(1)

    try:
        username = validate_username(args.username)
    except ValueError as e:
        logging.error("Username validation failed: %s", e)
        sys.exit(1)

    # Prompt for password securely
    try:
        password = getpass.getpass(prompt="GitHub password: ")
    except Exception as e:
        logging.error("Password input error: %s", e)
        sys.exit(1)

    if not password:
        logging.error("Password cannot be empty.")
        sys.exit(1)

    try:
        fetcher = GitFetcher(org=org_name, username=username, password=password)
        org_info = fetcher.get_org_info()
    except urllib2.HTTPError as http_err:
        logging.error("HTTP error: %s", http_err.code)
        sys.exit(1)
    except urllib2.URLError as url_err:
        logging.error("URL error: %s", url_err.reason)
        sys.exit(1)
    except Exception as err:
        logging.error("Unexpected error: %s", err)
        sys.exit(1)

    # Pretty-print the organization info
    try:
        print(json.dumps(org_info, indent=4, sort_keys=True))
    except Exception as out_err:
        logging.error("Error formatting output: %s", out_err)
        sys.exit(1)


if __name__ == "__main__":
    main()

