import re
import sqlite3
from typing import Dict, Any, List, Tuple, Optional, Mapping

MAX_RESULT_ROWS = 10_000
# Destructive or potentially malicious keywords
FORBIDDEN_KEYWORDS = {
    "DROP", "DELETE", "TRUNCATE", "ALTER", "CREATE",
    "REPLACE", "UNION", "EXCEPT", "INTERSECT",
    "INSERT", "UPDATE", "MERGE", "EXEC", "CALL",
}

ALLOWED_TEMPLATE_CHARS_RE = re.compile(r"^[a-zA-Z0-9_<>=%\s\.\,\(\)\*\-]+$")

class QueryExecutionError(RuntimeError):
    """Generic query execution error without leaking details."""


def _validate_template(template: str) -> None:
    if not isinstance(template, str):
        raise TypeError("Query template must be a string.")
    if not template.strip():
        raise ValueError("Query template cannot be empty.")

    # Disallow multiple statements by ensuring no semicolons
    if ";" in template:
        raise ValueError("Semicolons are not allowed in query template.")

    # Basic character whitelist
    if not ALLOWED_TEMPLATE_CHARS_RE.fullmatch(template):
        raise ValueError("Query template contains disallowed characters.")

    # Tokenize and check for forbidden keywords
    tokens = {word.upper() for word in re.findall(r" (\w+) ", template)}
    if tokens & FORBIDDEN_KEYWORDS:
        raise ValueError("Destructive or forbidden keywords are not allowed in query template.")


def _validate_parameters(params: Mapping[str, Any]) -> None:
    if not isinstance(params, Mapping):
        raise TypeError("Parameters must be a mapping.")
    allowed_types = (str, int, float, bytes, type(None))
    for key, value in params.items():
        if not isinstance(key, str):
            raise TypeError(f"Parameter name '{key}' is not a string.")
        if not isinstance(value, allowed_types):
            raise TypeError(
                f"Parameter '{key}' has disallowed type {type(value).__name__}."
            )


def _extract_placeholders(template: str) -> List[str]:
    return re.findall(r":(\w+)", template)


def _validate_placeholder_usage(template: str, params: Mapping[str, Any]) -> None:
    placeholders = set(_extract_placeholders(template))
    supported_placeholders = set(params.keys())
    missing = placeholders - supported_placeholders
    if missing:
        raise ValueError(f"Missing values for placeholders: {', '.join(sorted(missing))}")
    unused = supported_placeholders - placeholders
    if unused:
        raise ValueError(f"Unused parameters provided: {', '.join(sorted(unused))}")


def execute_query(
    query_template: str,
    scope: Dict[str, Any],
    parameters: Dict[str, Any]
) -> List[Dict[str, Any]]:
    """
    Executes a SQL query safely using an SQLite connection from the provided scope.
    Returns the result set as a list of dictionaries mapping column names to values.
    """
    _validate_template(query_template)
    _validate_parameters(parameters)

    if not isinstance(scope, dict):
        raise TypeError("Scope must be a dictionary.")
    if "conn" not in scope:
        raise KeyError("Scope must contain a 'conn' key.")
    conn = scope["conn"]
    if type(conn) is not sqlite3.Connection:  # Ensure plain sqlite3.Connection, no subclass
        raise TypeError("Scope['conn'] must be an sqlite3.Connection object.")
    _validate_placeholder_usage(query_template, parameters)

    try:
        cur = conn.cursor()
        cur.execute(query_template, parameters)
        col_names = [desc[0] for desc in cur.description] if cur.description else []
        rows = cur.fetchmany(MAX_RESULT_ROWS)
        result = [dict(zip(col_names, row)) for row in rows]
        # If more rows exist beyond LIMIT, consume them without exposing
        while cur.fetchone():
            pass
        return result
    except sqlite3.Error:
        raise QueryExecutionError("An error occurred while executing the query.") from None

import ast

# Functions that are explicitly allowed to be used in the sandbox.
SAFE_FUNCTIONS = {
    "len": len,
    "range": range,
    "int": int,
    "float": float,
    "str": str,
}

# Allowed binary and unary operators mapped to their implementations.
ALLOWED_OPERATORS = {
    ast.Add: lambda a, b: a + b,
    ast.Sub: lambda a, b: a - b,
    ast.Mult: lambda a, b: a * b,
    ast.Div: lambda a, b: a / b,
    ast.Mod: lambda a, b: a % b,
    ast.Pow: lambda a, b: a ** b,
    ast.UAdd: lambda a: +a,
    ast.USub: lambda a: -a,
    ast.Eq: lambda a, b: a == b,
    ast.NotEq: lambda a, b: a != b,
    ast.Lt: lambda a, b: a < b,
    ast.LtE: lambda a, b: a <= b,
    ast.Gt: lambda a, b: a > b,
    ast.GtE: lambda a, b: a >= b,
    ast.And: lambda a, b: a and b,
    ast.Or: lambda a, b: a or b,
}


class _SafeEvalVisitor(ast.NodeVisitor):
    """
    AST visitor that evaluates a restricted subset of Python expressions.
    """

    def __init__(self, instance, globals_dict=None):
        if not isinstance(instance, object):
            raise TypeError("instance must be an object")
        self._instance = instance
        self._globals = globals_dict if globals_dict is not None else {}

    def visit_Module(self, node):
        for stmt in node.body:
            self.visit(stmt)

    def visit_Expr(self, node):
        self.visit(node.value)

    def visit_Assign(self, node):
        if len(node.targets) != 1:
            raise ValueError("Only single target assignments are allowed")
        target = node.targets[0]
        value = self.visit(node.value)
        if isinstance(target, ast.Attribute):
            if isinstance(target.value, ast.Name) and target.value.id == "instance":
                attr_name = target.attr
                if attr_name.startswith("_"):
                    raise ValueError("Setting private attributes is not allowed")
                if callable(value):
                    raise ValueError("Assigning callables to instance attributes is not allowed")
                setattr(self._instance, attr_name, value)
            else:
                raise ValueError("Assignment target must be an attribute of 'instance'")
        elif isinstance(target, ast.Name):
            self._globals[target.id] = value
        else:
            raise ValueError("Unsupported assignment target")

    def visit_Call(self, node):
        """
        Only allows calls of functions that are explicitly whitelisted.
        Calls to methods of the instance are prohibited.
        """
        # Reject callable expressions that refer to instance attributes.
        if isinstance(node.func, ast.Attribute):
            if isinstance(node.func.value, ast.Name) and node.func.value.id == "instance":
                raise ValueError("Direct method calls on 'instance' are forbidden")
        func = self.visit(node.func)
        args = [self.visit(arg) for arg in node.args]
        kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
        return func(*args, **kwargs)

    def visit_Name(self, node):
        if node.id == "instance":
            return self._instance
        if node.id in self._globals:
            return self._globals[node.id]
        if node.id in SAFE_FUNCTIONS:
            return SAFE_FUNCTIONS[node.id]
        raise ValueError(f"Undefined name '{node.id}'")

    def visit_Attribute(self, node):
        value = self.visit(node.value)
        if isinstance(value, object):
            if value is self._instance:
                if node.attr.startswith("_"):
                    raise ValueError("Access to private instance attributes is forbidden")
                attr = getattr(value, node.attr)
                if callable(attr):
                    raise ValueError("Access to callable instance attributes is forbidden")
                return attr
            else:
                # Allow attribute access on other objects (globals) only if the
                # attribute is not callable and does not start with an underscore.
                if node.attr.startswith("_"):
                    raise ValueError("Access to private attributes is forbidden")
                attr = getattr(value, node.attr)
                if callable(attr):
                    raise ValueError("Access to callable attributes is forbidden")
                return attr
        raise ValueError("Attribute access is not allowed")

    def visit_BinOp(self, node):
        left = self.visit(node.left)
        right = self.visit(node.right)
        op_func = ALLOWED_OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Operator {type(node.op).__name__} not allowed")
        return op_func(left, right)

    def visit_UnaryOp(self, node):
        operand = self.visit(node.operand)
        op_func = ALLOWED_OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unary operator {type(node.op).__name__} not allowed")
        return op_func(operand)

    def visit_Constant(self, node):
        return node.value

    # Compatibility methods for Python <3.8
    def visit_Num(self, node):  # pragma: no cover
        return node.n

    def visit_Str(self, node):  # pragma: no cover
        return node.s

    def visit_NameConstant(self, node):  # pragma: no cover
        return node.value

    def generic_visit(self, node):
        raise ValueError(f"Disallowed node type: {type(node).__name__}")


def exec_in_instance_context(instance, code_str, max_length=10000):
    """
    Execute a code string in a sandboxed context where the only mutable object
    is ``instance``.  Only safe operations are permitted.
    """
    if not isinstance(instance, object):
        raise TypeError("instance argument must be an object")
    if not isinstance(code_str, str):
        raise TypeError("code_str must be a string")
    if len(code_str) > max_length:
        raise ValueError("code_str exceeds maximum allowed length")

    try:
        parsed = ast.parse(code_str, mode="exec")
    except SyntaxError as e:
        raise ValueError(f"Invalid code: {e}") from None

    visitor = _SafeEvalVisitor(instance)
    try:
        visitor.visit(parsed)
    except Exception as exc:
        raise RuntimeError("Execution failed") from exc
    return None

import os
import pandas as pd
import tensorflow as tf
from typing import List, Callable, Optional, Any

# Directory where data files are allowed to reside
BASE_DATA_DIR = os.path.abspath(os.getenv("BASE_DATA_DIR", os.getcwd()))

# Secure mappings for allowed optimizer, loss and metrics
ALLOWED_OPTIMIZERS = {
    "adam": tf.keras.optimizers.Adam,
    "sgd": tf.keras.optimizers.SGD,
    "rmsprop": tf.keras.optimizers.RMSprop,
}

ALLOWED_LOSSES = {
    "mse": tf.keras.losses.MeanSquaredError,
    "binary_crossentropy": tf.keras.losses.BinaryCrossentropy,
    "categorical_crossentropy": tf.keras.losses.CategoricalCrossentropy,
    "sparse_categorical_crossentropy": tf.keras.losses.SparseCategoricalCrossentropy,
}

ALLOWED_METRICS = {
    "accuracy": "accuracy",
    "mae": "mae",
    "mse": "mse",
}

def _validate_file_path(path: str) -> str:
    """Validate that the file path is a readable file within the allowed data directory."""
    if not isinstance(path, str):
        raise ValueError("File path must be a string.")
    abs_path = os.path.realpath(path)
    if not abs_path.startswith(BASE_DATA_DIR + os.sep):
        raise PermissionError(f"File path {abs_path} is outside the allowed data directory.")
    if not os.path.isfile(abs_path):
        raise FileNotFoundError(f"File not found: {abs_path}")
    return abs_path

def _load_and_preprocess(csv_path: str, max_rows: Optional[int] = None) -> pd.DataFrame:
    """Load CSV file, perform minimal preprocessing, and optionally limit rows."""
    safe_path = _validate_file_path(csv_path)
    try:
        df = pd.read_csv(safe_path, engine="c", nrows=max_rows)
    except Exception as exc:
        raise RuntimeError(f"Failed to load CSV data from {safe_path}.") from exc
    if df.empty:
        raise ValueError(f"CSV file {safe_path} contains no data.")
    df = df.dropna()
    for col in df.select_dtypes(include="object").columns:
        df[col] = df[col].str.lower()
    return df

def compile_and_prepare_model(
    model_builder: Callable[[], tf.keras.Model],
    train_data_path: str,
    val_data_path: str,
    optimizer_name: str,
    loss_name: str,
    metrics_list: List[str],
    batch_size: int = 32,
    epochs: int = 10,
    preprocess_fn: Optional[Callable[[pd.DataFrame], pd.DataFrame]] = None,
    max_rows_per_file: Optional[int] = None,
) -> tf.keras.Model:
    """
    Compiles a TensorFlow model with specified optimizer, loss, and metrics.
    Loads and preprocesses training and validation data from CSV files.
    Returns the compiled model ready for training.
    """
    if not isinstance(optimizer_name, str):
        raise TypeError("optimizer_name must be a string.")
    if not isinstance(loss_name, str):
        raise TypeError("loss_name must be a string.")
    if not isinstance(metrics_list, list):
        raise TypeError("metrics_list must be a list of strings.")
    if not metrics_list:
        raise ValueError("metrics_list cannot be empty.")
    for metric in metrics_list:
        if not isinstance(metric, str):
            raise TypeError("Each metric must be a string.")
        if metric not in ALLOWED_METRICS:
            raise ValueError(f"Unsupported metric: {metric}")
    if optimizer_name not in ALLOWED_OPTIMIZERS:
        raise ValueError(f"Unsupported optimizer: {optimizer_name}")
    if loss_name not in ALLOWED_LOSSES:
        raise ValueError(f"Unsupported loss function: {loss_name}")
    if not isinstance(batch_size, int) or batch_size <= 0:
        raise ValueError("batch_size must be a positive integer.")
    if not isinstance(epochs, int) or epochs <= 0:
        raise ValueError("epochs must be a positive integer.")

    train_df = _load_and_preprocess(train_data_path, max_rows=max_rows_per_file)
    val_df = _load_and_preprocess(val_data_path, max_rows=max_rows_per_file)

    if preprocess_fn is not None:
        if not callable(preprocess_fn):
            raise TypeError("preprocess_fn must be callable.")
        train_df = preprocess_fn(train_df)
        val_df = preprocess_fn(val_df)

    if train_df.empty or val_df.empty:
        raise ValueError("Training or validation data is empty after preprocessing.")

    def df_to_dataset(df: pd.DataFrame, shuffle: bool = True) -> tf.data.Dataset:
        ds = tf.data.Dataset.from_tensor_slices(dict(df))
        if shuffle:
            ds = ds.shuffle(buffer_size=len(df), reshuffle_each_iteration=True)
        return ds.batch(batch_size)

    train_ds = df_to_dataset(train_df)
    val_ds = df_to_dataset(val_df, shuffle=False)

    model = model_builder()
    model.compile(
        optimizer=ALLOWED_OPTIMIZERS[optimizer_name](),
        loss=ALLOWED_LOSSES[loss_name](),
        metrics=[ALLOWED_METRICS[m] for m in metrics_list],
    )
    model.user_data = {"train_ds": train_ds, "val_ds": val_ds}
    return model

