#!/usr/bin/env python3
import argparse
import logging
import os
import re
import shutil
import subprocess
from pathlib import Path
from typing import Optional, Sequence

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s: %(message)s",
    datefmt="%Y-%m-%dT%H:%M:%S%z",
)


class KickstartSetupError(Exception):
    """Custom exception for kickstart setup errors."""
    pass


# Allowed top-level directories for all paths
ALLOWED_ROOTS = [
    Path("/var/www/kickstart"),
    Path("/srv/kickstart"),
    Path("/var/www/html/kickstart"),
]

# Mapping of permitted command names to absolute paths
ALLOWED_COMMANDS = {
    "timedatectl": Path("/usr/bin/timedatectl"),
    "bash": Path("/bin/bash"),
}


def validate_hostname(hostname: str) -> str:
    if not hostname or len(hostname) > 255:
        raise KickstartSetupError("Hostname must be 1-255 characters.")
    allowed = set("abcdefghijklmnopqrstuvwxyz0123456789-.")
    if set(hostname.lower()) - allowed:
        raise KickstartSetupError("Hostname contains invalid characters.")
    if hostname.startswith("-") or hostname.endswith("-"):
        raise KickstartSetupError("Hostname cannot start or end with a hyphen.")
    return hostname


# Accept IPv4/IPv6 region/city format with allowed characters
TIMEZONE_REGEX = re.compile(r"^[A-Za-z0-9_][A-Za-z0-9_/-]*[A-Za-z0-9_]$")


def validate_timezone(timezone: str) -> str:
    if "/" not in timezone:
        raise KickstartSetupError("Timezone must contain a '/'.")
    if not TIMEZONE_REGEX.match(timezone):
        raise KickstartSetupError("Timezone contains invalid characters.")
    return timezone


def safe_resolve(target: Path) -> Path:
    try:
        resolved = target.resolve(strict=False)
    except RuntimeError as exc:
        raise KickstartSetupError(f"Could not resolve path {target}") from exc
    # Ensure resolved path is under an allowed root
    for root in ALLOWED_ROOTS:
        try:
            resolved.relative_to(root.resolve())
            break
        except ValueError:
            continue
    else:
        raise KickstartSetupError(f"Path {target} is outside allowed directories.")
    # Ensure no symlink component
    current = Path(resolved.root)
    for part in resolved.parts[1:]:
        current = current / part
        if current.is_symlink():
            raise KickstartSetupError(f"Symlink detected in path component {current}")
    return resolved


def copy_and_modify(src: Path, dst: Path, replacements: dict) -> None:
    try:
        shutil.copy2(src, dst)
    except OSError as exc:
        raise KickstartSetupError(f"Failed to copy {src} to {dst}: {exc}") from exc
    try:
        with dst.open("r", encoding="utf-8") as f:
            content = f.read()
        for placeholder, value in replacements.items():
            content = content.replace(placeholder, value)
        with dst.open("w", encoding="utf-8") as f:
            f.write(content)
    except OSError as exc:
        raise KickstartSetupError(f"Failed to modify {dst}: {exc}") from exc
    # Set secure permissions
    try:
        if dst.suffix in {".sh", ".py"}:
            dst.chmod(0o755)
        else:
            dst.chmod(0o644)
    except OSError:
        pass


def run_subprocess(command: Sequence[str], *, cwd: Optional[Path] = None, env: Optional[dict] = None) -> str:
    if not isinstance(command, Sequence) or not command:
        raise KickstartSetupError("Command must be a non-empty sequence of strings.")
    for part in command:
        if not isinstance(part, str) or not part:
            raise KickstartSetupError("Command parts must be non-empty strings.")

    cmd_name = command[0]
    if cmd_name not in ALLOWED_COMMANDS:
        raise KickstartSetupError(f"Unauthorized command {cmd_name}.")

    # Replace the command name with its absolute path
    command = [str(ALLOWED_COMMANDS[cmd_name])] + list(command[1:])

    if cwd is not None:
        cwd = safe_resolve(cwd)

    # Build sanitized environment: inherit current env but remove PATH override
    sanitized_env = {k: v for k, v in os.environ.items() if k != "PATH"}
    if env:
        sanitized_env.update({k: v for k, v in env.items() if k != "PATH"})

    try:
        result = subprocess.run(
            command,
            cwd=str(cwd) if cwd else None,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            env=sanitized_env,
        )
    except subprocess.CalledProcessError as exc:
        raise KickstartSetupError(
            f"Command {command} failed with exit code {exc.returncode}: {exc.stderr}"
        ) from exc
    finally:
        # Do not keep references to sensitive data
        command = None

    return result.stdout.strip()


def main() -> None:
    parser = argparse.ArgumentParser(description="Prepare CentOS 7 kickstart files.")
    parser.add_argument(
        "src_dir", type=Path, help="Source directory containing kickstart files and scripts."
    )
    parser.add_argument(
        "dest_dir",
        type=Path,
        help="Destination directory for the prepared files.",
    )
    parser.add_argument(
        "--hostname",
        required=True,
        help="Hostname to set in the kickstart configuration.",
    )
    parser.add_argument(
        "--basedir",
        required=True,
        help="Base directory for the kickstart server (e.g., /var/www/html/kickstart).",
    )
    parser.add_argument(
        "--timezone",
        required=True,
        help="Timezone to use in the kickstart configuration.",
    )
    args = parser.parse_args()

    try:
        hostname = validate_hostname(args.hostname)
        timezone = validate_timezone(args.timezone)
    except KickstartSetupError as e:
        logging.error(e)
        raise SystemExit(1)

    try:
        src_dir = safe_resolve(args.src_dir)
        dest_dir = safe_resolve(args.dest_dir)
        base_dir = safe_resolve(Path(args.basedir))
    except KickstartSetupError as e:
        logging.error(e)
        raise SystemExit(1)

    if not src_dir.is_dir() or not dest_dir.is_dir():
        logging.error("Source and destination must be directories.")
        raise SystemExit(1)

    placeholders = {
        "__HOSTNAME__": hostname,
        "__BASEDIR__": str(base_dir),
        "__TIMEZONE__": timezone,
    }

    ks_file = src_dir / "centos7.ks"
    if not ks_file.is_file():
        logging.error(f"Kickstart file {ks_file} does not exist.")
        raise SystemExit(1)

    dest_ks = dest_dir / ks_file.name
    copy_and_modify(ks_file, dest_ks, placeholders)
    logging.info(f"Prepared kickstart file at {dest_ks.relative_to(dest_dir)}")

    scripts_dir = src_dir / "scripts"
    dest_scripts_dir = dest_dir / "scripts"
    dest_scripts_dir.mkdir(parents=True, exist_ok=True)

    for script in scripts_dir.iterdir():
        if script.is_file() and script.suffix in {".sh", ".py"}:
            dest_script = dest_scripts_dir / script.name
            copy_and_modify(script, dest_script, placeholders)
            logging.info(f"Prepared script {dest_script.relative_to(dest_dir)}")

    # Example of safe subprocess use:
    # run_subprocess(["timedatectl", "set-timezone", timezone], env={"LANG": "C"})

    logging.info("Kickstart configuration and scripts are ready.")


if __name__ == "__main__":
    main()

