if BASE_DIR == Path("/"):
    raise RuntimeError("BASE_DIR cannot be the root directory")

MAX_ATTRIBUTE_LENGTH = 65536


def _ensure_within_base(path: Path) -> None:
    """Ensure that the given path is within BASE_DIR and does not contain
    any symlink components.
    """
    try:
        resolved = path.resolve(strict=False)
    except Exception:
        raise ValueError("Invalid path provided")

    try:
        resolved.relative_to(BASE_DIR)
    except ValueError:
        raise ValueError("Path is outside the allowed base directory")

    current = BASE_DIR
    for part in resolved.relative_to(BASE_DIR).parts:
        current = current / part
        if current.is_symlink():
            raise ValueError("Symlink detected in path component")
    if BASE_DIR.is_symlink():
        raise ValueError("BASE_DIR is a symlink")


def _is_valid_file(path: Path) -> bool:
    """Return True if path is an existing regular file and not a symlink."""
    return path.is_file() and not path.is_symlink()


def _open_input(path: Path, mode: str = "rt"):
    if path.suffix == ".gz" or path.name.endswith(".gz"):
        return gzip.open(path, mode, encoding="utf-8", errors="replace")
    return open(path, mode, encoding="utf-8", errors="replace")


def _parse_attributes(attr_str: str) -> Dict[str, str]:
    if len(attr_str) > MAX_ATTRIBUTE_LENGTH:
        _logger.warning(
            "Attribute string exceeds maximum length (%d); skipping line",
            MAX_ATTRIBUTE_LENGTH,
        )
        return {}
    attrs: Dict[str, str] = {}
    for part in filter(None, attr_str.split(";")):
        if "=" in part:
            key, value = part.split("=", 1)
            attrs[key.strip()] = value.strip()
    return attrs


def _format_attributes(attrs: Dict[str, str]) -> str:
    return ";".join(f'{k} "{v}"' for k, v in attrs.items()) + ";"


def _validate_dialect(dialect: str) -> None:
    allowed = {"standard", "custom"}
    if dialect not in allowed:
        raise ValueError("Unsupported dialect")


def gff3_to_gtf(
    input_path: str,
    output_path: str,
    dialect: str = "standard",
) -> None:
    """
    Convert a GFF3 file (plain or gzipped) to GTF format using the specified dialect.

    Parameters
    ----------
    input_path : str
        Path to the input GFF3 file. Can be plain or gzipped (.gz).
    output_path : str
        Path where the resulting GTF file will be written.
    dialect : str, optional
        Dialect of the GTF output. Currently supports 'standard' and 'custom'.
        Other values raise a ValueError.

    Raises
    ------
    FileNotFoundError
        If the input file does not exist.
    PermissionError
        If the output file cannot be written.
    ValueError
        If an unsupported dialect is specified or paths are invalid.
    """
    try:
        _validate_dialect(dialect)

        input_path_obj = Path(input_path).expanduser().resolve()
        output_path_obj = Path(output_path).expanduser().resolve()

        _ensure_within_base(input_path_obj)
        _ensure_within_base(output_path_obj)

        if not _is_valid_file(input_path_obj):
            raise FileNotFoundError("Input file does not exist or is invalid")

        if input_path_obj == output_path_obj:
            raise ValueError("Input and output paths must differ")

        output_path_obj.parent.mkdir(parents=True, exist_ok=True)

        with _open_input(input_path_obj, "rt") as in_file, output_path_obj.open(
            "x", encoding="utf-8"
        ) as out_file:
            for line in in_file:
                if line.startswith("#") or not line.strip():
                    continue

                fields = line.rstrip("
").split("	")
                if len(fields) != 9:
                    _logger.warning("Skipping malformed line")
                    continue

                seqid, source, type_field, start, end, score, strand, phase, attributes_str = fields

                # Validate numeric fields
                try:
                    start_int = int(start)
                    end_int = int(end)
                    if start_int > end_int:
                        _logger.warning("Start greater than end")
                        continue
                except ValueError:
                    _logger.warning("Invalid start/end values")
                    continue

                # Validate score (float or '.')
                if score != ".":
                    try:
                        float(score)
                    except ValueError:
                        _logger.warning("Invalid score")
                        continue

                # Validate strand
                if strand not in ("+", "-", "."):
                    _logger.warning("Invalid strand")
                    continue

                gtf_attrs = _parse_attributes(attributes_str)
                attr_string = _format_attributes(gtf_attrs)

                gtf_fields = [
                    seqid,
                    source,
                    type_field,
                    str(start_int),
                    str(end_int),
                    score,
                    strand,
                    ".",
                    attr_string,
                ]

                out_file.write("	".join(gtf_fields) + "
")

    except (OSError, ValueError) as exc:
        _logger.error("Error during GFF3 to GTF conversion")
        raise

