import json
import os
import sys
import logging
import numpy as np
import cv2
import tempfile
from pathlib import Path
from typing import List, Any
import stat
import contextlib

def _create_log_file() -> Path:
    log_dir = Path("/tmp/feature_extractor_logs")
    log_dir.mkdir(mode=0o700, exist_ok=True)
    fd, path = tempfile.mkstemp(dir=log_dir, prefix="log_", suffix=".log")
    os.close(fd)
    os.chmod(path, 0o600)
    return Path(path)

_LOG_FILE = _create_log_file()
logging.basicConfig(
    filename=str(_LOG_FILE),
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s %(message)s",
)

class SecureError(Exception):
    """Custom exception for secure error reporting."""
    pass

def safe_open(path: Path, mode: str, *, encoding=None) -> Any:
    """Open a file securely, forbidding symlinks and ensuring permissions."""
    flags = os.O_NOFOLLOW | os.O_CREAT
    if "r" in mode:
        flags |= os.O_RDONLY
    else:
        flags |= os.O_WRONLY | os.O_TRUNC
    try:
        # Ensure target is not a symlink
        if path.exists() and not path.is_file():
            raise SecureError(f"Target {path} is not a regular file.")
        fd = os.open(str(path), flags, mode=0o600)
        if encoding:
            return os.fdopen(fd, mode, encoding=encoding)
        else:
            return os.fdopen(fd, mode)
    except OSError as e:
        logging.error(f"Failed to open file {path}: {e}")
        raise SecureError("Cannot open file.") from e

def load_json(json_path: Path) -> Any:
    with safe_open(json_path, "r", encoding="utf-8") as f:
        try:
            return json.load(f)
        except json.JSONDecodeError as e:
            logging.error(f"JSON decode error in {json_path}: {e}")
            raise SecureError("Invalid JSON.") from e

def load_npy(npy_path: Path) -> Any:
    try:
        return np.load(npy_path, allow_pickle=False)
    except (ValueError, OSError, TypeError) as e:
        logging.error(f"Failed to load numpy file {npy_path}: {e}")
        raise SecureError("Invalid vocabulary file.") from e

def validate_image_path(image_path: Path, base_dir: Path) -> Path:
    try:
        abs_path = image_path.resolve(strict=True)
    except FileNotFoundError as e:
        raise SecureError("Image file does not exist.") from e
    try:
        abs_path.relative_to(base_dir.resolve(strict=True))
    except ValueError:
        raise SecureError("Image path is outside the allowed directory.")
    try:
        fd = os.open(str(abs_path), os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as e:
        raise SecureError("Failed to securely open image file.") from e
    os.close(fd)
    return abs_path

def read_file_bytes(path: Path) -> bytes:
    try:
        fd = os.open(str(path), os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as e:
        logging.error(f"Failed to open file descriptor for {path}: {e}")
        raise SecureError("Failed to open image file.") from e
    with os.fdopen(fd, "rb") as f:
        return f.read()

def extract_features(image_path: Path, vocab: Any) -> List[float]:
    img_bytes = read_file_bytes(image_path)
    image = cv2.imdecode(np.frombuffer(img_bytes, dtype=np.uint8), cv2.IMREAD_COLOR)
    if image is None:
        raise SecureError("Failed to load image.")
    if image.shape[0] * image.shape[1] > 10_000_000:
        raise SecureError("Image is too large.")
    orb = cv2.ORB_create()
    try:
        keypoints, descriptors = orb.detectAndCompute(image, None)
    except Exception as e:
        logging.error(f"ORB compute error for {image_path}: {e}")
        raise SecureError("Error computing descriptors.") from e
    if descriptors is None:
        descriptors = np.empty((0, orb.descriptorSize()), dtype=np.float32)
    if not isinstance(vocab, np.ndarray):
        raise SecureError("Vocabulary format is invalid; expected a numpy array.")
    n_clusters = vocab.shape[0]
    histogram = np.zeros(n_clusters, dtype=np.float32)
    if descriptors.size > 0:
        try:
            distances = np.linalg.norm(descriptors[:, None] - vocab[None, :], axis=2)
            nearest = np.argmin(distances, axis=1)
            for idx in nearest:
                histogram[idx] += 1
        except Exception as e:
            logging.error(f"Feature mapping error for {image_path}: {e}")
            raise SecureError("Error during feature mapping.") from e
    norm = np.linalg.norm(histogram)
    if norm > 0:
        histogram = histogram / norm
    return histogram.tolist()

def main():
    parser = argparse.ArgumentParser(description="Process images and extract features.")
    parser.add_argument("--annotations", required=True, help="Path to JSON annotation file.")
    parser.add_argument("--vocab", required=True, help="Path to .npy vocabulary file.")
    parser.add_argument("--image-dir", required=True, help="Path to directory containing images.")
    parser.add_argument("--output", help="Path to output JSON file. If omitted, prints to stdout.")
    args = parser.parse_args()

    annotations_path = Path(args.annotations)
    vocab_path = Path(args.vocab)
    image_dir = Path(args.image_dir)

    for path in (annotations_path, vocab_path, image_dir):
        if not path.exists():
            raise SecureError(f"Path does not exist: {path}")

    annotations = load_json(annotations_path)
    vocab = load_npy(vocab_path)

    if not isinstance(annotations, list):
        raise SecureError("Annotations JSON must be a list of records.")
    features_per_image: List[Any] = []

    for record in annotations:
        if not isinstance(record, dict):
            raise SecureError("Each annotation record must be a JSON object.")
        image_rel = record.get("image_path")
        if not isinstance(image_rel, str):
            raise SecureError("Annotation record missing 'image_path' string.")
        image_path = image_dir / image_rel
        abs_image_path = validate_image_path(image_path, image_dir)
        hist = extract_features(abs_image_path, vocab)
        features_per_image.append(hist)

    output_data = {"features": features_per_image}

    try:
        if args.output:
            safe_output_dir = Path.cwd() / "output"
            safe_output_dir.mkdir(mode=0o700, exist_ok=True)
            output_name = Path(args.output).name
            output_path = safe_output_dir / output_name
            with safe_open(output_path, "w", encoding="utf-8") as f:
                json.dump(output_data, f, separators=(",", ":"))
        else:
            print(json.dumps(output_data, separators=(",", ":")))
    except OSError as e:
        logging.error(f"Failed to write output: {e}")
        raise SecureError("Failed to write output.") from e

if __name__ == "__main__":
    try:
        main()
    except SecureError as e:
        sys.stderr.write(str(e) + "
")
        sys.exit(1)
    except Exception as e:
        logging.error(f"Unhandled exception: {e}")
        sys.stderr.write("An error occurred during execution.
")
        sys.exit(1)

