import os
import pathlib

# Absolute, readâonly paths to the predefined files
PREDEFINED_FASTA = pathlib.Path("/usr/share/genomics/predefined.fasta").resolve(strict=True)
PREDEFINED_GTF = pathlib.Path("/usr/share/genomics/predefined.gtf").resolve(strict=True)

DEFAULT_BUFFER = 8192

def _contains_symlink(path: pathlib.Path) -> bool:
    """
    Return True if any component of the path is a symbolic link.
    """
    current = path
    while True:
        if current.is_symlink():
            return True
        if current.parent == current:
            break
        current = current.parent
    return False

def _validate_file(path: pathlib.Path, *, must_be_writable: bool = False) -> None:
    if not path.is_absolute():
        raise ValueError(f"Path must be absolute: {path!s}")
    if not path.exists():
        raise ValueError(f"Path does not exist: {path!s}")
    if not path.is_file():
        raise ValueError(f"Path must refer to a regular file: {path!s}")
    if _contains_symlink(path):
        raise ValueError(f"Symlink component detected: {path!s}")
    if not os.access(path, os.R_OK):
        raise PermissionError(f"Read permission required for {path!s}")
    if must_be_writable and not os.access(path, os.W_OK):
        raise PermissionError(f"Write permission required for {path!s}")

def _open_read_atomic(path: pathlib.Path):
    fd = os.open(path, os.O_RDONLY | os.O_NOFOLLOW)
    try:
        return os.fdopen(fd, "rb", buffering=DEFAULT_BUFFER)
    except Exception:
        os.close(fd)
        raise

def _open_append_atomic(path: pathlib.Path):
    fd = os.open(path, os.O_WRONLY | os.O_APPEND | os.O_NOFOLLOW)
    try:
        return os.fdopen(fd, "ab", buffering=DEFAULT_BUFFER)
    except Exception:
        os.close(fd)
        raise

def append_predefined(gtf_file: str, fasta_file: str) -> None:
    """
    Append the contents of predefined FASTA and GTF files to the userâsupplied
    FASTA and GTF files respectively.
    """
    gtf_path = pathlib.Path(gtf_file).expanduser().resolve(strict=True)
    fasta_path = pathlib.Path(fasta_file).expanduser().resolve(strict=True)

    # Validate user files
    _validate_file(gtf_path, must_be_writable=True)
    _validate_file(fasta_path, must_be_writable=True)

    # Validate predefined files
    _validate_file(PREDEFINED_GTF)
    _validate_file(PREDEFINED_FASTA)

    try:
        with _open_read_atomic(PREDEFINED_FASTA) as src_fasta:
            fasta_data = src_fasta.read()
        with _open_append_atomic(fasta_path) as dst_fasta:
            dst_fasta.write(fasta_data)

        with _open_read_atomic(PREDEFINED_GTF) as src_gtf:
            gtf_data = src_gtf.read()
        with _open_append_atomic(gtf_path) as dst_gtf:
            dst_gtf.write(gtf_data)
    except Exception as exc:
        raise OSError("Failed to append predefined files") from exc

import collections
from collections import defaultdict
from typing import Any, Callable, Optional


class SecureDefaultDict(defaultdict):
    """
    A ``defaultdict`` variant that validates the ``default_factory`` passed to it.
    Accepts only callable objects or ``None``.
    """

    def __init__(
        self,
        default_factory: Optional[Callable[..., Any]] = None,
        *args: Any,
        **kwargs: Any,
    ) -> None:
        if default_factory is not None and not callable(default_factory):
            raise TypeError(
                "default_factory must be a callable or None, got "
                f"{type(default_factory).__name__}"
            )
        super().__init__(default_factory, *args, **kwargs)


class TrackingSecureDefaultDict(SecureDefaultDict):
    """
    Tracks calls to ``__missing__`` for testing purposes.
    """

    def __init__(
        self,
        default_factory: Optional[Callable[..., Any]] = None,
        *args: Any,
        **kwargs: Any,
    ) -> None:
        super().__init__(default_factory, *args, **kwargs)
        self._missing_called = False

    @property
    def missing_called(self) -> bool:
        return self._missing_called

    @missing_called.setter
    def missing_called(self, value: bool) -> None:
        self._missing_called = value

    def __missing__(self, key: Any) -> Any:
        self._missing_called = True
        return super().__missing__(key)


def test_defaultdict_repr_and_missing() -> None:
    # Test repr for empty SecureDefaultDict
    empty_dd = SecureDefaultDict(int)
    empty_repr = repr(empty_dd)
    if not isinstance(empty_repr, str):
        raise AssertionError("repr of empty SecureDefaultDict should be a string")
    if not empty_repr.startswith("defaultdict(<class 'int'>"):
        raise AssertionError("repr of empty SecureDefaultDict missing expected prefix")

    # Test repr for non-empty SecureDefaultDict
    non_empty_dd = SecureDefaultDict(int)
    non_empty_dd["a"] = 1
    non_empty_repr = repr(non_empty_dd)
    if not isinstance(non_empty_repr, str):
        raise AssertionError("repr of non-empty SecureDefaultDict should be a string")
    if "'a': 1" not in non_empty_repr:
        raise AssertionError("repr of non-empty SecureDefaultDict should contain the key-value pair")

    # Verify __missing__ behavior with a tracking subclass
    td = TrackingSecureDefaultDict(int)
    # Access a missing key; __missing__ should be invoked
    _ = td["missing"]
    if not td.missing_called:
        raise AssertionError("__missing__ was not called on first access")
    # Value for the missing key should be default (0)
    if td["missing"] != 0:
        raise AssertionError("Default value for missing key is incorrect")

    # Re-access same key; __missing__ should not be invoked again
    td.missing_called = False
    _ = td["missing"]
    if td.missing_called:
        raise AssertionError("__missing__ was incorrectly called on second access")

    # Ensure that providing an invalid default_factory raises TypeError
    try:
        SecureDefaultDict(None)
    except TypeError:
        pass
    else:
        raise AssertionError("Expected TypeError for invalid default_factory")


if __name__ == "__main__":
    test_defaultdict_repr_and_missing()

import json
import re
from decimal import Decimal, InvalidOperation
from typing import Any, Dict, Optional


class Quantity:
    def __init__(self, data: Dict[str, Any]) -> None:
        if not isinstance(data, dict):
            raise ValueError("Input must be a dictionary.")
        try:
            amount = self._sanitize_amount(data.get("amount"))
            unit = self._sanitize_unit(data.get("unit"))
            upper = self._sanitize_amount(data.get("upperBound"))
        except Exception as e:
            raise ValueError("Invalid input data.") from e

        self.amount: Decimal = amount
        self.unit: str = unit
        self.upperBound: Decimal = upper

    @classmethod
    def fromWikibase(cls, wikibase_data: Dict[str, Any]) -> "Quantity":
        if not isinstance(wikibase_data, dict):
            raise ValueError("Wikibase data must be a dictionary.")
        mapping: Dict[str, Any] = {}
        for key in ("amount", "unit", "upperBound"):
            if key in wikibase_data:
                mapping[key] = wikibase_data[key]
        if not all(k in mapping for k in ("amount", "unit", "upperBound")):
            raise ValueError("Required Wikibase fields are missing.")
        return cls(mapping)

    def __str__(self) -> str:
        try:
            data = {
                "amount": str(self.amount),
                "unit": self.unit,
                "upperBound": str(self.upperBound),
            }
            return json.dumps(data, separators=(",", ":"))
        except Exception:
            return "{}"

    def __eq__(self, other: Any) -> bool:
        if not isinstance(other, Quantity):
            return False
        return (
            self.amount == other.amount
            and self.unit == other.unit
            and self.upperBound == other.upperBound
        )

    @staticmethod
    def _sanitize_amount(value: Any) -> Decimal:
        if value is None:
            raise ValueError("Amount cannot be None.")
        if isinstance(value, Decimal):
            return value
        if isinstance(value, int):
            return Decimal(value)
        if isinstance(value, float):
            return Decimal(str(value))
        if isinstance(value, str):
            cleaned = value.strip()
            if not cleaned:
                raise ValueError("Amount string cannot be empty.")
            try:
                return Decimal(cleaned)
            except InvalidOperation:
                raise ValueError("Amount string is not a valid number.")
        raise ValueError("Amount must be a number or numeric string.")

    @staticmethod
    def _sanitize_unit(value: Any) -> str:
        if not isinstance(value, str):
            raise ValueError("Unit must be a string.")
        sanitized = value.strip()
        if not sanitized:
            raise ValueError("Unit cannot be empty.")
        # Allow only ASCII alphanumeric characters and the symbols / . -
        if not re.fullmatch(r"[A-Za-z0-9/.\-]+", sanitized):
            raise ValueError("Unit contains invalid characters.")
        return sanitized

