import errno
import pathlib
import yaml
from typing import Any, Dict, Optional


def load_yaml_config(config_path: Optional[str] = None,
                     example_config_path: str = "example.yaml") -> Dict[str, Any]:
    """
    Safely load YAML configuration from the specified path or a default example file.
    Returns a dictionary representation of the YAML data.
    """
    base_dir = pathlib.Path.cwd().resolve()

    def _resolve_path(path: str) -> pathlib.Path:
        if not isinstance(path, str):
            raise ValueError("Configuration path must be a string")

        resolved = pathlib.Path(path).expanduser().resolve()
        # Ensure the file is within the current working directory
        try:
            resolved.relative_to(base_dir)
        except ValueError:
            raise ValueError("Configuration file must reside within the current working directory")

        if not resolved.is_file():
            raise FileNotFoundError(errno.ENOENT, "File not found", str(resolved))

        if " " in str(resolved):
            raise ValueError("Path contains disallowed spaces")

        return resolved

    path_to_use = config_path or example_config_path

    try:
        yaml_file = _resolve_path(path_to_use)
        with yaml_file.open(mode="r", encoding="utf-8", errors="strict") as fh:
            data = yaml.safe_load(fh)
        if data is None:
            data = {}
        if not isinstance(data, dict):
            raise ValueError("YAML top-level structure must be a mapping")
        return data
    except (OSError, yaml.YAMLError, ValueError) as exc:
        # Avoid leaking internal details; provide a generic error
        raise RuntimeError("Unable to load configuration") from None

