import logging
from pathlib import Path
import re
from typing import Dict, Any


CONFIG_DIR = Path("/etc/myapp").resolve()  # Trusted configuration directory


class ConfigurationError(RuntimeError):
    """Raised when a configuration file cannot be accessed securely."""


def _ensure_within_config_dir(path: Path) -> None:
    """
    Ensure that `path` points to a location inside CONFIG_DIR.
    Raises ValueError if it does not.
    """
    try:
        if not path.is_relative_to(CONFIG_DIR):
            raise ValueError
    except AttributeError:
        # Fallback for Python < 3.9
        if CONFIG_DIR not in path.parents:
            raise ValueError


def read_settings(file_path: str, defaults: Dict[str, Any]) -> Dict[str, Any]:
    """
    Read a simple key=value settings file and return a dictionary combining the defaults
    with any values found in the file. The function verifies that the file resides in
    CONFIG_DIR and that it is an actual file. Permission errors are logged and
    surfaced as ConfigurationError.
    """
    path = Path(file_path).expanduser().resolve()

    # Ensure the resolution is within the allowed configuration directory
    _ensure_within_config_dir(path)

    settings = defaults.copy()

    try:
        if not path.is_file():
            raise FileNotFoundError(path)

        with path.open(mode="r", encoding="utf-8", errors="strict") as f:
            for line in f:
                raw = line.strip()
                if not raw or raw.startswith(("#", ";")):
                    continue

                if "=" not in raw:
                    continue
                key, value = raw.split("=", 1)
                key = key.strip()
                value = value.strip()

                if not re.match(r"^[\w-]+$", key):
                    continue

                if key in settings:
                    settings[key] = value

    except FileNotFoundError as e:
        logging.debug("Config file not found: %s", path)
    except PermissionError as e:
        logging.error("Permission denied reading config file %s: %s", path, e)
        raise ConfigurationError(f"Unable to read config file '{path}'.") from e
    except OSError as e:
        logging.error("OS error while reading config file %s: %s", path, e)
        raise ConfigurationError(f"Error reading config file '{path}'.") from e

    return settings

