import decimal
import sys
import logging
from pathlib import Path
from typing import Sequence, Iterable

logging.basicConfig(
    filename="generate_report.log",
    level=logging.ERROR,
    format="%(asctime)s - %(levelname)s - %(message)s",
)

def _log_error(exc: Exception | str) -> None:
    if isinstance(exc, BaseException):
        logging.exception("Exception occurred", exc_info=exc)
    else:
        logging.error(f"Error: {exc}")


def _validate_directory(path_str: str) -> Path:
    try:
        path = Path(path_str).expanduser().resolve(strict=True)
    except Exception as exc:
        _log_error(exc)
        raise ValueError("Invalid directory path.") from exc

    if not path.is_dir():
        _log_error(f"Provided path is not a directory: {path}")
        raise ValueError("Provided path is not a directory.")
    return path


def _read_statistics(stats_file: Path, required_keys: Iterable[str]) -> dict[str, str]:
    stats: dict[str, str] = {}
    try:
        with stats_file.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line or ":" not in line:
                    continue
                key, value = (part.strip() for part in line.split(":", 1))
                if key in required_keys:
                    stats[key] = value
    except Exception as exc:
        _log_error(exc)
        raise RuntimeError("Failed to read statistics file.") from exc

    missing = set(required_keys) - set(stats)
    if missing:
        _log_error(f"Missing required statistics: {missing}")
        raise ValueError(f"Missing required statistics: {', '.join(sorted(missing))}")
    return stats


def _parse_numerics(stats: dict[str, str]) -> tuple[int, int, decimal.Decimal, decimal.Decimal]:
    try:
        reticulations = int(stats["Reticulations"])
        taxa = int(stats["Taxa"])
        increase_raw = decimal.Decimal(stats["Increase"])
        decrease_raw = decimal.Decimal(stats["Decrease"])
    except Exception as exc:
        _log_error(exc)
        raise ValueError("Invalid numeric values in statistics file.") from exc
    return reticulations, taxa, increase_raw, decrease_raw


def _validate_coefficient(coeff: float) -> decimal.Decimal:
    try:
        coeff_dec = decimal.Decimal(str(coeff))
    except Exception as exc:
        _log_error(exc)
        raise ValueError("Coefficient must be a number.") from exc
    return coeff_dec


def _write_report(
    report_path: Path,
    reticulations: int,
    taxa: int,
    increase_scaled: decimal.Decimal,
    decrease_scaled: decimal.Decimal,
    outgroup: str,
    base_path: Path,
) -> None:
    try:
        with report_path.open("wt", encoding="utf-8") as out:
            out.write(f"Reticulations: {reticulations}
")
            out.write(f"Taxa: {taxa}
")
            out.write(f"Increase: {increase_scaled}
")
            out.write(f"Decrease: {decrease_scaled}
")
            out.write(f"Outgroup: {outgroup}

")
            out.write("Alignment files:
")
            for file_path in base_path.iterdir():
                if (
                    file_path.is_file()
                    and file_path.suffix.lower() in {".aln", ".fasta", ".fa", ".fastq"}
                ):
                    try:
                        out.write(f"-- Begin {file_path.name} --
")
                        with file_path.open("r", encoding="utf-8", errors="replace") as af:
                            for line in af:
                                out.write(line)
                        out.write(f"-- End {file_path.name} --

")
                    except Exception as exc:
                        _log_error(exc)
    except Exception as exc:
        _log_error(exc)
        raise RuntimeError("Failed to write report file.") from exc


def generate_report(directory: str, coefficient: float) -> Path:
    base_path = _validate_directory(directory)

    stats_file = base_path / "statistics.txt"
    if not stats_file.is_file():
        _log_error(f"Statistics file not found: {stats_file}")
        raise ValueError("Statistics file not found.")

    required_keys = {"Reticulations", "Taxa", "Increase", "Decrease", "Outgroup"}
    stats = _read_statistics(stats_file, required_keys)

    reticulations, taxa, increase_raw, decrease_raw = _parse_numerics(stats)
    coeff_dec = _validate_coefficient(coefficient)

    increase_scaled = increase_raw * coeff_dec
    decrease_scaled = decrease_raw * coeff_dec

    report_path = base_path / "report.txt"
    _write_report(
        report_path,
        reticulations,
        taxa,
        increase_scaled,
        decrease_scaled,
        stats["Outgroup"],
        base_path,
    )

    return report_path


if __name__ == "__main__":
    if len(sys.argv) < 3:
        print(
            "Usage: python generate_report.py <directory_path> <coefficient>",
            file=sys.stderr,
        )
        sys.exit(1)

    dir_path = sys.argv[1]
    try:
        coeff = float(sys.argv[2])
    except ValueError:
        print("Coefficient must be a numeric value.", file=sys.stderr)
        sys.exit(1)

    try:
        report_file = generate_report(dir_path, coeff)
        print(f"Report generated at: {report_file}")
    except Exception:
        print("An error occurred while generating the report.", file=sys.stderr)
        sys.exit(1)

import hashlib
from typing import Union

ALLOWED_ALGORITHMS = {
    "sha224",
    "sha256",
    "sha384",
    "sha512",
    "blake2b",
    "blake2s",
}

class SecureHash:
    def __init__(self, algorithm: str = "sha256") -> None:
        if not isinstance(algorithm, str):
            raise TypeError("Algorithm must be a string.")
        alg = algorithm.lower()
        if alg not in ALLOWED_ALGORITHMS:
            raise ValueError(f"Unsupported hash algorithm: {algorithm}")
        try:
            self._hasher = hashlib.new(alg)
        except Exception as e:
            raise ValueError(f"Failed to create hasher for algorithm '{algorithm}'.") from e

    def update(self, data: Union[str, bytes, bytearray]) -> None:
        if isinstance(data, str):
            data_bytes = data.encode("utf-8")
        elif isinstance(data, (bytes, bytearray)):
            data_bytes = data
        else:
            raise TypeError("Data must be a string or bytes.")
        self._hasher.update(data_bytes)

    def digest(self) -> bytes:
        return self._hasher.digest()

    def hexdigest(self) -> str:
        return self._hasher.hexdigest()

    def clone(self) -> "SecureHash":
        clone = SecureHash(self._hasher.name)
        clone._hasher = self._hasher.copy()
        return clone

def compute_hash(data: str, algorithm: str = "sha256") -> str:
    if not isinstance(data, str):
        raise TypeError("Input must be a string.")
    hasher = SecureHash(algorithm)
    hasher.update(data)
    return hasher.hexdigest()

