)

_PATH_PATTERN = re.compile(r"^[A-Za-z0-9_\-./]+$")

_MAX_PATH_LENGTH = 256
_MAX_KEY_PATH_LENGTH = 256
_MIN_PORT = 1
_MAX_PORT = 65535

def _validate_ip(ip: str) -> str:
    try:
        addr = ipaddress.ip_address(ip)
        return str(addr)
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc

def _validate_path(path: str) -> str:
    if not path or len(path) > _MAX_KEY_PATH_LENGTH:
        raise ValueError("Invalid path length")
    if not _PATH_PATTERN.match(path):
        raise ValueError("Invalid path")
    if ".." in path or path.startswith("/"):
        raise ValueError("Path cannot contain '..' or start with '/'")
    return path.strip("/")

def _validate_file_path(path: str) -> str:
    if not path or len(path) > _MAX_PATH_LENGTH:
        raise ValueError("Invalid file path length")
    if not _PATH_PATTERN.match(path):
        raise ValueError("Invalid file path")
    if ".." in path or path.startswith("/"):
        raise ValueError("Path cannot reference parent directories or root")
    cwd_abs = os.path.abspath(os.getcwd())
    real_path = os.path.realpath(os.path.join(cwd_abs, path))
    if not real_path.startswith(cwd_abs):
        raise ValueError("File path traversal detected")
    if not os.path.isfile(real_path):
        raise ValueError("File does not exist")
    if not os.access(real_path, os.R_OK):
        raise ValueError("File is not readable")
    return real_path

def get_etcd_data(
    ip_address: str,
    key_path: str,
    use_ssl: bool = False,
    cert_file: Optional[str] = None,
    key_file: Optional[str] = None,
    ca_file: Optional[str] = None,
    port: int = 2379,
) -> Optional[Dict]:
    if not (_MIN_PORT <= port <= _MAX_PORT):
        return None
    try:
        host = _validate_ip(ip_address)
        path = _validate_path(key_path)
    except ValueError:
        return None

    protocol = "https" if use_ssl else "http"
    url = f"{protocol}://{host}:{port}/{urllib.parse.quote(path, safe='')}"
    req_kwargs = {'timeout': 10, 'allow_redirects': False, 'headers': {'Accept': 'application/json'}}

    if use_ssl:
        if not (cert_file and key_file and ca_file):
            return None
        try:
            cert_file_path = _validate_file_path(cert_file)
            key_file_path = _validate_file_path(key_file)
            ca_file_path = _validate_file_path(ca_file)
        except ValueError:
            return None
        req_kwargs['cert'] = (cert_file_path, key_file_path)
        req_kwargs['verify'] = ca_file_path

    try:
        response = requests.get(url, **req_kwargs)
        response.raise_for_status()
        return response.json()
    except (requests.RequestException, ValueError, OSError):
        return None

import os
import platform
import subprocess
import time
import signal
import logging
import sys
import ctypes

logger = logging.getLogger(__name__)

def _get_system32() -> str:
    """Return the real System32 directory on Windows."""
    buffer = ctypes.create_unicode_buffer(260)
    ctypes.windll.kernel32.GetSystemDirectoryW(buffer, 260)
    return buffer.value

def _ensure_windows_tool(name: str) -> str:
    system32 = _get_system32()
    path = os.path.join(system32, f"{name}.exe")
    if not os.path.isfile(path):
        raise FileNotFoundError(f"Required tool {name}.exe not found at {path}")
    return path

def _process_owner_linux(pid: int) -> int:
    try:
        return os.stat(f"/proc/{pid}").st_uid
    except Exception:
        return -1

def terminate_process(
    pid: int,
    initial_sleep: float = 0.5,
    max_sleep: float = 5.0,
    factor: float = 2.0,
) -> int:
    """
    Terminate a process safely.

    Returns:
        0  : Termination succeeded.
        -1 : Process not found, inaccessible, or not permitted to terminate.
    """
    if not isinstance(pid, int) or pid <= 0:
        logger.debug("PID %s is not a positive integer", pid)
        return -1

    MAX_PID = 0x7fffffff
    if pid > MAX_PID:
        logger.debug("PID %s exceeds maximum allowed value", pid)
        return -1

    system = platform.system()
    tasklist_path = None
    taskkill_path = None

    if system == "Windows":
        try:
            tasklist_path = _ensure_windows_tool("tasklist")
            taskkill_path = _ensure_windows_tool("taskkill")
        except FileNotFoundError as e:
            logger.error("Required Windows tool missing: %s", e)
            return -1

        if pid <= 4:
            logger.warning("Attempt to terminate critical Windows system process %d denied", pid)
            return -1
    else:
        if pid == 1:
            logger.warning("Attempt to terminate init process denied")
            return -1

    current_user_id = os.geteuid() if hasattr(os, "geteuid") else None

    def _process_exists() -> bool:
        if system == "Windows":
            try:
                output = subprocess.check_output(
                    [tasklist_path, "/FI", f"PID eq {pid}"],
                    stderr=subprocess.DEVNULL,
                    text=True,
                    timeout=5,
                )
                return f" {pid} " in output
            except (OSError, subprocess.SubprocessError, subprocess.TimeoutExpired):
                return False
        else:
            if current_user_id is None:
                logger.error("Unable to determine effective user ID; permission checks cannot be performed")
                return False
            try:
                os.kill(pid, 0)
                owner = _process_owner_linux(pid)
                return owner == current_user_id
            except (OSError, subprocess.SubprocessError, subprocess.TimeoutExpired):
                return False

    def _send_signal() -> bool:
        if system == "Windows":
            try:
                subprocess.run(
                    [taskkill_path, "/PID", str(pid), "/F"],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    check=True,
                    timeout=5,
                )
                return True
            except (OSError, subprocess.SubprocessError, subprocess.TimeoutExpired):
                return False
        else:
            try:
                os.kill(pid, signal.SIGTERM)
                return True
            except (OSError, subprocess.SubprocessError, subprocess.TimeoutExpired):
                return False

    if not _process_exists():
        logger.debug("Process %d not found or not accessible", pid)
        return -1

    logger.info(
        "Attempting to terminate process %d by user %s at %s",
        pid,
        current_user_id,
        time.strftime("%Y-%m-%d %H:%M:%S"),
    )

    sleep_time = initial_sleep
    while True:
        if _send_signal() and not _process_exists():
            logger.info("Process %d terminated successfully", pid)
            return 0
        time.sleep(sleep_time)
        if sleep_time < max_sleep:
            sleep_time = min(sleep_time * factor, max_sleep)
        if not _process_exists():
            logger.info("Process %d terminated successfully after waiting", pid)
            return 0
        if sleep_time == max_sleep:
            break

    logger.warning("Failed to terminate process %d within allowed time", pid)
    return -1

if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    try:
        test_pid = int(sys.argv[1]) if len(sys.argv) > 1 else 1234
    except ValueError:
        logger.error("Invalid PID argument: %s", sys.argv[1] if len(sys.argv) > 1 else "")
        sys.exit(2)
    result = terminate_process(test_pid)
    print("Result:", result)

