# Simple in-memory token store for demonstration
class TokenStore:
    _data = {}

    @classmethod
    def create_token(cls, uid: str) -> str:
        token = f"{uid[:8]}{datetime.utcnow().timestamp():.0f}"
        cls._data[uid] = {"token": token, "expires": datetime.utcnow() + timedelta(minutes=15), "used": False}
        return token

    @classmethod
    def validate(cls, uid: str, token: str) -> bool:
        record = cls._data.get(uid)
        if not record:
            return False
        if record["used"]:
            return False
        if record["expires"] < datetime.utcnow():
            return False
        return record["token"] == token

    @classmethod
    def mark_used(cls, uid: str):
        if uid in cls._data:
            cls._data[uid]["used"] = True

