class BaseResetView(MethodView):
    @staticmethod
    def _is_valid_hex(value: str, length: int) -> bool:
        if not isinstance(value, str):
            return False
        pattern = rf'^[0-9a-f]{{{length}}}$'
        return re.fullmatch(pattern, value.lower()) is not None

    @staticmethod
    def _login_url() -> str:
        try:
            return url_for('login', _external=True)
        except Exception:
            abort(500)

    def _render_template(self, template_name: str, **context):
        try:
            return render_template(template_name, **context)
        except Exception as e:
            g.app.logger.exception("Template rendering error: %s", e)
            abort(500)

class RequestResetView(BaseResetView):
    def get(self, uid: str, token: str):
        if not (self._is_valid_hex(uid, 32) and self._is_valid_hex(token, 64)):
            abort(400, description="Invalid reset parameters.")
        if not TokenStore.validate(uid, token):
            abort(400, description="Invalid or expired token.")
        # After validation, mark token as used to prevent reuse
        TokenStore.mark_used(uid)
        # Render form with hidden fields
        return self._render_template('reset_password_form.html', uid=uid, token=token)

class CompleteResetView(BaseResetView):
    def post(self, uid: str):
        form_token = request.form.get('token', '')
        new_password = request.form.get('password', '')
        if not (self._is_valid_hex(uid, 32) and self._is_valid_hex(form_token, 64)):
            abort(400, description="Invalid reset parameters.")
        if not form_token or not new_password or len(new_password) < 8:
            abort(400, description="Password does not meet complexity requirements.")
        # Password complexity check
        if not re.search(r'[A-Z]', new_password) or not re.search(r'[a-z]', new_password)            or not re.search(r'\d', new_password) or not re.search(r'\W', new_password):
            abort(400, description="Password must contain uppercase, lowercase, digit, and special character.")
        # Verify token again
        if not TokenStore.validate(uid, form_token):
            abort(400, description="Invalid or expired token.")
        # Hash and store password
        password_hash = pwd_context.hash(new_password)
        UserStore.set_password(uid, password_hash)
        # Mark token as used
        TokenStore.mark_used(uid)
        login_url = self._login_url()
        return self._render_template('reset_success.html', login_url=login_url)

def register_reset_views(app: Flask):
    app.add_url_rule(
        '/reset/<uid>/<token>/', view_func=RequestResetView.as_view('reset_request')
    )
    app.add_url_rule(
        '/reset/complete/<uid>/', view_func=CompleteResetView.as_view('reset_complete'), methods=['GET', 'POST']
    )

