import os
import re
import secrets
from urllib.parse import urlencode, urlparse

import requests
from flask import redirect, request, session

ALLOWED_SCHEMES = {"https"}
SCOPE_REGEX = re.compile(r"^[a-zA-Z0-9_:.\-]+$")
PROVIDER_DOMAIN_WHITELIST = []  # Add allowed domains if required

_SECRET_STORAGE = {}


def _validate_url(url: str) -> bool:
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ALLOWED_SCHEMES or not parsed.netloc:
            return False
        if parsed.username or parsed.password:
            return False
        if PROVIDER_DOMAIN_WHITELIST:
            host = parsed.hostname
            if host not in PROVIDER_DOMAIN_WHITELIST:
                return False
        return True
    except Exception:
        return False


def oauth2_authenticate(
    api_key: str,
    api_secret: str,
    auth_endpoint: str,
    callback_url: str | None = None,
    scopes: list[str] | None = None,
):
    if not all(isinstance(v, str) and v for v in (api_key, api_secret, auth_endpoint)):
        raise ValueError("api_key, api_secret, and auth_endpoint must be non-empty strings")

    if not _validate_url(auth_endpoint):
        raise ValueError("auth_endpoint must be a valid HTTPS URL")

    if callback_url is None:
        if not request.is_secure:
            raise ValueError("Request must be over HTTPS to derive callback URL")
        callback_url = request.url_root.rstrip("/") + request.path

    if not _validate_url(callback_url):
        raise ValueError("callback_url must be a valid HTTPS URL")

    session["oauth_client_id"] = api_key
    session["oauth_state"] = state = secrets.token_urlsafe(32)
    _SECRET_STORAGE[state] = api_secret

    params = {
        "response_type": "code",
        "client_id": api_key,
        "redirect_uri": callback_url,
        "state": state,
    }
    if scopes:
        if not isinstance(scopes, (list, tuple)):
            raise ValueError("scopes must be a list or tuple of strings")
        cleaned_scopes = []
        for scope in scopes:
            if not isinstance(scope, str) or not SCOPE_REGEX.match(scope):
                raise ValueError(f"Invalid scope value: {scope!r}")
            cleaned_scopes.append(scope)
        params["scope"] = " ".join(cleaned_scopes)

    redirect_uri = f"{auth_endpoint}?{urlencode(params)}"
    return redirect(redirect_uri, code=302)

import argparse
import hashlib
import os
import sys
from pathlib import Path

class SecurityError(Exception):
    """Raised when a security validation fails."""
    pass

def is_path_within(path: Path, base: Path) -> bool:
    try:
        # Python 3.9+: use is_relative_to
        return path.is_relative_to(base)
    except AttributeError:
        try:
            return base in path.parents or path == base
        except Exception:
            return False

def validate_file_path(file_path: Path, base_dir: Path) -> Path:
    if not file_path.exists():
        raise SecurityError("The specified file does not exist.")
    resolved = file_path.resolve(strict=True)
    if not resolved.is_file():
        raise SecurityError("The specified path is not a file.")
    if not is_path_within(resolved, base_dir):
        raise SecurityError("The file is located outside the permitted directory.")
    return resolved

def compute_sha256(file_path: Path) -> str:
    sha256 = hashlib.sha256()
    try:
        with file_path.open("rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                sha256.update(chunk)
    except Exception as e:
        raise SecurityError("Failed to read the file.") from e
    return sha256.hexdigest()

def load_stored_hash(hash_file: Path) -> str:
    if hash_file.is_file():
        try:
            with hash_file.open("r", encoding="utf-8") as f:
                return f.read().strip()
        except Exception:
            return ""
    return ""

def update_hash_file(hash_file: Path, new_hash: str):
    try:
        with hash_file.open("w", encoding="utf-8") as f:
            f.write(new_hash)
        os.chmod(hash_file, 0o600)
    except Exception as e:
        raise SecurityError("Unable to update hash file.") from e

def main():
    parser = argparse.ArgumentParser(description="Check and update file version hash.")
    parser.add_argument("file", help="Path to the file to check.")
    parser.add_argument(
        "--hash-file",
        default=".file_hash.txt",
        help="Filename to store the hash (relative to base directory).",
    )
    parser.add_argument(
        "--base-dir",
        default=".",
        help="Base directory that contains the file.",
    )
    args = parser.parse_args()

    # Reject symlink base directory
    original_base = Path(args.base_dir)
    if original_base.is_symlink():
        print("Error: base directory cannot be a symbolic link.", file=sys.stderr)
        sys.exit(1)

    base_dir = original_base.resolve(strict=True)

    file_path = Path(args.file)
    try:
        resolved_file = validate_file_path(file_path, base_dir)
    except SecurityError as e:
        print("Error:", e, file=sys.stderr)
        sys.exit(1)

    hash_file_candidate = base_dir / Path(args.hash_file)
    hash_file = hash_file_candidate.resolve(strict=False)
    if not is_path_within(hash_file, base_dir):
        print("Error: hash file path is outside the base directory.", file=sys.stderr)
        sys.exit(1)

    try:
        new_hash = compute_sha256(resolved_file)
    except SecurityError as e:
        print("Error:", e, file=sys.stderr)
        sys.exit(1)

    stored_hash = load_stored_hash(hash_file)

    if new_hash != stored_hash:
        try:
            update_hash_file(hash_file, new_hash)
        except SecurityError as e:
            print("Error:", e, file=sys.stderr)
            sys.exit(1)
        print("Hash updated.")
    else:
        print("Hash matches; no update needed.")

if __name__ == "__main__":
    main()

