_logger = logging.getLogger(__name__)

__SAFE_DISTRIBUTION_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")
_MAX_VALUES = 10_000
_ALLOWED_PERCENTILE_KWARGS = {"axis", "method", "keepdims", "assume_sorted"}

def _validate_distribution_name(distribution_name: str) -> bool:
    return isinstance(distribution_name, str) and __SAFE_DISTRIBUTION_PATTERN.match(distribution_name)

def _sanitize_values(values: Iterable[float]) -> Optional[List[float]]:
    sanitized: List[float] = []
    for idx, val in enumerate(values):
        try:
            num = float(val)
            if not np.isfinite(num):
                _logger.warning("Nonâfinite value at index %d: %s", idx, val)
                continue
            sanitized.append(num)
        except (TypeError, ValueError) as exc:
            _logger.warning("Invalid value at index %d: %s", idx, exc)
            continue
        if len(sanitized) > _MAX_VALUES:
            _logger.error("Input contains more than %d valid numeric values.", _MAX_VALUES)
            return None
    if not sanitized:
        _logger.warning("No valid numeric values were supplied.")
        return None
    return sanitized

def get_percentile_function(distribution_name: str, values: Iterable[float], **kwargs) -> Optional[Callable[[float], float]]:
    if not _validate_distribution_name(distribution_name):
        _logger.warning("Invalid distribution name: %s", distribution_name)
        return None

    sanitized_values = _sanitize_values(values)
    if sanitized_values is None:
        return None

    distribution = getattr(stats, distribution_name, None)
    if distribution and hasattr(distribution, "ppf"):
        def _scaled_ppf(prob: float) -> float:
            if not isinstance(prob, (int, float)):
                raise TypeError("Probability must be a number.")
            if not 0.0 <= prob <= 1.0:
                raise ValueError("Probability must be between 0 and 1.")
            try:
                return distribution.ppf(prob)
            except Exception as exc:
                _logger.error("Error in distribution ppf: %s", exc)
                raise
        return _scaled_ppf

    saved_kwargs = {k: v for k, v in kwargs.items() if k in _ALLOWED_PERCENTILE_KWARGS}
    if "interpolation" in kwargs:
        _logger.warning("Deprecated keyword 'interpolation' ignored; use 'method' instead.")
    saved_kwargs.setdefault("method", "linear")

    def _fallback_ppf(prob: float) -> float:
        if not isinstance(prob, (int, float)):
            raise TypeError("Probability must be a number.")
        if not 0.0 <= prob <= 1.0:
            raise ValueError("Probability must be between 0 and 1.")
        try:
            return np.percentile(sanitized_values, prob * 100.0, **saved_kwargs)
        except Exception as exc:
            _logger.error("Error in fallback percentile calculation: %s", exc)
            raise
    return _fallback_ppf

