import os
import re
import subprocess
import shutil
from pathlib import Path
import logging

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler()],
)

SAFE_FILENAME_RE = re.compile(r"^(?!\.)[A-Za-z0-9_\-\.]+$")
MAX_DIMENSION = 5000
ALLOWED_OUTPUT_ROOT = Path.cwd()
ALLOWED_CONVERT_PATHS = [Path("/usr/bin/convert"), Path("/usr/local/bin/convert")]


def _get_convert_path() -> Path:
    for path in ALLOWED_CONVERT_PATHS:
        if path.is_file() and not path.is_symlink() and os.access(path, os.X_OK):
            return path.resolve(strict=True)
    found = shutil.which("convert")
    if found:
        resolved = Path(found).resolve(strict=True)
        if resolved.is_file() and not resolved.is_symlink() and os.access(resolved, os.X_OK):
            return resolved
    raise RuntimeError("ImageMagick 'convert' not found or not safe.")


_convert_path = _get_convert_path()


def _is_safe_filename(filename: str) -> bool:
    return bool(SAFE_FILENAME_RE.fullmatch(filename)) and ".." not in filename


def _validate_dimensions(width: int, height: int) -> None:
    for value, name in ((width, "width"), (height, "height")):
        if not isinstance(value, int):
            raise ValueError(f"{name} must be an integer.")
        if value <= 0 or value > MAX_DIMENSION:
            raise ValueError(
                f"{name} must be between 1 and {MAX_DIMENSION} (got {value})."
            )


def resize_images(
    file_list: list[str],
    input_dir: str,
    output_dir: str,
    width: int,
    height: int,
) -> list[str]:
    if not isinstance(file_list, list) or any(not isinstance(f, str) for f in file_list):
        raise ValueError("file_list must be a list of strings.")
    if not isinstance(input_dir, str) or not isinstance(output_dir, str):
        raise ValueError("input_dir and output_dir must be strings.")

    input_path = Path(input_dir).resolve(strict=True)
    output_path = Path(output_dir).resolve()

    if not output_path.is_relative_to(ALLOWED_OUTPUT_ROOT):
        raise ValueError("output_dir must be inside the current working directory.")

    try:
        output_path.mkdir(parents=True, exist_ok=True)
    except Exception as e:
        raise RuntimeError(f"Could not create output directory: {output_dir}") from e

    _validate_dimensions(width, height)

    resized_files: list[str] = []

    for filename in file_list:
        if not _is_safe_filename(filename):
            raise ValueError(f"Unacceptable filename: {filename}")

        infile = (input_path / filename).resolve(strict=True)
        if not infile.is_file():
            raise ValueError(f"Input file does not exist: {infile}")
        if infile.is_symlink():
            raise ValueError(f"Symlink not allowed for input file: {filename}")

        try:
            infile.relative_to(input_path)
        except ValueError:
            raise ValueError(f"File {filename} is outside the input directory.")

        outfile = output_path / filename
        outfile_parent = outfile.parent
        try:
            outfile_parent.mkdir(parents=True, exist_ok=True)
        except Exception as e:
            raise RuntimeError(f"Could not create directory for output file: {outfile_parent}") from e

        # Detect symlink traversal in output path
        for part in outfile.parents:
            if part.is_symlink():
                raise ValueError(f"Symlink detected in output path: {part}")

        # Ensure resolved output path stays within the output directory
        if not outfile.resolve(strict=False).is_relative_to(output_path):
            raise ValueError(f"Output file {outfile} is outside the allowed output directory.")

        command = [
            str(_convert_path),
            str(infile),
            "-resize",
            f"{width}x{height}",
            str(outfile),
        ]

        try:
            subprocess.run(
                command,
                check=True,
                capture_output=True,
                text=True,
            )
        except subprocess.CalledProcessError as e:
            logging.error("Failed to resize image '%s': %s", filename, e.stderr.strip())
            raise RuntimeError(
                f"Failed to resize image '{filename}'. Please check the logs for details."
            ) from None
        except OSError as e:
            logging.error("OS error during resizing of '%s': %s", filename, str(e))
            raise RuntimeError(
                f"OS error during resizing of '{filename}'. Please check the logs for details."
            ) from None

        if not outfile.is_file():
            raise RuntimeError(f"Conversion failed; output not created: {outfile}")

        resized_files.append(str(outfile))

    return resized_files


if __name__ == "__main__":
    try:
        resized = resize_images(
            file_list=["photo1.jpg", "image2.png"],
            input_dir="/path/to/input",
            output_dir="/path/to/output",
            width=800,
            height=600,
        )
        print("Resized files:", resized)
    except Exception as exc:
        logging.error("Error during image resizing: %s", exc)

