from typing import List, Dict, Tuple

def open_secure_pdf(pdf_path: pathlib.Path) -> Tuple[pathlib.Path, int]:
    # Reject if path contains symlinks
    if pdf_path.is_symlink():
        raise ValueError(f"Input PDF '{pdf_path}' is a symlink, which is not allowed.")
    for parent in pdf_path.parents:
        if parent.is_symlink():
            raise ValueError(f"Directory component '{parent}' of PDF path is a symlink.")
    try:
        fd = os.open(str(pdf_path), os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as e:
        raise ValueError(f"Error opening PDF file '{pdf_path}': {e}") from e
    try:
        header = os.read(fd, 5)
        if header != b"%PDF-":
            raise ValueError(f"Input file '{pdf_path}' does not appear to be a PDF.")
        fstat = os.fstat(fd)
        if fstat.st_uid != os.geteuid():
            raise PermissionError(f"PDF file '{pdf_path}' is not owned by the current user.")
    finally:
        os.close(fd)
    return pdf_path, fd

def validate_pdf_path(pdf_path: pathlib.Path) -> pathlib.Path:
    if not pdf_path.exists():
        raise ValueError(f"Input PDF '{pdf_path}' does not exist.")
    if not pdf_path.is_file():
        raise ValueError(f"Input PDF '{pdf_path}' is not a file.")
    if pdf_path.suffix.lower() != ".pdf":
        raise ValueError(f"Input file '{pdf_path}' is not a PDF.")
    return pdf_path

def validate_output_path(out_path: pathlib.Path) -> pathlib.Path:
    out_path = out_path.resolve(strict=False)
    cwd = pathlib.Path.cwd()
    try:
        out_path.relative_to(cwd)
    except ValueError:
        raise ValueError(f"Output path '{out_path}' is outside the current working directory.")
    if out_path.is_dir():
        raise ValueError(f"Output path '{out_path}' is a directory.")
    if out_path.is_symlink():
        raise ValueError(f"Output path '{out_path}' is a symlink.")
    for parent in out_path.parents:
        if parent.is_symlink():
            raise ValueError(f"Directory component '{parent}' of output path is a symlink.")
    out_dir = out_path.parent
    if not out_dir.is_dir():
        raise ValueError(f"Output directory '{out_dir}' does not exist.")
    if out_dir.is_symlink():
        raise ValueError(f"Output directory '{out_dir}' is a symlink.")
    return out_path

def extract_text_from_pdf(pdf_path: pathlib.Path, fd: int) -> str:
    pdftotext = shutil.which("pdftotext")
    if not pdftotext:
        raise RuntimeError("pdftotext command not found. Ensure it is installed and in PATH.")
    real_path = os.path.realpath(pdftotext)
    if os.path.islink(pdftotext) or os.path.islink(real_path):
        raise RuntimeError("pdftotext binary is a symlink, which is not allowed.")
    # Use the open file descriptor in /proc/self/fd/ to avoid TOCTOU
    proc_fd_path = f"/proc/self/fd/{fd}"
    command: List[str] = [real_path, "-layout", "-q", proc_fd_path, "-"]
    try:
        result = subprocess.run(
            command,
            capture_output=True,
            text=True,
            check=True,
            shell=False,
        )
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"pdftotext failed: {e.stderr.strip()}") from e
    return result.stdout

def tokenize(text: str) -> List[str]:
    return re.findall(r" \w+ ", text.lower())

def build_bow(tokens: List[str]) -> Dict[str, int]:
    return dict(collections.Counter(tokens))

def write_bow_to_file(bow: Dict[str, int], out_path: pathlib.Path) -> None:
    try:
        tmp_file = tempfile.NamedTemporaryFile(
            dir=out_path.parent,
            delete=False,
            prefix=out_path.name + ".",
            suffix=".tmp",
            mode="w",
            encoding="utf-8",
        )
        with tmp_file:
            json.dump(bow, tmp_file, ensure_ascii=False)
        os.replace(tmp_file.name, out_path)
        try:
            os.chmod(out_path, 0o640)
        except OSError:
            pass
    except OSError as e:
        raise RuntimeError(f"Failed to write bag-of-words file '{out_path}': {e}") from e

def main() -> None:
    parser = argparse.ArgumentParser(description="Extract bag-of-words from a PDF.")
    parser.add_argument("input_pdf", help="Path to the input PDF file")
    parser.add_argument("output_bow", help="Path to the output bag-of-words JSON file")
    args = parser.parse_args()

    try:
        pdf_path = validate_pdf_path(pathlib.Path(args.input_pdf))
        out_path = validate_output_path(pathlib.Path(args.output_bow))
        pdf_path, fd = open_secure_pdf(pdf_path)
        text = extract_text_from_pdf(pdf_path, fd)
        tokens = tokenize(text)
        bow = build_bow(tokens)
        write_bow_to_file(bow, out_path)
        print(f"Bag-of-words written to {out_path}")
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()

import json
import os
import re
import fcntl
import threading
import logging
from pathlib import Path
from typing import Any, Dict, List

logging.basicConfig(level=logging.WARNING, format="%(asctime)s %(levelname)s:%(message)s")

MAX_RECORD_SIZE = 10 * 1024  # 10 KB per record
MAX_RECORDS_PER_TYPE = 10_000
MAX_TOTAL_SIZE = 5 * 1024 * 1024  # 5 MB per database


class DataFilter:
    __slots__ = ("_db_path", "_data", "_lock", "_base_dir", "_file_lock_fd")

    TYPE_REGEX = re.compile(r"^[A-Za-z0-9_]+$")

    def __init__(self, db_path: str) -> None:
        if not isinstance(db_path, str):
            raise TypeError("db_path must be a string")
        if "�" in db_path:
            raise ValueError("db_path contains null byte")

        self._base_dir: Path = Path(__file__).resolve(strict=True).parent / "data"
        self._base_dir.mkdir(mode=0o700, exist_ok=True)

        resolved_path = Path(db_path).expanduser().resolve(strict=False)
        if resolved_path.is_absolute() and resolved_path.is_symlink():
            resolved_path = resolved_path.resolve(strict=True)

        if not str(resolved_path).startswith(str(self._base_dir) + os.sep):
            raise ValueError("db_path must be located within the allowed data directory")

        self._db_path = resolved_path
        lock_path = self._db_path.with_suffix(self._db_path.suffix + ".lock")
        self._file_lock_fd = open(lock_path, "a", encoding="utf-8")
        self._lock = threading.Lock()
        self._load()

    def _acquire_file_lock(self) -> None:
        fcntl.flock(self._file_lock_fd.fileno(), fcntl.LOCK_EX)

    def _release_file_lock(self) -> None:
        fcntl.flock(self._file_lock_fd.fileno(), fcntl.LOCK_UN)

    def _load(self) -> None:
        self._acquire_file_lock()
        try:
            if self._db_path.is_file():
                try:
                    with self._db_path.open("r", encoding="utf-8") as f:
                        self._data = json.load(f)
                        if not isinstance(self._data, dict):
                            self._data = {}
                except (json.JSONDecodeError, OSError):
                    self._data = {}
            else:
                self._data = {}

            if not self._db_path.exists():
                self._db_path.parent.mkdir(parents=True, exist_ok=True)
                self._db_path.write_bytes(b"")
            os.chmod(str(self._db_path), 0o600)
        finally:
            self._release_file_lock()

    def _validate_type(self, data_type: str) -> None:
        if not isinstance(data_type, str):
            raise TypeError("data_type must be a string")
        if not self.TYPE_REGEX.fullmatch(data_type):
            raise ValueError("data_type contains invalid characters")

    def record(self, data_type: str, data: Any) -> None:
        self._validate_type(data_type)
        try:
            json_str = json.dumps(data, default=str)
        except (TypeError, OverflowError) as exc:
            raise ValueError("Data is not JSON serializable") from exc

        if len(json_str.encode("utf-8")) > MAX_RECORD_SIZE:
            raise ValueError("Record size exceeds maximum allowed")

        with self._lock:
            record_list: List[str] = self._data.get(data_type, [])
            if not isinstance(record_list, list):
                record_list = []

            if len(record_list) >= MAX_RECORDS_PER_TYPE:
                raise ValueError("Maximum number of records per type reached")

            record_list.append(json_str)
            self._data[data_type] = record_list

            total_size = len(json.dumps(self._data, separators=(",", ":")).encode("utf-8"))
            if total_size > MAX_TOTAL_SIZE:
                raise ValueError("Database size exceeds maximum allowed")

            self._persist()

    def playback(self, data_type: str) -> List[Any]:
        self._validate_type(data_type)
        with self._lock:
            record_list = self._data.get(data_type, [])
            if not isinstance(record_list, list):
                record_list = []
            try:
                return [json.loads(item) for item in record_list]
            except json.JSONDecodeError as exc:
                raise RuntimeError("Failed to decode stored data") from exc

    def _persist(self) -> None:
        temp_path = self._db_path.with_suffix(self._db_path.suffix + ".tmp")
        self._acquire_file_lock()
        try:
            with temp_path.open("w", encoding="utf-8") as f:
                json.dump(self._data, f, separators=(",", ":"))
            temp_path.replace(self._db_path)
            os.chmod(str(self._db_path), 0o600)
        except OSError as exc:
            raise RuntimeError("Failed to persist data") from exc
        finally:
            self._release_file_lock()

    def close(self) -> None:
        try:
            self._file_lock_fd.close()
        except OSError:
            pass

    def __enter__(self) -> "DataFilter":
        return self

    def __exit__(self, exc_type, exc_val, exc_tb) -> None:
        self.close()


def create_data_filter(db_path: str) -> DataFilter:
    return DataFilter(db_path)

import logging
import os
import re
import json
import mysql.connector
from mysql.connector import Error
from typing import List, Tuple, Dict, Any
from pathlib import Path

logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s - %(levelname)s - %(message)s",
)
logger = logging.getLogger(__name__)

ALLOWED_SECRET_DIR = Path("/run/secrets")
ALLOWED_SECRET_FILE = "db_credentials.json"

class _DBConfig(dict):
    """Readâonly wrapper for database configuration."""
    def __init__(self, data: Dict[str, Any]) -> None:
        super().__init__(data)

    def __setitem__(self, key, value):
        raise RuntimeError("Configuration is read-only")

    def __delitem__(self, key):
        raise RuntimeError("Configuration is read-only")

    def copy(self):
        return _DBConfig(dict(self))

def _load_db_config() -> Dict[str, Any]:
    """Internal loader that validates the secret file path and permissions."""
    secret_path = os.getenv("DB_SECRET_FILE")
    if not secret_path:
        raise RuntimeError("DB_SECRET_FILE environment variable is not set")

    secret_path_obj = Path(secret_path).expanduser().resolve()
    if not secret_path_obj.is_file():
        raise RuntimeError(f"Secret file does not exist: {secret_path_obj}")

    # Ensure the file lies within the allowed directory
    try:
        secret_path_obj.relative_to(ALLOWED_SECRET_DIR)
    except ValueError:
        raise RuntimeError("Secret file is outside the permitted directory")

    if secret_path_obj.name != ALLOWED_SECRET_FILE or not secret_path_obj.suffix == ".json":
        raise RuntimeError("Secret file name or extension is invalid")

    # Enforce restrictive permissions (owner read/write only)
    mode = secret_path_obj.stat().st_mode & 0o777
    if mode & 0o077:
        logger.warning(
            "Secret file permissions are %03o; expected 0600. Consider tightening permissions.",
            mode,
        )

    try:
        with secret_path_obj.open("r", encoding="utf-8") as f:
            config = json.load(f)
    except (OSError, json.JSONDecodeError) as exc:
        raise RuntimeError("Failed to load database secrets") from exc

    required_keys = {"host", "database", "user", "password"}
    if not required_keys.issubset(config):
        missing = required_keys - config.keys()
        raise RuntimeError(f"Missing required DB configuration keys: {missing}")

    # Optional SSL parameters â enforce that if any SSL params are supplied, ssl_ca must be present
    ssl_params = {}
    if config.get("ssl_ca"):
        ssl_params["ssl_ca"] = config["ssl_ca"]
        if config.get("ssl_cert"):
            ssl_params["ssl_cert"] = config["ssl_cert"]
        if config.get("ssl_key"):
            ssl_params["ssl_key"] = config["ssl_key"]
    elif config.get("ssl_cert") or config.get("ssl_key"):
        raise RuntimeError("SSL cert or key provided without ssl_ca")

    config.update(ssl_params)
    return config

try:
    _RAW_DB_CONFIG = _load_db_config()
    DB_CONFIG = _DBConfig(_RAW_DB_CONFIG)
except Exception as exc:
    logger.critical("Could not load database configuration: %s", exc)
    raise

USERNAME_PATTERN = re.compile(r"^[a-zA-Z0-9_-]{1,150}$")

def get_player_data(username: str) -> List[Tuple]:
    """Retrieve player information for a given username."""
    if not isinstance(username, str):
        raise ValueError("Username must be a string")

    if not USERNAME_PATTERN.fullmatch(username):
        raise ValueError("Invalid username format")

    query = """
        SELECT pi.player_id, pi.username, ps.score, ps.level
        FROM playerinfo pi
        JOIN playerstats ps ON pi.player_id = ps.player_id
        WHERE pi.username = %s
    """

    try:
        with mysql.connector.connect(**DB_CONFIG) as conn:
            with conn.cursor() as cursor:
                cursor.execute(query, (username,))
                results = cursor.fetchall()
        return results
    except Error as exc:
        logger.warning("Database error while retrieving player data")
        logger.debug("Exception details: %s", exc, exc_info=True)
        return []

import os
import subprocess
import logging
import shutil
import pathlib
import stat
import sys

def _is_trusted_ssh_keygen(path: str) -> bool:
    """Ensure ssh-keygen is located in trusted directories."""
    trusted_dirs = ("/usr/bin/", "/usr/local/bin/")
    return any(path.startswith(d) for d in trusted_dirs)

def generate_ssh_keys(vm_root_fs: str, logger_name: str) -> None:
    logger = logging.getLogger(logger_name)
    try:
        vm_root_fs = os.path.realpath(vm_root_fs)
        if not vm_root_fs.startswith("/") or vm_root_fs == "/":
            raise ValueError("Invalid VM root path")
        if not os.path.isdir(vm_root_fs):
            raise FileNotFoundError(f"VM root directory does not exist: {vm_root_fs}")

        ssh_keygen_path = shutil.which("ssh-keygen")
        if not ssh_keygen_path:
            raise EnvironmentError("ssh-keygen not found in PATH")
        ssh_keygen_path = os.path.realpath(ssh_keygen_path)
        if not _is_trusted_ssh_keygen(ssh_keygen_path):
            raise EnvironmentError(f"Untrusted ssh-keygen at {ssh_keygen_path}")

        ssh_dir = os.path.join(vm_root_fs, "etc", "ssh")
        pathlib.Path(ssh_dir).mkdir(parents=True, exist_ok=True)

        key_specs = [
            {"type": "rsa", "bits": 4096, "name": "ssh_host_rsa_key"},
            {"type": "ed25519", "name": "ssh_host_ed25519_key"},
        ]

        for key in key_specs:
            key_path = os.path.join(ssh_dir, key["name"])
            pub_path = f"{key_path}.pub"

            cmd = [ssh_keygen_path, "-q", "-f", key_path, "-t", key["type"]]
            if "bits" in key:
                cmd.extend(["-b", str(key["bits"])])
            cmd.extend(["-N", "", "-C", ""])

            try:
                subprocess.run(
                    cmd,
                    check=True,
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.PIPE,
                    text=True,
                )
            except subprocess.CalledProcessError as e:
                logger.error("Failed to generate %s key: %s", key["type"], e.stderr.strip())
                continue

            if not os.path.isfile(key_path) or os.path.getsize(key_path) == 0:
                logger.error("Private key %s not created or empty.", key_path)
                continue
            if not os.path.isfile(pub_path) or os.path.getsize(pub_path) == 0:
                logger.error("Public key %s not created or empty.", pub_path)
                continue

            try:
                os.chmod(key_path, stat.S_IRUSR | stat.S_IWUSR)
                os.chmod(pub_path, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH)
                if hasattr(os, "geteuid") and os.geteuid() == 0:
                    os.chown(key_path, 0, 0)
                    os.chown(pub_path, 0, 0)
                else:
                    logger.warning("Skipping chown on %s; not running as root", key_path)
            except OSError as e:
                logger.error("Failed to set permissions or ownership for %s: %s", key_path, e)

        sshd_config_path = os.path.join(ssh_dir, "sshd_config")
        sshd_config_path = os.path.realpath(sshd_config_path)
        if not os.path.isfile(sshd_config_path):
            logger.warning("sshd_config not found at %s; skipping configuration", sshd_config_path)
            return

        try:
            with open(sshd_config_path, "r", encoding="utf-8") as f:
                lines = f.readlines()
        except OSError as e:
            logger.error("Failed to read sshd_config: %s", e)
            return

        existing_keys = {line.split(None, 1)[1] for line in lines if line.strip().startswith("HostKey") and len(line.split(None, 1)) == 2}

        new_lines = []
        for key in key_specs:
            key_path_in_vm = f"/etc/ssh/{key['name']}"
            if key_path_in_vm not in existing_keys:
                new_lines.append(f"HostKey {key_path_in_vm}
")

        if new_lines:
            try:
                with open(sshd_config_path, "a", encoding="utf-8") as f:
                    f.writelines(new_lines)
            except OSError as e:
                logger.error("Failed to append to sshd_config: %s", e)

    except Exception as exc:
        logger.exception("Unexpected error during SSH key generation: %s", exc)

import warnings

def _sanitize_identifier(name: str) -> str:
    if not isinstance(name, str):
        raise TypeError("Attribute names must be strings")
    if not name.isidentifier():
        raise ValueError(f"Invalid identifier: {name!r}")
    return name

def _deprecation_warning(old_name: str, new_name: str, version: str) -> None:
    message = (
        f"'{old_name}' is deprecated as of version {version}. "
        f"Use '{new_name}' instead."
    )
    warnings.warn(message, DeprecationWarning, stacklevel=2)

def deprecate_attribute(old_name: str, new_name: str, version: str):
    """
    Returns a property that forwards access from *old_name* to *new_name*
    while emitting a deprecation warning.

    Parameters:
        old_name (str): The deprecated attribute name.
        new_name (str): The preferred attribute name.
        version (str): The version in which the deprecation occurs.
    """
    old_name = _sanitize_identifier(old_name)
    new_name = _sanitize_identifier(new_name)

    if old_name == new_name:
        raise ValueError("old_name and new_name must be different")

    def getter(self):
        _deprecation_warning(old_name, new_name, version)
        if not hasattr(self, new_name):
            raise AttributeError(
                f"'{self.__class__.__name__}' object has no attribute '{new_name}'"
            )
        return getattr(self, new_name)

    def setter(self, value):
        _deprecation_warning(old_name, new_name, version)
        setattr(self, new_name, value)

    def deleter(self):
        _deprecation_warning(old_name, new_name, version)
        if not hasattr(self, new_name):
            raise AttributeError(
                f"'{self.__class__.__name__}' object has no attribute '{new_name}'"
            )
        delattr(self, new_name)

    return property(getter, setter, deleter)

import argparse
import json
import logging
import os
import pathlib
import sys
import tempfile

logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

MAX_JSON_FILE_SIZE = 10 * 1024 * 1024  # 10 MB
MAX_RECURSION_DEPTH = 1000


def _is_allowed_json_type(obj, depth=0):
    if depth > MAX_RECURSION_DEPTH:
        raise ValueError("JSON structure too deep")
    if obj is None or isinstance(obj, (bool, int, float, str)):
        return True
    if isinstance(obj, (list, tuple)):
        return all(_is_allowed_json_type(item, depth + 1) for item in obj)
    if isinstance(obj, dict):
        return all(
            isinstance(k, str) and _is_allowed_json_type(v, depth + 1)
            for k, v in obj.items()
        )
    return False


def safe_load_json(file_path: pathlib.Path):
    try:
        if file_path.stat().st_size > MAX_JSON_FILE_SIZE:
            raise ValueError("JSON file size exceeds limit")
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not _is_allowed_json_type(data):
            raise ValueError("Disallowed data structure detected during JSON load")
        return data
    except (json.JSONDecodeError, OSError, ValueError) as exc:
        raise ValueError(f"Failed to safely load JSON file {file_path}: {exc}") from exc


def safe_dump_json(data, file_path: pathlib.Path):
    if not _is_allowed_json_type(data):
        raise TypeError("Attempted to dump disallowed data into JSON")
    file_path.parent.mkdir(parents=True, exist_ok=True)
    dir_name = file_path.parent
    try:
        with tempfile.NamedTemporaryFile("w", dir=dir_name, delete=False, encoding="utf-8") as tmp:
            json.dump(data, tmp, ensure_ascii=False, separators=(",", ":"))
        os.replace(tmp.name, file_path)
    except Exception as exc:
        raise RuntimeError(f"Failed to safely write JSON file {file_path}: {exc}") from exc


def _flatten_numeric(data):
    result = []
    if isinstance(data, dict):
        for v in data.values():
            result.extend(_flatten_numeric(v))
    elif isinstance(data, (list, tuple)):
        for item in data:
            result.extend(_flatten_numeric(item))
    elif isinstance(data, (int, float)):
        result.append(data)
    return result


def interpolate_numeric(data):
    if isinstance(data, dict):
        numeric_keys = [
            k
            for k in data
            if isinstance(k, (int, float)) and isinstance(data[k], (int, float))
        ]
        if not numeric_keys:
            return data
        min_key, max_key = min(numeric_keys), max(numeric_keys)
        interpolated = {}
        for x in range(int(min_key), int(max_key) + 1):
            left_keys = [k for k in numeric_keys if k <= x]
            right_keys = [k for k in numeric_keys if k >= x]
            if left_keys and right_keys:
                k_left, k_right = max(left_keys), min(right_keys)
                v_left, v_right = data[k_left], data[k_right]
                if k_left == k_right:
                    interpolated[x] = v_left
                else:
                    t = (x - k_left) / (k_right - k_left)
                    interpolated[x] = v_left + t * (v_right - v_left)
        return interpolated
    elif isinstance(data, (list, tuple)):
        dict_repr = {i: v for i, v in enumerate(data)}
        return interpolate_numeric(dict_repr)
    return data


def _replace_in_structure(obj, old_substr: str, new_substr: str):
    if isinstance(obj, dict):
        return {k: _replace_in_structure(v, old_substr, new_substr) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        replaced = [_replace_in_structure(item, old_substr, new_substr) for item in obj]
        return type(obj)(replaced)
    if isinstance(obj, str):
        return obj.replace(old_substr, new_substr)
    return obj


def replace_in_data(data, old_substr: str, new_substr: str):
    return _replace_in_structure(data, old_substr, new_substr)


def validate_pickle_path(path_str: str):
    path = pathlib.Path(path_str).expanduser().resolve()
    if not path.is_file():
        raise FileNotFoundError(f"File not found: {path}")
    if path.suffix.lower() != ".pkl":
        raise ValueError(f"Expected a pickle file (.pkl), got: {path.suffix}")
    if path.is_symlink():
        raise ValueError(f"Path is a symbolic link: {path}")
    return path


def main():
    parser = argparse.ArgumentParser(description="Process pickle files with interpolation and string replacement.")
    parser.add_argument("interp_input", help="Pickle file for interpolation")
    parser.add_argument("replace_input", help="Pickle file for search/replace")
    parser.add_argument("other_input", help="Third pickle file (unused)")
    parser.add_argument("interp_output", help="Output pickle file for interpolated data")
    parser.add_argument("replace_output", help="Output pickle file for modified replace data")
    args = parser.parse_args()

    try:
        interp_in_path = validate_pickle_path(args.interp_input)
        replace_in_path = validate_pickle_path(args.replace_input)
        _ = validate_pickle_path(args.other_input)

        interp_out_path = pathlib.Path(args.interp_output).expanduser().resolve()
        replace_out_path = pathlib.Path(args.replace_output).expanduser().resolve()

        interp_data = safe_load_json(interp_in_path)
        interpolated = interpolate_numeric(interp_data)
        safe_dump_json(interpolated, interp_out_path)

        replace_data = safe_load_json(replace_in_path)
        replaced = replace_in_data(replace_data, "foo", "bar")
        safe_dump_json(replaced, replace_out_path)

    except Exception as exc:
        logging.error("An error occurred: %s", exc, exc_info=True)
        sys.exit(1)


if __name__ == "__main__":
    main()

import ast
import os
import sys


def _allowed_builtins():
    """Return dictionary of safe built-in functions and objects."""
    return {
        "abs": abs,
        "all": all,
        "any": any,
        "bool": bool,
        "chr": chr,
        "dict": dict,
        "float": float,
        "int": int,
        "len": len,
        "list": list,
        "max": max,
        "min": min,
        "pow": pow,
        "range": range,
        "str": str,
        "tuple": tuple,
        "sum": sum,
        "enumerate": enumerate,
        "zip": zip,
    }


def _safe_exec(script_str):
    """
    Execute script_str if it contains a single assignment to 'result'
    with a safe expression. Return the evaluated value or None on error.
    """
    try:
        parsed = ast.parse(script_str, mode="exec")
    except SyntaxError:
        return None

    if len(parsed.body) != 1:
        return None
    node = parsed.body[0]
    if not isinstance(node, ast.Assign):
        return None
    if len(node.targets) != 1 or not isinstance(node.targets[0], ast.Name):
        return None
    if node.targets[0].id != "result":
        return None

    try:
        return _safe_eval_expr(node.value, {})
    except Exception:
        return None


def _safe_eval_expr(node, local_vars):
    builtins = _allowed_builtins()

    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Name):
        if node.id in builtins:
            return builtins[node.id]
        if node.id in local_vars:
            return local_vars[node.id]
        raise ValueError(f"Unknown name '{node.id}'")

    if isinstance(node, ast.BinOp):
        left = _safe_eval_expr(node.left, local_vars)
        right = _safe_eval_expr(node.right, local_vars)
        op = node.op
        if isinstance(op, ast.Add):
            return left + right
        if isinstance(op, ast.Sub):
            return left - right
        if isinstance(op, ast.Mult):
            return left * right
        if isinstance(op, ast.Div):
            return left / right
        if isinstance(op, ast.FloorDiv):
            return left // right
        if isinstance(op, ast.Mod):
            return left % right
        if isinstance(op, ast.Pow):
            return left ** right
        raise ValueError(f"Unsupported binary operator {op}")

    if isinstance(node, ast.UnaryOp):
        operand = _safe_eval_expr(node.operand, local_vars)
        op = node.op
        if isinstance(op, ast.UAdd):
            return +operand
        if isinstance(op, ast.USub):
            return -operand
        if isinstance(op, ast.Not):
            return not operand
        raise ValueError(f"Unsupported unary operator {op}")

    if isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            for value in node.values:
                if not _safe_eval_expr(value, local_vars):
                    return False
            return True
        if isinstance(node.op, ast.Or):
            for value in node.values:
                if _safe_eval_expr(value, local_vars):
                    return True
            return False
        raise ValueError(f"Unsupported boolean operator {node.op}")

    if isinstance(node, ast.Compare):
        left = _safe_eval_expr(node.left, local_vars)
        for op, comp in zip(node.ops, node.comparators):
            right = _safe_eval_expr(comp, local_vars)
            if isinstance(op, ast.Eq):
                if not left == right:
                    return False
            elif isinstance(op, ast.NotEq):
                if not left != right:
                    return False
            elif isinstance(op, ast.Lt):
                if not left < right:
                    return False
            elif isinstance(op, ast.LtE):
                if not left <= right:
                    return False
            elif isinstance(op, ast.Gt):
                if not left > right:
                    return False
            elif isinstance(op, ast.GtE):
                if not left >= right:
                    return False
            else:
                return False
            left = right
        return True

    if isinstance(node, ast.Call):
        if not isinstance(node.func, ast.Name):
            raise ValueError("Only simple function calls allowed")
        func_name = node.func.id
        if func_name not in builtins:
            raise ValueError(f"Call to forbidden function '{func_name}'")
        func = builtins[func_name]
        args = [_safe_eval_expr(arg, local_vars) for arg in node.args]
        kwargs = {kw.arg: _safe_eval_expr(kw.value, local_vars) for kw in node.keywords}
        return func(*args, **kwargs)

    if isinstance(node, ast.Subscript):
        value = _safe_eval_expr(node.value, local_vars)
        slice_ = _safe_eval_expr(node.slice, local_vars)
        return value[slice_]

    if isinstance(node, ast.Index):  # for Python <3.9
        return _safe_eval_expr(node.value, local_vars)

    if isinstance(node, ast.Slice):
        lower = _safe_eval_expr(node.lower, local_vars) if node.lower else None
        upper = _safe_eval_expr(node.upper, local_vars) if node.upper else None
        step = _safe_eval_expr(node.step, local_vars) if node.step else None
        return slice(lower, upper, step)

    if isinstance(node, (ast.Tuple, ast.List)):
        elts = [_safe_eval_expr(e, local_vars) for e in node.elts]
        return tuple(elts) if isinstance(node, ast.Tuple) else list(elts)

    raise ValueError(f"Unsupported expression type {type(node)}")


def run_scripts(main_script):
    """
    Execute main_script and optionally a secondary script if a file path is provided as
    the first command-line argument. Securely resolve script paths and print results.
    """
    result = _safe_exec(main_script)
    if result is not None:
        print(result)
    else:
        print("Main script executed. No result value set.")

    if len(sys.argv) > 1:
        secondary_path = sys.argv[1]

        scripts_dir = os.path.abspath(
            os.path.join(os.path.dirname(__file__), "scripts")
        )

        if os.path.isabs(secondary_path):
            print(f"Rejected absolute path for secondary script: {secondary_path}")
            return

        safe_path = os.path.abspath(
            os.path.join(scripts_dir, os.path.normpath(secondary_path))
        )

        if os.path.commonpath([scripts_dir, safe_path]) != scripts_dir:
            print(f"Secondary script path escapes trusted directory: {secondary_path}")
            return

        try:
            with open(safe_path, "r", encoding="utf-8") as f:
                secondary_script = f.read()
        except Exception:
            print(f"Unable to read secondary script: {secondary_path}")
            return

        sec_result = _safe_exec(secondary_script)
        if sec_result is not None:
            print(sec_result)
        else:
            print("Secondary script executed. No result value set.")


if __name__ == "__main__":
    main_script = """
result = sum(range(10))
"""
    run_scripts(main_script)

import os
import json
import logging

# Maximum depth for nested data structures
MAX_SAFE_DEPTH = 1000

# Fallback for missing ppmatlab dependency
try:
    from ppmatlab import mat
except ImportError:
    class _MissingPPMatlab:
        def open(self, *_, **__):
            raise RuntimeError(
                "Required dependency 'ppmatlab' is not installed. "
                "Please install it using 'pip install ppmatlab'."
            )

    mat = _MissingPPMatlab()


def _sanitize_path(provided_path: str, allowed_root: str) -> str:
    abs_path = os.path.realpath(os.path.abspath(provided_path))
    root = os.path.realpath(os.path.abspath(allowed_root))
    if os.path.commonpath([abs_path, root]) != root:
        raise ValueError(
            f"The path '{provided_path}' resolves outside the allowed directory '{allowed_root}'."
        )
    return abs_path


def _is_safe_data(data):
    """Iteratively ensure data consists of basic immutable types."""
    stack = [(data, 0)]
    while stack:
        current, depth = stack.pop()
        if isinstance(current, (int, float, bool, str, type(None))):
            continue
        if isinstance(current, (list, tuple)):
            if depth >= MAX_SAFE_DEPTH:
                raise ValueError("Maximum nesting depth exceeded in data.")
            for item in reversed(current):
                stack.append((item, depth + 1))
        elif isinstance(current, dict):
            if depth >= MAX_SAFE_DEPTH:
                raise ValueError("Maximum nesting depth exceeded in data.")
            for key, value in reversed(list(current.items())):
                if not isinstance(key, str):
                    return False
                stack.append((value, depth + 1))
        else:
            return False
    return True


def _load_shelf_data(shelf_path, key):
    """Load data from a shelf-like JSON file ensuring safety."""
    try:
        with open(shelf_path, "r", encoding="utf-8") as fp:
            content = json.load(fp)
    except (OSError, json.JSONDecodeError) as exc:
        logging.error("Error reading JSON shelf file: %s", exc, exc_info=False)
        raise RuntimeError("Failed to read mesh data from the shelf.") from exc

    if key not in content:
        raise KeyError(f"Key '{key}' not found in shelf.")

    mesh_data = content[key]
    if not _is_safe_data(mesh_data):
        raise ValueError("Unsafe data type detected in shelf content.")
    return mesh_data


def mesh_from_shelf_to_mat(
    shelf_filename: str,
    output_filename: str,
    shelf_key: str = "mesh",
    allowed_root: str = None,
):
    if allowed_root is None:
        allowed_root = os.getcwd()

    try:
        safe_shelf = _sanitize_path(shelf_filename, allowed_root)
        safe_output = _sanitize_path(output_filename, allowed_root)
    except ValueError as e:
        raise ValueError(f"Invalid file path: {e}") from None

    try:
        mesh_data = _load_shelf_data(safe_shelf, shelf_key)
    except (KeyError, ValueError) as exc:
        logging.error("Key error or unsafe data: %s", exc, exc_info=False)
        raise RuntimeError("Invalid or unsafe mesh data in the shelf.") from exc

    try:
        with mat.open(safe_output, mode="w") as mat_file:
            mat_file["mesh"] = mesh_data
    except Exception as exc:
        logging.error("Error writing MATLAB file: %s", exc, exc_info=False)
        raise RuntimeError("Failed to write mesh data to MATLAB file.") from exc

import re
import pytest

_email_pattern = re.compile(r"^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$", re.ASCII)

def _is_valid_email(email: str) -> bool:
    """Validate email format without external libraries."""
    return bool(_email_pattern.fullmatch(email))

@pytest.mark.parametrize(
    "email,password",
    [
        ("user@example.com", "incorrect_password"),
        ("unknown_user@nonexistent.com", "any_password"),
    ],
)
def test_login_invalid_credentials(testapp, email, password):
    """
    Submit login form with invalid credentials and verify
    that an appropriate error message is displayed.
    """
    if not _is_valid_email(email):
        pytest.fail(f"Test input email invalid: {email}")

    payload = {"email": email, "password": password}
    response = testapp.post("/login", params=payload, expect_errors=True)

    valid_status_codes = {200, 401, 403}
    if response.status_code not in valid_status_codes:
        pytest.fail(
            f"Unexpected status code: {response.status_code} for email {email}"
        )

    body_bytes = getattr(response, "body", b"")
    body_text = body_bytes.decode("utf-8", errors="replace").lower()
    keywords = {"invalid", "error", "failed"}
    if not any(keyword in body_text for keyword in keywords):
        pytest.fail("Authentication failure message not found in response.")

