import os
import hashlib
from pathlib import Path
from urllib.parse import urlparse
from typing import Optional

# Directory where thumbnails will be stored
THUMBNAIL_DIR = Path.cwd() / "thumbnails"

# Allowed file extensions
ALLOWED_EXTENSIONS = {".jpg", ".jpeg", ".png", ".gif"}


def _validate_url(url: str) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("Invalid or unsupported URL format.")
    return url


def _validate_dimensions(dim: int, name: str, *, min_value: int = 1, max_value: int = 5000) -> int:
    if not isinstance(dim, int):
        raise ValueError(f"{name} must be an integer.")
    if not (min_value <= dim <= max_value):
        raise ValueError(f"{name} must be between {min_value} and {max_value}.")
    return dim


def _sanitize_extension(ext: Optional[str]) -> str:
    if ext is None:
        return ".png"
    ext = ext.lower().strip()
    if not ext.startswith("."):
        ext = f".{ext}"
    if ext not in ALLOWED_EXTENSIONS:
        return ".png"
    return ext


def get_thumbnail_path(url: str, width: int, height: int, ext: Optional[str] = None) -> str:
    _validate_url(url)
    width = _validate_dimensions(width, "width")
    height = _validate_dimensions(height, "height")
    ext = _sanitize_extension(ext)

    try:
        THUMBNAIL_DIR.mkdir(parents=True, mode=0o700, exist_ok=True)
    except OSError as exc:
        raise RuntimeError("Failed to create thumbnail directory.") from exc

    parsed = urlparse(url)
    path_hash_input = (parsed.netloc + parsed.path).encode("utf-8")
    hash_digest = hashlib.sha256(path_hash_input).hexdigest()

    filename = f"{hash_digest}_{width}x{height}{ext}"
    thumbnail_path = THUMBNAIL_DIR / filename

    return str(thumbnail_path.resolve())

import inspect
import types

class _Unspecified:
    pass  # sentinel for unlimited args

def test_library_method(library_mock, method_name):
    """Test a library method for expected behavior and argument limits."""
    if not isinstance(method_name, str):
        raise ValueError("method_name must be a string")
    if not method_name.isidentifier() or method_name.startswith("_"):
        raise ValueError("method_name must be a public identifier")

    EXPECTED = {
        "add": {"expected_return": 5, "min_args": 2, "max_args": 2},
        "concat": {"expected_return": "hello world", "min_args": 2, "max_args": 2},
    }

    if method_name not in EXPECTED:
        raise KeyError(f"Unknown method: {method_name}")

    config = EXPECTED[method_name]

    try:
        handler = PythonHandler(library_mock, method_name)
    except Exception as exc:
        raise RuntimeError(f"Failed to instantiate handler for {method_name}") from exc

    try:
        method = getattr(handler, method_name)
    except AttributeError as exc:
        raise AssertionError(f"Method '{method_name}' not found in handler") from exc

    if not isinstance(method, (types.FunctionType, types.MethodType)):
        raise AssertionError(f"Attribute '{method_name}' is not callable")

    try:
        sig = inspect.signature(method)
    except (ValueError, TypeError) as exc:
        raise AssertionError(f"Unable to inspect signature for {method_name}") from exc

    params = sig.parameters
    required = [
        p
        for p in params.values()
        if p.default == inspect.Parameter.empty
        and p.kind in (
            inspect.Parameter.POSITIONAL_ONLY,
            inspect.Parameter.POSITIONAL_OR_KEYWORD,
        )
    ]
    min_args = len(required)

    has_var_positional = any(p.kind == inspect.Parameter.VAR_POSITIONAL for p in params.values())
    max_args = _Unspecified if has_var_positional else len(params)

    if min_args != config["min_args"]:
        raise AssertionError(
            f"Argument limits for {method_name} mismatch: expected min {config['min_args']} "
            f"got min {min_args}"
        )

    if not has_var_positional and max_args != config["max_args"]:
        raise AssertionError(
            f"Argument limits for {method_name} mismatch: expected max {config['max_args']} "
            f"got max {max_args}"
        )

    sample_args = [1, 2] if method_name == "add" else ["hello ", "world"]

    try:
        result = method(*sample_args)
    except Exception as exc:
        raise AssertionError(f"Method {method_name} raised an exception: {exc}") from exc

    if result != config["expected_return"]:
        raise AssertionError(
            f"Method {method_name} returned {result}; expected {config['expected_return']}"
        )

import ast
import sys
import os
import marshal
import multiprocessing
import time
from multiprocessing import Process, Pipe
import warnings

# ------------------------------------------------------------------------------
# Configuration constants
# ------------------------------------------------------------------------------
_MAX_OPTION_SIZE = 1024  # 1 KiB
_MAX_CODE_BYTES = 64 * 1024  # 64 KiB
_AST_MAX_DEPTH = 50
_FUNCTION_BODY_LIMIT = 50
_EXEC_TIMEOUT_SECONDS = 5.0

# ------------------------------------------------------------------------------
# Options validation â disallow dangerous types and large objects
# ------------------------------------------------------------------------------
_ALLOWED_BASE = (int, float, str, bool, type(None), complex)
_CONTAINERS = (list, tuple, set, dict)

_DISALLOWED_OPTION_NAMES = {
    "__builtins__", "__import__", "open", "eval", "exec", "compile",
    "globals", "locals", "vars", "__dict__", "__class__",
    "__class_getitem__",
}

def _validate_options(options: dict) -> None:
    if not isinstance(options, dict):
        raise TypeError("options must be a dictionary")
    for key, value in options.items():
        if not isinstance(key, str):
            raise ValueError("Option keys must be strings")
        if key in _DISALLOWED_OPTION_NAMES:
            raise ValueError(f"Disallowed option key: {key}")
        _validate_value(value, path=key)

def _validate_value(val, path=""):
    if isinstance(val, _ALLOWED_BASE):
        return
    if isinstance(val, str):
        if len(val) > _MAX_OPTION_SIZE:
            raise ValueError(f"String too large at {path}")
        return
    if isinstance(val, _CONTAINERS):
        if isinstance(val, dict):
            for k, v in val.items():
                if not isinstance(k, str):
                    raise ValueError(f"Dictionary keys must be strings at {path}")
                _validate_value(v, path=f"{path}['{k}']")
        else:
            for i, item in enumerate(val):
                _validate_value(item, path=f"{path}[{i}]")
        return
    raise ValueError(f"Disallowed type in options at {path}: {type(val).__name__}")

# ------------------------------------------------------------------------------
# AST validation â depth, allowed node types, function body limits
# ------------------------------------------------------------------------------
_ALLOWED_NODE_TYPES = (
    ast.Module, ast.Expr, ast.Call, ast.Name, ast.Load, ast.Constant,
    ast.Attribute, ast.Subscript, ast.List, ast.Tuple, ast.Dict, ast.Set,
    ast.BinOp, ast.UnaryOp, ast.BoolOp, ast.Compare, ast.IfExp,
    ast.FunctionDef, ast.Return, ast.Assign, ast.AugAssign, ast.arguments, ast.arg,
    ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Mod, ast.Pow, ast.FloorDiv,
    ast.USub, ast.UAdd, ast.Not, ast.And, ast.Or, ast.Eq, ast.NotEq,
    ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.In, ast.NotIn, ast.Is, ast.IsNot,
)

_DISALLOWED_NAMES = {
    "__import__", "open", "eval", "exec", "compile",
    "globals", "locals", "vars", "__dict__", "__class__",
    "__class_getitem__",
}

def _check_ast_depth(node, depth=0):
    if depth > _AST_MAX_DEPTH:
        raise ValueError("AST depth exceeds allowed limit")
    for child in ast.iter_child_nodes(node):
        _check_ast_depth(child, depth + 1)

def _count_function_body(node):
    if not isinstance(node, ast.FunctionDef):
        return 0
    return sum(isinstance(child, (ast.stmt, ast.expr)) for child in node.body)

# ------------------------------------------------------------------------------
# Resource limits (Unix)
# ------------------------------------------------------------------------------
def _apply_resource_limits():
    if os.name != "posix":
        return
    try:
        import resource
        # CPU time limits
        resource.setrlimit(resource.RLIMIT_CPU, (1, 2))
        # Address space limits
        rss_limits = (64 * 1024 * 1024, 128 * 1024 * 1024)
        resource.setrlimit(resource.RLIMIT_AS, rss_limits)
        # Stack size limits
        stack_limits = (8 * 1024 * 1024, 16 * 1024 * 1024)
        resource.setrlimit(resource.RLIMIT_STACK, stack_limits)
    except Exception:
        warnings.warn("Failed to set resource limits")
    sys.setrecursionlimit(200)

# ------------------------------------------------------------------------------
# Worker that executes user code in a restricted namespace
# ------------------------------------------------------------------------------
def _worker(code_bytes: bytes, globals_dict: dict, conn):
    try:
        _apply_resource_limits()
        code_obj = marshal.loads(code_bytes)
        console_globals = {"__builtins__": {}}
        console_globals.update(globals_dict)
        exec(code_obj, console_globals, None)
        result = console_globals.get("_result")
        conn.send(("ok", result))
    except Exception as e:
        conn.send(("error", str(e)))
    finally:
        conn.close()

# ------------------------------------------------------------------------------
# Public API â safe_execute
# ------------------------------------------------------------------------------
def safe_execute(func_str: str, options: dict):
    """
    Execute a user-provided Python snippet in a restricted environment.
    Returns the value of the last expression or None.
    """
    if not isinstance(func_str, str):
        raise TypeError("func_str must be a string")
    if len(func_str.encode("utf-8")) > _MAX_CODE_BYTES:
        raise ValueError("Code string too large")
    if not isinstance(options, dict):
        raise TypeError("options must be a dictionary")

    _validate_options(options)

    try:
        tree = ast.parse(func_str, mode="exec")
    except SyntaxError as exc:
        raise ValueError(f"Invalid Python code: {exc}") from None

    for node in ast.walk(tree):
        if not isinstance(node, _ALLOWDER_NODE_TYPES):
            raise ValueError(f"Disallowed construct: {type(node).__name__}")
        if isinstance(node, ast.Name) and node.id in _DISALLOWED_NAMES:
            raise ValueError(f"Disallowed name: {node.id}")
        if isinstance(node, (ast.Assign, ast.AugAssign)):
            targets = node.targets if isinstance(node, ast.Assign) else [node.target]
            for t in targets:
                if isinstance(t, ast.Attribute):
                    if t.attr in _DISALLOWED_NAMES:
                        raise ValueError(f"Assignment to forbidden attribute: {t.attr}")
                    raise ValueError("Assignment to an attribute is prohibited")
                if isinstance(t, ast.Name) and t.id in _DISALLOWED_NAMES:
                    raise ValueError(f"Assignment to forbidden name: {t.id}")
        if isinstance(node, ast.Constant) and isinstance(node.value, (str, bytes)):
            if len(node.value) > _MAX_OPTION_SIZE:
                raise ValueError(f"String literal too large at line {getattr(node, 'lineno', '?')}")

    _check_ast_depth(tree)

    if tree.body and isinstance(tree.body[-1], ast.Expr):
        last_expr = tree.body.pop()
        tree.body.append(
            ast.Assign(
                targets=[ast.Name(id="_result", ctx=ast.Store())],
                value=last_expr.value,
            )
        )

    for node in tree.body:
        if isinstance(node, ast.FunctionDef):
            if _count_function_body(node) > _FUNCTION_BODY_LIMIT:
                raise ValueError(f"Function {node.name} is too large")

    code_obj = compile(tree, "<string>", "exec")
    code_bytes = marshal.dumps(code_obj)

    if len(code_bytes) > _MAX_CODE_BYTES:
        raise ValueError("Compiled code size too large")

    parent_conn, child_conn = Pipe()
    p = Process(target=_worker, args=(code_bytes, options, child_conn), daemon=True)
    p.start()
    child_conn.close()

    try:
        if not parent_conn.poll(_EXEC_TIMEOUT_SECONDS):
            p.terminate()
            p.join()
            raise TimeoutError("Execution timed out")
        status, payload = parent_conn.recv()
    except EOFError:
        raise RuntimeError("Execution process failed to report result")
    finally:
        parent_conn.close()
        if p.is_alive():
            p.terminate()
            p.join()

    if status == "ok":
        return payload
    else:
        raise RuntimeError(f"Execution failed: {payload}")

from collections import namedtuple
from typing import Any, List, Tuple

def get_tables(cursor: Any) -> Tuple[List[str], List[Any]]:
    """
    Safely retrieve a list of table names and their corresponding namedtuples
    from a database cursor. Validates the cursor interface, query result
    integrity, and protects against sensitive data leakage in errors.
    """
    required = ("execute", "fetchall", "description")
    if not all(hasattr(cursor, name) for name in required):
        raise ValueError("Cursor must provide execute, fetchall, and description")

    if not callable(getattr(cursor, "execute", None)):
        raise ValueError("Cursor.execute must be callable")
    if not callable(getattr(cursor, "fetchall", None)):
        raise ValueError("Cursor.fetchall must be callable")

    desc = cursor.description
    if desc is None:
        raise ValueError("Cursor.description is None")
    if not isinstance(desc, (list, tuple)):
        raise ValueError("Cursor.description must be a list or tuple")
    column_names: List[str] = []
    for d in desc:
        if not isinstance(d, (list, tuple)):
            raise ValueError("Each entry in cursor.description must be a list or tuple")
        if len(d) == 0 or not isinstance(d[0], str):
            raise ValueError("Each entry in cursor.description must start with a string")
        column_names.append(d[0])
    if not column_names:
        column_names = ["table_name"]

    try:
        cursor.execute("SHOW TABLES")
        rows = cursor.fetchall()
    except Exception:
        raise RuntimeError("Failed to retrieve tables from database") from None

    if rows:
        if len(rows[0]) != len(column_names):
            raise ValueError("Row column count does not match description")
        for row in rows:
            if len(row) != len(column_names):
                raise ValueError("Inconsistent row length detected")

    TableTuple = namedtuple("Table", column_names)
    named_tuples: List[Any] = [TableTuple(*row) for row in rows]
    table_names: List[str] = [nt[0] for nt in named_tuples]

    return table_names, named_tuples

import json
import logging
import re
import socket
import ssl
import urllib.error
import urllib.parse
import urllib.request
import ipaddress
from typing import Dict, Tuple

logger = logging.getLogger(__name__)

MAX_RESPONSE_BYTES = 1 << 20  # 1 MiB

class NoRedirectHandler(urllib.request.HTTPRedirectHandler):
    """Handler that prevents following HTTP redirects."""
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        # Do not return a new Request object -> no redirect
        return None

def _validate_url(url: str) -> None:
    if not isinstance(url, str):
        raise TypeError("URL must be a string")
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("URL scheme must be http or https")
    if not parsed.netloc:
        raise ValueError("URL must contain a network location")
    hostname = parsed.hostname
    if hostname is None:
        raise ValueError("URL missing hostname")

    # Resolve hostname and prohibit private/reserved IPs
    try:
        addrinfo = socket.getaddrinfo(hostname, None, proto=socket.IPPROTO_TCP)
    except socket.gaierror as exc:
        raise ValueError(f"Unable to resolve hostname: {hostname}") from exc
    for entry in addrinfo:
        ip_string = entry[4][0]
        try:
            ip = ipaddress.ip_address(ip_string)
            if ip.is_private or ip.is_loopback or ip.is_reserved or ip.is_multicast:
                raise ValueError("URL points to a private, loopback, reserved, or multicast IP")
        except ValueError:
            continue  # skip non-IP addresses, should not happen

    # Disallow fragments
    if parsed.fragment:
        raise ValueError("URL must not contain a fragment")

    # Sanitise the URL
    if re.search(r"[;\&@]", url):
        raise ValueError("URL contains suspicious characters")
    if re.search(r"[�-\]", parsed.path):
        raise ValueError("URL path contains control or backslash characters")

def _sanitize_query_params(params: Dict[str, object]) -> str:
    if not isinstance(params, dict):
        raise TypeError("Parameters must be a dict")
    safe_params = {}
    for key, value in params.items():
        if not isinstance(key, str):
            raise TypeError("Parameter keys must be strings")
        if not re.match(r"^[A-Za-z0-9_-]+$", key):
            raise ValueError(f"Invalid parameter key: {key}")
        if isinstance(value, (list, dict)):
            raise TypeError("Parameter values must be primitive types")
        safe_params[key] = str(value)
    return urllib.parse.urlencode(safe_params)

def _build_delete_url(base_url: str, params: Dict[str, str]) -> str:
    parsed = urllib.parse.urlparse(base_url)
    existing = dict(urllib.parse.parse_qsl(parsed.query, keep_blank_values=True))
    existing.update(params)
    new_query = urllib.parse.urlencode(existing)
    new_parsed = parsed._replace(query=new_query)
    return urllib.parse.urlunparse(new_parsed)

def _create_opener(context: ssl.SSLContext) -> urllib.request.OpenerDirector:
    return urllib.request.build_opener(
        urllib.request.ProxyHandler({}),   # disable proxy usage
        urllib.request.HTTPHandler(),
        urllib.request.HTTPSHandler(context=context),
        NoRedirectHandler()
    )

def _read_response(resp) -> str:
    """Read response body with a size limit."""
    data = resp.read(MAX_RESPONSE_BYTES + 1)
    if len(data) > MAX_RESPONSE_BYTES:
        raise RuntimeError("Response body exceeds size limit")
    return data.decode("utf-8", errors="strict")

def send_post_and_delete(
    url: str,
    *,
    post_payload: Dict[str, object],
    delete_params: Dict[str, object],
    expected_post_message: str,
    expected_delete_message: str,
) -> Tuple[Dict[str, object], Dict[str, object]]:
    _validate_url(url)

    if not isinstance(post_payload, dict):
        raise TypeError("POST payload must be a dict")
    if not isinstance(delete_params, dict):
        raise TypeError("DELETE parameters must be a dict")

    headers = {
        "Content-Type": "application/json",
        "Accept": "application/json",
        "User-Agent": "SecureClient/1.0",
    }

    ssl_context = ssl.create_default_context(ssl.Purpose.SERVER_AUTH)
    ssl_context.check_hostname = True
    ssl_context.verify_mode = ssl.CERT_REQUIRED

    try:
        post_data = json.dumps(post_payload).encode("utf-8")
    except (TypeError, ValueError) as exc:
        logger.error("Invalid POST payload: %s", exc.__class__.__name__)
        raise RuntimeError("Invalid POST payload") from exc

    post_req = urllib.request.Request(url, data=post_data, headers=headers, method="POST")
    opener = _create_opener(ssl_context)
    try:
        with opener.open(post_req, timeout=10) as resp:
            post_body = _read_response(resp)
            post_json = json.loads(post_body)
    except urllib.error.HTTPError as err:
        logger.error("POST request failed with status %s", err.code)
        raise RuntimeError(f"POST request failed with status {err.code}") from err
    except urllib.error.URLError as err:
        logger.error("POST request failed: %s", err.reason)
        raise RuntimeError(f"POST request failed: {err.reason}") from err
    except (json.JSONDecodeError, RuntimeError):
        logger.error("Response from POST is not valid JSON or is too large")
        raise RuntimeError("Response from POST is not valid JSON") from None

    if expected_post_message not in post_json.get("message", ""):
        logger.error("Expected message not found in POST response")
        raise AssertionError("Expected message not found in POST response")

    try:
        query_string = _sanitize_query_params(delete_params)
        delete_params_dict = dict(urllib.parse.parse_qsl(query_string))
        delete_url = _build_delete_url(url, delete_params_dict)
    except Exception as err:
        logger.error("Error encoding delete parameters: %s", err.__class__.__name__)
        raise RuntimeError("Error encoding delete parameters") from err

    delete_req = urllib.request.Request(delete_url, headers=headers, method="DELETE")
    try:
        with opener.open(delete_req, timeout=10) as resp:
            delete_body = _read_response(resp)
            delete_json = json.loads(delete_body)
    except urllib.error.HTTPError as err:
        logger.error("DELETE request failed with status %s", err.code)
        raise RuntimeError(f"DELETE request failed with status {err.code}") from err
    except urllib.error.URLError as err:
        logger.error("DELETE request failed: %s", err.reason)
        raise RuntimeError(f"DELETE request failed: {err.reason}") from err
    except (json.JSONDecodeError, RuntimeError):
        logger.error("Response from DELETE is not valid JSON or is too large")
        raise RuntimeError("Response from DELETE is not valid JSON") from None

    if expected_delete_message not in delete_json.get("message", ""):
        logger.error("Expected message not found in DELETE response")
        raise AssertionError("Expected message not found in DELETE response")

    return post_json, delete_json

import argparse
import logging
import os
import shutil
import sys
import tempfile
import zipfile
from pathlib import Path
import secrets

try:
    from cryptography.hazmat.primitives.ciphers.aead import AESGCM
except ImportError:
    print("Missing dependency: cryptography. Install with pip install cryptography")
    sys.exit(1)

MAX_ZIP_SIZE_BYTES = 100 * 1024 * 1024  # 100 MB
OUTPUT_DIR_MODE = 0o700
TEMP_FILE_PREFIX = "enc_"

def validate_path(path_str: str, description: str) -> Path:
    p = Path(path_str).expanduser()
    if p.is_symlink():
        raise ValueError(f"{description} must not be a symlink")
    try:
        resolved = p.resolve(strict=True)
    except FileNotFoundError:
        raise FileNotFoundError(f"{description} not found at {p}")
    if not resolved.is_file():
        raise FileNotFoundError(f"{description} is not a file at {resolved}")
    return resolved

def validate_dir(path_str: str, description: str) -> Path:
    p = Path(path_str).expanduser()
    if p.is_symlink():
        raise ValueError(f"{description} must not be a symlink")
    try:
        resolved = p.resolve(strict=False)
    except Exception:
        resolved = p
    if resolved.exists() and not resolved.is_dir():
        raise NotADirectoryError(f"{description} exists and is not a directory")
    return resolved

def read_key_file(key_path: Path) -> bytes:
    if key_path.is_symlink():
        raise ValueError("Key file must not be a symlink")
    size = key_path.stat().st_size
    if size < 32:
        raise ValueError("Key file must contain at least 32 bytes for AES-256")
    key_bytes = key_path.read_bytes()
    return key_bytes[:32]

def encrypt_and_package(input_zip: Path, key_bytes: bytes, output_dir: Path) -> None:
    os.makedirs(output_dir, mode=OUTPUT_DIR_MODE, exist_ok=True)

    file_size = input_zip.stat().st_size
    if file_size > MAX_ZIP_SIZE_BYTES:
        raise ValueError(f"Input zip is too large ({file_size} bytes)")

    try:
        data = input_zip.read_bytes()
    except Exception as e:
        raise RuntimeError(f"Failed to read input zip: {e}") from e

    nonce = secrets.token_bytes(12)
    aesgcm = AESGCM(key_bytes)
    try:
        ciphertext = aesgcm.encrypt(nonce, data, None)
    except Exception as e:
        raise RuntimeError(f"Encryption failed: {e}") from e

    tmp_fd, tmp_path = tempfile.mkstemp(prefix=TEMP_FILE_PREFIX, text=False)
    try:
        with os.fdopen(tmp_fd, 'wb') as tmp_file:
            tmp_file.write(nonce + ciphertext)
        tmp_enc_path = Path(tmp_path)

        dest_enc = output_dir / tmp_enc_path.name
        shutil.move(str(tmp_enc_path), dest_enc)

        zip_path = output_dir / "encrypted_contents.zip"
        with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as zf:
            zf.write(dest_enc, arcname=dest_enc.name)

        try:
            input_zip.unlink()
        except Exception as e:
            raise RuntimeError(f"Could not remove original zip: {e}") from e
    finally:
        if os.path.exists(tmp_path):
            try:
                os.unlink(tmp_path)
            except Exception:
                pass

def main() -> None:
    parser = argparse.ArgumentParser(description="Encrypt a zip file and package it.")
    parser.add_argument("input_zip", help="Path to the zip file to encrypt.")
    parser.add_argument("key_file", help="Path to the file containing the encryption key.")
    parser.add_argument(
        "--output-dir",
        default="encrypted_output",
        help="Directory to store encrypted files.",
    )
    args = parser.parse_args()

    logging.basicConfig(level=logging.INFO, format="%(levelname)s: %(message)s")

    try:
        input_zip_path = validate_path(args.input_zip, "Input zip")
        key_file_path = validate_path(args.key_file, "Key file")
        key_bytes = read_key_file(key_file_path)
        output_dir = validate_dir(args.output_dir, "Output directory")
        encrypt_and_package(input_zip_path, key_bytes, output_dir)
        logging.info("Encryption and packaging completed successfully.")
    except Exception as e:
        logging.error(e)
        sys.exit(1)

if __name__ == "__main__":
    main()

import json
import os
import shlex
import subprocess
import sys
import resource
import stat
from pathlib import Path

ALLOWED_COMMANDS = {
    "echo",
    "ls",
    "pwd",
    "whoami",
    "date",
}

MAX_OUTPUT_BYTES = 10_000_000
CPU_LIMIT_SEC = 10
MEM_LIMIT_BYTES = 100 * 1024 * 1024


def send_call(error_message: str) -> None:
    sys.stderr.write(f"ERROR: {error_message}
")
    sys.stderr.flush()


def is_safe_json_fd(fd: int) -> bool:
    try:
        st = os.fstat(fd)
    except OSError:
        return False
    if not stat.S_ISREG(st.st_mode):
        return False
    if st.st_mode & (stat.S_IRWXG | stat.S_IRWXO | stat.S_IWGRP | stat.S_IWOTH):
        return False
    if st.st_uid != os.getuid():
        return False
    return True


def load_commands(fd: int) -> dict:
    try:
        file_obj = os.fdopen(fd, "r", encoding="utf-8")
        data = json.load(file_obj)
    except json.JSONDecodeError:
        raise ValueError("JSON parse error")
    except Exception:
        raise ValueError("Failed to read JSON file")
    if not isinstance(data, dict):
        raise ValueError("JSON root must be an object")
    if "commands" not in data or not isinstance(data["commands"], list):
        raise ValueError("JSON must contain a 'commands' list")
    return data


def enforce_resource_limits():
    resource.setrlimit(resource.RLIMIT_CPU, (CPU_LIMIT_SEC, CPU_LIMIT_SEC))
    soft, hard = resource.getrlimit(resource.RLIMIT_AS)
    resource.setrlimit(resource.RLIMIT_AS, (MEM_LIMIT_BYTES, hard))


def run_command(cmd_parts, cwd, timeout):
    try:
        proc = subprocess.Popen(
            cmd_parts,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            cwd=cwd,
            preexec_fn=enforce_resource_limits,
        )
    except Exception as exc:
        raise RuntimeError(f"Failed to start command: {exc}")

    def read_stream(stream, max_bytes):
        chunks = []
        total = 0
        while True:
            chunk = stream.read(8192)
            if not chunk:
                break
            chunks.append(chunk)
            total += len(chunk.encode("utf-8"))
            if total >= max_bytes:
                break
        return "".join(chunks)

    try:
        stdout = read_stream(proc.stdout, MAX_OUTPUT_BYTES)
        stderr = read_stream(proc.stderr, MAX_OUTPUT_BYTES)
        proc.wait(timeout=timeout)
        return proc.returncode, stdout, stderr
    except subprocess.TimeoutExpired:
        proc.kill()
        proc.communicate()
        raise
    except Exception as e:
        proc.kill()
        proc.communicate()
        raise RuntimeError(f"Command execution error: {e}")


def main() -> None:
    if len(sys.argv) != 2:
        sys.stderr.write(f"Usage: {Path(sys.argv[0]).name} <commands.json>
")
        sys.exit(1)

    json_path = Path(sys.argv[1]).expanduser().resolve()
    if not json_path.is_file():
        sys.stderr.write(f"File not found: {json_path}
")
        sys.exit(1)

    fd = os.open(json_path, os.O_RDONLY | os.O_NOFOLLOW)
    try:
        if not is_safe_json_fd(fd):
            sys.stderr.write(
                f"Refusing to execute user-supplied JSON with unsafe permissions: {json_path}
"
            )
            sys.exit(1)

        try:
            data = load_commands(fd)
        except ValueError as err:
            sys.stderr.write(f"{err}
")
            sys.exit(1)
    finally:
        os.close(fd)

    print("Welcome to Secure Command Executor")
    cwd = os.path.realpath(Path.cwd())

    for idx, cmd_entry in enumerate(data["commands"], start=1):
        if not isinstance(cmd_entry, dict):
            sys.stderr.write(
                f"Invalid command entry at index {idx}: must be an object.
"
            )
            continue

        line_number = cmd_entry.get("line")
        comment = cmd_entry.get("comment", "")
        command_input = cmd_entry.get("input")

        if not isinstance(line_number, int):
            sys.stderr.write(
                f"Invalid or missing line number at index {idx}.
"
            )
            continue
        if not isinstance(comment, str):
            sys.stderr.write(
                f"Invalid comment at index {idx}.
"
            )
            continue
        if not isinstance(command_input, str):
            sys.stderr.write(
                f"Invalid command input at index {idx}.
"
            )
            continue

        try:
            cmd_parts = shlex.split(command_input)
        except ValueError:
            sys.stderr.write(
                f"Command rejected due to invalid syntax: {command_input}
"
            )
            continue

        if not cmd_parts:
            sys.stderr.write(f"Empty command at index {idx}.
")
            continue
        if cmd_parts[0] not in ALLOWED_COMMANDS:
            sys.stderr.write(
                f"Command '{cmd_parts[0]}' not allowed for line {line_number}.
"
            )
            continue

        print(f"
Line {line_number}: {comment}")
        print(f"Command: {command_input}")

        try:
            returncode, stdout, stderr = run_command(
                cmd_parts,
                cwd=cwd,
                timeout=CPU_LIMIT_SEC,
            )
        except subprocess.TimeoutExpired:
            send_call(f"Command timed out for line {line_number}")
            continue
        except Exception as exc:
            send_call(f"Execution failed for line {line_number}: {exc}")
            continue

        output_body = stdout.strip()
        if stderr:
            output_body += "
" + stderr.strip()

        print("Output:")
        if len(output_body.encode("utf-8")) > MAX_OUTPUT_BYTES:
            output_body = output_body[:MAX_OUTPUT_BYTES] + "
[output truncated]"
        print(output_body or "(no output)")

        if returncode != 0:
            send_call(
                f"Non-zero exit code {returncode} for line {line_number}"
            )

        try:
            input("Press Enter to continue...")
        except EOFError:
            break


if __name__ == "__main__":
    main()

import re
import logging
import secrets
import threading
from dataclasses import dataclass, field
from typing import List, Optional, Dict

import argon2
from argon2 import PasswordHasher

# Configure minimal logging (non-sensitive)
logger = logging.getLogger(__name__)
handler = logging.StreamHandler()
handler.setFormatter(logging.Formatter("[%(levelname)s] %(asctime)s %(message)s"))
logger.addHandler(handler)
logger.setLevel(logging.INFO)

ALLOWED_PERMISSIONS = {"read", "write", "delete", "admin"}
USERNAME_RE = re.compile(r"^[a-zA-Z0-9_]{3,30}$")
EMAIL_RE = re.compile(
    r"^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$"
)

# Password policy
MIN_PASSWORD_LENGTH = 8
MAX_PASSWORD_LENGTH = 128
MAX_EMAIL_LENGTH = 254

# Argon2 config
ph = PasswordHasher()

@dataclass
class User:
    user_id: str
    username: str
    email: str
    password_hash: str
    is_staff: bool = False
    permissions: List[str] = field(default_factory=list)

class UserStore:
    """In-memory user store. Replace with persistent storage in production."""
    _lock = threading.Lock()
    _users_by_username: Dict[str, User] = {}

    @classmethod
    def get(cls, username: str) -> Optional[User]:
        with cls._lock:
            return cls._users_by_username.get(username.lower())

    @classmethod
    def add(cls, user: User) -> None:
        with cls._lock:
            cls._users_by_username[user.username.lower()] = user

def validate_username(username: str) -> bool:
    return bool(USERNAME_RE.fullmatch(username))

def validate_email(email: str) -> bool:
    if len(email) > MAX_EMAIL_LENGTH:
        return False
    return bool(EMAIL_RE.fullmatch(email))

def sanitize_input(value: str) -> str:
    if value is None:
        raise ValueError("Input cannot be None")
    return value.strip()

def hash_password(password: str) -> str:
    return ph.hash(password)

def validate_permissions(perms: List[str]) -> List[str]:
    invalid = [p for p in perms if p not in ALLOWED_PERMISSIONS]
    if invalid:
        raise ValueError("Invalid permission(s) provided.")
    return perms

def create_user(
    username: str,
    email: str,
    password: str,
    is_staff: bool = False,
    permissions: Optional[List[str]] = None,
) -> User:
    """
    Create a new user or return an existing user.
    All inputs are validated and sanitized. Passwords are hashed using Argon2.
    """
    username = sanitize_input(username)
    email = sanitize_input(email)

    if not validate_username(username):
        raise ValueError("Invalid username. Must be 3-30 alphanumeric characters or underscores.")
    if not validate_email(email):
        raise ValueError("Invalid email address.")

    if permissions is None:
        permissions = []
    else:
        permissions = validate_permissions(permissions)

    if len(password) < MIN_PASSWORD_LENGTH or len(password) > MAX_PASSWORD_LENGTH:
        raise ValueError("Password must be between 8 and 128 characters.")

    existing = UserStore.get(username)
    if existing:
        return existing

    try:
        pwd_hash = hash_password(password)
    except Exception as exc:
        logger.exception("Password hashing failed.")
        raise ValueError("An internal error occurred.") from exc

    user = User(
        user_id=secrets.token_urlsafe(16),
        username=username,
        email=email,
        password_hash=pwd_hash,
        is_staff=is_staff,
        permissions=permissions,
    )

    try:
        UserStore.add(user)
    except Exception as exc:
        logger.exception("Failed to store user.")
        raise ValueError("An internal error occurred.") from exc

    del password
    return user

CREATE OR REPLACE FUNCTION test_table_operations(lock_name TEXT)
RETURNS INTEGER
LANGUAGE plpgsql
AS $$
DECLARE
    inserted_count INTEGER := 0;
BEGIN
    IF lock_name IS NULL OR lock_name !~ '^[A-Za-z0-9_]+$' THEN
        RAISE EXCEPTION 'OperationalError: invalid lock name';
    END IF;

    DROP TEMPORARY TABLE IF EXISTS temp_test_table;
    CREATE TEMPORARY TABLE temp_test_table (
        id   SERIAL PRIMARY KEY,
        name TEXT NOT NULL
    ) ON COMMIT DROP;

    INSERT INTO temp_test_table(name) VALUES ('Name1'), ('Name2');
    inserted_count := inserted_count + 2;

    PERFORM pg_advisory_xact_lock(hashtext(lock_name)::bigint);

    INSERT INTO temp_test_table(name) VALUES ('Name1');
    inserted_count := inserted_count + 1;

    RETURN inserted_count;
EXCEPTION
    WHEN OTHERS THEN
        RAISE;
END;
$$;

import os
import json
import warnings
from pathlib import Path
from typing import Any, Dict

def test_file_system_operations(base_dir: str) -> None:
    """
    Test creating, reading, and serializing a file system object securely.
    """
    if not isinstance(base_dir, str) or not base_dir:
        raise ValueError("Base directory must be a non-empty string.")

    # Resolve and validate base directory
    try:
        safe_base: Path = Path(base_dir).expanduser().resolve(strict=True)
    except Exception as exc:
        raise ValueError("Invalid or nonexistent base directory.") from exc

    # Ensure the base directory is within the current working directory
    cwd: Path = Path.cwd().resolve()
    try:
        base_within_cwd = safe_base.is_relative_to(cwd)  # type: ignore[attr-defined]
    except AttributeError:
        base_within_cwd = any(parent == cwd for parent in [safe_base] + list(safe_base.parents))
    if not base_within_cwd:
        raise PermissionError("Base directory must be within the current working directory.")

    # Create temporary subdirectory with secure permissions
    subdir: Path = safe_base / "tmp_test_dir"
    try:
        os.makedirs(str(subdir), mode=0o700, exist_ok=True)
    except Exception as exc:
        raise RuntimeError("Failed to create test subdirectory.") from exc

    # Create test file atomically with secure permissions
    test_file: Path = subdir / "test_file.txt"
    try:
        # Use O_CREAT | O_EXCL to avoid race conditions
        fd = os.open(str(test_file), os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write("Hello, world!")
    except FileExistsError:
        raise RuntimeError("Test file already exists.")
    except Exception as exc:
        raise RuntimeError("Failed to write test file.") from exc

    # Read back content
    try:
        content: str = test_file.read_text(encoding="utf-8")
    except Exception as exc:
        raise RuntimeError("Failed to read test file.") from exc

    if content != "Hello, world!":
        raise AssertionError("File content does not match expected value.")

    # Validate error handling for non-existent file
    non_existent: Path = subdir / "does_not_exist.txt"
    try:
        non_existent.read_text(encoding="utf-8")
    except FileNotFoundError:
        pass
    else:
        raise AssertionError("Expected FileNotFoundError was not raised.")

    # Build file system representation
    fs_obj: Dict[str, Any] = {
        "directory": str(subdir),
        "files": sorted(f.name for f in subdir.iterdir()),
        "content": content,
    }

    # Serialize with JSON
    try:
        pickled = json.dumps(fs_obj, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    except Exception as exc:
        raise RuntimeError("Serialization of file system object failed.") from exc

    # Deserialize
    try:
        unpickled = json.loads(pickled.decode("utf-8"))
    except Exception as exc:
        raise RuntimeError("Deserialization of file system object failed.") from exc

    if unpickled != fs_obj:
        raise AssertionError("Deserialized object does not match original.")

    # Clean up test artifacts
    try:
        test_file.unlink(missing_ok=True)
    except Exception as exc:
        warnings.warn(f"Failed to delete test file: {exc}")

    try:
        subdir.rmdir()
    except Exception as exc:
        warnings.warn(f"Failed to remove test directory: {exc}")

import os
import pathlib
import getpass
import keyring
from dataclasses import dataclass, field
from typing import Any, Dict, Optional, Union


class ConfigMock:
    def __init__(self, data: Dict[str, Any]) -> None:
        self._data = dict(data)

    def safe_get(
        self,
        key: str,
        default: Optional[Any] = None,
        *,
        expose_sensitive: bool = False,
    ) -> Any:
        if not isinstance(key, str):
            return default
        # Mask any unauthenticated access to auth fields
        if not expose_sensitive and key.startswith("auth"):
            return default
        try:
            if key == "auth.password":
                if expose_sensitive:
                    return keyring.get_password("vnx_cli", self._data["auth"]["username"])
                return default
            return self._data.get(key, default)
        except Exception:
            return default


def configure_vnx_cli(
    interval_seconds: int,
    naviseccli_path: str,
    username: str,
    password: str,
) -> ConfigMock:
    if not isinstance(interval_seconds, int) or interval_seconds <= 0:
        raise ValueError("interval_seconds must be a positive integer")

    path_obj = pathlib.Path(naviseccli_path)
    if not path_obj.is_absolute():
        raise ValueError("naviseccli_path must be an absolute path")
    resolved = path_obj.resolve(strict=True)
    trusted_dir = pathlib.Path("/usr/local/bin").resolve(strict=True)
    if not (resolved == trusted_dir or resolved.is_relative_to(trusted_dir)):
        raise ValueError("naviseccli_path must reside within /usr/local/bin")

    if not isinstance(username, str) or not username.strip():
        raise ValueError("username must be a non-empty string")
    if not isinstance(password, str) or not password:
        raise ValueError("password must be a non-empty string")

    keyring.set_password("vnx_cli", username, password)

    config_data: Dict[str, Any] = {
        "intervals": {
            "task_a": interval_seconds,
            "task_b": interval_seconds // 2,
            "task_c": interval_seconds * 2,
        },
        "naviseccli_path": str(resolved),
        "auth": {
            "username": username,
        },
    }

    return ConfigMock(config_data)


@dataclass(frozen=True)
class TestData:
    sample_id: int
    description: str
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        if not isinstance(self.sample_id, int):
            raise TypeError("sample_id must be an int")
        if not isinstance(self.description, str):
            raise TypeError("description must be a string")
        if not isinstance(self.metadata, dict):
            raise TypeError("metadata must be a dictionary")


if __name__ == "__main__":
    try:
        username = getpass.getuser()
        if not username:
            raise ValueError("Failed to determine current user")

        password = os.getenv("VNX_CLI_PASSWORD")
        if not password:
            try:
                password = getpass.getpass(prompt="Enter VNX CLI password: ")
            except Exception as e:
                raise ValueError("Password input failed") from e

        cfg = configure_vnx_cli(
            interval_seconds=300,
            naviseccli_path="/usr/local/bin/naviseccli",
            username=username,
            password=password,
        )
        test_instance = TestData(sample_id=1, description="Sample test data")
        print(cfg.safe_get("intervals", {}))
        print(test_instance)
    except ValueError as ve:
        print(f"Configuration error: {ve}")

package certutil

import (
	"errors"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"syscall"
)

const allowedRoot = "/etc/ssl"

var rootAbs, _ = filepath.Abs(allowedRoot)

// GetCombinedPEM accepts an OAuth HTTP request, extracts a certificate
// location from the "X-Cert-Location" header, and returns a combined
// PEM containing the certificate and private key.
//
// The header value must be a relative path under allowedRoot.
// The function looks for files named cert.pem and key.pem
// within that directory.
func GetCombinedPEM(req *http.Request) ([]byte, error) {
	if req == nil {
		return nil, errors.New("request is nil")
	}

	location := req.Header.Get("X-Cert-Location")
	if location == "" {
		return nil, errors.New("missing X-Cert-Location header")
	}

	if filepath.IsAbs(location) {
		return nil, errors.New("absolute paths not allowed")
	}

	cleaned := filepath.Clean(location)
	if strings.Contains(cleaned, "..") {
		return nil, errors.New("path traversal detected")
	}

	baseDir := filepath.Join(allowedRoot, cleaned)
	baseDirAbs, err := filepath.Abs(baseDir)
	if err != nil {
		log.Println("failed to resolve absolute path")
		return nil, errors.New("unable to read certificate")
	}

	resolvedBase, err := filepath.EvalSymlinks(baseDirAbs)
	if err != nil {
		log.Println("failed to evaluate symlinks")
		return nil, errors.New("unable to read certificate")
	}

	// Ensure resolvedBase is inside rootAbs
	if resolvedBase != rootAbs {
		if !strings.HasPrefix(resolvedBase, rootAbs+string(filepath.Separator)) {
			log.Println("path is outside allowed root")
			return nil, errors.New("unable to read certificate")
		}
	}

	info, err := os.Stat(resolvedBase)
	if err != nil || !info.IsDir() {
		log.Println("certificate path is not a directory")
		return nil, errors.New("unable to read certificate")
	}

	certPath := filepath.Join(resolvedBase, "cert.pem")
	keyPath := filepath.Join(resolvedBase, "key.pem")

	certFile, err := os.OpenFile(certPath, os.O_RDONLY|syscall.O_NOFOLLOW, 0)
	if err != nil {
		log.Println("failed to open certificate file")
		return nil, errors.New("unable to read certificate")
	}
	defer certFile.Close()

	certInfo, err := certFile.Stat()
	if err != nil || !certInfo.Mode().IsRegular() {
		log.Println("invalid certificate file")
		return nil, errors.New("unable to read certificate")
	}
	certPEM, err := io.ReadAll(certFile)
	if err != nil {
		log.Println("failed to read certificate file")
		return nil, errors.New("unable to read certificate")
	}

	keyFile, err := os.OpenFile(keyPath, os.O_RDONLY|syscall.O_NOFOLLOW, 0)
	if err != nil {
		log.Println("failed to open key file")
		return nil, errors.New("unable to read certificate")
	}
	defer keyFile.Close()

	keyInfo, err := keyFile.Stat()
	if err != nil || !keyInfo.Mode().IsRegular() {
		log.Println("invalid key file")
		return nil, errors.New("unable to read certificate")
	}
	keyPEM, err := io.ReadAll(keyFile)
	if err != nil {
		log.Println("failed to read key file")
		return nil, errors.New("unable to read certificate")
	}

	combined := make([]byte, 0, len(certPEM)+len(keyPEM)+1)
	combined = append(combined, certPEM...)
	combined = append(combined, '
')
	combined = append(combined, keyPEM...)

	return combined, nil
}

// CertHandler is an example HTTP handler that returns the combined PEM.
// The handler should be protected with proper authentication.
func CertHandler(w http.ResponseWriter, r *http.Request) {
	combinedPEM, err := GetCombinedPEM(r)
	if err != nil {
		http.Error(w, "Failed to retrieve certificate", http.StatusBadRequest)
		return
	}

	w.Header().Set("Content-Type", "application/pem-file")
	if _, err := w.Write(combinedPEM); err != nil {
		http.Error(w, "Failed to write response", http.StatusInternalServerError)
	}
}

import os
import shutil
import subprocess

def get_process_command(pid):
    """
    Return the command line of a process identified by the given PID.
    Raises ValueError for invalid input and RuntimeError for execution failures.
    """
    # Normalize bytes to string
    if isinstance(pid, bytes):
        try:
            pid = pid.decode()
        except Exception as exc:
            raise ValueError("PID must be a string or integer.") from exc

    # Ensure input is string or integer
    if not isinstance(pid, (str, int)):
        raise ValueError("PID must be a string or integer.")

    # Convert to integer, validate non-negative
    try:
        int_pid = int(pid)
    except Exception as exc:
        raise ValueError("PID must be an integer.") from exc

    if int_pid < 0:
        raise ValueError("PID must be non-negative.")

    # Resolve absolute path to 'ps' to avoid shell injection via PATH
    ps_executable = shutil.which("ps")
    if not ps_executable:
        raise RuntimeError("Required 'ps' command is not available.")
    ps_path = os.path.abspath(ps_executable)

    command = [ps_path, "-p", str(int_pid), "-o", "cmd="]

    try:
        completed = subprocess.run(
            command,
            capture_output=True,
            text=True,
            check=True,
            timeout=5,
            stdin=subprocess.DEVNULL,
        )
        cmd_line = completed.stdout.strip()
    except FileNotFoundError as exc:
        raise RuntimeError("Required 'ps' command is not available.") from exc
    except subprocess.TimeoutExpired as exc:
        raise RuntimeError("Retrieving process command timed out.") from exc
    except subprocess.CalledProcessError as exc:
        if exc.returncode == 1:
            raise RuntimeError(f"No process found with PID {int_pid}.") from exc
        raise RuntimeError("Failed to retrieve process command.") from exc
    except Exception as exc:
        raise RuntimeError(
            "An unexpected error occurred while retrieving the process command."
        ) from exc

    if not cmd_line:
        raise RuntimeError(f"No process found with PID {int_pid}.")
    return cmd_line

import re
import ast
import operator

MAX_TEMPLATE_SIZE = 10_000
MAX_EXPRESSION_NODES = 20
MAX_RESULT_SIZE = 10_000
MAX_EXPONENT = 1_000
MAX_MULTIPLIER = 1_000

ALLOWED_BUILTINS = {
    "str": str,
    "int": int,
    "float": float,
    "len": len,
}

BINARY_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
}
UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Not: operator.not_,
}

class ExpressionValidator(ast.NodeVisitor):
    ALLOWED_NODES = (
        ast.Expression,
        ast.BinOp,
        ast.UnaryOp,
        ast.Call,
        ast.Name,
        ast.Constant,
        ast.arg,
    )
    ALLOWED_OPERATORS = (
        ast.Add,
        ast.Sub,
        ast.Mult,
        ast.Div,
        ast.Mod,
        ast.Pow,
        ast.UAdd,
        ast.USub,
        ast.Not,
    )
    ALLOWED_NAMES = {"_n", "str", "int", "float", "len"}

    def __init__(self):
        self.node_count = 0

    def generic_visit(self, node):
        if not isinstance(node, self.ALLOWED_NODES):
            raise ValueError(f"Disallowed syntax: {type(node).__name__}")
        self.node_count += 1
        if self.node_count > MAX_EXPRESSION_NODES:
            raise ValueError("Expression too complex")
        super().generic_visit(node)

    def visit_Name(self, node):
        if node.id not in self.ALLOWED_NAMES:
            raise ValueError(f"Unallowed name: {node.id}")

    def visit_Call(self, node):
        if not isinstance(node.func, ast.Name):
            raise ValueError("Only simple function calls allowed")
        if node.func.id not in self.ALLOWED_NAMES:
            raise ValueError(f"Unallowed function: {node.func.id}")

def _check_result_within_limit(value, context=""):
    if isinstance(value, int):
        if len(str(abs(value))) > MAX_RESULT_SIZE:
            raise ValueError(f"Intermediate numeric result too large {context}")
    elif isinstance(value, float):
        if len(repr(value)) > MAX_RESULT_SIZE:
            raise ValueError(f"Intermediate float result too large {context}")
    elif isinstance(value, str):
        if len(value) > MAX_RESULT_SIZE:
            raise ValueError(f"Intermediate string result too large {context}")
    return value

def _safe_eval(node, local_vars):
    if isinstance(node, ast.Expression):
        return _safe_eval(node.body, local_vars)
    if isinstance(node, ast.Constant):
        return _check_result_within_limit(node.value)
    if isinstance(node, ast.Name):
        if node.id == "_n":
            return _check_result_within_limit(local_vars["_n"])
        raise ValueError(f"Unhandled name: {node.id}")
    if isinstance(node, ast.BinOp):
        left = _safe_eval(node.left, local_vars)
        right = _safe_eval(node.right, local_vars)
        op_type = type(node.op)
        if op_type is ast.Pow:
            if isinstance(right, int) and abs(right) > MAX_EXPONENT:
                raise ValueError("Exponent too large")
        if op_type is ast.Mult:
            # Handle string replication bounds
            if isinstance(left, str) and isinstance(right, int):
                if right < 0 or right > MAX_MULTIPLIER:
                    raise ValueError("Multiplier too large")
                if len(left) * right > MAX_RESULT_SIZE:
                    raise ValueError("String multiplication would exceed size limit")
            elif isinstance(right, str) and isinstance(left, int):
                if left < 0 or left > MAX_MULTIPLIER:
                    raise ValueError("Multiplier too large")
                if len(right) * left > MAX_RESULT_SIZE:
                    raise ValueError("String multiplication would exceed size limit")
        op_func = BINARY_OPS.get(op_type)
        if op_func is None:
            raise ValueError(f"Unsupported binary operator: {op_type.__name__}")
        result = op_func(left, right)
        return _check_result_within_limit(result, context="BinOp")
    if isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand, local_vars)
        op_func = UNARY_OPS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        return _check_result_within_limit(op_func(operand), context="UnaryOp")
    if isinstance(node, ast.Call):
        func_name = node.func.id
        func = ALLOWED_BUILTINS.get(func_name)
        if func is None:
            raise ValueError(f"Unsupported function: {func_name}")
        args = [_safe_eval(arg, local_vars) for arg in node.args]
        return _check_result_within_limit(func(*args), context="Call")
    raise ValueError(f"Unsupported expression node: {type(node).__name__}")

def compile_template(template: str):
    if not isinstance(template, str):
        raise TypeError("Template must be a string")
    if len(template) > MAX_TEMPLATE_SIZE:
        raise ValueError("Template size exceeds limit")

    token_re = re.compile(r"({{.*?}})", re.S)
    raw_tokens = token_re.split(template)

    parts = []
    for token in raw_tokens:
        if token.startswith("{{") and token.endswith("}}"):
            expr = token[2:-2].strip()
            if not expr:
                raise ValueError("Empty expression in template")
            try:
                expr_ast = ast.parse(expr, mode="eval")
            except SyntaxError as exc:
                raise ValueError(f"Invalid syntax in expression: {exc}") from exc
            validator = ExpressionValidator()
            validator.visit(expr_ast)
            parts.append(("expr", expr_ast))
        else:
            parts.append(("lit", token))

    def template_fn(_n):
        if not isinstance(_n, (int, float, str)):
            raise TypeError("_n must be int, float, or str")
        local_vars = {"_n": _n}
        result_parts = []
        accumulated_length = 0
        for typ, val in parts:
            if typ == "lit":
                part = val
            else:
                try:
                    result = _safe_eval(val, local_vars)
                except Exception as exc:
                    raise ValueError("Failed to evaluate template expression") from exc
                part = str(result)
            part_length = len(part)
            if accumulated_length + part_length > MAX_RESULT_SIZE:
                raise ValueError("Result size exceeds limit")
            accumulated_length += part_length
            result_parts.append(part)
        return "".join(result_parts)

    return template_fn

