import ast
import logging
import multiprocessing
import os
import re
import resource
import operator
from typing import Any, Dict, List, Tuple, Union

logging.basicConfig(level=logging.INFO, format="%(levelname)s: %(message)s")
logger = logging.getLogger(__name__)

_ALLOWED_PRIMITIVES = (int, float, str, bool, type(None))
_ALLOWED_BUILTINS = {
    "len": len,
    "range": range,
    "int": int,
    "float": float,
    "str": str,
    "bool": bool,
    "dict": dict,
    "list": list,
    "sum": sum,
    "sorted": sorted,
    "abs": abs,
    "min": min,
    "max": max,
}
_ALLOWED_AST_NODE_TYPES = {
    ast.Module,
    ast.Assign,
    ast.Expr,
    ast.Name,
    ast.Constant,
    ast.BinOp,
    ast.UnaryOp,
    ast.Call,
    ast.Load,
    ast.Store,
}
_ALLOWED_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.FloorDiv: operator.floordiv,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
    ast.MatMult: operator.matmul,
}
_SCRIPT_CHAR_PATTERN = re.compile(r"^[ -~]+$")

def _validate_experiment_definitions(defs: Any) -> List[str]:
    if not isinstance(defs, list):
        raise ValueError("Experiment definitions must be a list.")
    safe_defs = []
    for idx, item in enumerate(defs):
        if not isinstance(item, str):
            raise ValueError(f"Experiment definition at index {idx} is not a string.")
        if not _SCRIPT_CHAR_PATTERN.fullmatch(item):
            raise ValueError(f"Experiment definition at index {idx} contains unsafe characters.")
        safe_defs.append(item)
    return safe_defs

def _recursive_validate(obj: Any, path: str = "") -> None:
    if isinstance(obj, _ALLOWED_PRIMITIVES):
        return
    if isinstance(obj, dict):
        for k, v in obj.items():
            _recursive_validate(k, f"{path}[dict_key]")
            _recursive_validate(v, f"{path}[{k}]")
        return
    if isinstance(obj, (list, tuple)):
        for idx, v in enumerate(obj):
            _recursive_validate(v, f"{path}[{idx}]")
        return
    raise ValueError(f"Unsupported data type at {path}: {type(obj).__name__}")

def _validate_input_data(data: Any) -> Any:
    if not isinstance(data, (list, tuple)):
        raise ValueError("Input data must be a list or tuple.")
    _recursive_validate(data)
    return data

def dev_func(data: List[Any]) -> Dict[str, Any]:
    result = {"dev_count": {}, "dev_total": len(data)}
    for item in data:
        key = str(item)
        result["dev_count"][key] = result["dev_count"].get(key, 0) + 1
    return result

def _eval_node(node: ast.AST, local_ns: Dict[str, Any]) -> Any:
    if isinstance(node, ast.Constant):
        return node.value
    if isinstance(node, ast.Name):
        if node.id in _ALLOWED_BUILTINS:
            return _ALLOWED_BUILTINS[node.id]
        if node.id in local_ns:
            return local_ns[node.id]
        raise ValueError(f"Name '{node.id}' is not defined.")
    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left, local_ns)
        right = _eval_node(node.right, local_ns)
        op_func = _ALLOWED_OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Operator {type(node.op).__name__} not allowed.")
        return op_func(left, right)
    if isinstance(node, ast.UnaryOp):
        operand = _eval_node(node.operand, local_ns)
        op_func = _ALLOWED_OPERATORS.get(type(node.op))
        if op_func is None:
            raise ValueError(f"Unary operator {type(node.op).__name__} not allowed.")
        return op_func(operand)
    if isinstance(node, ast.Call):
        if not isinstance(node.func, ast.Name):
            raise ValueError("Only simple function calls are allowed.")
        func_name = node.func.id
        if func_name not in _ALLOWED_BUILTINS:
            raise ValueError(f"Function '{func_name}' is not allowed.")
        func = _ALLOWED_BUILTINS[func_name]
        args = [_eval_node(arg, local_ns) for arg in node.args]
        return func(*args)
    raise ValueError(f"Disallowed expression: {ast.dump(node)}")

def _validate_and_compile_script(script: str) -> ast.Module:
    try:
        tree = ast.parse(script, mode="exec")
    except SyntaxError as e:
        raise ValueError(f"Syntax error in script: {e}") from None
    for node in ast.walk(tree):
        if not isinstance(node, tuple(_ALLOWED_AST_NODE_TYPES)):
            raise ValueError(f"Disallowed construct: {type(node).__name__}")
    return tree

def _execute_script(tree: ast.Module, return_dict: multiprocessing.managers.DictProxy) -> None:
    try:
        resource.setrlimit(resource.RLIMIT_CPU, (2, 2))
        resource.setrlimit(resource.RLIMIT_AS, (256 * 1024 * 1024, 256 * 1024 * 1024))
        local_ns: Dict[str, Any] = {}
        for stmt in tree.body:
            if isinstance(stmt, ast.Assign):
                if len(stmt.targets) != 1 or not isinstance(stmt.targets[0], ast.Name):
                    raise ValueError("Only simple variable assignments are allowed.")
                value = _eval_node(stmt.value, local_ns)
                local_ns[stmt.targets[0].id] = value
            elif isinstance(stmt, ast.Expr):
                _eval_node(stmt.value, local_ns)
            else:
                raise ValueError(f"Unsupported statement type: {type(stmt).__name__}")
        clean_dict = {k: v for k, v in local_ns.items() if isinstance(v, _ALLOWED_PRIMITIVES)}
        return_dict.update(clean_dict)
    except Exception as exc:
        return_dict["error"] = str(exc)

def _run_script_with_timeout(tree: ast.Module, timeout_sec: float = 2.0) -> Tuple[Dict[str, Any], Union[Exception, None]]:
    manager = multiprocessing.Manager()
    return_dict = manager.dict()
    process = multiprocessing.Process(target=_execute_script, args=(tree, return_dict))
    process.start()
    process.join(timeout=timeout_sec)
    if process.is_alive():
        process.terminate()
        process.join()
        return {}, TimeoutError("Script execution timed out.")
    if process.exitcode != 0:
        return {}, RuntimeError(f"Worker exited with code {process.exitcode}")
    if "error" in return_dict:
        return {}, Exception(return_dict["error"])
    return dict(return_dict), None

def run_experiments(exp_defs: Any, input_data: Any) -> Dict[str, Any]:
    try:
        safe_defs = _validate_experiment_definitions(exp_defs)
        safe_data = _validate_input_data(input_data)
    except Exception as exc:
        logger.error(f"Input validation failed: {exc}")
        return {}
    combined_locals: Dict[str, Any] = {}
    for idx, script in enumerate(safe_defs):
        try:
            tree = _validate_and_compile_script(script)
            locals_dict, error = _run_script_with_timeout(tree, timeout_sec=2.0)
            if error:
                logger.warning(f"Experiment {idx} execution failed: {error}")
                continue
            combined_locals.update(locals_dict)
        except Exception as exc:
            logger.warning(f"Experiment {idx} execution failed: {exc}")
            continue
    return combined_locals

import json
import os
import re
import logging
import hmac
import hashlib
import ipaddress
from typing import Any, Dict

logging.basicConfig(level=logging.INFO, format="%(levelname)s:%(message)s")

class ConfigurationError(Exception):
    """Raised when configuration validation fails."""
    pass

class Config:
    host: str = ""
    port: int = 0
    languages: list[str] = []
    encryption_key: str = ""
    db_host: str = ""
    db_name: str = ""
    db_user: str = ""
    db_password: str = ""

    @classmethod
    def load(cls, file_path: str) -> None:
        if not isinstance(file_path, str):
            raise ConfigurationError("Configuration file path must be a string.")
        if len(file_path) > 4096:
            raise ConfigurationError("Configuration file path exceeds maximum length.")
        file_path = os.path.realpath(file_path)
        if not os.path.isfile(file_path):
            raise ConfigurationError("Configuration file not found.")
        try:
            with open(file_path, "r", encoding="utf-8") as fh:
                raw = fh.read()
        except OSError as e:
            raise ConfigurationError("Failed to read configuration file.") from e
        try:
            data: Dict[str, Any] = json.loads(raw)
        except json.JSONDecodeError as e:
            raise ConfigurationError("Configuration file contains invalid JSON.") from e

        # Optional integrity verification if secret is available
        hmac_secret = os.getenv("CONFIG_HMAC_SECRET")
        if hmac_secret and isinstance(hmac_secret, str):
            file_hmac = data.pop("hmac", None)
            if not file_hmac:
                raise ConfigurationError("Missing HMAC in configuration.")
            computed = hmac.new(
                hmac_secret.encode(), raw.encode(), hashlib.sha256
            ).hexdigest()
            if not hmac.compare_digest(file_hmac, computed):
                raise ConfigurationError("Configuration file integrity check failed.")
        elif hmac_secret:
            raise ConfigurationError("HMAC secret must be a string.")

        # Retrieve encryption key from environment
        env_key = os.getenv("ENCRYPTION_KEY")
        if not env_key or not isinstance(env_key, str):
            raise ConfigurationError("Encryption key not provided via environment.")
        if not re.fullmatch(r"[a-fA-F0-9]{64}", env_key):
            raise ConfigurationError("Encryption key must be 64 hex characters.")
        cls.encryption_key = env_key

        # Validators
        host_pattern = re.compile(
            r"^(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)+"
            r"[A-Za-z]{2,}$|^(?:[1-9]\d?|1\d\d|2[0-4]\d|25[0-5])(?:\."
            r"(?:[1-9]\d?|1\d\d|2[0-4]\d|25[0-5])){3}$"
        )
        non_empty_pattern = re.compile(r"^[A-Za-z0-9_.-]+$")

        def validate_host(value: Any) -> bool:
            if not isinstance(value, str):
                return False
            try:
                ipaddress.ip_address(value)
                return True
            except ValueError:
                return bool(host_pattern.fullmatch(value))

        def validate_port(value: Any) -> bool:
            return isinstance(value, int) and 1 <= value <= 65535

        def validate_languages(value: Any) -> bool:
            if not isinstance(value, list):
                return False
            return all(isinstance(item, str) and item.isalpha() and len(item) <= 10 for item in value)

        def validate_non_empty_string(value: Any) -> bool:
            return isinstance(value, str) and bool(non_empty_pattern.fullmatch(value.strip()))

        required_fields = {
            "host": validate_host,
            "port": validate_port,
            "languages": validate_languages,
            "db_host": validate_non_empty_string,
            "db_name": validate_non_empty_string,
            "db_user": validate_non_empty_string,
            "db_password": validate_non_empty_string,
        }

        for key, validator in required_fields.items():
            if key not in data:
                raise ConfigurationError("Missing required configuration field.")
            if not validator(data[key]):
                raise ConfigurationError("Invalid value for configuration field.")

        cls.host = data["host"]
        cls.port = data["port"]
        cls.languages = data["languages"]
        cls.db_host = data["db_host"]
        cls.db_name = data["db_name"]
        cls.db_user = data["db_user"]
        # Keep database password plain only during authentication; do not transform
        cls.db_password = data["db_password"]

        logging.info("Configuration loaded and validated successfully.")

