_LOCK_TTL_SECONDS = 10.0  # Maximum time to consider a lock stale


def _validate_input(filename: str, key: str, value: Union[int, float], callback: Callable[[float], Any]) -> None:
    if not isinstance(filename, str) or not filename:
        raise TypeError("filename must be a non-empty string")
    if pathlib.Path(filename).is_absolute():
        raise ValueError("absolute paths are not allowed for the store file")
    if any(part in (".", "..") for part in pathlib.Path(filename).parts):
        raise ValueError("filename cannot contain '.' or '..' segments")
    if not isinstance(key, str) or not key:
        raise TypeError("key must be a non-empty string")
    if not isinstance(value, (int, float)):
        raise TypeError("value must be a number (int or float)")
    if not callable(callback):
        raise TypeError("callback must be callable")


def _resolve_path(filename: str) -> pathlib.Path:
    base_dir = pathlib.Path.cwd().resolve()
    full_path = pathlib.Path(filename).resolve()
    if not str(full_path).startswith(str(base_dir)):
        raise ValueError("path traversal detected")
    return full_path


def _acquire_lock(lock_path: pathlib.Path) -> int:
    pid = os.getpid()
    now = time.time()
    try:
        fd = os.open(lock_path, os.O_CREAT | os.O_EXCL | os.O_RDWR)
        with os.fdopen(fd, "wb") as f:
            f.write(f"{pid}:{now}".encode("utf-8"))
        return fd
    except FileExistsError:
        # Lock file already exists â examine it
        try:
            with lock_path.open("rb") as f:
                content = f.read().decode("utf-8").strip()
            lock_pid_str, lock_time_str = content.split(":", 1)
            lock_time = float(lock_time_str)
            if now - lock_time > _LOCK_TTL_SECONDS:
                logger.debug("Stale lock detected at %s. Removing.", lock_path)
                lock_path.unlink(missing_ok=True)
                return _acquire_lock(lock_path)
        except (ValueError, UnicodeDecodeError, FileNotFoundError) as e:
            # Corrupted or vanished lock â remove and retry
            logger.debug("Corrupted or missing lock file %s: %s", lock_path, e)
            lock_path.unlink(missing_ok=True)
            return _acquire_lock(lock_path)
        except Exception:
            logger.exception("Unexpected error when accessing lock file %s", lock_path)
            raise RuntimeError("Store is already locked by another process") from None
        raise RuntimeError("Store is already locked by another process")


def _release_lock(fd: int, lock_path: pathlib.Path) -> None:
    try:
        os.close(fd)
    finally:
        lock_path.unlink(missing_ok=True)


def _atomic_write(data: dict, path: pathlib.Path) -> None:
    tmp_path = path.with_suffix(path.suffix + ".tmp")
    with tmp_path.open("w", encoding="utf-8") as f:
        json.dump(data, f, separators=(",", ":"))
        f.flush()
        os.fsync(f.fileno())
    os.replace(tmp_path, path)


