        def delayed_call() -> None:
            try:
                callback(total)
            except Exception as exc:  # pragma: no cover
                logger.exception("Callback raised an exception: %s", exc)

        timer = threading.Timer(3.0, delayed_call)
        timer.daemon = True
        timer.start()
    except Exception:
        logger.exception("Failed to store key-value pair")
        raise
    finally:
        if lock_fd is not None:
            _release_lock(lock_fd, lock_path)

