class CustomRewardWrapper(gym.Wrapper):
    """Wraps a gym environment and modifies the reward based on provided parameters.
    Expected parameters: 'scale' and 'offset' (numeric)."""

    def __init__(self, env: gym.Env, params: Dict[str, Any]) -> None:
        super().__init__(env)
        self.scale = self._validate_numeric(params.get("scale", 1.0), "scale")
        self.offset = self._validate_numeric(params.get("offset", 0.0), "offset")

    @staticmethod
    def _validate_numeric(value: Any, name: str) -> float:
        try:
            val = float(value)
        except (ValueError, TypeError):
            raise ValueError(f"Invalid numeric value for {name}: {value}")
        if not (-float("inf") < val < float("inf")):
            raise ValueError(f"Numeric value for {name} is not finite: {value}")
        return val

    def step(self, action: Any):
        observation, reward, terminated, truncated, info = self.env.step(action)
        modified_reward = self.scale * reward + self.offset
        return observation, modified_reward, terminated, truncated, info


