import sqlite3
import re
import pathlib
import logging
import sys
import os

# Configure minimal logging for errors
logging.basicConfig(
    filename='app.log',
    level=logging.ERROR,
    format='%(asctime)s %(levelname)s:%(message)s'
)

# Allowed SQLite data types
ALLOWED_TYPES = {"TEXT", "INTEGER", "REAL", "BLOB", "NUMERIC"}

def get_input(prompt: str) -> str:
    try:
        return input(prompt)
    except EOFError:
        print("
Input terminated. Exiting.")
        sys.exit(1)

def sanitize_db_path(path_str: str) -> pathlib.Path:
    path = pathlib.Path(path_str).expanduser().resolve()
    cwd = pathlib.Path.cwd().resolve()
    try:
        if not path.is_relative_to(cwd):
            raise ValueError
    except AttributeError:
        try:
            path.relative_to(cwd)
        except Exception:
            raise ValueError("Database path must be within the current working directory.")
    if path.suffix != '.db':
        raise ValueError("Database file must have a .db extension.")
    return path

def sanitize_identifier(name: str) -> str:
    if not re.fullmatch(r'\w+', name):
        raise ValueError(f"Invalid identifier: {name}")
    return name

def parse_columns(col_str: str):
    columns = []
    parts = [p.strip() for p in col_str.split(',')]
    for part in parts:
        if not part:
            continue
        tokens = part.split()
        if len(tokens) != 2:
            raise ValueError(f"Column definition must be 'name type': {part}")
        name, col_type = tokens
        name = sanitize_identifier(name)
        col_type = col_type.upper()
        if col_type not in ALLOWED_TYPES:
            raise ValueError(f"Unsupported column type: {col_type}")
        columns.append((name, col_type))
    if not columns:
        raise ValueError("At least one column must be defined.")
    return columns

def quote_identifier(name: str) -> str:
    return f'"{name}"'

def create_table(cursor, table_name: str, columns):
    cols_sql = ", ".join([f"{quote_identifier(name)} {col_type}" for name, col_type in columns])
    sql = f"CREATE TABLE IF NOT EXISTS {quote_identifier(table_name)} ({cols_sql});"
    cursor.execute(sql)

def insert_record(cursor, table_name: str, columns, values):
    placeholders = ", ".join(["?"] * len(values))
    col_names = ", ".join([quote_identifier(name) for name, _ in columns])
    sql = f"INSERT INTO {quote_identifier(table_name)} ({col_names}) VALUES ({placeholders});"
    cursor.execute(sql, values)

def main():
    try:
        db_path_input = get_input("Enter the database file name (with .db extension): ").strip()
        db_path = sanitize_db_path(db_path_input)

        table_name = get_input("Enter the table name: ").strip()
        table_name = sanitize_identifier(table_name)

        col_str = get_input("Enter column definitions (e.g., 'name TEXT, age INTEGER'): ").strip()
        columns = parse_columns(col_str)

        with sqlite3.connect(str(db_path)) as conn:
            cursor = conn.cursor()
            create_table(cursor, table_name, columns)

            values_input = get_input(
                f"Enter values for each column separated by commas ({', '.join(name for name, _ in columns)}): "
            ).strip()
            values = [v.strip() for v in values_input.split(',')]
            if len(values) != len(columns):
                raise ValueError("Number of values does not match number of columns.")

            insert_record(cursor, table_name, columns, values)
            conn.commit()
            print("Record inserted successfully.")
    except Exception:
        logging.exception("An unexpected error occurred.")
        print("An error occurred. Please check the logs for details.")

if __name__ == "__main__":
    main()

import inspect
import types
import functools
import logging
from typing import Any

def secure_modify_setters(target_obj: Any) -> Any:
    """
    Find pairs of Get/Set methods on *target_obj* and replace each Set method
    with a wrapper that first retrieves the current value using the matching
    Get method. The wrapper preserves the original method signature and
    updates the corresponding attribute on the object.
    """
    if target_obj is None:
        raise ValueError("Target object must not be None")

    if not hasattr(target_obj, "__dict__"):
        raise TypeError("Target must be an instance with a mutable __dict__")

    logger = logging.getLogger(__name__)

    try:
        get_methods = {}
        for name in dir(target_obj):
            if not name.startswith("Get"):
                continue
            attr = getattr(target_obj, name)
            if not callable(attr):
                continue
            # Use the part after 'Get' as the key, preserving case
            suffix = name[3:]  # e.g., 'Name' from 'GetName'
            get_methods[suffix] = name

        for suffix, get_name in get_methods.items():
            set_name = f"Set{suffix}"
            if not hasattr(target_obj, set_name):
                continue

            original_set = getattr(target_obj, set_name)
            if not callable(original_set):
                continue

            # Create a wrapper that preserves the original method's signature
            @functools.wraps(original_set)
            def wrapper(self, *args: Any, _original=original_set, _get_name=get_name, **kwargs: Any):
                try:
                    current_value = getattr(self, _get_name)(*args, **kwargs)
                except Exception as exc:
                    logger.warning(
                        "Failed to retrieve current value via '%s': %s",
                        _get_name,
                        exc,
                    )
                    raise

                attr_name = _get_name[3:]  # e.g., 'Name'
                # Attempt to call the original set logic
                try:
                    result = _original(*args, **kwargs)
                except Exception as exc:
                    logger.warning(
                        "Original set method '%s' failed: %s",
                        _original.__name__,
                        exc,
                    )
                    raise

                # Write the new value back to the attribute if it exists
                try:
                    if attr_name in self.__dict__ or hasattr(self.__class__, attr_name):
                        setattr(self, attr_name, args[0] if args else None)
                except Exception as exc:
                    logger.warning("Failed to set attribute '%s': %s", attr_name, exc)
                    raise

                return result

            # Bind the wrapper to the instance so that 'self' refers to target_obj
            bound_set = types.MethodType(wrapper, target_obj)
            setattr(target_obj, set_name, bound_set)

    except Exception as error:
        logger.error("Failed to modify setter methods securely: %s", error)
        raise RuntimeError("Failed to modify setter methods securely") from None

    return target_obj

