import argparse
import configparser
import logging
import os
import re
from typing import Any, Callable, Dict, List

# Configure logging
logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s %(levelname)s [%(name)s] %(message)s",
    datefmt="%Y-%m-%d %H:%M:%S",
)
logger = logging.getLogger(__name__)

# Debug flag to expose handler exceptions
_DEBUG_ENABLED = os.getenv("APP_CONFIG_DEBUG", "0") == "1"

# Global configuration dictionary and auxiliary data
_config: Dict[str, Any] = {}
_cli_config: Dict[str, Any] = {}
_source_map: Dict[str, str] = {}

# List of handler callbacks to broadcast configuration items
_handlers: List[Callable[[str, Any], None]] = []

# Regular expression for valid configuration keys
_valid_key_pattern = re.compile(r"^[A-Za-z0-9_]+$")

def _sanitize_key(key: str) -> str:
    """Validate and sanitize a configuration key."""
    if not isinstance(key, str):
        raise TypeError("Configuration key must be a string")
    key = key.strip()
    if not _valid_key_pattern.match(key):
        raise ValueError(f"Invalid configuration key: '{key}'")
    return key

def _sanitize_file_path(file_path: str) -> str:
    """Ensure the configuration file resides within the prescribed directory and has a safe extension."""
    base_dir = os.path.abspath(os.path.join(os.path.dirname(__file__), "config"))
    abs_path = os.path.abspath(file_path)
    if not abs_path.startswith(base_dir):
        raise ValueError(f"Unauthorized config file path: {abs_path}")
    if not abs_path.endswith(".ini"):
        raise ValueError(f"Unsupported configuration file extension: {abs_path}")
    if not os.path.isfile(abs_path):
        raise FileNotFoundError(f"Configuration file does not exist: {abs_path}")
    return abs_path

def _load_from_cli() -> Dict[str, Any]:
    """Load configuration from command-line arguments."""
    parser = argparse.ArgumentParser(add_help=False)
    known_args, unknown_args = parser.parse_known_args()
    cli_config: Dict[str, Any] = {}
    for arg in unknown_args:
        if arg.startswith("--") and "=" in arg:
            key, val = arg[2:].split("=", 1)
            try:
                key_clean = _sanitize_key(key)
                cli_config[key_clean] = val
            except Exception:
                logger.info(f"Skipping invalid CLI argument '{arg}'")
    return cli_config

def _load_from_file(file_path: str) -> Dict[str, Any]:
    """Load configuration from an INI-style file securely."""
    try:
        safe_path = _sanitize_file_path(file_path)
    except Exception as e:
        logger.warning(f"Invalid config file path '{file_path}': {e}")
        return {}

    parser = configparser.ConfigParser()
    try:
        parser.read(safe_path)
    except configparser.Error as e:
        logger.warning(f"Error reading configuration file '{safe_path}': {e}")
        return {}

    file_config: Dict[str, Any] = {}
    for section in parser.sections():
        for key, val in parser.items(section):
            try:
                key_clean = _sanitize_key(key)
                file_config[key_clean] = val
            except Exception as e:
                logger.info(f"Skipping invalid key '{key}' in section '{section}': {e}")
    return file_config

def _initialize_config() -> None:
    """Populate the global configuration dictionary from CLI and file."""
    global _config, _cli_config, _source_map
    if _config:
        return  # Already initialized

    config_file = os.getenv("APP_CONFIG_FILE", "app.ini")
    file_config = _load_from_file(config_file)
    _cli_config = _load_from_cli()

    # Merge configurations: CLI overrides file
    merged = {**file_config, **_cli_config}
    _config.update(merged)

    # Build source map for logging
    for key in merged:
        _source_map[key] = "CLI" if key in _cli_config else "File"

def register_handler(handler: Callable[[str, Any], None]) -> None:
    """Register a callback to receive configuration items."""
    if not callable(handler):
        raise TypeError("Handler must be callable")
    _handlers.append(handler)

def _broadcast(name: str, value: Any) -> None:
    for handler in _handlers:
        try:
            handler(name, value)
        except Exception as e:
            if _DEBUG_ENABLED:
                logger.warning(f"Handler raised exception for '{name}'", exc_info=True)
            else:
                logger.warning(f"Handler raised exception for '{name}'")

def get_config_item(name: str) -> Any:
    """
    Retrieve a configuration item by name.

    Returns the value if present, otherwise raises KeyError.
    Logs a warning and broadcasts the item to registered handlers.
    """
    if not _config:
        _initialize_config()
    key_clean = _sanitize_key(name)
    if key_clean not in _config:
        raise KeyError(f"Configuration key '{key_clean}' not found")
    value = _config[key_clean]
    source = _source_map.get(key_clean, "Unknown")
    obj_id = id(value)
    logger.warning(
        f"Accessed configuration '{key_clean}' from {source}; object id: {obj_id}"
    )
    _broadcast(key_clean, value)
    return value

# Example: register a simple handler that prints the item
def _sample_handler(name: str, value: Any) -> None:
    print(f"Handler received config item: {name} = {value}")

register_handler(_sample_handler)

