import hashlib
import tempfile
from urllib import parse
import requests
import zipfile
import tarfile
import logging

logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')

MAX_DOWNLOAD_SIZE_BYTES_DEFAULT = 50 * 1024 * 1024      # 50 MiB
MAX_EXTRACT_SIZE_BYTES_DEFAULT = 500 * 1024 * 1024      # 500 MiB

SUPPORTED_ZIP_EXTS = {'.zip'}
SUPPORTED_TAR_EXTS = {'.tar', '.gz', '.bz2', '.xz'}
SUPPORTED_TAR_NAMES = {'.tar.gz', '.tgz', '.tar.bz2', '.tar.xz'}


def is_valid_url(url: str) -> bool:
    parsed = parse.urlparse(url)
    return parsed.scheme in ('http', 'https') and bool(parsed.netloc)


def generate_unique_filename(url: str) -> pathlib.Path:
    path = parse.urlparse(url).path
    base = os.path.basename(path) or 'downloaded_file'
    stem = pathlib.Path(base).stem
    suffix = pathlib.Path(path).suffix.lower()
    if suffix not in {'.zip', '.tgz', '.tar.gz', '.tar.bz2'}:
        suffix = '.zip'
    # Append a short hash of the URL to avoid collisions
    url_hash = hashlib.sha256(url.encode()).hexdigest()[:8]
    return pathlib.Path(f"{stem}_{url_hash}{suffix}")


def safe_extract_zip(zip_path: pathlib.Path, target_dir: pathlib.Path, max_total_size: int):
    total_extracted = 0
    with zipfile.ZipFile(zip_path, 'r') as zf:
        for member in zf.infolist():
            member_name = pathlib.PurePosixPath(member.filename).parts
            if any(part == '..' or isinstance(part, str) and part.startswith('/') for part in member_name):
                raise RuntimeError('Path traversal detected in ZIP entry')
            dest_path = target_dir / pathlib.Path(*member_name)
            if not dest_path.resolve().is_relative_to(target_dir.resolve()):
                raise RuntimeError('ZIP entry resolves outside target directory')
            dest_path.parent.mkdir(parents=True, exist_ok=True)
            if member.is_dir():
                dest_path.mkdir(parents=True, exist_ok=True)
                continue
            with zf.open(member, 'r') as source, open(dest_path, 'wb') as dest:
                shutil.copyfileobj(source, dest)
            total_extracted += dest_path.stat().st_size
            if total_extracted > max_total_size:
                raise RuntimeError('Maximum extraction size exceeded for ZIP archive')


def safe_extract_tar(tar_path: pathlib.Path, target_dir: pathlib.Path, max_total_size: int):
    total_extracted = 0
    with tarfile.open(tar_path, 'r:*') as tf:
        members = tf.getmembers()
        for member in members:
            member_name = pathlib.PurePosixPath(member.name).parts
            if any(part == '..' or isinstance(part, str) and part.startswith('/') for part in member_name):
                raise RuntimeError('Path traversal detected in TAR entry')
            dest_path = target_dir / pathlib.Path(*member_name)
            if not dest_path.resolve().is_relative_to(target_dir.resolve()):
                raise RuntimeError('TAR entry resolves outside target directory')
            if member.isdir():
                dest_path.mkdir(parents=True, exist_ok=True)
            elif member.islnk() or member.issym():
                # Skip hard and symbolic links
                continue
            elif member.isfile():
                dest_path.parent.mkdir(parents=True, exist_ok=True)
                with tf.extractfile(member) as source, open(dest_path, 'wb') as dest:
                    shutil.copyfileobj(source, dest)
                total_extracted += dest_path.stat().st_size
                if total_extracted > max_total_size:
                    raise RuntimeError('Maximum extraction size exceeded for TAR archive')


def download_file(url: str, dest: pathlib.Path, max_size: int):
    try:
        with requests.get(url, stream=True, timeout=30, verify=True) as r:
            r.raise_for_status()
            with open(dest, 'wb') as f:
                downloaded = 0
                for chunk in r.iter_content(chunk_size=8192):
                    if chunk:
                        downloaded += len(chunk)
                        if downloaded > max_size:
                            raise RuntimeError(f'Download exceeded maximum allowed size of {max_size} bytes')
                        f.write(chunk)
    except Exception as exc:
        if dest.exists():
            dest.unlink()
        raise RuntimeError('Failed to download file') from exc


def compute_sha256_of_file(file_path: pathlib.Path, chunk_size: int = 65536) -> str:
    sha = hashlib.sha256()
    with open(file_path, 'rb') as f:
        for chunk in iter(lambda: f.read(chunk_size), b''):
            sha.update(chunk)
    return sha.hexdigest()


def is_supported_archive(file_path: pathlib.Path) -> bool:
    if file_path.suffix.lower() in SUPPORTED_ZIP_EXTS:
        return True
    lower = file_path.suffix.lower()
    if lower in SUPPORTED_TAR_EXTS:
        return True
    name_lower = file_path.name.lower()
    return any(name_lower.endswith(ext) for ext in SUPPORTED_TAR_NAMES)


def main():
    parser = argparse.ArgumentParser(description='Securely download and extract a compressed file.')
    parser.add_argument('url', help='URL of the compressed file to download')
    parser.add_argument('--max-download-size', type=int, default=MAX_DOWNLOAD_SIZE_BYTES_DEFAULT,
                        help='Maximum size (bytes) allowed for the download; default 50MiB')
    parser.add_argument('--max-extract-size', type=int, default=MAX_EXTRACT_SIZE_BYTES_DEFAULT,
                        help='Maximum total size (bytes) allowed for extraction; default 500MiB')
    parser.add_argument('--sha256', help='Expected SHA-256 hash of the downloaded file')
    parser.add_argument('--output-dir', type=pathlib.Path,
                        help='Directory to extract files into; defaults to a temporary directory')
    args = parser.parse_args()

    if not is_valid_url(args.url):
        logging.error('Invalid URL provided.')
        sys.exit(1)

    filename = generate_unique_filename(args.url)
    script_dir = pathlib.Path(__file__).parent.resolve()
    compressed_path = script_dir / filename

    # Determine extraction directory
    if args.output_dir:
        extract_dir = args.output_dir.resolve()
    else:
        extract_dir = pathlib.Path(tempfile.mkdtemp(prefix='extracted_'))
    if extract_dir.exists() and any(extract_dir.iterdir()):
        logging.info('Extraction directory already exists and is not empty. Skipping extraction.')
        sys.exit(0)

    if not compressed_path.exists():
        logging.info('Downloading compressed file...')
        try:
            download_file(args.url, compressed_path,
                          max_size=args.max_download_size)
            if args.sha256:
                actual_hash = compute_sha256_of_file(compressed_path)
                if actual_hash.lower() != args.sha256.lower():
                    compressed_path.unlink()
                    raise RuntimeError('SHA-256 hash mismatch')
        except Exception as e:
            logging.error(str(e))
            sys.exit(1)
    else:
        logging.info('Compressed file already exists. Using existing file.')

    if not is_supported_archive(compressed_path):
        logging.error('Unsupported compressed file format.')
        sys.exit(1)

    try:
        extract_dir.mkdir(parents=True, exist_ok=True)
        if compressed_path.suffix.lower() == '.zip':
            safe_extract_zip(compressed_path, extract_dir, args.max_extract_size)
        else:
            safe_extract_tar(compressed_path, extract_dir, args.max_extract_size)
    except Exception as e:
        logging.error(f'Extraction failed: {e}')
        sys.exit(1)

    try:
        compressed_path.unlink()
    except Exception as exc:
        logging.warning(f'Failed to remove compressed file: {exc}')

    logging.info(f'Download and extraction completed successfully. Files extracted to {extract_dir}')


if __name__ == '__main__':
    main()

