import re
import sqlite3
from typing import List


class TableSchemaMismatchError(Exception):
    pass


class TableEmptyError(Exception):
    pass


class InvalidTableNameError(Exception):
    pass


def get_row_counts(db_path: str, table_names: List[str]) -> List[int]:
    if not isinstance(db_path, str) or not db_path.strip():
        raise ValueError("db_path must be a non-empty string")
    if not isinstance(table_names, list) or not table_names:
        raise ValueError("table_names must be a non-empty list")

    safe_name_re = re.compile(r"^[A-Za-z][A-Za-z0-9_]*$")
    validated_names: List[str] = []
    for name in table_names:
        if not isinstance(name, str):
            raise InvalidTableNameError("Table names must be strings")
        if not safe_name_re.fullmatch(name):
            raise InvalidTableNameError(f"Invalid table name: {name}")
        validated_names.append(name)

    try:
        with sqlite3.connect(db_path, isolation_level=None) as conn:
            schemas = {}
            for name in validated_names:
                cur = conn.execute(f"PRAGMA table_info({name})")
                columns = cur.fetchall()
                if not columns:
                    raise InvalidTableNameError(f"Table does not exist: {name}")
                schemas[name] = [(col[1], col[2]) for col in columns]

            schema_values = list(schemas.values())
            first_schema = schema_values[0]
            for other_schema in schema_values[1:]:
                if other_schema != first_schema:
                    raise TableSchemaMismatchError("Tables have differing schemas")

            counts: List[int] = []
            for name in validated_names:
                cur = conn.execute(f"SELECT COUNT(*) FROM "{name}"")
                count = cur.fetchone()[0]
                if count == 0:
                    raise TableEmptyError(f"Table {name} is empty")
                counts.append(count)

            return counts
    except sqlite3.Error as exc:
        raise RuntimeError("Database operation failed") from exc

