from pathlib import Path

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)

def validate_credentials_line(line: str, line_num: int):
    if not line.strip():
        return None
    if ":" not in line:
        raise ValueError(f"Invalid credentials format at line {line_num}")
    user_part, pwd_part = line.split(":", 1)
    user = user_part.strip()
    pwd = pwd_part.strip()
    if not user or not pwd:
        raise ValueError(f"Empty username or password at line {line_num}")
    return user, pwd

def decrypt_credentials_file(credentials_path: Path, secret_key: str | None = None):
    try:
        raw = credentials_path.read_bytes()
    except OSError as exc:
        logging.error(f"Error reading credentials file: {exc}")
        sys.exit(1)

    if raw.startswith(b"ENC:"):
        if secret_key is None:
            logging.error("Encrypted credentials file requires a secret key.")
            sys.exit(1)
        try:
            from cryptography.fernet import Fernet
        except ImportError:
            logging.error("cryptography package required for encrypted credentials.")
            sys.exit(1)
        try:
            fernet = Fernet(secret_key.encode("utf-8"))
            decrypted = fernet.decrypt(raw[4:])
            return decrypted.decode("utf-8")
        except Exception as exc:
            logging.error(f"Failed to decrypt credentials file: {exc}")
            sys.exit(1)
    else:
        return raw.decode("utf-8")

def load_credentials(credentials_path: Path, secret_key: str | None = None):
    decoded = decrypt_credentials_file(credentials_path, secret_key)
    creds = {}
    for idx, line in enumerate(decoded.splitlines(), start=1):
        parsed = validate_credentials_line(line, idx)
        if parsed:
            user, pwd = parsed
            creds[user] = pwd
    if not creds:
        logging.error("No valid credentials found in the file.")
        sys.exit(1)
    return creds, decoded

def escape_sql_string(s: str) -> str:
    return s.replace("\", "\\").replace("'", "''")

def parse_create_user(sql: str):
    pattern = re.compile(
        r"CREATE\s+USER\s+(?P<q1>['"]?)(?P<user>[^'"]+)(?P=q1)\s+@(?P<q2>['"]?)(?P<host>[^'"]+)(?P=q2)",
        re.IGNORECASE,
    )
    for match in pattern.finditer(sql):
        yield match.group("user"), match.group("host")

def append_password_statements(init_sql_path: Path, creds: dict, output_path: Path):
    try:
        content = init_sql_path.read_text(encoding="utf-8")
    except OSError as exc:
        logging.error(f"Error reading init_sql file: {exc}")
        sys.exit(1)

    new_statements = []
    for user, host in parse_create_user(content):
        pwd = creds.get(user)
        if pwd:
            escaped_user = escape_sql_string(user)
            escaped_host = escape_sql_string(host)
            escaped_pwd = escape_sql_string(pwd)
            stmt = (
                f"ALTER USER '{escaped_user}'@'{escaped_host}' IDENTIFIED BY '{escaped_pwd}';"
            )
            new_statements.append(stmt)
        else:
            logging.warning(f"No password found for user '{user}'@'{host}'")

    if not new_statements:
        logging.error("No ALTER USER statements to append.")
        sys.exit(1)

    try:
        with output_path.open("w", encoding="utf-8") as out_file:
            out_file.write(content.rstrip("
") + "
")
            out_file.write("
".join(new_statements) + "
")
    except OSError as exc:
        logging.error(f"Error writing modified SQL file: {exc}")
        sys.exit(1)

def ensure_secure_credentials_file(cred_file: Path):
    try:
        cred_file.chmod(0o600)
    except OSError as exc:
        logging.warning(f"Could not set file permissions: {exc}")

def execute_sql(cred_file_path: Path, sql_file_path: Path):
    cmd = [
        "mysql",
        f"--defaults-extra-file={cred_file_path}",
        sql_file_path.as_posix(),
    ]
    try:
        subprocess.run(
            cmd,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )
        logging.info("SQL executed successfully.")
    except subprocess.CalledProcessError as e:
        logging.error(
            f"SQL execution failed with return code {e.returncode}
"
            f"Stdout:
{e.stdout}
"
            f"Stderr:
{e.stderr}"
        )
        sys.exit(1)

def get_temp_file_for_mysql(credentials_text: str) -> Path:
    try:
        fd, temp_path = os.open(
            tempfile.mktemp(prefix="mysql_creds_", suffix=".cnf"),
            os.O_CREAT | os.O_EXCL | os.O_WRONLY,
            mode=0o600,
        )
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(credentials_text)
        return Path(temp_path)
    except OSError as exc:
        logging.error(f"Failed to create temporary credentials file: {exc}")
        sys.exit(1)

def get_secret_key(cli_key: str | None = None):
    env_key = os.getenv("CRED_SECRET_KEY")
    if cli_key:
        logging.warning(
            "Providing the Fernet key via command line is insecure and "
            "will be deprecated. Prefer using the CRED_SECRET_KEY "
            "environment variable."
        )
        return cli_key
    if env_key:
        return env_key
    return None

def main():
    parser = argparse.ArgumentParser(
        description="Setup MySQL user passwords from credentials file."
    )
    parser.add_argument(
        "--init-sql",
        default="init_db.sql",
        help="Path to the original SQL initialization file.",
    )
    parser.add_argument(
        "--credentials",
        default="db-credentials-file",
        help="Path to the credentials file with user:password per line.",
    )
    parser.add_argument(
        "--output-sql",
        default="init_db_with_passwords.sql",
        help="Path to output the modified SQL file.",
    )
    parser.add_argument(
        "--cred-secret-key",
        help="Base64-encoded Fernet key to decrypt credentials file if prefixed with ENC:; optional.",
    )
    args = parser.parse_args()

    init_sql_path = Path(args.init_sql).resolve()
    cred_file_path = Path(args.credentials).resolve()
    output_sql_path = Path(args.output_sql).resolve()

    if not init_sql_path.is_file():
        logging.error(f"Initialization SQL file not found: {init_sql_path}")
        sys.exit(1)
    if not cred_file_path.is_file():
        logging.error(f"Credentials file not found: {cred_file_path}")
        sys.exit(1)

    secret_key = get_secret_key(args.cred_secret_key)
    credentials, decrypted_text = load_credentials(cred_file_path, secret_key)
    append_password_statements(init_sql_path, credentials, output_sql_path)
    ensure_secure_credentials_file(cred_file_path)

    temp_cred = get_temp_file_for_mysql(decrypted_text)
    try:
        execute_sql(temp_cred, output_sql_path)
    finally:
        try:
            temp_cred.unlink()
        except OSError:
            pass

if __name__ == "__main__":
    main()

import ast
import re
from typing import Any, Dict, List, Tuple

MAX_LOCK_STR_LENGTH = 5_000
MAX_FUNCTION_DEFINITIONS = 100

def evaluate_lock_definition(
    lock_def_str: str,
    function_defs: List[Tuple[str, List[Any], Dict[str, Any]]],
) -> Tuple[Any, List[str]]:
    warnings: List[str] = []

    if not isinstance(lock_def_str, str):
        raise TypeError("lock_def_str must be a string.")
    if not isinstance(function_defs, list):
        raise TypeError("function_defs must be a list of tuples.")
    if len(function_defs) > MAX_FUNCTION_DEFINITIONS:
        raise ValueError("Too many function definitions provided.")

    if len(lock_def_str) > MAX_LOCK_STR_LENGTH:
        raise ValueError("Lock definition string exceeds maximum allowed length.")

    try:
        tree = ast.parse(lock_def_str, mode="eval")
    except SyntaxError as exc:
        raise ValueError(f"Syntax error in lock definition: {exc}") from exc

    disallowed_node_types = (
        ast.Import,
        ast.ImportFrom,
        ast.FunctionDef,
        ast.Lambda,
        ast.Global,
        ast.Nonlocal,
        ast.Try,
        ast.With,
        ast.ClassDef,
        ast.Delete,
        ast.Assign,
        ast.AugAssign,
        ast.AsyncFunctionDef,
        ast.Yield,
        ast.YieldFrom,
        ast.Await,
        ast.AsyncFor,
        ast.AsyncWith,
        ast.AsyncDelete,
    )
    for node in ast.walk(tree):
        if isinstance(node, disallowed_node_types):
            raise ValueError(f"Disallowed syntax: {type(node).__name__}")

    safe_globals: Dict[str, Any] = {
        "__builtins__": {},
        "True": True,
        "False": False,
        "None": None,
    }

    func_name_pat = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

    for entry in function_defs:
        if not (isinstance(entry, tuple) and len(entry) == 3):
            warnings.append(f"Invalid function definition entry: {entry}")
            continue

        func_name, pos_args, kw_args = entry

        if not isinstance(func_name, str) or not func_name_pat.match(func_name):
            warnings.append(f"Invalid or unsafe function name: {func_name}")
            continue

        if not isinstance(pos_args, list):
            warnings.append(f"Positional arguments for '{func_name}' must be a list")
            continue

        if not isinstance(kw_args, dict):
            warnings.append(f"Keyword arguments for '{func_name}' must be a dict")
            continue

        def _make_safe_func(pos: Tuple[Any, ...], kw: Dict[str, Any]):
            def safe_func(*_, **__):
                return {"positional_args": pos, "keyword_args": kw}
            return safe_func

        safe_func = _make_safe_func(tuple(pos_args), kw_args)
        safe_globals[func_name] = safe_func

    def _evaluate(node: ast.AST) -> Any:
        if isinstance(node, ast.Expression):
            return _evaluate(node.body)
        if isinstance(node, ast.Constant):
            return node.value
        if isinstance(node, ast.Name):
            if node.id in safe_globals:
                return safe_globals[node.id]
            raise ValueError(f"Unknown name: {node.id}")
        if isinstance(node, ast.Call):
            func = _evaluate(node.func)
            if not callable(func):
                raise ValueError(f"Attempted call of non-callable: {node.func}")
            args = [_evaluate(arg) for arg in node.args]
            kwargs = {kw.arg: _evaluate(kw.value) for kw in node.keywords}
            return func(*args, **kwargs)
        if isinstance(node, (ast.Tuple, ast.List)):
            return type(node)(_evaluate(elt) for elt in node.elts)
        if isinstance(node, ast.Dict):
            keys = [_evaluate(k) for k in node.keys]
            values = [_evaluate(v) for v in node.values]
            return dict(zip(keys, values))
        raise ValueError(f"Unsupported AST node: {type(node).__name__}")

    try:
        result = _evaluate(tree)
    except Exception as exc:
        raise RuntimeError(f"Error during evaluation: {exc}") from exc

    return result, warnings

import hashlib
import os
import pathlib
import re
import sqlite3
import sys
from typing import Dict, Set, Tuple

DB_FILE = "index.db"
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MiB


def _validate_directory(path: str) -> pathlib.Path:
    """Return a resolved directory path or raise ValueError."""
    try:
        p = pathlib.Path(path).resolve(strict=True)
    except Exception:
        raise ValueError("Provided path does not resolve to an existing directory.")
    if not p.is_dir():
        raise ValueError("Provided path is not a directory.")
    if p.is_symlink():
        raise ValueError("Provided path is a symlink which is not allowed.")
    return p


def _stem(term: str) -> str:
    """Simple stemming: lower case and remove common suffixes."""
    term = term.lower()
    suffixes = ("ing", "ed", "ly", "es", "s")
    for suf in suffixes:
        if term.endswith(suf) and len(term) > len(suf) + 2:
            return term[: -len(suf)]
    return term


def _tokenize(text: str) -> list[str]:
    """Return a list of word tokens from text."""
    return re.findall(r" \w+ ", text.lower())


def _file_uri(path: pathlib.Path) -> str:
    """Return a file:// URI for the given path."""
    return path.as_uri()


def _ensure_db_tables(conn: sqlite3.Connection) -> None:
    """Create tables if they do not exist."""
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS inverted (
            term TEXT NOT NULL,
            doc_id TEXT NOT NULL,
            PRIMARY KEY (term, doc_id)
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS forward (
            doc_id TEXT PRIMARY KEY,
            content_hash TEXT NOT NULL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS idToUrl (
            doc_id TEXT PRIMARY KEY,
            url TEXT NOT NULL
        )
        """
    )
    conn.commit()


def buildIndex(directory: str) -> None:
    """Build inverted, forward, and id-to-URL indexes for text files in the given directory."""
    try:
        base_path = _validate_directory(directory)
    except ValueError as exc:
        print(f"Error: {exc}", file=sys.stderr)
        return

    # Ensure DB file exists before setting permissions
    db_exists = os.path.exists(DB_FILE)
    try:
        conn = sqlite3.connect(DB_FILE, timeout=30.0, isolation_level="EXCLUSIVE")
        _ensure_db_tables(conn)
        existing_ids: Set[str] = set()

        for file_path in base_path.rglob("*"):
            # Skip directories, symlinks, and ensure we stay inside base_path
            if file_path.is_dir() or file_path.is_symlink():
                continue
            if base_path not in file_path.parents and file_path != base_path:
                continue

            try:
                if file_path.stat().st_size > MAX_FILE_SIZE:
                    continue
                file_hash = hashlib.sha256()
                with file_path.open("rb") as f:
                    while True:
                        chunk = f.read(8192)
                        if not chunk:
                            break
                        file_hash.update(chunk)
                content_hash = file_hash.hexdigest()
            except OSError:
                continue

            doc_id = hashlib.sha256(str(file_path).encode("utf-8")).hexdigest()
            counter = 1
            while doc_id in existing_ids:
                doc_id = f"{doc_id}_{counter}"
                counter += 1
            existing_ids.add(doc_id)

            conn.execute(
                "INSERT OR REPLACE INTO forward (doc_id, content_hash) VALUES (?, ?)",
                (doc_id, content_hash),
            )
            conn.execute(
                "INSERT OR REPLACE INTO idToUrl (doc_id, url) VALUES (?, ?)",
                (doc_id, _file_uri(file_path)),
            )

            # For tokenization, read text once; we already read binary
            try:
                text = file_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue

            tokens = _tokenize(text)
            for term in {_stem(tok) for tok in tokens}:
                conn.execute(
                    "INSERT OR IGNORE INTO inverted (term, doc_id) VALUES (?, ?)",
                    (term, doc_id),
                )
        conn.commit()
    except Exception:
        print("An error occurred during indexing.", file=sys.stderr)
    finally:
        if "conn" in locals():
            conn.close()
        if not db_exists:
            try:
                os.chmod(DB_FILE, 0o600)
            except OSError:
                pass

