import subprocess
import re
import sys
import shutil
from typing import List, Optional

_AMIXER_PATH = shutil.which("amixer")
if _AMIXER_PATH is None:
    sys.stderr.write("Error: 'amixer' not found.
")
    sys.exit(1)


def _run_amixer(
    args: List[str],
    suppress_output: bool = False,
    capture_output: bool = False,
) -> Optional[subprocess.CompletedProcess]:
    """Run the amixer command with the provided arguments.

    Args:
        args: List of arguments to pass to amixer.
        suppress_output: If True, redirect stdout and stderr to DEVNULL.
        capture_output: If True, capture stdout and stderr.

    Returns:
        CompletedProcess on success, or None on error.
    """
    command = [_AMIXER_PATH] + args
    kwargs: dict = {"check": True}
    if suppress_output:
        kwargs["stdout"] = subprocess.DEVNULL
        kwargs["stderr"] = subprocess.DEVNULL
    if capture_output:
        kwargs["capture_output"] = True
        kwargs["text"] = True
    try:
        return subprocess.run(command, **kwargs)
    except (FileNotFoundError, subprocess.CalledProcessError):
        return None


def adjust_volume(cmd: str) -> str:
    """Adjust the system master volume up or down and return the current level.

    Args:
        cmd: One of 'up' or 'down'.

    Returns:
        The current volume level (e.g., '50%') or an error message.
    """
    action_map = {"up": "10%+", "down": "10%-"}
    if cmd not in action_map:
        return "Error: unrecognized command"

    if _run_amixer(["sset", "Master", action_map[cmd]], suppress_output=True) is None:
        return "Error: failed to change volume"

    result = _run_amixer(["sget", "Master"], capture_output=True)
    if result is None or result.returncode != 0:
        return "Error: failed to retrieve volume"

    if result.stdout is None:
        return "Error: no output from amixer"

    for line in result.stdout.splitlines():
        match = re.search(r"\[(\d+%)\]", line)
        if match:
            return match.group(1)

    return "Error: could not parse volume level"


if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python3 script.py [up|down]")
        sys.exit(1)
    output = adjust_volume(sys.argv[1])
    print(output)

