import re
from typing import Dict

# Regular expression for a sane device ID: 1-64 alphanumeric characters or hyphens
_DEVICE_ID_REGEX = re.compile(r'^[A-Za-z0-9-]{1,64}$', flags=re.ASCII)

class InvalidDeviceIDError(ValueError):
    """Raised when the provided device ID is invalid."""

def _validate_device_id(device_id: str) -> None:
    """Validate that *device_id* is a nonâempty, properly formatted string."""
    if not isinstance(device_id, str):
        raise InvalidDeviceIDError("Device ID must be a string.")
    if not _DEVICE_ID_REGEX.fullmatch(device_id):
        raise InvalidDeviceIDError(
            "Device ID must be 1â64 characters of letters, digits, or hyphens."
        )

def _generate_vm_id(device_id: str) -> str:
    """
    Generate a deterministic VM ID from *device_id* using SHAâ256.

    Returns the first 12 hexadecimal characters of the hash.
    """
    return hashlib.sha256(device_id.encode("utf-8")).hexdigest()[:12]

def get_port_tags(device_id: str) -> Dict[str, str]:
    """
    Create a fake switch and port, then return the port's tags which
    include the VM ID derived from *device_id*.

    Raises:
        InvalidDeviceIDError: If *device_id* does not match the expected pattern.
        ValueError: For any other unexpected error during tag generation.
    """
    try:
        _validate_device_id(device_id)
        vm_id = _generate_vm_id(device_id)

        switch = {
            "switch_id": "fake-switch-001",
            "ports": [
                {"port_id": "port-01", "tags": {"vm_id": vm_id}},
            ],
        }

        return switch["ports"][0]["tags"]
    except InvalidDeviceIDError:
        raise InvalidDeviceIDError("Invalid device ID provided.") from None
    except Exception:
        raise ValueError("An unexpected error occurred while generating port tags.") from None

import subprocess
from typing import List, Sequence

# Define commands that are considered safe for this module
ALLOWED_COMMANDS = {
    "echo",
    "ls",
    "cat",
    "date",
    "whoami",
    # Add other safe commands here as needed
}

def run_command(cmd: Sequence[str], expected_rc: int = 0) -> subprocess.CompletedProcess:
    if not isinstance(expected_rc, int):
        raise ValueError("expected_rc must be an int")
    if not isinstance(cmd, (list, tuple)) or not cmd:
        raise ValueError("cmd must be a non-empty list or tuple of strings")

    command_name = cmd[0]
    if command_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Command '{command_name}' is not allowed")

    disallowed_chars = {"$", "`", ";", "&", "|", "<", ">", "*", "?", "\", "'", '"'}

    sanitized_cmd: List[str] = []
    for arg in cmd:
        if not isinstance(arg, str):
            raise ValueError("all command elements must be strings")
        if not arg:
            raise ValueError("empty argument not allowed")
        if any(ch in arg for ch in disallowed_chars):
            raise ValueError(f"disallowed character in argument: {arg!r}")
        sanitized_cmd.append(arg)

    try:
        result = subprocess.run(
            sanitized_cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            shell=False,
            check=False,
        )
    except FileNotFoundError as exc:
        raise RuntimeError(f"Command not found: {sanitized_cmd[0]!r}") from exc
    except Exception as exc:  # pragma: no cover
        raise RuntimeError("Error executing command") from exc

    if result.returncode != expected_rc:
        raise AssertionError(
            f"Command returned {result.returncode} but expected {expected_rc}"
        )

    return result

import json
import logging
import os
import pathlib
from typing import Any, List

logging.basicConfig(level=logging.ERROR)
logger = logging.getLogger(__name__)

BASE_DB_DIR = pathlib.Path("/var/lib/yourapp/dbs").expanduser().resolve()


def store_items_safely(items: List[Any], db_path: str) -> bool:
    if not isinstance(items, list):
        logger.error("Items must be a list")
        return False
    if not isinstance(db_path, str) or not db_path:
        logger.error("DB path must be a non-empty string")
        return False

    try:
        json_data = json.dumps(items, ensure_ascii=False)
    except (TypeError, ValueError):
        logger.error("Items contain non-JSON serialisable objects")
        return False

    try:
        potential_path = (BASE_DB_DIR / db_path).resolve()
        if not potential_path.is_relative_to(BASE_DB_DIR):
            logger.error("Attempted to use a path outside the allowed base directory")
            return False
    except Exception:
        logger.error("Failed to resolve DB path")
        return False

    if potential_path.is_dir():
        logger.error("Target path points to a directory")
        return False

    try:
        if not potential_path.parent.is_dir():
            potential_path.parent.mkdir(parents=True, exist_ok=True, mode=0o700)
            os.chmod(potential_path.parent, 0o700)
    except Exception:
        logger.error("Directory creation failed")
        return False

    try:
        with open(potential_path, "w", encoding="utf-8") as file:
            file.write(json_data)
        os.chmod(potential_path, 0o600)
        return True
    except Exception:
        logger.error("File write operation failed")
        return False

