import os
import json
import logging
import re
from typing import List, Dict, Any

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")
logger = logging.getLogger(__name__)

_ALLOWED_EXTENSIONS = {".png", ".jpg", ".jpeg", ".gif", ".svg"}
_SYMBOLIC_NAME_RE = re.compile(r"^[A-Za-z0-9._-]+$")
_CACHE_FILE = os.path.join(os.path.expanduser("~"), ".bundle_image_cache.json")
_ALLOWED_BUNDLE_ROOT = os.path.join(os.path.expanduser("~"), "bundles")

def _sanitize_cache_key(name: str) -> str:
    return re.sub(r"[^A-Za-z0-9._-]", "_", name)

def _load_cache() -> Dict[str, Dict[str, Any]]:
    try:
        if not os.path.isfile(_CACHE_FILE):
            logger.debug("Cache file not found; initializing new cache.")
            return {}
        with open(_CACHE_FILE, "r", encoding="utf-8") as fp:
            data = json.load(fp)
            if isinstance(data, dict):
                return data
            logger.warning("Cache content invalid; resetting.")
            return {}
    except (OSError, ValueError) as exc:
        logger.exception("Failed to load cache: %s", exc)
        return {}

def _save_cache(cache: Dict[str, Dict[str, Any]]) -> None:
    try:
        with open(_CACHE_FILE, "w", encoding="utf-8") as fp:
            json.dump(cache, fp, indent=4, sort_keys=True)
        os.chmod(_CACHE_FILE, 0o600)
    except Exception as exc:
        logger.exception("Failed to save cache: %s", exc)

def find_images_in_bundle(symbolic_name: str, image_types: List[str], context) -> List[str]:
    if not isinstance(symbolic_name, str) or not _SYMBOLIC_NAME_RE.fullmatch(symbolic_name):
        logger.error("Invalid symbolic name: %s", symbolic_name)
        return []

    if not isinstance(image_types, list) or not image_types:
        logger.error("Image types must be a non-empty list.")
        return []

    requested_exts = set()
    for typ in image_types:
        if not isinstance(typ, str):
            logger.error("Image type must be a string: %r", typ)
            return []
        ext = f".{typ.lower()}"
        if ext not in _ALLOWED_EXTENSIONS:
            logger.error("Unsupported image type: %s", typ)
            return []
        requested_exts.add(ext)

    cache = _load_cache()

    try:
        bundle_root = context.get_bundle_root(symbolic_name)
    except Exception as exc:
        logger.exception("Failed to get bundle root for %s: %s", symbolic_name, exc)
        return []

    if not isinstance(bundle_root, str) or not os.path.isdir(bundle_root):
        logger.error("Invalid bundle root path: %s", bundle_root)
        return []

    bundle_root = os.path.abspath(bundle_root)
    expected_base = os.path.abspath(_ALLOWED_BUNDLE_ROOT)
    if not bundle_root.startswith(expected_base + os.sep):
        logger.error("Bundle root %s is outside allowed directory %s", bundle_root, expected_base)
        return []

    found_images = []

    for root, dirs, files in os.walk(bundle_root, topdown=True, followlinks=False):
        dirs[:] = [d for d in dirs if not d.startswith('.')]
        for filename in files:
            _, ext = os.path.splitext(filename)
            if ext.lower() in requested_exts:
                full_path = os.path.abspath(os.path.join(root, filename))
                if not full_path.startswith(bundle_root):
                    logger.warning("Skipping out-of-bounds file: %s", full_path)
                    continue
                relative_path = os.path.relpath(full_path, bundle_root)
                found_images.append(relative_path)
                logger.debug("Found image: %s", relative_path)

    cache_key = _sanitize_cache_key(symbolic_name)
    cache_entry = cache.get(cache_key, {})
    cache_entry.update({"images": found_images, "types": sorted(requested_exts)})
    cache[cache_key] = cache_entry
    _save_cache(cache)

    return found_images

