        ast.NameConstant, ast.Load, ast.Store, ast.AugLoad, ast.AugStore,
        ast.Del, ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv,
        ast.Mod, ast.Pow, ast.LShift, ast.RShift, ast.BitOr, ast.BitXor,
        ast.BitAnd, ast.MatMult, ast.And, ast.Or, ast.Not,
