                raise ValueError("Container literal exceeds maximum size")
        if isinstance(node, ast.Dict):
            if len(node.keys) > MAX_DICT_SIZE:
                raise ValueError("Dictionary literal exceeds maximum size")
        super().generic_visit(node)

def _validate_code(code: str, local_names: Set[str]) -> None:
