def _exec_in_process(code: str, globals_dict: Dict[str, Any], locals_dict: Dict[str, Any], out_q: Queue):
    try:
        compiled = compile(code, "<sandbox>", "exec")
        builtins.exec(compiled, globals_dict, locals_dict)
        out_q.put(("ok", locals_dict))
    except Exception as e:
        out_q.put(("error", e))

def _run_with_timeout(
    code: str,
    globals_dict: Dict[str, Any],
    locals_dict: Dict[str, Any],
    timeout_sec: int = 1,
) -> None:
    out_q: Queue = Queue()
    p = Process(target=_exec_in_process, args=(code, dict(globals_dict), dict(locals_dict), out_q))
    p.start()
    p.join(timeout_sec)
    if p.is_alive():
        p.terminate()
        p.join()
        raise TimeoutError("Execution timed out")
    try:
        status, result = out_q.get_nowait()
    except Exception:
        raise RuntimeError("Failed to retrieve execution result")
    if status == "error":
        raise result
    updated_locals = result
    locals_dict.update(updated_locals)

