import ast

def safe_eval(expr: str):
    if not isinstance(expr, str):
        raise TypeError("Expression must be a string.")

    allowed_chars = set("0123456789+-*/(). 	
")
    for ch in expr:
        if ch not in allowed_chars:
            raise ValueError(f"Invalid character '{ch}' in expression.")

    try:
        tree = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError("Invalid syntax in expression.") from e

    def validate(node: ast.AST):
        if isinstance(node, (ast.Expression, ast.BinOp, ast.UnaryOp)):
            for child in ast.iter_child_nodes(node):
                validate(child)
        elif isinstance(node, (ast.Constant, ast.Num)):
            value = getattr(node, "value", getattr(node, "n", None))
            if isinstance(value, bool):
                raise ValueError("Boolean literals are not allowed.")
            if not isinstance(value, (int, float, complex)):
                raise ValueError("Only numeric constants allowed.")
        elif isinstance(
            node,
            (
                ast.Add,
                ast.Sub,
                ast.Mult,
                ast.Div,
                ast.Mod,
                ast.Pow,
                ast.UAdd,
                ast.USub,
            ),
        ):
            pass
        else:
            raise ValueError(f"Disallowed expression: {type(node).__name__}")

    validate(tree)

    def compute(node: ast.AST):
        if isinstance(node, ast.Expression):
            return compute(node.body)
        if isinstance(node, (ast.Constant, ast.Num)):
            return getattr(node, "value", getattr(node, "n", None))
        if isinstance(node, ast.BinOp):
            left = compute(node.left)
            right = compute(node.right)
            op = node.op
            if isinstance(op, ast.Add):
                return left + right
            if isinstance(op, ast.Sub):
                return left - right
            if isinstance(op, ast.Mult):
                return left * right
            if isinstance(op, ast.Div):
                return left / right
            if isinstance(op, ast.Mod):
                return left % right
            if isinstance(op, ast.Pow):
                return left ** right
        if isinstance(node, ast.UnaryOp):
            operand = compute(node.operand)
            op = node.op
            if isinstance(op, ast.UAdd):
                return +operand
            if isinstance(op, ast.USub):
                return -operand
        raise ValueError(f"Disallowed expression: {type(node).__name__}")

    try:
        return compute(tree)
    except Exception as e:
        raise ValueError("Error evaluating expression.") from e


def evaluate(expr):
    return safe_eval(expr)


def main():
    try:
        expression = input("Enter expression: ")
    except EOFError:
        return
    try:
        result = evaluate(expression)
    except ValueError as e:
        print(f"Error: {e}")
    else:
        print(f"Result: {result}")


