import hashlib
import hmac
import secrets
import re
from typing import Optional

class UserAccount:
    __slots__ = (
        "username",
        "phone_number",
        "emergency_contact",
        "_password_hash",
        "_secret_key",
    )

    _HASH_ALGORITHM: str = "sha256"
    _PBKDF2_ITERATIONS: int = 100_000
    _SALT_LENGTH: int = 16  # bytes
    _SECRET_KEY_LENGTH: int = 32  # bytes

    _USERNAME_REGEX = re.compile(r"^[A-Za-z0-9_]{3,30}$")
    _PHONE_REGEX = re.compile(r"^\+?[0-9]{7,15}$")

    def __init__(self, username: str, phone_number: str, emergency_contact: str) -> None:
        self.username = self._validate_username(username)
        self.phone_number = self._validate_phone_number(phone_number)
        self.emergency_contact = self._validate_emergency_contact(emergency_contact)
        self._password_hash: Optional[str] = None
        self._secret_key: Optional[bytes] = None

    @staticmethod
    def _validate_username(username: str) -> str:
        if not isinstance(username, str):
            raise ValueError("Username must be a string.")
        if not UserAccount._USERNAME_REGEX.fullmatch(username):
            raise ValueError("Invalid username format.")
        return username

    @staticmethod
    def _validate_phone_number(phone: str) -> str:
        if not isinstance(phone, str):
            raise ValueError("Phone number must be a string.")
        if not UserAccount._PHONE_REGEX.fullmatch(phone):
            raise ValueError("Invalid phone number format.")
        return phone

    @staticmethod
    def _validate_emergency_contact(contact: str) -> str:
        if not isinstance(contact, str):
            raise ValueError("Emergency contact must be a string.")
        if not UserAccount._PHONE_REGEX.fullmatch(contact):
            raise ValueError("Invalid emergency contact format.")
        return contact

    def set_password(self, password: str) -> None:
        if not isinstance(password, str):
            raise ValueError("Password must be a string.")
        if len(password) < 8:
            raise ValueError("Password must be at least 8 characters long.")
        salt = secrets.token_bytes(self._SALT_LENGTH)
        dk = hashlib.pbkdf2_hmac(
            self._HASH_ALGORITHM,
            password.encode("utf-8"),
            salt,
            self._PBKDF2_ITERATIONS,
        )
        self._password_hash = f"{self._PBKDF2_ITERATIONS}${salt.hex()}${dk.hex()}"

    def verify_password(self, password: str) -> bool:
        if self._password_hash is None:
            return False
        if not isinstance(password, str):
            return False
        try:
            iterations_str, salt_hex, dk_hex = self._password_hash.split("$", 2)
            iterations = int(iterations_str)
            salt = bytes.fromhex(salt_hex)
            dk_expected = bytes.fromhex(dk_hex)
            dk_actual = hashlib.pbkdf2_hmac(
                self._HASH_ALGORITHM,
                password.encode("utf-8"),
                salt,
                iterations,
            )
            return hmac.compare_digest(dk_actual, dk_expected)
        except Exception:
            return False

    def generate_secret_key(self) -> bytes:
        self._secret_key = secrets.token_bytes(self._SECRET_KEY_LENGTH)
        return self._secret_key

    @property
    def secret_key(self) -> Optional[bytes]:
        return self._secret_key

    def __repr__(self) -> str:
        return (
            f"{self.__class__.__name__}(username={self.username!r}, "
            f"phone_number={self.phone_number!r}, "
            f"emergency_contact={self.emergency_contact!r})"
        )

import logging
import inspect
import unittest.mock as mock
from functools import wraps
from typing import Callable, Any

def wrap_with_mock(original: Callable[..., Any], mock_enabled: bool) -> Callable[..., Any]:
    if not callable(original):
        raise TypeError("First argument must be a callable.")
    if not isinstance(mock_enabled, bool):
        raise TypeError("Second argument must be a boolean.")

    @wraps(original)
    def wrapper(*args, **kwargs):
        try:
            if mock_enabled:
                mocked = mock.MagicMock(name=original.__name__, side_effect=original)
                return mocked(*args, **kwargs)
            return original(*args, **kwargs)
        except Exception as exc:
            logging.warning("Error executing %s: %s", original.__qualname__, exc)
            raise RuntimeError(f"Error executing {original.__qualname__}.") from exc

    # Preserve signature
    wrapper.__signature__ = inspect.signature(original)
    return wrapper

