import os
import pathlib
import re
import subprocess
import urllib.parse
from typing import Optional, Set

DEFAULT_SVN_PATH = pathlib.Path("/usr/bin/svn").resolve()
ALLOWED_SCHEMES: Set[str] = {"https", "svn", "svn+ssh"}
ALLOWED_HOSTS: Set[str] = {"trusted.example.com"}
BASE_CHECKOUT_DIR = pathlib.Path("/opt/svn_checkouts").resolve()

def svn_checkout_and_get_revision(
    repo_url: str,
    checkout_dir: str,
    svn_path: str = str(DEFAULT_SVN_PATH),
) -> Optional[int]:
    expected_path = DEFAULT_SVN_PATH
    try:
        svn_executable = pathlib.Path(svn_path).expanduser().resolve(strict=True)
    except Exception:
        return None

    if (
        svn_executable != expected_path
        or not (svn_executable.is_file() and os.access(svn_executable, os.X_OK))
    ):
        return None

    try:
        parsed = urllib.parse.urlparse(repo_url)
    except Exception:
        return None

    if parsed.scheme not in ALLOWED_SCHEMES:
        return None

    host = parsed.hostname
    if not host or host not in ALLOWED_HOSTS:
        return None

    # Validate path component of the URL
    path = parsed.path
    if not path:
        return None
    if '..' in [segment for segment in path.split('/') if segment]:
        return None
    if 'file://' in path:
        return None

    checkout_path = pathlib.Path(checkout_dir).expanduser().resolve(strict=False)
    try:
        checkout_path.mkdir(parents=True, exist_ok=True)
    except Exception:
        return None

    try:
        resolved = checkout_path.resolve(strict=False)
    except Exception:
        return None
    if resolved != checkout_path:
        return None
    if checkout_path.is_symlink():
        return None

    # Ensure checkout directory is within the authorized base directory
    try:
        resolved.is_relative_to(BASE_CHECKOUT_DIR)  # Python 3.9+
    except AttributeError:
        # Manual relative check for older Python versions
        try:
            resolved.relative_to(BASE_CHECKOUT_DIR)
        except Exception:
            return None
    except Exception:
        return None

    cmd = [str(svn_executable), "checkout", repo_url, str(checkout_path)]

    try:
        result = subprocess.run(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            text=True,
            check=True,
            timeout=120,
        )
    except (subprocess.CalledProcessError, subprocess.TimeoutExpired):
        return None
    except Exception:
        return None

    match = re.search(r"Checked out revision (\d+)\.", result.stdout)
    if match:
        try:
            return int(match.group(1))
        except ValueError:
            return None

    return None

