        raise ValueError(f"Option key must not start with '-': {key!r}")
    return _safe_string(key)

def _validate_value(value: str) -> bool:
    if value.startswith('-'):
        return False
    return NUMERIC_OR_STR_RE.fullmatch(value) is not None

def compute_albedo(interval: str, **kwargs: Any) -> Dict[str, Any]:
    """Execute get_shortwave_data with validated arguments and compute albedo."""
    try:
        safe_interval = _safe_string(interval)
    except ValueError:
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": "Invalid interval format."
        }

    if not GET_SHORTWAVE_DATA_BIN.is_file() or not os.access(GET_SHORTWAVE_DATA_BIN, os.X_OK):
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": "Executable not found or not executable."
        }

    command = [str(GET_SHORTWAVE_DATA_BIN), "--interval", safe_interval]

    for key, val in kwargs.items():
        try:
            key_str = _safe_option_key(str(key))
        except ValueError:
            return {
                "label": "albedo",
                "value": None,
                "unit": "dimensionless",
                "error": f"Invalid option key: {key}"
            }
        val_str = str(val)
        if not _validate_value(val_str):
            return {
                "label": "albedo",
                "value": None,
                "unit": "dimensionless",
                "error": f"Invalid value for option {key}: {val}"
            }
        command.extend([f"--{key_str}", val_str])

    env = {"PATH": "/usr/local/sbin:/usr/local/bin"}

    try:
        result = subprocess.run(
            command,
            check=True,
            capture_output=True,
            text=True,
            timeout=30,
            env=env,
        )

        if len(result.stdout.encode("utf-8")) > MAX_OUTPUT_BYTES:
            return {
                "label": "albedo",
                "value": None,
                "unit": "dimensionless",
                "error": "Command output too large."
            }

        data = json.loads(result.stdout.strip())
        upward = data.get("upward")
        downward = data.get("downward")

        if not isinstance(upward, (int, float)) or not isinstance(downward, (int, float)):
            return {
                "label": "albedo",
                "value": None,
                "unit": "dimensionless",
                "error": "Invalid data types in output."
            }

        albedo_value = None if downward == 0 else upward / downward

        return {
            "label": "albedo",
            "value": albedo_value,
            "unit": "dimensionless",
            "error": None
        }

    except subprocess.TimeoutExpired:
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": "Command timed out."
        }
    except subprocess.CalledProcessError as exc:
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": f"Command failed with exit code {exc.returncode}."
        }
    except (FileNotFoundError, OSError) as e:
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": f"Execution error: {e}"
        }
    except json.JSONDecodeError:
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": "Invalid JSON output from command."
        }
    except Exception as e:
        logging.error("Unexpected error in compute_albedo: %s", e)
        return {
            "label": "albedo",
            "value": None,
            "unit": "dimensionless",
            "error": "An unexpected error occurred."
        }

