    }

    _IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")
    _LOGGER = logging.getLogger(__name__)

    def __init__(self, cls: type, params: dict):
        if not isinstance(cls, type):
            raise TypeError("cls must be a class type")
        if not isinstance(params, dict):
            raise TypeError("params must be a dictionary")
        self._cls = cls
        self._params = dict(params)

    @property
    def cls(self) -> type:
        return self._cls

    @property
    def params(self) -> dict:
        return dict(self._params)

    def to_dict(self) -> dict:
        return {
            "class": f"{self._cls.__module__}.{self._cls.__qualname__}",
            "params": dict(self._params),
        }

    @staticmethod
    def from_dict(data: _t.Mapping) -> "Transformation":
        if not isinstance(data, dict):
            raise TypeError("data must be a dictionary")
        if not {"class", "params"}.issubset(data):
            raise KeyError("data must contain 'class' and 'params'")

        class_path = data["class"]
        if not isinstance(class_path, str):
            raise TypeError("'class' must be a string")

        params = data["params"]
