            raise TypeError("'params' must be a dictionary")

        # Validate parameter keys and values
        for key, value in params.items():
            if not isinstance(key, str):
                raise TypeError("All parameter keys must be strings")
            if not isinstance(value, (int, float, str, bool, type(None))):
                raise TypeError(f"Unsupported parameter type for key '{key}': {type(value).__name__}")

        module_name, _, class_name = class_path.rpartition(".")
        if not module_name or not class_name:
            raise ValueError("Invalid class path format; expected 'module.ClassName'")

        # Restrict module name to whitelist and disallow nested paths
        if "." in module_name:
            raise ValueError("Module name must not contain nested paths")
        if module_name not in Transformation._ALLOWED_MODULES:
            raise PermissionError("import from the specified module is not allowed")

        if not Transformation._IDENTIFIER_RE.match(class_name):
            raise ValueError("class name is not a valid Python identifier")

        # Disallow dunder class names
        if class_name.startswith("__") and class_name.endswith("__"):
            raise ValueError("class name cannot use dunder notation")

        allowed_classes = Transformation._ALLOWED_CLASSES.get(module_name)
        if allowed_classes is not None and class_name not in allowed_classes:
            raise PermissionError("class is not in the allowed list for this module")

        try:
            module = importlib.import_module(module_name)
            cls_obj = getattr(module, class_name)
            if not isinstance(cls_obj, type):
                raise TypeError(f"{class_path!r} is not a class")
            # Ensure the module file resides within the same directory as this file
            if hasattr(module, "__file__"):
                module_file = os.path.abspath(module.__file__)
                base_dir = os.path.abspath(os.path.dirname(__file__))
                if not module_file.startswith(base_dir):
                    raise PermissionError("Module file location is outside the allowed directory")
        except Exception as exc:
            Transformation._LOGGER.debug("Failed to import %s", class_path, exc_info=exc)
            raise ImportError("Failed to import the specified class") from exc

        return Transformation(cls_obj, params)

