import ipaddress
import re
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any


@dataclass(frozen=True)
class StorageCenterConfig:
    san_ip: str
    san_login: str
    san_password: str = field(repr=False)
    dell_ssn: str
    server_folder: str
    volume_folder: str
    api_port: int
    iscsi_ip: str
    iscsi_port: int


def _validate_ip(value: Any, name: str) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a string")
    try:
        ipaddress.ip_address(value)
    except ValueError:
        raise ValueError(f"Invalid {name.lower()} address")
    return value


def _validate_port(value: Any, name: str) -> int:
    if not isinstance(value, int):
        raise ValueError(f"{name} must be an integer")
    if not (1 <= value <= 65535):
        raise ValueError(f"{name} must be between 1 and 65535")
    return value


def _validate_login(login: Any) -> str:
    if not isinstance(login, str):
        raise ValueError("SAN login must be a string")
    if not login or login.strip() == "":
        raise ValueError("SAN login cannot be empty")
    if not re.fullmatch(r"[A-Za-z0-9_]{3,32}", login):
        raise ValueError("SAN login must be 3-32 alphanumeric characters or underscores")
    return login


def _validate_password(password: Any) -> str:
    if not isinstance(password, str):
        raise ValueError("SAN password must be a string")
    if not password or password.strip() == "":
        raise ValueError("SAN password cannot be empty")
    if len(password) < 8:
        raise ValueError("SAN password must be at least 8 characters long")
    return password


def _validate_ssn(ssn: Any) -> str:
    if not isinstance(ssn, str):
        raise ValueError("DELL SSN must be a string")
    if not re.fullmatch(r"\d{9}", ssn):
        raise ValueError("DELL SSN must be a 9-digit number")
    return ssn


def _validate_folder(folder: Any, name: str) -> str:
    if not isinstance(folder, str):
        raise ValueError(f"{name} must be a string")
    if not folder or folder.strip() == "":
        raise ValueError(f"{name} cannot be empty")
    path = Path(folder)
    if not path.is_absolute():
        raise ValueError(f"{name} must be an absolute path")
    if ".." in path.parts:
        raise ValueError(f"{name} cannot contain '..'")
    if any(part.startswith(".") for part in path.parts):
        raise ValueError(f"{name} cannot contain hidden components")
    return folder


def build_mock_config(
    san_ip: str,
    san_login: str,
    san_password: str,
    dell_ssn: str,
    server_folder: str,
    volume_folder: str,
    api_port: int,
    iscsi_ip: str,
    iscsi_port: int,
) -> StorageCenterConfig:
    san_ip = _validate_ip(san_ip, "SAN IP")
    iscsi_ip = _validate_ip(iscsi_ip, "iSCSI IP")
    api_port = _validate_port(api_port, "API Port")
    iscsi_port = _validate_port(iscsi_port, "iSCSI Port")
    san_login = _validate_login(san_login)
    san_password = _validate_password(san_password)
    dell_ssn = _validate_ssn(dell_ssn)
    server_folder = _validate_folder(server_folder, "Server folder")
    volume_folder = _validate_folder(volume_folder, "Volume folder")

    return StorageCenterConfig(
        san_ip=san_ip,
        san_login=san_login,
        san_password=san_password,
        dell_ssn=dell_ssn,
        server_folder=server_folder,
        volume_folder=volume_folder,
        api_port=api_port,
        iscsi_ip=iscsi_ip,
        iscsi_port=iscsi_port,
    )

import logging
import sys
import re
from urllib.parse import urlparse
from urllib.request import Request, urlopen
from urllib.error import HTTPError, URLError
import ipaddress

logging.basicConfig(
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s: %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

ALLOWED_HOSTS = {"example.com"}
ALLOWED_SUBNETS = [ipaddress.IPv4Network("192.168.0.0/16")]


def is_allowed_host(host: str) -> bool:
    if host in ALLOWED_HOSTS:
        return True
    try:
        ip = ipaddress.ip_address(host)
        for net in ALLOWED_SUBNETS:
            if ip in net:
                return True
    except ValueError:
        return False
    return False


def validate_url(url: str) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("Unsupported URL scheme")
    if not parsed.netloc:
        raise ValueError("Invalid URL")
    host = parsed.hostname.lower()
    if not host or not is_allowed_host(host):
        raise ValueError(f"Host '{host}' is not permitted")
    return url


def fetch_remote_output(url: str) -> str:
    request = Request(url, headers={"User-Agent": "SecureClient/1.0"})
    try:
        with urlopen(request, timeout=10) as response:
            return response.read().decode("utf-8")
    except HTTPError as e:
        logging.error(f"HTTP error: {e.code}")
        raise RuntimeError("HTTP error during data retrieval") from e
    except URLError as e:
        logging.error(f"URL error: {e.reason}")
        raise RuntimeError("Failed to retrieve data from remote server") from e
    except Exception as e:
        logging.error(f"Fetching error: {e}")
        raise RuntimeError("Unable to retrieve data from remote server") from e


def extract_value(
    output: str, key_pattern: str, value_pattern: str
) -> str:
    try:
        key_re = re.compile(key_pattern)
    except re.error as e:
        logging.error("Invalid key regex pattern")
        raise ValueError("Malformed key regex pattern") from e
    match = key_re.search(output)
    if not match:
        raise RuntimeError("Desired key not found in remote output")
    if not match.groups():
        raise RuntimeError("Key regex does not capture a value")
    value = match.group(1)
    if not re.fullmatch(value_pattern, value):
        raise ValueError("Extracted value does not match expected format")
    return value


def main() -> None:
    url = "https://example.com/api/status"
    key_regex = r"SpecificKey:\s*(\S+)"
    expected_value_regex = r"[a-zA-Z0-9]{8}"

    try:
        safe_url = validate_url(url)
        output = fetch_remote_output(safe_url)
        value = extract_value(output, key_regex, expected_value_regex)
        print(f"Extracted value: {value}")
    except Exception:
        print("Failed to retrieve value", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
import argparse
import json
import subprocess
import sys
from collections import defaultdict
from pathlib import Path
from typing import Dict, List, Set, Tuple


def validate_repo_path(repo_path: str) -> Path:
    try:
        p = Path(repo_path).expanduser().resolve(strict=True)
    except FileNotFoundError:
        raise ValueError(f"Path does not exist: {repo_path}")
    if not p.is_dir():
        raise ValueError(f"Not a directory: {repo_path}")
    if not (p / ".hg").is_dir():
        raise ValueError(f"Not a Mercurial repository: {repo_path}")
    return p


def run_hg_log(repo_dir: Path) -> List[Dict[str, List[str]]]:
    template = """{node}::{branch}::{parents}
"""
    try:
        result = subprocess.run(
            ["hg", "log", "-T", template],
            cwd=repo_dir,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True,
            shell=False,
        )
    except FileNotFoundError:
        raise RuntimeError("Executable 'hg' not found. Ensure Mercurial is installed.")
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"hg log failed: {e.stderr.strip()}")

    commits: List[Dict[str, List[str]]] = []
    for line in result.stdout.splitlines():
        parts = line.split("::")
        if len(parts) < 3:
            continue
        node = parts[0].strip()
        branch = parts[1].strip()
        parents = parts[2].strip().split() if parts[2].strip() else []
        commits.append({"node": node, "branch": branch, "parents": parents})
    return commits


def build_graph(commits: List[Dict[str, List[str]]]) -> Tuple[Dict[str, List[str]], Dict[str, List[str]]]:
    parents_map: Dict[str, List[str]] = {}
    children_map: Dict[str, List[str]] = defaultdict(list)
    for c in commits:
        node = c["node"]
        parents_map[node] = c["parents"]
        for p in c["parents"]:
            children_map[p].append(node)
    return parents_map, children_map


def compute_heads(parents_map: Dict[str, List[str]], children_map: Dict[str, List[str]]) -> Set[str]:
    heads: Set[str] = set()
    for node in parents_map:
        if not children_map.get(node):
            heads.add(node)
    return heads


def count_branch_heaps(
    children_map: Dict[str, List[str]], heads: Set[str], all_nodes: Set[str]
) -> Dict[str, int]:
    cache: Dict[str, Set[str]] = {}

    def descendants_heads(node: str) -> Set[str]:
        if node in cache:
            return cache[node]
        if node in heads:
            cache[node] = {node}
            return cache[node]
        heads_set: Set[str] = set()
        for child in children_map.get(node, []):
            heads_set.update(descendants_heads(child))
        cache[node] = heads_set
        return heads_set

    result: Dict[str, int] = {}
    for node in all_nodes:
        result[node] = len(descendants_heads(node))
    return result


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Mercurial branch count per commit"
    )
    parser.add_argument("repo_path", help="Path to Mercurial repository")
    args = parser.parse_args()

    try:
        repo_dir = validate_repo_path(args.repo_path)
    except ValueError as e:
        sys.stderr.write(f"{e}
")
        sys.exit(1)

    try:
        commits = run_hg_log(repo_dir)
    except RuntimeError as e:
        sys.stderr.write(f"{e}
")
        sys.exit(1)

    parents_map, children_map = build_graph(commits)
    all_nodes = set(parents_map.keys())
    heads = compute_heads(parents_map, children_map)
    branch_counts = count_branch_heaps(children_map, heads, all_nodes)

    print(json.dumps(branch_counts, indent=2, sort_keys=True))


if __name__ == "__main__":
    main()

import ast
import logging
from typing import Any, Dict, Optional

# Configure moduleâlevel logger
logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())

# Maximum accepted size for the source string (64 KiB)
MAX_CODE_SIZE = 64 * 1024

# Allowed builtin function names that may be called
_ALLOWED_BUILTINS = {
    "abs", "max", "min", "sum", "len", "range", "round", "float",
    "int", "str", "bool", "list", "dict", "set", "tuple", "pow",
}

# Allowed operator types for binary and unary operations
_ALLOWED_BINOPS = {
    ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
    ast.LShift, ast.RShift, ast.BitOr, ast.BitXor, ast.BitAnd,
}
_ALLOWED_UNARYOPS = {ast.UAdd, ast.USub, ast.Not, ast.Invert}
_ALLOWED_COMPARATORS = {
    ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE,
    ast.Is, ast.IsNot, ast.In, ast.NotIn,
}

# Allowed node types for strict safety
ALLOWED_NODE_TYPES = {
    ast.Module,
    ast.Expression,
    ast.Expr,
    ast.BinOp,
    ast.UnaryOp,
    ast.BoolOp,
    ast.Compare,
    ast.Call,
    ast.Name,
    ast.Load,
    ast.Constant,
    ast.Num,
    ast.Str,
    ast.Bytes,
    ast.NameConstant,
    ast.Tuple,
    ast.List,
    ast.Dict,
    ast.Set,
}

def _is_allowed_node(node: ast.AST) -> bool:
    """Recursively verify that a node and its children are safe."""
    if type(node) not in ALLOWED_NODE_TYPES:
        return False

    if isinstance(node, (ast.Module, ast.Expression, ast.Expr)):
        return all(_is_allowed_node(child) for child in ast.iter_child_nodes(node))

    if isinstance(node, ast.BinOp):
        if type(node.op) not in _ALLOWED_BINOPS:
            return False
        return _is_allowed_node(node.left) and _is_allowed_node(node.right)

    if isinstance(node, ast.UnaryOp):
        if type(node.op) not in _ALLOWED_UNARYOPS:
            return False
        return _is_allowed_node(node.operand)

    if isinstance(node, ast.BoolOp):
        return all(_is_allowed_node(v) for v in node.values)

    if isinstance(node, ast.Compare):
        if any(type(comp) not in _ALLOWED_COMPARATORS for comp in node.comparators):
            return False
        return _is_allowed_node(node.left) and all(_is_allowed_node(c) for c in node.comparators)

    if isinstance(node, ast.Call):
        if not (isinstance(node.func, ast.Name) and node.func.id in _ALLOWED_BUILTINS):
            return False
        return all(_is_allowed_node(arg) for arg in node.args) and all(
            _is_allowed_node(keyword.value) for keyword in node.keywords
        )

    if isinstance(node, ast.Name):
        # Names used in expressions must be safe lookup â only allowed builtins
        if node.id not in _ALLOWED_BUILTINS:
            return False
        return True

    # For constants and containers, just ensure their elements are safe
    if isinstance(node, (ast.Tuple, ast.List, ast.Set)):
        return all(_is_allowed_node(elt) for elt in node.elts)

    if isinstance(node, ast.Dict):
        return all(_is_allowed_node(k) and _is_allowed_node(v)
                   for k, v in zip(node.keys, node.values))

    # Constant values are inherently safe
    if isinstance(node, (ast.Constant, ast.Num, ast.Str, ast.Bytes, ast.NameConstant)):
        return True

    return False


def compile_code_safely(code: str, symbol: str) -> Optional[Dict[str, Any]]:
    """
    Compile the provided source code string for the given execution mode ('single' or 'eval')
    with strict safety checks. Returns a dictionary containing the compiled code object
    and the symbol if compilation succeeds; otherwise returns None.
    """
    if not isinstance(code, str) or not isinstance(symbol, str):
        return None

    normalized_symbol = symbol.strip().lower()
    if normalized_symbol not in {"single", "eval"}:
        return None

    if len(code) > MAX_CODE_SIZE:
        logger.warning("Source code exceeds maximum allowed size.")
        return None

    try:
