from typing import Callable, Dict, List, Union, Tuple, Any

def create_minuit(
    minuit_func: Callable,
    param_dict: Dict[str, Union[float, Tuple[float, float, float]]],
    exclusions: List[float],
    centroids: List[float],
) -> Any:
    """
    Create a Minuit instance, configure its parameters, and assign a custom
    numeric values list that satisfies input contractual expectations.
    """
    from iminuit import Minuit

    if not callable(minuit_func):
        raise TypeError("minuit_func must be callable")

    if not isinstance(param_dict, dict):
        raise TypeError("param_dict must be a dictionary")
    if not isinstance(exclusions, list) or not isinstance(centroids, list):
        raise TypeError("exclusions and centroids must be lists")
    if len(exclusions) != len(centroids):
        raise ValueError("exclusions and centroids must have equal length")

    safe_params: Dict[str, Union[float, Tuple[float, float, float]]] = {}
    for name, value in param_dict.items():
        if not isinstance(name, str) or not name.isidentifier():
            continue
        if isinstance(value, (int, float)):
            safe_params[name] = float(value)
        elif isinstance(value, (tuple, list)) and len(value) == 3:
            if not all(isinstance(v, (int, float)) for v in value):
                continue
            initial, lower, upper = map(float, value)
            if lower > upper:
                raise ValueError(
                    f"Parameter {name} has lower bound greater than upper bound"
                )
            safe_params[name] = (initial, lower, upper)
        else:
            continue

    if not safe_params:
        raise ValueError("No valid parameter definitions found")

    try:
        m = Minuit(minuit_func, **safe_params)
    except Exception as exc:
        raise RuntimeError(f"Failed to initialize Minuit: {exc}") from exc

    values_list: List[float] = []
    for ex, cen in zip(exclusions, centroids):
        if not isinstance(ex, (int, float)) or not isinstance(cen, (int, float)):
            raise ValueError("exclusions and centroids must contain only numeric values")
        values_list.append(float(ex) + float(cen))

    if len(values_list) != len(safe_params):
        raise ValueError("values_list length must match number of parameters")

    if hasattr(m, "values"):
        m.values = values_list
    else:
        raise AttributeError("Minuit object lacks 'values' attribute")

    return m

import os
import re
import psycopg2
from psycopg2 import sql, OperationalError, Error
from typing import Optional


_DB_NAME_REGEX = re.compile(r"^[a-zA-Z][a-zA-Z0-9_-]{0,63}$")
_OWNER_REGEX = re.compile(r"^[a-zA-Z][a-zA-Z0-9_-]{0,63}$")


def _is_valid_identifier(value: str, pattern: re.Pattern[str]) -> bool:
    return bool(value) and bool(pattern.fullmatch(value))


def _require_env(key: str) -> str:
    value = os.getenv(key)
    if not value:
        raise RuntimeError(f"Environment variable {key} is required but not set.")
    return value.strip()


def create_database(db_name: str, owner: Optional[str] = None) -> None:
    """
    Create a new PostgreSQL database with a validated name and optional owner.
    Raises ValueError for invalid inputs and RuntimeError on database errors.
    """
    if not _is_valid_identifier(db_name, _DB_NAME_REGEX):
        raise ValueError("Invalid database name.")
    if owner is not None and not _is_valid_identifier(owner, _OWNER_REGEX):
        raise ValueError("Invalid owner name.")

    conn: Optional[psycopg2.extensions.connection] = None
    try:
        conn = psycopg2.connect(
            dbname="postgres",
            user=_require_env("POSTGRES_USER"),
            password=_require_env("POSTGRES_PASSWORD"),
        )
        conn.autocommit = True
        with conn.cursor() as cur:
            query = sql.SQL("CREATE DATABASE {db}").format(db=sql.Identifier(db_name))
            if owner:
                query = query + sql.SQL(" OWNER {owner}").format(owner=sql.Identifier(owner))
            cur.execute(query)
    except (OperationalError, Error) as exc:
        raise RuntimeError("Failed to create database.") from exc
    finally:
        if conn:
            conn.close()

