import torch
from torch.utils.data import DataLoader
from torchvision import datasets, transforms

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler()],
)

TRUSTED_MODELS_DIR = Path("./trusted_models").resolve()


def _validate_config(config: Any) -> Dict[str, Any]:
    if not isinstance(config, dict):
        raise ValueError("Configuration must be a dictionary.")
    for key, value in config.items():
        if not isinstance(key, str):
            raise ValueError(f"Config key {key!r} is not a string.")
        if not isinstance(value, (str, int, float, bool)):
            raise ValueError(
                f"Config value for key {key!r} has unsupported type {type(value).__name__}."
            )
    return config


def _validate_network_name(name: str) -> Path:
    if not isinstance(name, str) or not name.strip():
        raise ValueError("Network name must be a non-empty string.")
    path = Path(name).expanduser().resolve()
    if path.is_symlink():
        raise ValueError(f"Model path must not be a symlink: {path}")
    if not path.is_file():
        raise FileNotFoundError(f"Model file not found: {path}")
    if path.parent != TRUSTED_MODELS_DIR:
        raise ValueError(
            f"Model file must be located in trusted directory {TRUSTED_MODELS_DIR}"
        )
    if path.suffix.lower() not in {".pt", ".pth", ".jit"}:
        raise ValueError(f"Unsupported model file extension: {path.suffix}")
    return path


def _validate_dataset_name(name: str) -> str:
    if not isinstance(name, str) or not name.strip():
        raise ValueError("Dataset name must be a non-empty string.")
    allowed = {"mnist", "cifar10", "fashion_mnist"}
    key = name.lower()
    if key not in allowed:
        raise ValueError(
            f"Unsupported dataset: {name}. Allowed: {allowed}"
        )
    return key


def _validate_output_path(path_str: str) -> Path:
    if not isinstance(path_str, str) or not path_str.strip():
        raise ValueError("Output path must be a non-empty string.")
    path = Path(path_str).expanduser().resolve()
    if path.is_symlink():
        raise ValueError(f"Output path must not be a symlink: {path}")
    cwd = Path.cwd()
    try:
        path.relative_to(cwd)
    except ValueError:
        raise ValueError("Output path must be inside the current working directory.")
    path.parent.mkdir(parents=True, exist_ok=True)
    return path


def _load_model(path: Path) -> torch.nn.Module:
    try:
        model = torch.jit.load(str(path), map_location=torch.device("cpu"))
    except Exception as e:
        raise RuntimeError(f"Failed to load model: {e}") from None
    if not isinstance(model, torch.nn.Module):
        raise TypeError("Loaded object is not a PyTorch model.")
    return model


def _get_dataset_loader(dataset_name: str, batch_size: int = 64) -> DataLoader:
    transform = transforms.Compose([transforms.ToTensor()])
    if dataset_name == "mnist":
        dataset = datasets.MNIST(root=".", train=False, download=False, transform=transform)
    elif dataset_name == "fashion_mnist":
        dataset = datasets.FashionMNIST(root=".", train=False, download=False, transform=transform)
    elif dataset_name == "cifar10":
        dataset = datasets.CIFAR10(root=".", train=False, download=False, transform=transform)
    else:
        raise RuntimeError(f"Unsupported dataset: {dataset_name}")
    if not len(dataset):
        raise RuntimeError(f"Dataset {dataset_name} is empty or not downloaded.")
    return DataLoader(dataset, batch_size=batch_size, shuffle=False)


def run_inference(
    config: Any,
    network_name: str,
    dataset_name: str,
    output_path: str,
) -> None:
    try:
        sanitized_config = _validate_config(config)
        model_path = _validate_network_name(network_name)
        dataset_key = _validate_dataset_name(dataset_name)
        output_file = _validate_output_path(output_path)

        logging.info("Starting inference with validated parameters.")

        model = _load_model(model_path)
        model.eval()

        test_loader = _get_dataset_loader(dataset_key)

        device = torch.device("cpu")
        all_outputs = []

        with torch.no_grad():
            for batch_idx, (data, _) in enumerate(test_loader):
                data = data.to(device)
                outputs = model(data)
                all_outputs.append(outputs.cpu())

        if not all_outputs:
            raise RuntimeError("Inference produced no outputs.")
        all_outputs_tensor = torch.cat(all_outputs, dim=0)

        torch.save(all_outputs_tensor, output_file)
        logging.info("Inference completed. Results saved to %s", output_file)

    except Exception as exc:
        logging.debug("Validation or inference error: %s", exc, exc_info=True)
        logging.error("An error occurred. See debug logs for details.")
        raise RuntimeError("Inference failed.") from None


if __name__ == "__main__":
    sample_config = {"batch_size": 64}
    try:
        run_inference(
            config=sample_config,
            network_name="trusted_models/example.pt",
            dataset_name="mnist",
            output_path="inference_output.pt",
        )
    except RuntimeError as e:
        logging.critical(e)

