def _validate_value(value, *, depth=0, depth_limit=10, max_length=1000):
    """Recursively validate that a value is JSON-serialisable-like with limits."""
    if depth > depth_limit:
        raise ValueError("Maximum depth exceeded for value")
    if isinstance(value, (str, int, float, bool, type(None))):
        return
    if isinstance(value, (list, tuple)):
        if len(value) > max_length:
            raise ValueError("Container too large")
        for item in value:
            _validate_value(item, depth=depth + 1, depth_limit=depth_limit, max_length=max_length)
    elif isinstance(value, dict):
        if len(value) > max_length:
            raise ValueError("Container too large")
        for key, val in value.items():
            if not isinstance(key, str):
                raise ValueError("Dictionary keys must be strings")
            _validate_value(val, depth=depth + 1, depth_limit=depth_limit, max_length=max_length)
    else:
        raise ValueError(f"Unsupported type: {type(value).__name__}")


def update_function(params: dict, func: types.FunctionType) -> types.FunctionType:
    """
    Returns a new function that behaves like `func` but can override
    parameters with values from `params`. The returned function has the
    same name, docstring, and representation as the original.
    """
    if not isinstance(params, dict):
        raise TypeError("params must be a dictionary")
    if not callable(func):
        raise TypeError("func must be callable")

    for key in params:
        if not isinstance(key, str):
            raise TypeError(f"Parameter name {key!r} is not a string")
        try:
            _validate_value(params[key])
        except ValueError as exc:
            raise ValueError(f"Parameter value for {key!r} is not valid: {exc}") from None

    try:
        orig_sig = inspect.signature(func)
    except ValueError:
        raise TypeError("Unable to inspect the signature of the provided function")

    for key in params:
        if key not in orig_sig.parameters:
            raise ValueError(f"Parameter {key!r} does not exist in the function's signature")

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        try:
            bound = orig_sig.bind_partial(*args, **kwargs)
        except TypeError as exc:
            raise TypeError(f"Argument error: {exc}") from None

        for key, value in params.items():
            if key not in bound.arguments:
                bound.arguments[key] = value

        try:
            return func(**bound.arguments)
        except Exception as exc:
            raise RuntimeError("An error occurred while executing the function") from None

    wrapper.__repr__ = lambda: f"<function {func.__name__}>"
    return wrapper

