import logging
from scapy.all import Packet
from scapy.layers.inet import IP, TCP
from scapy.layers.udp import UDP
from scapy.layers.http import HTTP, HTTPRequest, HTTPResponse

logging.basicConfig(level=logging.WARNING, format='%(levelname)s: %(message)s')
_MAX_LAYER_COUNT = 100  # Hard limit to mitigate DoS attacks


def update_packet(packet: Packet) -> Packet | None:
    """
    Update and sanitize packet layers.
    Removes HTTP-related layers and updates common header fields.
    Returns a new packet or None if all layers were removed.
    """
    if not isinstance(packet, Packet):
        raise TypeError("Input must be a scapy Packet")

    try:
        new_layers = []
        for idx, layer in enumerate(packet.iter_payload(), start=1):
            if idx > _MAX_LAYER_COUNT:
                logging.warning("Packet truncated: too many layers")
                break

            layer_name = layer.name
            if layer_name in {"HTTP", "HTTPRequest", "HTTPResponse"}:
                continue

            if isinstance(layer, IP):
                layer.ttl = 64
                layer.id = 0
            elif isinstance(layer, TCP):
                layer.flags = "PA"
            elif isinstance(layer, UDP):
                layer.chksum = None
            elif hasattr(layer, "load"):
                payload = layer.load
                if isinstance(payload, bytes) and len(payload) > 2048:
                    layer.load = payload[:2048]

            new_layers.append(layer.copy())

        if not new_layers:
            return None

        pkt = new_layers[0]
        for nxt in new_layers[1:]:
            pkt = pkt / nxt
        return pkt
    except Exception:
        logging.warning("Failed to update packet.")
        return None

import re
