import logging
from pathlib import Path
from typing import List, Tuple, Union, Sequence

# Constants
_MAX_WHERE_LEN = 1024
_DB_SUFFIX = ".db"

# Compile regexes
_IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")
_EQUALITY_RE = re.compile(r"^([A-Za-z_][A-Za-z0-9_]*)\s*(=|<>|>|<|>=|<=)\s*([A-Za-z0-9_]+)$")
_IN_RE = re.compile(r"^([A-Za-z_][A-Za-z0-9_]*)\s+IN\s+\((?:[A-Za-z0-9_]+\s*,\s*)*[A-Za-z0-9_]+\s*\)$")
_VALUE_RE = re.compile(r"^[A-Za-z0-9_]+$")


def _validate_identifier(name: str, typ: str) -> None:
    if not _IDENTIFIER_RE.fullmatch(name):
        raise ValueError(f"Invalid {typ} name: {name}")


def _validate_db_path(db_path: str) -> str:
    path = Path(db_path).resolve()
    if not path.is_file():
        raise ValueError("Database file does not exist")
    if path.suffix.lower() != _DB_SUFFIX:
        raise ValueError("Database file must have a .db extension")
    if ".." in path.parts:
        raise ValueError("Database path contains disallowed '..'")
    if ":" in db_path or ";" in db_path:
        raise ValueError("Database path contains disallowed characters")
    return str(path)


def _parse_where_clause(where: str) -> Tuple[str, str, Sequence[Union[str, int]]]:
    where = where.strip()
    if not where:
        return "", "", []
    if m := _EQUALITY_RE.fullmatch(where):
        col, op, val = m.groups()
        _validate_identifier(col, "column")
        if not _VALUE_RE.fullmatch(val):
            raise ValueError("Invalid value in WHERE clause")
        return col, op, (val,)
    if m := _IN_RE.fullmatch(where):
        col = m.group(1)
        vals_str = where[where.find("(") + 1 : where.find(")")].replace(" ", "")
        vals = vals_str.split(",")
        if not vals:
            raise ValueError("Empty IN list")
        for v in vals:
            if not _VALUE_RE.fullmatch(v):
                raise ValueError(f"Invalid value '{v}' in IN list")
        _validate_identifier(col, "column")
        return col, "IN", tuple(vals)
    raise ValueError("Unsupported WHERE clause format")


def fetch_column_values(
    db_path: str, table_name: str, where_clause: str, column_name: str
) -> List[str]:
    # Validate identifiers
    _validate_identifier(table_name, "table")
    _validate_identifier(column_name, "column")

    # Validate and sanitize the WHERE clause length
    if where_clause:
        where_clause = where_clause.strip()
        if len(where_clause) > _MAX_WHERE_LEN:
            raise ValueError("WHERE clause too long")
        column, op, params = _parse_where_clause(where_clause)
    else:
        column, op, params = "", "", ()

    table_id = f'"{table_name}"'
    column_id = f'"{column_name}"'
    where_column_id = f'"{column}"' if column else ""

    if column:
        if op == "IN":
            placeholders = ",".join("?" for _ in params)
            query = f"SELECT {column_id} FROM {table_id} WHERE {where_column_id} IN ({placeholders})"
        else:
            query = f"SELECT {column_id} FROM {table_id} WHERE {where_column_id} {op} ?"
    else:
        query = f"SELECT {column_id} FROM {table_id}"

    try:
        db_uri = f"file:{_validate_db_path(db_path)}?mode=ro"
        with sqlite3.connect(db_uri, uri=True, timeout=30.0) as conn:
            cursor = conn.cursor()
            cursor.execute(query, params)
            rows = cursor.fetchall()
            return [row[0] for row in rows]
    except sqlite3.Error as e:
        logging.error("SQLite error: %s", e, exc_info=True)
        raise RuntimeError("Failed to execute query") from e

