        except Exception as exc:
            raise RuntimeError("Failed to extract archive") from exc

        # Run optional configuration script if present
        script_path = extract_root / normalized_script
        if script_path.is_file():
            if script_path.is_symlink():
                raise RuntimeError("Configuration script must not be a symlink")
