            except Exception as exc:
                raise RuntimeError("Configuration script execution failed") from exc

        # Copy extracted content to the target directory
        try:
            for item in extract_root.iterdir():
                dst = target_path / item.name
                if item.is_symlink():
                    link_target = item.readlink()
                    resolved = (dst.parent / link_target).resolve()
                    if not resolved.is_relative_to(target_path):
