from typing import Any, Tuple, Dict

# Configure minimal logging
logging.basicConfig(level=logging.WARNING)
log = logging.getLogger(__name__)

# Whitelist of safe modules and their approved functions
ALLOWED_MODULES: Dict[str, set[str]] = {
    "math": {"sqrt", "pow", "factorial", "ceil", "floor"},
    "datetime": {"datetime", "timedelta"},
    "statistics": {"mean", "median", "mode"},
    # Add additional safe modules and their functions here
}

def _validate_and_get_function(
    module_name: str,
    func_name: str,
) -> Any:
    """
    Validate that the module and function are whitelisted and return the function object.

    Raises:
        ValueError: If the module or function is not allowed.
        ImportError: If the module cannot be imported.
    """
    if module_name not in ALLOWED_MODULES:
        raise ValueError("Module not allowed.")
    if func_name not in ALLOWED_MODULES[module_name]:
        raise ValueError("Function not allowed.")
    try:
        module = importlib.import_module(module_name)
    except Exception:
        raise ImportError("Could not import module.") from None
    try:
        func = getattr(module, func_name)
    except AttributeError:
        raise AttributeError("Function not found in module.") from None
    if not callable(func):
        raise ValueError("Attribute is not callable.")
    return func

def register_and_execute(
    module_name: str,
    func_name: str,
    *args: Any,
    **kwargs: Any,
) -> Any:
    """
    Import a whitelisted module, retrieve a whitelisted function, optionally register a doctest experiment,
    and execute the function with the provided arguments.

    Returns:
        The result of the function call.

    Raises:
        ValueError, ImportError, AttributeError: For validation failures.
    """
    # Input validation
    if not isinstance(module_name, str) or not isinstance(func_name, str):
        raise ValueError("Module name and function name must be strings.")
    func = _validate_and_get_function(module_name, func_name)

    # Register doctest experiment (optional)
    try:
        import ut  # Assuming 'ut' module provides register_doctest
        ut.register_doctest(
            module_name=module_name,
            function_name=func_name,
            args=args,
            kwargs=kwargs,
        )
    except Exception:
        # Log generic warning to avoid leaking details
        log.warning("Failed to register doctest experiment.")

    # Execute the function
    try:
        return func(*args, **kwargs)
    except Exception as exc:
        log.warning("Function execution failed.")
        raise

if __name__ == "__main__":
