import json
import re
import pathlib
import os
import stat
from typing import Iterator, Optional, Union, Dict, Any

try:
    import boto3
    from botocore.exceptions import BotoCoreError, ClientError
except ImportError:
    boto3 = None  # S3 functionality will not be available


class InputMissingError(RuntimeError):
    """Raised when the requested input does not exist and fail_missing is True."""


class SecureInputSource:
    _DEFAULT_ROOT = pathlib.Path("/var/app/input")

    _S3_BUCKET_REGEX = re.compile(r"^(?!-)[a-z0-9-]{1,63}(?<!-)$")
    _S3_KEY_REGEX = re.compile(r"^[^�-@]+$")  # disallow control and '@'
    _PROHIBITED_PATH_COMPONENTS = {"..", "", "."}

    def __init__(
        self,
        *,
        source_type: str,
        path: Optional[str] = None,
        bucket_name: Optional[str] = None,
        object_key: Optional[str] = None,
        fail_missing: bool = True,
        root_dir: Optional[str] = None,
    ) -> None:
        if source_type not in ("file", "s3"):
            raise ValueError("source_type must be 'file' or 's3'")
        self.source_type = source_type
        self.fail_missing = fail_missing

        # Resolve and validate root_dir
        root_path = pathlib.Path(root_dir or self._DEFAULT_ROOT).expanduser().resolve()
        if not root_path.is_dir():
            raise ValueError(f"root_dir '{root_path}' is not a directory")
        # Enforce root_dir must be under DEFAULT_ROOT
        try:
            if not root_path.is_relative_to(self._DEFAULT_ROOT):
                raise ValueError(f"root_dir '{root_path}' is outside allowed base {self._DEFAULT_ROOT}")
        except AttributeError:
            if not str(root_path).startswith(str(self._DEFAULT_ROOT)):
                raise ValueError(f"root_dir '{root_path}' is outside allowed base {self._DEFAULT_ROOT}")
        self.root_dir = root_path

        if source_type == "file":
            if not path:
                raise ValueError("path must be provided for file source")
            self.path = self._sanitize_and_validate_path(path)
        else:  # s3
            if not (bucket_name and object_key):
                raise ValueError("bucket_name and object_key must be provided for s3 source")
            self.bucket_name = self._sanitize_and_validate_bucket(bucket_name)
            self.object_key = self._sanitize_and_validate_key(object_key)

    def _sanitize_and_validate_path(self, path: str) -> str:
        """Validate that the provided path is within the root directory and points to an existing file."""
        if "�" in path:
            raise ValueError("path contains null byte")
        p = pathlib.Path(path).expanduser()
        resolved = p.resolve(strict=False)
        for comp in resolved.parts:
            if comp in self._PROHIBITED_PATH_COMPONENTS:
                raise InputMissingError("Path contains prohibited components")
        try:
            if not resolved.is_relative_to(self.root_dir):
                raise InputMissingError("Path outside allowed directory")
        except AttributeError:
            if not str(resolved).startswith(str(self.root_dir)):
                raise InputMissingError("Path outside allowed directory")
        return str(resolved)

    @staticmethod
    def _sanitize_and_validate_bucket(bucket: str) -> str:
        """Validate the S3 bucket name against AWS naming rules."""
        if not SecureInputSource._S3_BUCKET_REGEX.fullmatch(bucket):
            raise ValueError(f"Invalid S3 bucket name: {bucket}")
        if ".." in bucket or bucket.startswith(".") or bucket.endswith("."):
            raise ValueError(f"Invalid S3 bucket name: {bucket}")
        return bucket

    @staticmethod
    def _sanitize_and_validate_key(key: str) -> str:
        """Validate the S3 object key to prevent traversal or injection."""
        if not key:
            raise ValueError("Object key cannot be empty")
        if any(comp in SecureInputSource._PROHIBITED_PATH_COMPONENTS for comp in key.split("/")):
            raise ValueError("Object key contains prohibited path components")
        if not SecureInputSource._S3_KEY_REGEX.fullmatch(key):
            raise ValueError("Invalid object key format")
        return key

    def __iter__(self) -> Iterator[str]:
        if self.source_type == "file":
            return self._file_line_iterator()
        return self._s3_line_iterator()

    def _file_line_iterator(self) -> Iterator[str]:
        file_path = pathlib.Path(self.path)
        if not file_path.is_file():
            if self.fail_missing:
                raise InputMissingError("File does not exist")
            return iter([])
        fd = os.open(
            str(file_path),
            os.O_RDONLY | os.O_CLOEXEC | os.O_NOFOLLOW
        )
        try:
            with os.fdopen(fd, 'r', encoding="utf-8", errors="replace") as f:
                # Verify the opened file is regular
                st = os.fstat(f.fileno())
                if not stat.S_ISREG(st.st_mode):
                    raise InputMissingError("Opened path is not a regular file")
                for line in f:
                    yield line.rstrip("
")
        finally:
            if not fd.closed:
                os.close(fd)

    def _s3_line_iterator(self) -> Iterator[str]:
        if boto3 is None:
            raise RuntimeError("boto3 library is required for S3 access")
        s3 = boto3.client("s3", config=boto3.session.Config(use_ssl=True))
        try:
            response = s3.get_object(Bucket=self.bucket_name, Key=self.object_key)
            body = response["Body"]
            for line_bytes in body.iter_lines():
                yield line_bytes.decode("utf-8", errors="replace")
        except ClientError as exc:
            code = exc.response.get("Error", {}).get("Code")
            if code == "NoSuchKey":
                if self.fail_missing:
                    raise InputMissingError("S3 object not found")
                return iter([])
            raise RuntimeError("Error accessing S3 object") from exc
        except Exception as exc:
            raise RuntimeError("Unexpected error accessing S3 object") from exc

    @classmethod
    def from_json(cls, data: Union[str, Dict[str, Any]]) -> "SecureInputSource":
        if isinstance(data, str):
            try:
                payload = json.loads(data)
            except json.JSONDecodeError as exc:
                raise ValueError("Invalid JSON string") from exc
        elif isinstance(data, dict):
            payload = data
        else:
            raise TypeError("data must be a str or dict")

        source_type = payload.get("source_type")
        fail_missing = payload.get("fail_missing", True)

        allowed_keys_file = {"source_type", "fail_missing", "path"}
        allowed_keys_s3 = {"source_type", "fail_missing", "bucket_name", "object_key"}

        if source_type == "file":
            if set(payload.keys()) - allowed_keys_file:
                raise ValueError("Unexpected keys for file source")
            path = payload.get("path")
            if path is None:
                raise ValueError("Missing 'path' for file source")
            return cls(source_type="file", path=path, fail_missing=fail_missing)
        if source_type == "s3":
            if set(payload.keys()) - allowed_keys_s3:
                raise ValueError("Unexpected keys for s3 source")
            bucket_name = payload.get("bucket_name")
            object_key = payload.get("object_key")
            if bucket_name is None or object_key is None:
                raise ValueError("Missing 'bucket_name' or 'object_key' for s3 source")
            return cls(
                source_type="s3",
                bucket_name=bucket_name,
                object_key=object_key,
                fail_missing=fail_missing,
            )
        raise ValueError("source_type must be 'file' or 's3'")

    def to_json(self) -> str:
        payload = {
            "source_type": self.source_type,
            "fail_missing": self.fail_missing,
        }
        if self.source_type == "file":
            payload["path"] = self.path
        else:
            payload["bucket_name"] = self.bucket_name
            payload["object_key"] = self.object_key
        return json.dumps(payload, separators=(",", ":"))

    @staticmethod
    def _escape_component(comp: str) -> str:
        return comp.replace("
", "\n").replace("", "\r")

    @property
    def display_name(self) -> str:
        if self.source_type == "file":
            return f"File: {self._escape_component(self.path)}"
        return f"S3: {self._escape_component(self.bucket_name)}/{self._escape_component(self.object_key)}"

