def sanitize_path(path):
    """Resolve a path to an absolute, real directory; exit on error."""
    abs_path = os.path.abspath(path)
    real_path = os.path.realpath(abs_path)
    if not os.path.isdir(real_path):
        logging.error(f"Path is not a directory: {path}")
        sys.exit(1)
    return real_path

def discover_py_scripts(root_dir, output_file):
    """Recursively find .py files under root_dir and write canonical paths to output_file."""
    try:
        with open(output_file, 'w', encoding='utf-8') as out_f:
            for dirpath, dirs, filenames in os.walk(root_dir, topdown=True):
                # Remove hidden subdirectories from traversal
                dirs[:] = [d for d in dirs if not d.startswith('.')]
                for fname in filenames:
                    if fname.lower().endswith('.py'):
                        py_path = os.path.normpath(os.path.realpath(os.path.join(dirpath, fname)))
                        out_f.write(py_path + os.linesep)
    except (OSError, PermissionError) as e:
        logging.error(f"Error accessing files: {e}")
        sys.exit(1)

def main():
    os.umask(0o077)

    script_dir = os.path.realpath(os.path.dirname(__file__))

    if len(sys.argv) >= 2:
        root_dir = sanitize_path(sys.argv[1])
    else:
        root_dir = os.path.realpath(os.getcwd())

