logger = logging.getLogger(__name__)

def _secure_copytree(src: Path, dest: Path, src_root: Path) -> None:
    """
    Recursively copy |src| to |dest| ensuring that all symbolic links within
    the source point inside the source tree. Files and directories are
    copied with metadata preserved. Symlinks are resolved and the target's
    contents are copied, not the symlink itself.
    """
    if dest.exists():
        if not dest.is_dir():
            raise RuntimeError(f"Destination {dest} exists and is not a directory.")
    else:
        dest.mkdir(parents=True, exist_ok=True)
        shutil.copystat(src, dest, follow_symlinks=False)

    for child in src.iterdir():
        child_dest = dest / child.name
        if child.is_symlink():
            try:
                target = child.resolve(strict=True)
            except FileNotFoundError:
                raise RuntimeError(f"Broken symlink detected: {child}") from None
            if not target.is_relative_to(src_root):
                raise RuntimeError(
                    f"Symlink {child} points outside the source directory: {target}"
                )
            shutil.copy2(child, child_dest, follow_symlinks=False)
        elif child.is_dir():
            _secure_copytree(child, child_dest, src_root)
        else:
            shutil.copy2(child, child_dest, follow_symlinks=False)

    # Finalize directory metadata (in case it was just created)
    if not dest.exists():
        shutil.copystat(src, dest, follow_symlinks=False)


def copy_directory(src: Union[str, Path], dest: Union[str, Path]) -> None:
    """
    Securely copy a directory from |src| to |dest| without following
    external symbolic links. The operation validates each symlink
    atomically as it is copied and ensures that the destination
    is not a symlink and is not located inside the source tree.
    """
    src_path = Path(src).expanduser()
    if not src_path.exists() or not src_path.is_dir():
        raise ValueError("Source must be an existing directory")

    dest_raw = Path(dest).expanduser()
    if dest_raw.is_symlink():
        raise ValueError("Destination must not be a symlink")

    dest_path = dest_raw.resolve(strict=False)

    if src_path.resolve() == dest_path:
        raise ValueError("Source and destination cannot be the same")

    if dest_path.is_relative_to(src_path):
        raise ValueError("Destination cannot be inside the source directory")

    dest_parent = dest_path.parent
    if not dest_parent.exists():
        raise ValueError("Destination parent directory does not exist")
    if not os.access(dest_parent, os.W_OK):
        raise PermissionError(f"Write permission denied for {dest_parent}")

    try:
        _secure_copytree(src_path.resolve(), dest_path, src_path.resolve())
    except RuntimeError as e:
        logger.error(e)
        raise
    except Exception as e:
        logger.error("Unexpected error during copy operation")
        raise RuntimeError("Directory copy failed") from e

    logger.debug(f"Completed copy from {src_path} to {dest_path}")

