import tarfile
import pathlib
from typing import Union, Any

def safe_extract_tarball(tar_path: Union[str, os.PathLike, pathlib.Path],
                         extract_dir: Union[str, os.PathLike, pathlib.Path]) -> None:
    # Validate input types
    if not isinstance(tar_path, (str, os.PathLike, pathlib.Path)):
        raise TypeError("tar_path must be a string or PathLike object")
    if not isinstance(extract_dir, (str, os.PathLike, pathlib.Path)):
        raise TypeError("extract_dir must be a string or PathLike object")

    tar_path = pathlib.Path(tar_path).expanduser().resolve(strict=True)
    extract_dir = pathlib.Path(extract_dir).expanduser().resolve(strict=True)

    # Reject if tar_path is a symlink to mitigate link attacks
    if tar_path.is_symlink():
        raise PermissionError(f"tar_path is a symlink: {tar_path}")

    # Ensure tar_path is a regular file
    if not tar_path.is_file():
        raise FileNotFoundError(f"Tar file not found or not a file: {tar_path}")

    # Guard against rogue tar file permissions
    mode = tar_path.stat().st_mode
    insecure_mask = stat.S_IWOTH | stat.S_IWGRP | stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH
    if mode & insecure_mask:
        safe_mode = mode & ~insecure_mask
        try:
            tar_path.chmod(safe_mode)
        except PermissionError as exc:
            raise PermissionError(f"Unable to modify permissions on tar file: {tar_path}") from exc

    # Ensure extraction directory is a directory (or create it if missing)
    if extract_dir.exists() and not extract_dir.is_dir():
        raise NotADirectoryError(f"Extraction target exists but is not a directory: {extract_dir}")
    # Reject if extract_dir is a symlink
    if extract_dir.is_symlink():
        raise PermissionError(f"extract_dir is a symlink: {extract_dir}")

    try:
        extract_dir.mkdir(parents=True, mode=0o750, exist_ok=True)
    except OSError as exc:
        raise RuntimeError(f"Could not create extraction directory: {extract_dir}") from exc

    try:
        with tarfile.open(tar_path, mode="r:*") as tar:
            for member in tar.getmembers():
                # Skip device files and links to prevent arbitrary file creation
                if member.isdev() or member.issym() or member.islnk():
                    continue
                # Normalize member name to avoid leading slashes
                member_name = pathlib.Path(member.name).as_posix()
                if member_name.startswith("/") or ".." in pathlib.Path(member_name).parts:
                    raise RuntimeError(f"Unsafe member name detected: {member.name}")

                member_path = (extract_dir / member_name).resolve()
                # Ensure extraction path remains under target directory
                if not (member_path == extract_dir or str(member_path).startswith(str(extract_dir) + os.sep)):
                    raise RuntimeError(f"Path traversal detected for member: {member.name}")

                tar.extract(member, path=str(extract_dir))
    except tarfile.TarError as exc:
        raise RuntimeError(f"Tar extraction error: {exc}") from exc
    except PermissionError as exc:
        raise PermissionError(f"Unable to read or extract tar file: {tar_path}") from exc
    except Exception as exc:  # pragma: no cover
        raise RuntimeError("Extraction failed.") from exc

    # Normalize permissions of the extracted files and directories
    for root, dirs, files in os.walk(extract_dir, topdown=True, followlinks=False):
        root_path = pathlib.Path(root)
        for d in dirs:
            dir_path = root_path / d
            try:
                dir_path.chmod(0o750)
            except PermissionError:
                pass  # ignore if we cannot change permissions
        for f in files:
            file_path = root_path / f
            try:
                file_path.chmod(0o640)
            except PermissionError:
                pass

