        return self._server_folder

    @property
    def connected(self) -> bool:
        return self._connected

    def connect(self) -> bool:
        try:
            if not self._volume_path.exists():
                raise FileNotFoundError("Volume path does not exist")
            if not self._server_folder.is_dir():
                raise FileNotFoundError("Server folder does not exist")
            # TODO: Replace with real connection logic using self._target_ip,
            # self._username, self._password
            self._connected = True
            return True
        except (FileNotFoundError, PermissionError, OSError):
            self._connected = False
            return False

    def __repr__(self) -> str:
        return (
            f"{self.__class__.__name__}(target_ip={self._target_ip!r}, "
            f"username={self._username!r}, volume_path={self._volume_path!s}, "
            f"server_folder={self._server_folder!s}, connected={self._connected})"
        )


def _validate_ip(ip: str) -> str:
    try:
        return str(ipaddress.ip_address(ip))
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc


def _validate_non_empty(key: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ValueError(f"{key} must be a non-empty string")
    return value.strip()


def _validate_path(raw: str, key: str, *, must_exist: bool = True,
                   must_be_dir: Optional[bool] = None) -> pathlib.Path:
    path = pathlib.Path(raw).expanduser().resolve(strict=must_exist)
    if must_be_dir is True and not path.is_dir():
        raise ValueError(f"{key} must be a directory")
    if must_be_dir is False and not path.is_file():
        raise ValueError(f"{key} must be a file")
    return path


def configure_dell_iscsi_driver(params: Dict[str, Any]) -> DellIScsiDriver:
    required_keys = {"target_ip", "username", "password", "volume_path", "server_folder"}
    missing = required_keys - params.keys()
    if missing:
        raise ValueError(f"Missing configuration keys: {', '.join(sorted(missing))}")

    ip = _validate_ip(params["target_ip"])
    username = _validate_non_empty("username", params["username"])
    password = _validate_non_empty("password", params["password"])
    volume_path = _validate_path(params["volume_path"], "volume_path", must_be_dir=False)
    server_folder = _validate_path(params["server_folder"], "server_folder", must_be_dir=True)

    driver = DellIScsiDriver(
        target_ip=ip,
        username=username,
        password=password,
        volume_path=volume_path,
        server_folder=server_folder,
    )

    if not driver.connect():
        raise RuntimeError("Failed to establish iSCSI connection")

    return driver

import secrets
import logging
from dataclasses import dataclass
from typing import Any

logger = logging.getLogger(__name__)

@dataclass(frozen=True)
class RegistrationProfile:
    user: Any
    activation_key: str
    salt: str

def create_registration_profile(user: Any) -> RegistrationProfile:
    """Create a registration profile with a SHA-256 activation key and a securely generated salt."""
    if not user:
        raise ValueError("User must be provided")

    username = getattr(user, "username", None)
    if not isinstance(username, str) or not username.strip():
        raise ValueError("User must have a non-empty username string")

    try:
        salt_bytes = secrets.token_bytes(16)
    except Exception as exc:
        logger.exception("Secure random bytes generation failed")
        raise RuntimeError("Could not generate salt") from exc

    salt_hex = salt_bytes.hex()
    hash_input = f"{username.strip().lower()}{salt_hex}".encode("utf-8")

    try:
        activation_hash = secrets.hashlib.sha256(hash_input).hexdigest()
    except Exception as exc:
        logger.exception("Hashing failed")
        raise RuntimeError("Could not generate activation key") from exc

    return RegistrationProfile(user=user, activation_key=activation_hash, salt=salt_hex)

