def _is_valid_date(value: Any) -> bool:
    if isinstance(value, datetime):
        return True
    if isinstance(value, str):
        try:
            datetime.fromisoformat(value)
            return True
        except ValueError:
            return False
    return False

def _sanitize_date(value: Any) -> Optional[str]:
    if isinstance(value, datetime):
        return value.strftime("%Y-%m-%d %H:%M:%S")
    if isinstance(value, str) and _is_valid_date(value):
        return datetime.fromisoformat(value).strftime("%Y-%m-%d %H:%M:%S")
    return None

def update_user_and_problems(
    conn: mysql.connector.connection.MySQLConnection,
    user_info: Dict[str, Any],
    problem_records: List[Dict[str, Any]]
) -> None:
    """
    Update user score, solved count, and last solved date,
    and update problem statistics atomically.
    """
    # Input validation
    required_user_keys = {"user_id", "score_delta", "solved_delta", "last_solved_date"}
    missing_user_keys = required_user_keys - user_info.keys()
    if missing_user_keys:
        raise ValueError(f"Missing required user_info keys: {missing_user_keys}")

    if not isinstance(user_info["user_id"], int):
        raise TypeError("user_id must be an integer")
    if not isinstance(user_info["score_delta"], (int, float)):
        raise TypeError("score_delta must be numeric")
    if not isinstance(user_info["solved_delta"], int):
        raise TypeError("solved_delta must be an integer")

    last_user_date = _sanitize_date(user_info["last_solved_date"])
    if last_user_date is None:
        raise ValueError("last_solved_date must be a valid datetime string or datetime object")

    for rec in problem_records:
        required_problem_keys = {"problem_id", "solved_delta", "last_solved_user", "last_solved_date"}
        missing_problem_keys = required_problem_keys - rec.keys()
        if missing_problem_keys:
            raise ValueError(f"Missing required problem record keys: {missing_problem_keys}")
        if not isinstance(rec["problem_id"], int):
            raise TypeError("problem_id must be an integer")
        if not isinstance(rec["solved_delta"], int):
            raise TypeError("solved_delta must be an integer")
        if not isinstance(rec["last_solved_user"], int):
            raise TypeError("last_solved_user must be an integer")
        sanitized_date = _sanitize_date(rec["last_solved_date"])
        if sanitized_date is None:
            raise ValueError("last_solved_date in problem record must be a valid datetime")

    cursor = None
    try:
        cursor = conn.cursor()
        conn.start_transaction()
        user_update_sql = (
            "UPDATE users "
            "SET score = score + %s, "
            "solved_count = solved_count + %s, "
            "last_solved_date = %s "
            "WHERE id = %s"
        )
        cursor.execute(
            user_update_sql,
            (
                user_info["score_delta"],
                user_info["solved_delta"],
                last_user_date,
                user_info["user_id"],
            ),
        )
        problem_update_sql = (
            "UPDATE problem_stats "
            "SET users_solved_count = users_solved_count + %s, "
            "last_solved_user = %s, "
            "last_solved_date = %s "
            "WHERE problem_id = %s"
        )
        for rec in problem_records:
            sanitized_date = _sanitize_date(rec["last_solved_date"])
            cursor.execute(
                problem_update_sql,
                (
                    rec["solved_delta"],
                    rec["last_solved_user"],
                    sanitized_date,
                    rec["problem_id"],
                ),
            )
        conn.commit()
    except Error as exc:
        logging.error("Database operation failed: %s", str(exc)[:200])
        conn.rollback()
        raise
    finally:
        if cursor is not None:
            cursor.close()

CREATE OR REPLACE FUNCTION rename_and_add_column(
    p_table_name   text,
    p_old_col      text,
    p_new_col      text,
    p_data_type    text,
    p_not_null     boolean DEFAULT false,
    p_default      text   DEFAULT NULL,
    p_check        text   DEFAULT NULL
)
RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql_rename  text;
    v_sql_add     text;
    v_schema       text := current_schema();
    allowed_types text[] := ARRAY[
        'smallint', 'integer', 'bigint',
        'numeric', 'decimal', 'real', 'double precision',
        'serial', 'bigserial', 'money',
        'char', 'varchar', 'text',
        'boolean', 'date', 'timestamp', 'time', 'interval',
        'bytea', 'uuid',
        'json', 'jsonb'
    ];
    disallowed_patterns text[] := ARRAY[
        '%;%','%--%','%/*%','%*/%','%drop%','%alter%','%create%','%grant%','%revoke%','%insert%','%update%','%delete%','%where%'
    ];
    constraint_sql  text := '';
BEGIN
    -- Validate data type
    IF NOT lower(p_data_type) = ANY(allowed_types) THEN
        RAISE EXCEPTION 'Unsupported data type %', p_data_type;
    END IF;

    -- Check target table existence
    IF NOT EXISTS (
        SELECT 1
        FROM information_schema.tables
        WHERE table_schema = v_schema
          AND table_name = p_table_name
    ) THEN
        RAISE EXCEPTION 'Table % does not exist', p_table_name;
    END IF;

    -- Check that old column exists
    IF NOT EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = v_schema
          AND table_name  = p_table_name
          AND column_name = p_old_col
    ) THEN
        RAISE EXCEPTION 'Column % does not exist in table %', p_old_col, p_table_name;
    END IF;

    -- Check that new column does not already exist
    IF EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = v_schema
          AND table_name  = p_table_name
          AND column_name = p_new_col
    ) THEN
        RAISE EXCEPTION 'Column % already exists in table %', p_new_col, p_table_name;
    END IF;

    -- Validate p_check expression
    IF p_check IS NOT NULL THEN
        IF p_check ILIKE ANY(disallowed_patterns) THEN
            RAISE EXCEPTION 'p_check contains disallowed patterns';
        END IF;
        IF NOT (lower(p_check) LIKE 'check (%' AND lower(p_check) LIKE '%)%') THEN
            IF lower(p_check) NOT LIKE 'check (%' THEN
                RAISE EXCEPTION 'p_check must start with CHECK(';
            END IF;
            IF lower(p_check) NOT LIKE '%)%' THEN
                RAISE EXCEPTION 'p_check must end with )';
            END IF;
        END IF;
        constraint_sql := concat(constraint_sql, ' ', p_check);
    END IF;

    -- Build NOT NULL and DEFAULT constraints
    IF p_not_null THEN
        constraint_sql := concat(constraint_sql, ' NOT NULL');
    END IF;

    IF p_default IS NOT NULL THEN
        constraint_sql := concat(constraint_sql, ' DEFAULT ', quote_nullable(p_default));
    END IF;

    -- Rename column
    v_sql_rename := format(
        'ALTER TABLE %I.%I RENAME COLUMN %I TO %I',
        v_schema, p_table_name, p_old_col, p_new_col
    );
    EXECUTE v_sql_rename;

    -- Add column with constraints
    v_sql_add := format(
        'ALTER TABLE %I.%I ADD COLUMN %I %s%s',
        v_schema, p_table_name, p_new_col, p_data_type, constraint_sql
    );
    EXECUTE v_sql_add;

    RETURN TRUE;
EXCEPTION
    WHEN OTHERS THEN
        RAISE LOG 'rename_and_add_column failed at % on table %I', now(), p_table_name;
        RETURN FALSE;
END;
$$;

