PAYPAL_MODE = os.getenv("PAYPAL_MODE", "sandbox")
PAYPAL_API_BASE = (
    "https://api.sandbox.paypal.com"
    if PAYPAL_MODE == "sandbox"
    else "https://api.paypal.com"
)
PAYPAL_OAUTH_URL = f"{PAYPAL_API_BASE}/v1/oauth2/token"
PAYPAL_PAYMENT_CREATE_URL = f"{PAYPAL_API_BASE}/v1/payments/payment"


def validate_paypal_credentials(client_id: str, client_secret: str) -> bool:
    return bool(client_id.strip() and client_secret.strip())


def get_access_token(client_id: str, client_secret: str) -> str:
    auth = (client_id, client_secret)
    payload = {"grant_type": "client_credentials"}
    response = requests.post(
        PAYPAL_OAUTH_URL, data=payload, auth=auth, timeout=10
    )
    if response.status_code != 200:
        raise RuntimeError("Failed to obtain access token")
    return response.json()["access_token"]


def create_paypal_payment(access_token: str, payment_amount: str) -> str:
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {access_token}",
    }
    payment_data = {
        "intent": "sale",
        "payer": {"payment_method": "paypal"},
        "transactions": [
            {
                "amount": {"total": payment_amount, "currency": "USD"},
                "description": "Sample payment",
            }
        ],
        "redirect_urls": {
            "return_url": url_for("payment_success", _external=True),
            "cancel_url": url_for("payment_canceled", _external=True),
        },
    }
    response = requests.post(
        PAYPAL_PAYMENT_CREATE_URL, json=payment_data, headers=headers, timeout=10
    )
    if response.status_code != 201:
        raise RuntimeError("Failed to create payment")
    for link in response.json().get("links", []):
        if link.get("rel") == "approval_url":
            return link.get("href")
    raise RuntimeError("Approval URL not found")


def generate_csrf_token() -> str:
    token = secrets.token_urlsafe(32)
    session["csrf_token"] = token
    return token


def check_csrf():
    token = session.pop("csrf_token", None)
    form_token = request.form.get("csrf_token", "")
    if not token or token != form_token:
        abort(400)


def validate_amount(amount_str: str) -> str:
    try:
        amt = Decimal(amount_str)
    except InvalidOperation:
        raise ValueError("Amount must be numeric")
    if amt <= 0:
        raise ValueError("Amount must be positive")
    if amt > Decimal("10000.00"):
        raise ValueError("Amount exceeds maximum allowed")
    # Ensure two decimal places
    amt = amt.quantize(Decimal("0.01"))
    return str(amt)


@app.route("/", methods=["GET", "POST"])
def payment_form():
    if request.method == "POST":
        check_csrf()
        client_id = request.form.get("client_id", "").strip()
        client_secret = request.form.get("client_secret", "").strip()
        if not validate_paypal_credentials(client_id, client_secret):
            return (
                render_template_string(
                    """<p>Invalid credentials. Both fields are required.</p>"""
                ),
                400,
            )
        amount_raw = request.form.get("amount", "10.00").strip()
        try:
            amount = validate_amount(amount_raw)
        except ValueError as e:
            return render_template_string(f"<p>{e}</p>"), 400
        try:
            access_token = get_access_token(client_id, client_secret)
            approval_url = create_paypal_payment(access_token, amount)
            return redirect(approval_url)
        except Exception:
            return (
                render_template_string(
                    "<p>Unable to process payment. Please try again later.</p>"
                ),
                500,
            )
    csrf_token = generate_csrf_token()
    return render_template_string(
        """
        <h1>PayPal Payment</h1>
        <form method="post">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <label>Client ID: <input type="text" name="client_id" required></label><br>
            <label>Client Secret: <input type="password" name="client_secret" required></label><br>
            <label>Amount (USD): <input type="text" name="amount" value="10.00" required></label><br>
            <button type="submit">Pay with PayPal</button>
        </form>
        """,
        csrf_token=csrf_token,
    )


@app.route("/payment_success")
def payment_success():
    return render_template_string(
        """
        <h1>Payment Successful</h1>
        <p>Your payment has been processed successfully.</p>
        """
