import logging
from types import MappingProxyType
from collections.abc import Iterable

logging.basicConfig(level=logging.ERROR, format="%(levelname)s: %(message)s")

_ALLOWED_FUNCTIONS = MappingProxyType(
    {
        "sum": sum,
        "len": len,
        "min": min,
        "max": max,
        "sorted": sorted,
    }
)

_ALLOWED_KWARGS = {
    "sum": set(),
    "len": set(),
    "min": {"default", "key"},
    "max": {"default", "key"},
    "sorted": {"key", "reverse"},
}

_PRIMITIVE_TYPES = (int, float, str, bool, type(None))

_MAX_DEPTH = 1024
_MAX_CONTAINER_SIZE = 100000


def _sanitize_value(value):
    stack = [(value, 0)]
    while stack:
        current, depth = stack.pop()
        if isinstance(current, _PRIMITIVE_TYPES):
            continue
        if isinstance(current, dict):
            if depth > _MAX_DEPTH:
                raise ValueError("Container depth exceeds maximum")
            if len(current) > _MAX_CONTAINER_SIZE:
                raise ValueError("Dictionary size too large")
            for k, v in current.items():
                if not isinstance(k, str):
                    raise ValueError("Dictionary keys must be strings")
                stack.append((v, depth + 1))
            continue
        if isinstance(current, (list, tuple, set)):
            if depth > _MAX_DEPTH:
                raise ValueError("Container depth exceeds maximum")
            if len(current) > _MAX_CONTAINER_SIZE:
                raise ValueError(f"Container type {type(current).__name__} too large")
            for item in current:
                stack.append((item, depth + 1))
            continue
        if isinstance(current, Iterable):
            # Unsupported iterable type that is not a builtâin container
            raise ValueError(f"Unsupported iterable type: {type(current).__name__}")
        if callable(current):
            raise ValueError("Callables are not allowed in arguments")
        raise ValueError(f"Unsupported argument type: {type(current).__name__}")
    return value


def execute_with_exec(func_name: str, *args, **kwargs):
    if not isinstance(func_name, str) or not func_name.isidentifier():
        raise ValueError("Invalid function name")
    func = _ALLOWED_FUNCTIONS.get(func_name)
    if func is None:
        raise ValueError("Function not allowed")
    allowed_kw = _ALLOWED_KWARGS.get(func_name, set())
    for key, value in kwargs.items():
        if key not in allowed_kw:
            raise ValueError(f"Keyword argument '{key}' is not allowed for {func_name}")
        _sanitize_value(value)
    for arg in args:
        _sanitize_value(arg)
    try:
        result = func(*args, **kwargs) if kwargs else func(*args)
    except Exception as exc:
        logging.error("Execution error: %s", exc)
        raise RuntimeError("Execution failed") from None
    return result

import os
