from urllib.parse import urlparse
from typing import Dict, Any, Set

# Constants
PEPPER = b"super_secret_pepper_value"
ALLOWED_HOSTS: Set[str] = {"auth.example.com", "sts.example.org"}

def _validate_url(url: str) -> bool:
    try:
        parsed = urlparse(url)
        return (
            parsed.scheme in {"http", "https"}
            and bool(parsed.netloc)
            and parsed.hostname in ALLOWED_HOSTS
        )
    except Exception:
        return False

def _safe_str(value: Any) -> str:
    if callable(value):
        raise ValueError("Environment value cannot be a callable")
    if hasattr(value, "__dict__"):
        raise ValueError("Environment value cannot be an object with attributes")
    return str(value)

def _sanitize(env: Dict[str, Any]) -> Dict[str, Any]:
    secret_keywords = {"PASS", "PWD", "SECRET", "TOKEN", "KEY"}
    sanitized: Dict[str, Any] = {}
    for key, value in env.items():
        if any(sec in key.upper() for sec in secret_keywords):
            continue  # drop key entirely
        sanitized[key] = value
    return sanitized

def authenticate_env(env: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(env, dict):
        raise TypeError("Input must be a dictionary")

    os_keys = {"OS_AUTH_URL", "OS_USERNAME", "OS_PASSWORD", "OS_TENANT_NAME"}
    st_keys = {"ST_AUTH", "ST_USER", "ST_KEY"}

    has_os = os_keys.issubset(env.keys())
    has_st = st_keys.issubset(env.keys())

    if has_os and has_st:
        raise ValueError("Ambiguous authentication credentials: both OS and ST provided")
    if has_os:
        auth_type = "OS"
    elif has_st:
        auth_type = "ST"
    else:
        raise ValueError("Unsupported or incomplete authentication credentials")

    # Validate URL
    url_key = "OS_AUTH_URL" if auth_type == "OS" else "ST_AUTH"
    if not _validate_url(env[url_key]):
        raise ValueError(f"Invalid {url_key}")

    # Prepare token source
    user_key = "OS_USERNAME" if auth_type == "OS" else "ST_USER"
    pass_key = "OS_PASSWORD" if auth_type == "OS" else "ST_KEY"

    username = _safe_str(env[user_key])
    password = _safe_str(env[pass_key])

    token_source = f"{username}:{password}"

    # Derive key using PBKDF2
    derived_key = hashlib.pbkdf2_hmac(
        "sha256",
        token_source.encode("utf-8"),
        PEPPER,
        200000,
        dklen=32,
    )

    # Compute HMAC-based token
    hmac_digest = hmac.new(
        derived_key,
        token_source.encode("utf-8"),
        hashlib.sha256,
    ).digest()
    auth_token = base64.urlsafe_b64encode(hmac_digest).decode("utf-8")

    sanitized_env = _sanitize(env)

    auth_version = "2.0" if auth_type == "OS" else "1.0"

    return {
        "auth_version": auth_version,
        "auth_token": auth_token,
        "env": sanitized_env,
    }

import hashlib
import re
from pathlib import Path
from typing import Optional

_PARENT_ID_RE = re.compile(r'^[A-Za-z0-9_-]+$')

def get_file_path(filename: str, parent_id: Optional[str] = None) -> str:
    if not isinstance(filename, str) or not filename:
        raise ValueError("filename must be a non-empty string")
    if parent_id is not None:
        if not isinstance(parent_id, str):
            raise ValueError("parent_id must be a string if provided")
        if not _PARENT_ID_RE.match(parent_id):
            raise ValueError("parent_id contains invalid characters")

    file_hash = hashlib.sha256(filename.encode("utf-8")).hexdigest()
    prefix = file_hash[:3]

    base_dir = Path("/files/attachments")
    parts = [base_dir]
    if parent_id:
        parts.append(Path(parent_id))
    parts.extend([Path(prefix), Path(file_hash)])
    full_path = Path(*parts)

    resolved = full_path.resolve(strict=False)
    if not resolved.is_absolute():
        raise RuntimeError("Unable to resolve absolute path")

    try:
        resolved.relative_to(base_dir.resolve(strict=False))
    except ValueError:
        raise RuntimeError("Resolved path is outside the base directory")

    return str(resolved)

