from mysql.connector import Error

logging.basicConfig(level=logging.INFO)

def _assert_int(value, name):
    if not isinstance(value, int):
        raise ValueError(f"{name} must be an integer")
    return value

def _assert_str(value, name):
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a string")
    return value

def _assert_port(value, name="port"):
    _assert_int(value, name)
    if not 0 <= value <= 65535:
        raise ValueError(f"{name} must be between 0 and 65535")
    return value

def _parse_date(value, name):
    if isinstance(value, datetime):
        return value
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a datetime or ISO format string")
    try:
        return datetime.fromisoformat(value)
    except ValueError:
        raise ValueError(f"{name} must be in ISO format")

def update_user_and_problems(db_config, user_info, problem_records):
    """
    Update user and problem data in a MySQL database.
    """
    # Validate db_config
    required_db_keys = ("host", "user", "password", "database", "port")
    for key in required_db_keys:
        if key not in db_config:
            raise ValueError(f"db_config missing key {key}")
        if key == "port":
            _assert_port(db_config[key], f"db_config[{key}]")
        else:
            _assert_str(db_config[key], f"db_config[{key}]")

    # Validate user_info
    required_user_keys = ("user_id", "score", "solved_count", "last_solved_date")
    for key in required_user_keys:
        if key not in user_info:
            raise ValueError(f"user_info missing key {key}")

    _assert_int(user_info["user_id"], "user_id")
    _assert_int(user_info["score"], "score")
    _assert_int(user_info["solved_count"], "solved_count")
    user_last_date = _parse_date(user_info["last_solved_date"], "last_solved_date")

    # Validate problem_records
    if not isinstance(problem_records, list):
        raise ValueError("problem_records must be a list")
    for record in problem_records:
        if not isinstance(record, dict):
            raise ValueError("Each problem record must be a dict")
        for key in ("problem_id", "last_solved_date"):
            if key not in record:
                raise ValueError(f"Each problem record must contain '{key}'")
        _assert_int(record["problem_id"], "problem_id")
        record["last_solved_date"] = _parse_date(
            record["last_solved_date"], "problem last_solved_date"
        )

    connection = None
    cursor = None
    try:
        connection = mysql.connector.connect(
            **db_config,
            connection_timeout=10,
            auth_plugin='mysql_native_password',
        )
        cursor = connection.cursor()
        connection.start_transaction()

        # Update user
        cursor.execute(
            """
            UPDATE users
            SET score = %s,
                solved_count = %s,
                last_solved_date = %s
            WHERE user_id = %s
            """,
            (
                user_info["score"],
                user_info["solved_count"],
                user_last_date,
                user_info["user_id"],
            ),
        )

        # Update problems
        cursor.execute(
            """
            UPDATE problems
            SET solved_count = solved_count + 1,
                last_solved_date = %s
            WHERE problem_id = %s
            """,
            tuple(
                rec for rec in map(
                    lambda r: (r["last_solved_date"], r["problem_id"]),
                    problem_records
                )
            ),
        )

        connection.commit()
    except Error as err:
        if connection:
            connection.rollback()
        logging.error("Database operation failed: %s", err)
        raise
    finally:
        if cursor:
            cursor.close()
        if connection:
            connection.close()

