def password_reset_request(request):
    # Host validation to prevent phishing
    allowed_hosts = getattr(settings, "ALLOWED_HOSTS", [])
    if not allowed_hosts:
        return HttpResponse("Server configuration error.", status=500)

    host = request.get_host().split(":")[0]
    if host not in allowed_hosts:
        return HttpResponseForbidden("Invalid host header.")

    domain = allowed_hosts[0]

    if request.method == "POST":
        client_ip, is_routable = get_client_ip(request)
        if not client_ip:
            client_ip = request.META.get("REMOTE_ADDR", "")

        attempts_key = f"pwd_reset_attempts:{client_ip}"
        attempts = cache.get(attempts_key, 0)
        if attempts >= RATE_LIMIT_MAX_ATTEMPTS:
            return HttpResponse("Too many attempts. Please try again later.", status=429)
        cache.set(attempts_key, attempts + 1, timeout=RATE_LIMIT_TIMEOUT)

        form = PasswordResetForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data["email"]
            users = form.get_users(email)
            processed = False
            for user in users:
                try:
                    token = default_token_generator.make_token(user)
                    uid_b64 = urlsafe_base64_encode(force_bytes(user.pk))
                    protocol = "https" if request.is_secure() else "http"
                    reset_url = f"{protocol}://{domain}{reverse('password_reset_confirm', kwargs={'uidb64': uid_b64, 'token': token})}"
