                            "user": user,
                            "reset_url": reset_url,
                            "domain": domain,
                            "site_name": user.get_username(),
                        },
                    )
                    user.email_user(subject, message)
                    processed = True
                except Exception:
                    logger.exception("Password reset email failed for user.")
            if not processed:
                logger.info("Password reset requested with unknown email address.")
            # Constant delay to mitigate timing attacks
            time.sleep(1)
            return render(request, "password_reset_done.html")
        else:
            return render(request, "password_reset_form.html", {"form": form})
    else:
        form = PasswordResetForm()
        return render(request, "password_reset_form.html", {"form": form})

