import argparse
import csv
import ipaddress
import logging
import os
import pathlib
import re
import sys
import urllib.parse

import scrapy
from scrapy.crawler import CrawlerProcess
from scrapy.exceptions import CloseSpider


def validate_url(url: str) -> str:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in {"http", "https"}:
        raise ValueError("URL scheme must be http or https.")
    if not parsed.netloc:
        raise ValueError("URL must have a network location.")
    host = parsed.hostname
    if not host:
        raise ValueError("Invalid host in URL.")
    try:
        addr = ipaddress.ip_address(host)
        if addr.is_private or addr.is_loopback or addr.is_reserved:
            raise ValueError("Disallowed IP address.")
    except ValueError:
        # Not an IP address, validate domain name
        if not re.fullmatch(r"^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$", host):
            raise ValueError("Invalid domain name.")
    # Reconstruct a minimal URL with scheme, netloc, and path
    return f"{parsed.scheme}://{parsed.netloc}{parsed.path}"


def validate_filename(filename: str) -> pathlib.Path:
    if not re.fullmatch(r"[A-Za-z0-9._-]+", filename):
        raise ValueError("Filename contains invalid characters.")
    path = pathlib.Path.cwd() / filename
    if path.is_symlink():
        raise ValueError("Filename is a symlink, which is disallowed.")
    return path


class DataSpider(scrapy.Spider):
    name = "data_spider"

    def __init__(self, start_url, **kwargs):
        super().__init__(**kwargs)
        self.start_urls = [start_url]
        self.custom_settings = {
            "LOG_LEVEL": "INFO",
            "DOWNLOAD_DELAY": 0.1,
            "ROBOTSTXT_OBEY": True,
            "ITEM_PIPELINES": {"__main__.CSVPipeline": 300},
        }

    def parse(self, response):
        title = response.css("title::text").get(default="untitled").strip()
        yield {"url": response.url, "title": title}
        raise CloseSpider(reason="Crawling single page only.")


class CSVPipeline:
    def __init__(self):
        self.file = None
        self.writer = None

    def open_spider(self, spider):
        csv_path = pathlib.Path(getattr(spider, "csv_path", None))
        if not csv_path:
            raise RuntimeError("CSV path not provided to the spider.")
        mode = "w"
        self.file = open(csv_path, mode, newline="", encoding="utf-8")
        self.writer = csv.DictWriter(
            self.file, fieldnames=["url", "title"], extrasaction="ignore"
        )
        self.writer.writeheader()

    def close_spider(self, spider):
        if self.file:
            self.file.close()

    def process_item(self, item, spider):
        self.writer.writerow(item)
        return item


def delete_existing_file(file_path: pathlib.Path):
    if file_path.is_file():
        try:
            os.remove(str(file_path))
        except OSError as exc:
            logging.error("Could not delete existing file: %s", exc)
            sys.exit(1)


def main():
    parser = argparse.ArgumentParser(description="Scrapy CSV downloader.")
    parser.add_argument("url", help="Target URL to scrape.")
    parser.add_argument("output", help="Output CSV filename.")
    args = parser.parse_args()

    try:
        safe_url = validate_url(args.url)
        output_path = validate_filename(args.output)
    except ValueError as err:
        logging.error("Input validation failed: %s", err)
        sys.exit(1)

    delete_existing_file(output_path)

    process = CrawlerProcess(
        settings={
            "LOG_LEVEL": "INFO",
            "ROBOTSTXT_OBEY": True,
            "DOWNLOAD_DELAY": 0.1,
            "FEEDS": {},  # Disable default feeds
        }
    )
    process.crawl(DataSpider, start_url=safe_url, csv_path=output_path)
    process.start()


if __name__ == "__main__":
    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s [%(levelname)s] %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )
    main()

