import os
import sys
import json
import getpass
import logging
import re
from pathlib import Path
from typing import Dict, Tuple, Optional

try:
    import requests
    import keyring
except ImportError as e:
    print("Required libraries are missing: requests, keyring", file=sys.stderr)
    sys.exit(1)

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

CONFIG_PATH = Path(__file__).with_name("config.json")
SERVICE_NAME = "my_script_auth"
USERNAME_PATTERN = re.compile(r"^(?=.{3,30}$)[a-zA-Z0-9](?:[a-zA-Z0-9@._-]*[a-zA-Z0-9])?$")


def read_config(path: Path) -> Dict[str, str]:
    if not path.is_file():
        logging.info(f"Configuration file {path} does not exist. Creating a new one.")
        return {}
    try:
        with path.open("r", encoding="utf-8") as f:
            return json.load(f)
    except (json.JSONDecodeError, OSError) as exc:
        logging.error(f"Failed to read configuration: {exc}")
        return {}


def write_config(path: Path, data: Dict[str, str]) -> None:
    try:
        with path.open(
            "w",
            encoding="utf-8",
            opener=lambda p, flags: os.open(
                p, flags | os.O_CREAT | os.O_WRONLY, 0o600
            ),
        ) as f:
            json.dump(data, f, indent=4, sort_keys=True)
        logging.info(f"Configuration written to {path}")
    except OSError as exc:
        logging.error(f"Failed to write configuration: {exc}")


def prompt_credentials() -> Tuple[str, str]:
    while True:
        username = input("Enter username: ").strip()
        if USERNAME_PATTERN.fullmatch(username):
            break
        else:
            print(
                "Invalid username. Start and end with letters or digits; "
                "allowed chars: @ . _ -; length 3-30.",
                file=sys.stderr,
            )
    password = getpass.getpass("Enter password: ")
    if not password:
        print("Password cannot be empty.", file=sys.stderr)
        sys.exit(1)
    # Store password in keyring and delete plaintext reference
    keyring.set_password(SERVICE_NAME, "password", password)
    username = keyring.set_password(SERVICE_NAME, "username", username)
    del password
    return username, keyring.get_password(SERVICE_NAME, "password")


def get_secret(key: str) -> Optional[str]:
    return keyring.get_password(SERVICE_NAME, key)


def set_secret(key: str, value: str) -> None:
    keyring.set_password(SERVICE_NAME, key, value)


def prompt_api_key_secret() -> Tuple[str, str]:
    api_key = get_secret("api_key")
    api_secret = get_secret("api_secret")
    if api_key and api_secret:
        return api_key, api_secret
    print("API key or secret not found. Please enter them.")
    api_key = input("Enter API key: ").strip()
    api_secret = getpass.getpass("Enter API secret: ")
    if not api_key or not api_secret:
        print("API key and secret cannot be empty.", file=sys.stderr)
        sys.exit(1)
    set_secret("api_key", api_key)
    set_secret("api_secret", api_secret)
    return api_key, api_secret


def authenticate(api_key: str, api_secret: str, username: str, password: str) -> bool:
    endpoint = os.getenv("API_ENDPOINT", "https://api.example.com/authenticate")
    payload = {"username": username, "password": password}
    headers = {"X-API-Key": api_key, "X-API-Secret": api_secret}
    try:
        response = requests.post(
            endpoint, json=payload, headers=headers, timeout=10
        )
        response.raise_for_status()
    except requests.exceptions.RequestException as exc:
        logging.error(f"Authentication request failed: {exc}")
        return False
    try:
        data = response.json()
        return data.get("success") is True
    except (ValueError, KeyError) as exc:
        logging.error(f"Invalid response format: {exc}")
        return False


def main() -> None:
    config = read_config(CONFIG_PATH)

    api_key, api_secret = prompt_api_key_secret()

    username = get_secret("username")
    if not username:
        logging.info("Username missing; prompting for input.")
        username, _ = prompt_credentials()
    password = get_secret("password")
    if not password:
        logging.info("Password missing; prompting for input.")
        _, password = prompt_credentials()

    if not authenticate(api_key, api_secret, username, password):
        print("Authentication failed.")
        sys.exit(1)

    print("Authentication successful.")
    # Zero out in-memory password variable
    del password


if __name__ == "__main__":
    main()

import os
import pathlib
import re
from typing import Dict

class MetadataExtractionError(RuntimeError):
    """Generic error for metadata extraction failures."""

def populate_metadata(file_path: str, dict_name: str) -> Dict[str, str]:
    # Basic type validation
    if not isinstance(file_path, str) or not isinstance(dict_name, str):
        raise MetadataExtractionError("Both file_path and dict_name must be strings.")

    if not file_path:
        raise MetadataExtractionError("file_path must not be empty.")
    if not dict_name:
        raise MetadataExtractionError("dict_name must not be empty.")

    # Resolve the path and ensure it's a relative path
    original_path = pathlib.Path(file_path)
    if original_path.is_absolute():
        raise MetadataExtractionError("Absolute paths are not allowed.")

    try:
        resolved_path = original_path.resolve(strict=True)
    except FileNotFoundError:
        raise MetadataExtractionError("The specified file does not exist.")
    except PermissionError:
        raise MetadataExtractionError("Insufficient permissions to resolve the file path.")
    except OSError as exc:
        raise MetadataExtractionError(f"Error resolving path: {exc}")

    cwd = pathlib.Path.cwd()

    # Verify that resolved_path is within cwd
    try:
        resolved_path.relative_to(cwd)
    except ValueError:
        # Fallback for Python < 3.9
        if os.path.commonpath([str(resolved_path), str(cwd)]) != str(cwd):
            raise MetadataExtractionError("Path traversal detected.")

    # Ensure the resolved path is absolute and still inside cwd
    if resolved_path.is_absolute() and not resolved_path.is_relative_to(cwd):
        raise MetadataExtractionError("Path traversal detected after resolution.")

    # Ensure the target exists and is a regular file
    if not resolved_path.is_file():
        raise MetadataExtractionError("The specified file does not exist or is not a regular file.")

    # Extract version string
    version = None
    try:
        with resolved_path.open("r", encoding="utf-8") as f:
            for line in f:
                match = re.match(r"^\s*Version\s*:\s*(\S+)", line, re.IGNORECASE)
                if match:
                    version = match.group(1)
                    break
    except PermissionError:
        raise MetadataExtractionError("Insufficient permissions to read the file.")
    except OSError as exc:
        raise MetadataExtractionError(f"Error reading file: {exc}")

    if version is None:
        raise MetadataExtractionError("Version line not found in the file.")

    # Return the metadata dictionary
    return {"name": dict_name, "version": version}

import argparse
import re
import sys
import pathlib
import os

MAX_PATTERN_LENGTH = 2000
MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024  # 10 MB

def validate_pattern(pattern: str) -> re.Pattern[str]:
    if len(pattern) > MAX_PATTERN_LENGTH:
        print(
            f"Error: pattern exceeds maximum length of {MAX_PATTERN_LENGTH} characters.",
            file=sys.stderr,
        )
        sys.exit(1)
    try:
        return re.compile(pattern)
    except re.error:
        print("Error: invalid regular expression pattern.", file=sys.stderr)
        sys.exit(1)


def read_file_content(file_path: pathlib.Path) -> str:
    try:
        if file_path.stat().st_size > MAX_FILE_SIZE_BYTES:
            print(
                f"Error: file size exceeds {MAX_FILE_SIZE_BYTES / (1024 * 1024)} MB limit.",
                file=sys.stderr,
            )
            sys.exit(1)
        with file_path.open("r", encoding="utf-8") as f:
            return f.read()
    except Exception:
        print("Error: could not read file.", file=sys.stderr)
        sys.exit(1)


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Extract file names matching a pattern."
    )
    parser.add_argument("filepath", help="Path to the input text file")
    parser.add_argument(
        "-p",
        "--pattern",
        default=r"[\w-]+-[0-9]+(?:\.[0-9]+)+\.tar\.gz",
        help="Regular expression pattern for matching file names (default: pattern-version.tar.gz)",
    )
    args = parser.parse_args()

    try:
        input_path = pathlib.Path(args.filepath).resolve(strict=True)
    except (FileNotFoundError, OSError):
        print("Error: file not found or inaccessible.", file=sys.stderr)
        sys.exit(1)

    if not input_path.is_file():
        print("Error: path is not a file.", file=sys.stderr)
        sys.exit(1)

    pattern = validate_pattern(args.pattern)

    content = read_file_content(input_path)

    matches = set(pattern.findall(content))
    for match in sorted(matches):
        print(match)


if __name__ == "__main__":
    main()

