import hashlib
import logging
from pathlib import Path
from typing import Optional

logging.basicConfig(level=logging.WARNING)

ALLOWED_ALGORITHMS = {"sha256", "sha384", "sha512"}

def compute_file_hash(
    file_path: str,
    hasher: hashlib._Hash,
    max_size: Optional[int] = None,
) -> Optional[str]:
    if not isinstance(file_path, str):
        logging.warning("compute_file_hash: file_path must be a string.")
        return None

    if not hasattr(hasher, "update") or not hasattr(hasher, "hexdigest"):
        logging.warning("compute_file_hash: hasher must be a hashlib hash object.")
        return None

    algorithm_name = getattr(hasher, "name", None)
    if algorithm_name not in ALLOWED_ALGORITHMS:
        logging.warning(
            "compute_file_hash: hasher algorithm must be one of %s.",
            ", ".join(sorted(ALLOWED_ALGORITHMS)),
        )
        return None

    file_path_obj = Path(file_path)

    if not file_path_obj.is_file():
        logging.warning("compute_file_hash: file does not exist or is not a regular file.")
        return None

    try:
        file_size = file_path_obj.stat().st_size
        if max_size is not None and file_size > max_size:
            logging.warning(
                "compute_file_hash: file size exceeds the maximum allowed (%d bytes).", max_size
            )
            return None
    except OSError as e:
        logging.warning("compute_file_hash: could not determine file size: %s", e)
        return None

    if not hasattr(hasher, "copy"):
        logging.warning("compute_file_hash: hasher does not support copy operation.")
        return None

    hasher_copy = hasher.copy()

    try:
        with file_path_obj.open("rb") as f:
            bytes_read = 0
            for chunk in iter(lambda: f.read(8192), b""):
                hasher_copy.update(chunk)
                bytes_read += len(chunk)
                if max_size is not None and bytes_read > max_size:
                    logging.warning("compute_file_hash: file size exceeded limit during read.")
                    return None
    except (OSError, PermissionError) as e:
        logging.warning("compute_file_hash: error reading file.")
        return None

    return hasher_copy.hexdigest()

import os
import subprocess
import shlex
import re
import shutil
from typing import List, Optional, Union

_SAFE_TOKEN = re.compile(r'^[A-Za-z0-9_\-./]+$')
_SUCCESS_RE = re.compile(r'SUCCESS', re.IGNORECASE)
_FAILURE_RE = re.compile(r'FAILURE', re.IGNORECASE)

_TRUSTED_BIN_DIRS = {
    '/usr/bin',
    '/bin',
    '/usr/local/bin',
}

def _parse_and_validate(command: Union[str, List[str]]) -> List[str]:
    if isinstance(command, str):
        tokens = shlex.split(command, posix=True)
    elif isinstance(command, list):
        tokens = list(command)
    else:
        raise TypeError("command must be a str or a list of str")

    if not tokens:
        raise ValueError("command is empty")

    for t in tokens:
        if not isinstance(t, str):
            raise ValueError("all command elements must be strings")
        if not _SAFE_TOKEN.fullmatch(t):
            raise ValueError(f"unsafe command token: {t!r}")

    cmd_path = shutil.which(tokens[0])
    if cmd_path is None:
        raise ValueError(f"command not found: {tokens[0]!r}")

    cmd_path = os.path.realpath(cmd_path)
    if not os.path.isabs(cmd_path):
        raise ValueError(f"resolved command path is not absolute: {cmd_path!r}")

    if not any(
        cmd_path == d or cmd_path.startswith(d + os.sep)
        for d in _TRUSTED_BIN_DIRS
    ):
        raise ValueError(f"executables outside trusted directories are not allowed: {cmd_path!r}")

    return tokens

def check_job_status(command: Union[str, List[str]]) -> Optional[int]:
    try:
        tokens = _parse_and_validate(command)
    except ValueError as exc:
        raise exc

    cmd_path = shutil.which(tokens[0])
    cmd_path = os.path.realpath(cmd_path)

    cmd_list = [cmd_path] + tokens[1:]

    try:
        result = subprocess.run(
            cmd_list,
            capture_output=True,
            text=True,
            timeout=300,
            check=False,
            executable=cmd_path,
        )
    except (subprocess.TimeoutExpired, OSError, subprocess.SubprocessError):
        return None

    output = result.stdout + result.stderr

    if _SUCCESS_RE.search(output):
        return 0
    if _FAILURE_RE.search(output):
        return 1
    return None

if __name__ == "__main__":
    status = check_job_status(["echo", "Job finished SUCCESS"])
    print(status)

using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;

class Program
{
    const long MaxSourceSizeBytes = 1_000_000;
    const int MaxSourceLines = 10_000;
    static readonly TimeSpan CompilationTimeout = TimeSpan.FromSeconds(30);
    static readonly TimeSpan ExecutionTimeout = TimeSpan.FromSeconds(30);

    static async Task<int> Main(string[] args)
    {
        if (args.Length == 0)
        {
            Console.Error.WriteLine("Usage: DynamicCompiler <source-file> [arguments...]");
            return 1;
        }

        string sourcePath = args[0];
        string[] payloadArgs = args.Skip(1).ToArray();

        if (!File.Exists(sourcePath))
        {
            Console.Error.WriteLine("Error: Source file does not exist.");
            return 1;
        }

        if (!Path.GetExtension(sourcePath).Equals(".cs", StringComparison.OrdinalIgnoreCase))
        {
            Console.Error.WriteLine("Error: Source file must have a .cs extension.");
            return 1;
        }

        FileInfo fileInfo;
        try
        {
            fileInfo = new FileInfo(sourcePath);
            if (fileInfo.Length > MaxSourceSizeBytes)
            {
                Console.Error.WriteLine("Error: Source file exceeds maximum allowed size.");
                return 1;
            }
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: Unable to access source file. {ex.Message}");
            return 1;
        }

        string sourceCode;
        try
        {
            sourceCode = await File.ReadAllTextAsync(sourcePath, Encoding.UTF8);
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: Unable to read source file. {ex.Message}");
            return 1;
        }

        if (CountLines(sourceCode) > MaxSourceLines)
        {
            Console.Error.WriteLine("Error: Source file exceeds maximum allowed lines.");
            return 1;
        }

        string tempExePath = null!;
        try
        {
            tempExePath = await CreateUniqueTempFilePathAsync(".exe");

            var syntaxTree = CSharpSyntaxTree.ParseText(sourceCode);
            var assemblyName = Path.GetFileNameWithoutExtension(tempExePath);
            var references = GetAllowedMetadataReferences();

            var compilation = CSharpCompilation.Create(
                assemblyName,
                new[] { syntaxTree },
                references,
                new CSharpCompilationOptions(OutputKind.ConsoleApplication)
                    .WithOptimizationLevel(OptimizationLevel.Release));

            var emitResult = await CompileWithTimeoutAsync(compilation, tempExePath, CompilationTimeout);
            if (!emitResult.Success)
            {
                Console.Error.WriteLine("Error: Compilation failed or timed out.");
                foreach (var diag in emitResult.Diagnostics.Where(d => d.Severity == DiagnosticSeverity.Error))
                {
                    Console.Error.WriteLine(diag.ToString());
                }
                return 1;
            }

            var psi = new ProcessStartInfo
            {
                FileName = tempExePath,
                UseShellExecute = false,
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                CreateNoWindow = true
            };
            psi.Environment.Clear();
            foreach (var arg in payloadArgs)
            {
                psi.ArgumentList.Add(arg);
            }

            int exitCode = await ExecuteWithTimeoutAsync(psi, ExecutionTimeout);
            return exitCode;
        }
        finally
        {
            if (tempExePath != null && File.Exists(tempExePath))
            {
                try { File.Delete(tempExePath); } catch { }
            }
        }
    }

    static int CountLines(string code) =>
        code.Split(new[] { "
", "
", "" }, StringSplitOptions.None).Length;

    static IEnumerable<MetadataReference> GetAllowedMetadataReferences()
    {
        var assemblies = new[]
        {
            typeof(object).Assembly,
            typeof(Console).Assembly,
            typeof(Enumerable).Assembly
        };

        return assemblies
            .Where(a => !a.IsDynamic && !string.IsNullOrEmpty(a.Location))
            .Select(a => MetadataReference.CreateFromFile(a.Location));
    }

    static async Task<EmitResult> CompileWithTimeoutAsync(CSharpCompilation compilation, string outputPath, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource();
        var task = Task.Run(() =>
        {
            try
            {
                using var fs = new FileStream(outputPath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, FileOptions.None);
                return compilation.Emit(fs, cancellationToken: cts.Token);
            }
            catch
            {
                return EmitResult.CreateFailedResult();
            }
        }, cts.Token);

        if (await Task.WhenAny(task, Task.Delay(timeout)) == task)
        {
            cts.Cancel();
            return await task;
        }
        else
        {
            cts.Cancel();
            return EmitResult.CreateFailedResult();
        }
    }

    static async Task<int> ExecuteWithTimeoutAsync(ProcessStartInfo psi, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource();
        try
        {
            var process = Process.Start(psi);
            if (process == null)
            {
                Console.Error.WriteLine("Error: Failed to start the compiled executable.");
                return 1;
            }

            var outputTask = RelayStreamAsync(process.StandardOutput, Console.Out);
            var errorTask = RelayStreamAsync(process.StandardError, Console.Error);

            var exitTask = process.WaitForExitAsync(cts.Token);

            if (await Task.WhenAny(exitTask, Task.Delay(timeout)) == exitTask)
            {
                cts.Cancel();
                await Task.WhenAll(outputTask, errorTask);
                return process.ExitCode;
            }
            else
            {
                try { process.Kill(true); } catch { }
                Console.Error.WriteLine("Error: Execution timed out.");
                return 1;
            }
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: Exception during execution. {ex.Message}");
            return 1;
        }
    }

    static async Task RelayStreamAsync(StreamReader reader, TextWriter writer)
    {
        string? line;
        try
        {
            while ((line = await reader.ReadLineAsync().ConfigureAwait(false)) != null)
            {
                await writer.WriteLineAsync(line).ConfigureAwait(false);
            }
        }
        catch
        {
        }
    }

    static async Task<string> CreateUniqueTempFilePathAsync(string extension)
    {
        string tempPath = Path.GetTempPath();
        while (true)
        {
            string fileName = $"{Guid.NewGuid()}{extension}";
            string fullPath = Path.Combine(tempPath, fileName);
            try
            {
                using var stream = new FileStream(fullPath, FileMode.CreateNew, FileAccess.Write, FileShare.None);
                stream.Dispose();
                return fullPath;
            }
            catch (IOException)
            {
                await Task.Yield();
                continue;
            }
        }
    }
}

