CREATE OR REPLACE FUNCTION install_row_trigger(
    p_schema              text,
    p_table               text,
    p_trigger_func        text,
    p_event               text,
    p_timing              text DEFAULT 'AFTER',
    p_trigger_name_pattern text DEFAULT 'auto_%',
    p_language            text DEFAULT 'plpgsql'
) RETURNS void
LANGUAGE plpgsql
VOLATILE
AS $$
DECLARE
    trigger_name   text;
    v_exists       boolean;
    generated_name text;
    allowed_languages text[] := ARRAY['plpgsql','sql','c'];
BEGIN
    -- Permission check
    IF NOT (has_superuser_privilege() OR current_user = 'trusted_role') THEN
        RAISE EXCEPTION 'Permission denied';
    END IF;

    -- Input validation
    IF p_schema IS NULL OR p_schema = '' THEN
        RAISE EXCEPTION 'Schema name cannot be null or empty';
    END IF;
    IF p_table IS NULL OR p_table = '' THEN
        RAISE EXCEPTION 'Table name cannot be null or empty';
    END IF;
    IF p_trigger_func IS NULL OR p_trigger_func = '' THEN
        RAISE EXCEPTION 'Trigger function name cannot be null or empty';
    END IF;
    IF p_event NOT IN ('INSERT','UPDATE','DELETE','TRUNCATE') THEN
        RAISE EXCEPTION 'Unsupported event %', p_event;
    END IF;
    IF p_timing NOT IN ('BEFORE','AFTER','INSTEAD OF') THEN
        RAISE EXCEPTION 'Unsupported timing %', p_timing;
    END IF;
    IF NOT p_trigger_name_pattern LIKE 'auto_%' THEN
        RAISE EXCEPTION 'Trigger name pattern must start with ''auto_''';
    END IF;
    IF length(p_trigger_name_pattern) > 100 THEN
        RAISE EXCEPTION 'Trigger name pattern too long';
    END IF;
    IF NOT p_language = ANY (allowed_languages) THEN
        RAISE EXCEPTION 'Unallowed language %', p_language;
    END IF;

    -- Verify trigger function exists
    SELECT EXISTS (
        SELECT 1
        FROM pg_proc p
        JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = p_schema
          AND p.proname = p_trigger_func
          AND p.prorettype = 'trigger'::regtype
    ) INTO v_exists;
    IF NOT v_exists THEN
        RAISE EXCEPTION 'Trigger function % does not exist in schema %', p_trigger_func, p_schema;
    END IF;

    -- Verify language exists
    SELECT EXISTS (
        SELECT 1 FROM pg_language WHERE lanname = p_language
    ) INTO v_exists;
    IF NOT v_exists THEN
        RAISE EXCEPTION 'Language % does not exist', p_language;
    END IF;

    -- Drop existing triggers matching pattern
    FOR trigger_name IN
        SELECT t.tgname
        FROM pg_trigger t
        JOIN pg_class c ON c.oid = t.tgrelid
        JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE n.nspname = p_schema
          AND c.relname = p_table
          AND t.tgname LIKE p_trigger_name_pattern
    LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I.%I', trigger_name, p_schema, p_table);
    END LOOP;

    generated_name := 'auto_' || to_char(NOW()::timestamp, 'YYYYMMDD_HH24MISSMS');

    EXECUTE format(
        'CREATE TRIGGER %I
         %s %s
         ON %I.%I
         FOR EACH ROW
         EXECUTE FUNCTION %I.%I()',
        generated_name,
        p_timing,
        p_event,
        p_schema,
        p_table,
        p_schema,
        p_trigger_func
    );

EXCEPTION
    WHEN others THEN
        RAISE LOG 'Error installing trigger: %', SQLSTATE;
        RAISE EXCEPTION 'Error while installing trigger';
END;
$$;

