#!/usr/bin/env python3
import sys
import os
import pathlib
import subprocess
import shutil
from typing import Tuple, Optional

BASE_DIR: pathlib.Path = pathlib.Path.cwd().resolve()
ALLOWED_PATHS = [
    pathlib.Path("/usr/local/bin").resolve(),
    pathlib.Path("/usr/bin").resolve(),
    pathlib.Path("/bin").resolve(),
]


def _is_abspath_safe(p: pathlib.Path) -> None:
    if not p.is_absolute():
        raise ValueError(f"Path must be absolute: {p}")


def _ensure_no_symlinks(p: pathlib.Path) -> None:
    cur = pathlib.Path(p.anchor) if p.is_absolute() else pathlib.Path.cwd()
    for part in p.parts:
        cur = cur / part
        if cur.is_symlink():
            raise ValueError(f"Symlink component detected in path: {cur}")


def _validate_within_base(p: pathlib.Path) -> None:
    resolved = p.resolve(strict=p.exists())
    if not resolved.is_relative_to(BASE_DIR):
        raise ValueError(f"Path escapes base directory: {p}")


def _resolve_optional(p: pathlib.Path) -> pathlib.Path:
    return p.resolve(strict=False)


def validate_file(path: pathlib.Path, must_exist: bool = True, must_be_file: bool = True) -> pathlib.Path:
    if not isinstance(path, pathlib.Path):
        raise TypeError("Path must be a pathlib.Path instance")
    _is_abspath_safe(path)
    _ensure_no_symlinks(path)
    _validate_within_base(path)

    if must_exist and not path.exists():
        raise FileNotFoundError(f"File does not exist: {path}")
    if must_be_file and not path.is_file():
        raise ValueError(f"Not a file: {path}")
    return _resolve_optional(path)


def validate_output_file(path: pathlib.Path) -> pathlib.Path:
    if not isinstance(path, pathlib.Path):
        raise TypeError("Path must be a pathlib.Path instance")
    _is_abspath_safe(path)
    _ensure_no_symlinks(path)
    _validate_within_base(path)
    return _resolve_optional(path)


def safe_environment() -> dict[str, str]:
    env_paths_raw = os.getenv("ML_TOOL_PATHS", ":".join([str(p) for p in ALLOWED_PATHS]))
    safe_paths = []
    for p in env_paths_raw.split(":"):
        p = pathlib.Path(p).resolve()
        if p not in ALLOWED_PATHS:
            raise ValueError(f"Disallowed mltool path in ML_TOOL_PATHS: {p}")
        safe_paths.append(str(p))
    return {"PATH": ":".join(sorted(set(safe_paths)))}


def locate_mltool(env: dict[str, str]) -> pathlib.Path:
    exe = shutil.which("mltool", path=env["PATH"])
    if exe is None:
        raise FileNotFoundError("mltool executable not found in safe PATH")
    exe_path = pathlib.Path(exe)
    if oe := exe_path.resolve():
        if not oe.is_file() or exe_path.is_symlink():
            raise FileNotFoundError(f"mltool path not a regular file or is a symlink: {exe}")
    return exe_path


def run_ml_tool(
    mltool_path: pathlib.Path,
    input_path: pathlib.Path,
    output_path: pathlib.Path,
    model_path: Optional[pathlib.Path] = None,
) -> Tuple[str, str]:
    validated_output = validate_output_file(output_path)
    cmd = [
        str(mltool_path),
        "--input",
        str(input_path),
        "--output",
        str(validated_output),
    ]
    if model_path:
        cmd.extend(["--model", str(model_path)])
    env = safe_environment()
    result = subprocess.run(
        cmd,
        capture_output=True,
        text=True,
        check=True,
        env=env,
    )
    return result.stdout, result.stderr


def main() -> None:
    if len(sys.argv) < 3:
        print(f"Usage: {sys.argv[0]} <input_file> <output_file> [<model_file>]")
        sys.exit(1)

    try:
        raw_input = pathlib.Path(sys.argv[1]).expanduser()
        raw_output = pathlib.Path(sys.argv[2]).expanduser()
        raw_model = pathlib.Path(sys.argv[3]).expanduser() if len(sys.argv) > 3 else None

        input_file = validate_file(raw_input, must_exist=True, must_be_file=True)
        model_file = validate_file(raw_model, must_exist=True, must_be_file=True) if raw_model else None

        output_dir = raw_output.parent
        _is_abspath_safe(output_dir)
        _ensure_no_symlinks(output_dir)
        _validate_within_base(output_dir)
        output_dir.mkdir(parents=True, exist_ok=True)

        mltool_exe = locate_mltool(safe_environment())

        stdout, stderr = run_ml_tool(mltool_exe, input_file, raw_output.resolve(), model_file)

        if stderr:
            print(f"mltool stderr: {stderr}", file=sys.stderr)

    except subprocess.CalledProcessError as exc:
        print(f"Command failed with exit code {exc.returncode}.")
        sys.exit(3)
    except PermissionError:
        print("Permission denied while accessing files.")
        sys.exit(4)
    except (FileNotFoundError, ValueError, TypeError) as exc:
        print(f"Input validation error: {exc}")
        sys.exit(4)
    except Exception as exc:
        print(f"An unexpected error occurred: {exc}")
        sys.exit(5)


if __name__ == "__main__":
    main()

