import logging
import re
from collections.abc import Mapping
from typing import Callable, Any

logger = logging.getLogger(__name__)

_HEADER_INJECTION_PATTERN = re.compile(r"[
]+")


def _is_valid_header(name: str, value: str) -> bool:
    return bool(
        isinstance(name, str)
        and isinstance(value, str)
        and not _HEADER_INJECTION_PATTERN.search(name)
        and not _HEADER_INJECTION_PATTERN.search(value)
    )


def _ensure_header(request: Any, name: str, value: str) -> None:
    if not _is_valid_header(name, value):
        raise ValueError(f"Invalid header name or value: {name!r}, {value!r}")
    if hasattr(request, "set_header"):
        request.set_header(name, value)
    else:
        request.headers[name] = value


def _set_status(request: Any, code: int) -> None:
    if hasattr(request, "set_status"):
        request.set_status(code)
    else:
        request.status_code = code


def handle_get(request: Any, write_fn: Callable[[bytes], None]) -> None:
    if request is None:
        logger.error("Invalid request: None")
        raise ValueError("Request object is required.")
    if not hasattr(request, "headers"):
        logger.error("Invalid request: missing headers")
        raise AttributeError("Request object must have a 'headers' attribute.")
    if not isinstance(request.headers, Mapping):
        logger.error("Headers attribute is not a mapping")
        raise TypeError("Request.headers must support Mapping protocol.")
    if not callable(write_fn):
        logger.error("Invalid write function: must be callable")
        raise ValueError("write_fn must be a callable that accepts bytes.")

    try:
        etag_request = request.headers.get("If-None-Match")
        etag_response = getattr(request, "etag", None)

        if etag_request is not None:
            etag_request = str(etag_request)
        if etag_response is not None:
            etag_response = str(etag_response)

        if etag_request and etag_response and etag_request == etag_response:
            _set_status(request, 304)
            return

        content = getattr(request, "content", b"")
        if isinstance(content, str):
            content_bytes = content.encode("utf-8")
        elif isinstance(content, (bytes, bytearray)):
            content_bytes = bytes(content)
        else:
            logger.error("Unsupported content type: %s", type(content))
            raise TypeError("Content must be bytes, bytearray, or str.")

        if not any(key.lower() == "content-length" for key in request.headers):
            _ensure_header(request, "Content-Length", str(len(content_bytes)))

        write_fn(content_bytes)
        _set_status(request, 200)

    except Exception as exc:
        logger.exception("Error handling GET request")
        _set_status(request, 500)
        try:
            write_fn(b"")
        except Exception:
            pass
        raise RuntimeError("Internal server error") from exc

