from django.db import models
from django.shortcuts import render
from django.conf import settings
import hashlib
from django.contrib.auth.hashers import check_password
from django.core.exceptions import ImproperlyConfigured
import logging

logger = logging.getLogger(__name__)

class EventPage(models.Model):
    title = models.CharField(max_length=200)
    date = models.DateField()
    time = models.TimeField()
    location = models.CharField(max_length=200)
    audience = models.CharField(max_length=100, blank=True)

    class Meta:
        ordering = ["date", "time"]

    @classmethod
    def filter_events(cls, location, audience):
        """
        Return a QuerySet of events filtered by location and audience.
        Inputs are validated and passed directly to the ORM.
        """
        loc = location if isinstance(location, str) else ""
        aud = audience if isinstance(audience, str) else ""
        try:
            return cls.objects.filter(
                location__iexact=loc,
                audience__iexact=aud
            )
        except Exception as e:
            logger.error(f"Error filtering events: {e}")
            return cls.objects.none()

    def render_with_password(self, request, template_name, password_plain):
        """
        Render the event detail page only if the provided password matches
        the hash stored in settings.EVENT_PAGE_PASSWORD_HASH.
        """
        if not password_plain or not isinstance(password_plain, str):
            logger.warning(
                "Password input missing or invalid from %s",
                request.META.get("REMOTE_ADDR"),
            )
            return render(
                request,
                "error.html",
                {"error": "Invalid password."},
                status=400,
            )

        expected_hash = getattr(settings, "EVENT_PAGE_PASSWORD_HASH", None)
        if expected_hash is None:
            raise ImproperlyConfigured("EVENT_PAGE_PASSWORD_HASH not configured.")

        if not check_password(password_plain, expected_hash):
            logger.warning(
                "Invalid password attempt from %s",
                request.META.get("REMOTE_ADDR"),
            )
            return render(
                request,
                "error.html",
                {"error": "Invalid password."},
                status=403,
            )

        context = {"event": self}
        try:
            return render(request, template_name, context)
        except Exception as e:
            logger.error(f"Error rendering event page: {e}")
            return render(
                request,
                "error.html",
                {"error": "An unexpected error occurred."},
                status=500,
            )

