    r'^\$6\$(?P<salt>[A-Za-z0-9./]{1,64})\$(?P<hash>[A-Za-z0-9./]{1,128})$'
)

def _validate_placeholder(name: str) -> None:
    if not _PLACEHOLDER_RE.match(name):
        raise ValueError(f"Invalid placeholder name: {name!r}")

def _validate_value(value: str) -> None:
    if not value:
        raise ValueError("Replacement value cannot be empty")
    if not _ALLOWED_CHARS_RE.match(value):
        raise ValueError("Replacement value contains disallowed characters")

def _validate_password_hash(hash_str: str) -> None:
    if not _PASSWORD_HASH_RE.match(hash_str):
        raise ValueError("Invalid password hash format")
    if '
' in hash_str or '' in hash_str:
        raise ValueError("Password hash cannot contain newlines")

def _secure_open_write(dst: Path):
    if dst.is_symlink():
        raise ValueError("Destination path is a symbolic link")
    if dst.is_dir():
        raise ValueError("Destination path is a directory")
    try:
        fd = os.open(
            str(dst),
            os.O_WRONLY | os.O_CREAT | os.O_NOFOLLOW | os.O_TRUNC,
            0o600,
        )
    except OSError as e:
        raise RuntimeError(f"Failed to open destination for writing: {e}") from None
    try:
