    password_line = f"%password --iscrypted {password_hash}
"

    try:
        with _secure_open_write(destination_file) as out_f:
            out_f.write(content)
            out_f.write(password_line)
    except Exception as exc:
        raise RuntimeError(f"Failed to write destination file: {exc}") from None

