import logging
import pickle
import zipfile
from io import BytesIO
from pathlib import Path
from typing import Any, Dict, List, Tuple
import tempfile
import os
import sys

try:
    import numpy as np
except ImportError as exc:
    raise RuntimeError("NumPy is required for DatasetLoader") from exc

# Configuration
BASE_DIR = Path.cwd() / "datasets"
MAX_PICKLE_SIZE = 100 * 1024 * 1024  # 100 MiB
ALLOWED_PICKLE_EXTENSIONS = {".pkl", ".pickle"}
MAX_ELEMENTS = 100_000  # Max number of images/labels
MAX_ZIP_IN_MEMORY = 50 * 1024 * 1024  # 50 MiB before using temp file

# Logger
logging.basicConfig(level=logging.INFO, format="%(levelname)s: %(message)s")
logger = logging.getLogger(__name__)

class DatasetLoader:
    """
    Securely loads pickled datasets and packages them into ZIP archives.
    """

    def __init__(self, train_path: str, val_path: str, test_path: str) -> None:
        self._train_data = self._load_pickle(train_path, "training")
        self._val_data = self._load_pickle(val_path, "validation")
        self._test_data = self._load_pickle(test_path, "testing")

    @staticmethod
    def _validate_path(file_path: Path) -> None:
        if not file_path.exists():
            raise ValueError(f"File not found: {file_path}")
        if file_path.suffix.lower() not in ALLOWED_PICKLE_EXTENSIONS:
            raise ValueError(f"Unsupported file extension: {file_path.suffix}")

        resolved = file_path.resolve(strict=True)
        if resolved.is_symlink():
            raise ValueError(f"Symlink disallowed: {file_path}")
        try:
            resolved.relative_to(BASE_DIR)
        except ValueError:
            raise ValueError(
                f"Path {file_path} is outside the allowed directory ({BASE_DIR})"
            )

        if resolved.stat().st_size == 0:
            raise ValueError(f"File {file_path} is empty")

    @staticmethod
    def _safe_load(file_obj: BytesIO) -> Any:
        class RestrictedUnpickler(pickle.Unpickler):
            def __init__(self, file):
                super().__init__(file)
                self._allowed_builtins = {
                    "list",
                    "dict",
                    "bytes",
                    "int",
                    "float",
                    "str",
                    "tuple",
                    "set",
                    "frozenset",
                }
                self._allowed_collections = {"OrderedDict"}
                try:
                    import numpy
                    self._allowed_numpy = {"ndarray"}
                    self._have_numpy = True
                except Exception:
                    self._have_numpy = False
                    self._allowed_numpy = set()

            def find_class(self, module: str, name: str):
                if module == "builtins" and name in self._allowed_builtins:
                    return getattr(__builtins__, name)
                if module == "collections" and name in self._allowed_collections:
                    import collections
                    return getattr(collections, name)
                if self._have_numpy and module == "numpy" and name in self._allowed_numpy:
                    import numpy
                    return getattr(numpy, name)
                raise pickle.UnpicklingError(
                    f"Disallowed class {module}.{name} attempted to be unpickled."
                )

        return RestrictedUnpickler(file_obj).load()

    def _load_pickle(self, path: str, dataset_name: str) -> Dict[str, Any]:
        try:
            p = Path(path)
            self._validate_path(p)

            if p.stat().st_size > MAX_PICKLE_SIZE:
                raise ValueError("Pickle file exceeds maximum allowed size")

            with p.open("rb") as f:
                data = self._safe_load(f)

            if not isinstance(data, (list, tuple)):
                raise ValueError("Data object must be a list or tuple.")
            if len(data) != 2:
                raise ValueError(
                    "Data object must contain two elements: images and labels."
                )
            images, labels = data
            if not isinstance(images, (list, tuple)):
                raise ValueError("Images must be a list or tuple.")
            if not isinstance(labels, (list, tuple)):
                raise ValueError("Labels must be a list or tuple.")
            if len(images) != len(labels):
                raise ValueError("Number of images and labels must match.")
            if len(images) > MAX_ELEMENTS:
                raise ValueError(f"Too many elements: {len(images)} (max {MAX_ELEMENTS})")

            # Validate each image and label
            for idx, img in enumerate(images):
                if not isinstance(img, np.ndarray):
                    raise ValueError(f"Image at index {idx} is not a numpy.ndarray.")
                if type(img) is not np.ndarray:
                    raise ValueError(f"Image at index {idx} is a subclass of ndarray.")
                # Basic memory check per image
                if img.nbytes > MAX_PICKLE_SIZE:
                    raise ValueError(f"Image at index {idx} exceeds max size.")
            for idx, lbl in enumerate(labels):
                if not isinstance(lbl, (int, float, str)):
                    raise ValueError(f"Label at index {idx} has invalid type.")

            return {"images": images, "labels": labels}
        except Exception as exc:
            logger.error("Failed to load %s dataset: %s", dataset_name, exc)
            raise ValueError(f"Failed to load {dataset_name} data.") from exc

    def _package_dataset(self, images: List[Any], labels: List[Any]) -> BytesIO:
        try:
            expected_size = sum(
                (img.nbytes + sys.getsizeof(str(lbl))) for img, lbl in zip(images, labels)
            )
            if expected_size > MAX_ZIP_IN_MEMORY:
                with tempfile.NamedTemporaryFile(delete=False) as tmp:
                    with zipfile.ZipFile(tmp.name, mode="w", compression=zipfile.ZIP_DEFLATED) as zf:
                        for idx, (img, lbl) in enumerate(zip(images, labels)):
                            if hasattr(img, "tobytes"):
                                img_bytes = img.tobytes()
                                ext = ".npy"
                                fname = f"image_{idx}_array{ext}"
                            else:
                                raise ValueError(f"Unsupported image type at index {idx}")
                            zf.writestr(fname, img_bytes)
                            zf.writestr(f"label_{idx}.txt", str(lbl))
                    tmp.seek(0)
                    mem_zip = BytesIO(tmp.read())
                os.unlink(tmp.name)
            else:
                mem_zip = BytesIO()
                with zipfile.ZipFile(
                    mem_zip, mode="w", compression=zipfile.ZIP_DEFLATED
                ) as zf:
                    for idx, (img, lbl) in enumerate(zip(images, labels)):
                        img_bytes = img.tobytes()
                        ext = ".npy"
                        fname = f"image_{idx}_array{ext}"
                        zf.writestr(fname, img_bytes)
                        zf.writestr(f"label_{idx}.txt", str(lbl))
                mem_zip.seek(0)
            return mem_zip
        except Exception as exc:
            logger.error("Error packaging dataset: %s", exc)
            raise RuntimeError("Failed to package dataset.") from exc

    def render_data(self, subset: str = "train") -> bytes:
        if subset == "train":
            data = self._train_data
        elif subset == "val":
            data = self._val_data
        elif subset == "test":
            data = self._test_data
        else:
            raise ValueError(
                f"Unsupported subset '{subset}'. Choose 'train', 'val', or 'test'."
            )

        mem_zip = self._package_dataset(data["images"], data["labels"])
        return mem_zip.getvalue()

