MAX_CONTROLLERS = 1000  # Max total controllers that can be instantiated in one request


class Controller:
    def __init__(self, controller_id: str, sequencer: Any, system: Any) -> None:
        if not isinstance(controller_id, str) or not controller_id:
            raise ValueError("Invalid controller ID")
        if sequencer is None:
            raise ValueError("Sequencer reference cannot be None")
        if system is None:
            raise ValueError("System reference cannot be None")

        self._id = controller_id
        self._sequencer = sequencer
        self._system = system

    @property
    def id(self) -> str:
        return self._id

    @property
    def sequencer(self) -> Any:
        return self._sequencer

    @property
    def system(self) -> Any:
        return self._system

    def start(self) -> None:
        logger.info(f"Controller {self._id} started.")

    def stop(self) -> None:
        logger.info(f"Controller {self._id} stopped.")


class AlphaController(Controller):
    def start(self) -> None:
        super().start()
        logger.info(f"AlphaController {self._id} performing alpha-specific start.")


class BetaController(Controller):
    def start(self) -> None:
        super().start()
        logger.info(f"BetaController {self._id} performing beta-specific start.")


ALLOWED_CONTROLLER_TYPES: Dict[str, Type[Controller]] = {
    "alpha": AlphaController,
    "beta": BetaController,
}


def create_controllers(
    specs: List[Dict[str, Any]],
    sequencer: Any,
    system: Any,
) -> List[Controller]:
    if not isinstance(specs, list):
        raise ValueError("Specifications must be a list.")
    if sequencer is None:
        raise ValueError("Sequencer reference cannot be None.")
    if system is None:
        raise ValueError("System reference cannot be None.")

    controllers: List[Controller] = []

    for idx, spec in enumerate(specs, start=1):
        if not isinstance(spec, dict):
            raise ValueError(f"Specification at index {idx} is not a dictionary.")

        controller_type = spec.get("type")
        count = spec.get("count")

        if not isinstance(controller_type, str):
            raise ValueError(f"Controller type must be a string in spec {idx}.")
        controller_type_clean = controller_type.strip().lower()
        if controller_type_clean not in ALLOWED_CONTROLLER_TYPES:
            raise ValueError(f"Unsupported controller type '{controller_type}' in spec {idx}.")

