import re
import textwrap
import ast
import multiprocessing
from queue import Empty
from typing import List, Dict, Any, Optional, Union

class SecureCodeExecutor:
    _SAFE_BUILTINS: Dict[str, Any] = {
        'abs': abs,
        'bool': bool,
        'bytes': bytes,
        'chr': chr,
        'dict': dict,
        'float': float,
        'int': int,
        'len': len,
        'list': list,
        'max': max,
        'min': min,
        'pow': pow,
        'range': range,
        'round': round,
        'str': str,
        'sum': sum,
        'tuple': tuple,
    }

    _UNSAFE_PATTERN: re.Pattern = re.compile(
        r'^\s*(import|from|exec|eval|open|__import__) ',
        re.IGNORECASE,
    )

    _PRINTABLE_ASCII: re.Pattern = re.compile(r'^[ -~]*$')
    _MAX_RANGE: int = 10_000_000
    _TIMEOUT_SECONDS: int = 5

    def __init__(self) -> None:
        self._lines: List[str] = []

    def add_line(self, line: str) -> None:
        if not isinstance(line, str):
            raise TypeError("Code line must be a string.")
        stripped = line.rstrip()
        if not self._PRINTABLE_ASCII.fullmatch(stripped):
            raise ValueError("Code contains non-printable or non-ASCII characters.")
        if self._UNSAFE_PATTERN.search(stripped):
            raise ValueError(f"Detected unsafe code pattern: {stripped!r}")
        self._lines.append(stripped)

    def get_code(self) -> str:
        return "
".join(self._lines)

    def get_indented_code(self, indent: int = 4) -> str:
        if not isinstance(indent, int) or indent < 0:
            raise ValueError("Indent must be a non-negative integer.")
        return textwrap.indent(self.get_code(), " " * indent)

    def _is_code_safe(self, code: str) -> bool:
        try:
            tree = ast.parse(code, mode='exec')
        except SyntaxError as e:
            raise ValueError(f"Syntax error in code: {e}") from e
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                return False
            if isinstance(node, ast.Call):
                func = node.func
                if isinstance(func, ast.Name) and func.id in ("exec", "eval", "open", "__import__"):
                    return False
        return True

    @staticmethod
    def _exec_process(
        code: str, globals_dict: Dict[str, Any], result_queue: multiprocessing.Queue
    ) -> None:
        try:
            import resource
            soft_mem, hard_mem = resource.getrlimit(resource.RLIMIT_AS)
            resource.setrlimit(resource.RLIMIT_AS, (100 * 1024 * 1024, hard_mem))
            soft_cpu, hard_cpu = resource.getrlimit(resource.RLIMIT_CPU)
            resource.setrlimit(resource.RLIMIT_CPU, (SecureCodeExecutor._TIMEOUT_SECONDS, hard_cpu))
        except Exception:
            # Resource limits are optional; ignore failures
            pass
        try:
            exec(code, globals_dict, {})
            result_queue.put(None)
        except Exception as e:
            result_queue.put(e)

    def run(self, globals_override: Optional[Dict[str, Any]] = None) -> None:
        code = self.get_code()
        if not code.strip():
            raise RuntimeError("No code to execute.")
        if not self._is_code_safe(code):
            raise ValueError("Code contains disallowed constructs.")

        restricted_globals: Dict[str, Any] = {"__builtins__": self._SAFE_BUILTINS}
        if globals_override:
            if not isinstance(globals_override, dict):
                raise TypeError("globals_override must be a dict.")
            for k, v in globals_override.items():
                if k.startswith("__"):
                    raise ValueError(f"Forbidden global name: {k}")
                if k not in self._SAFE_BUILTINS:
                    raise ValueError(f"Global override '{k}' is not allowed.")
                restricted_globals[k] = v

        result_queue: multiprocessing.Queue = multiprocessing.Queue()
        process = multiprocessing.Process(
            target=self._exec_process,
            args=(code, restricted_globals, result_queue)
        )
        process.start()
        process.join(self._TIMEOUT_SECONDS)

        if process.is_alive():
            process.terminate()
            process.join()
            raise TimeoutError("Execution timed out")

        try:
            result = result_queue.get_nowait()
        except Empty:
            result = None

        if isinstance(result, Exception):
            raise result

def main(argv: Optional[List[str]] = None) -> None:
    if argv is None:
        argv = sys.argv[1:]
    executor = SecureCodeExecutor()
    if not argv:
        for raw_line in sys.stdin:
            executor.add_line(raw_line)
    else:
        for raw_line in argv:
            executor.add_line(raw_line)
    executor.run()

