    if len(command) > _MAX_COMMAND_LENGTH:
        raise ValueError("Command exceeds maximum allowed length.")
    args = shlex.split(command, comments=False, posix=True)
    if not args:
        raise ValueError("Command must contain at least one token.")
    cmd_name = args[0]
    # Prevent usage of a script path
    if "/" in cmd_name:
        raise ValueError("Command path must not contain '/'.")
