        text=True,
        close_fds=not os.name == "nt",
        bufsize=1,
    )

def _setup_timeout(proc: subprocess.Popen, timeout: Optional[float]) -> None:
    if timeout is None:
        return

    def _kill() -> None:
        try:
            proc.kill()
        except Exception:
