def secure_process_css(
    url: str,
    pattern: str = r"foo",
    replacement: str = "bar",
) -> str:
    """Retrieve CSS from a trusted URL, apply a regex substitution, write the
    modified content to a temporary file, and return its SHA256 hash."""
    # ---- URL validation ----
    try:
        parsed = urlparse(url)
    except Exception as exc:
        raise CSSProcessingError("URL parsing failed.") from exc

    if parsed.scheme not in {"http", "https"}:
        raise CSSProcessingError("Unsupported URL scheme.")

    if parsed.username or parsed.password:
        raise CSSProcessingError("URL must not contain credentials.")

    if not parsed.path.lower().endswith(".css"):
        raise CSSProcessingError("URL does not point to a .css file.")

    if not _is_allowed_host(parsed.hostname or ""):
        raise CSSProcessingError("Host is not whitelisted.")

    # ---- HTTP request (streamed) ----
    session = requests.Session()
    try:
        response = session.get(
            url,
            timeout=10,
            verify=True,
            allow_redirects=True,
            stream=True,
            headers={"User-Agent": DEFAULT_USER_AGENT},
        )
        response.raise_for_status()
    except requests.RequestException as exc:
        raise CSSProcessingError("Failed to download CSS content.") from exc

    # Verify final host and scheme after redirects
    final_url = urlparse(response.url)
    final_host = final_url.hostname
    if not _is_allowed_host(final_host or ""):
        raise CSSProcessingError("Redirected to a non-whitelisted host.")
    final_scheme = final_url.scheme
    if final_scheme not in {"http", "https"} or (
        final_scheme == "http" and parsed.scheme != "http"
    ):
        raise CSSProcessingError("Insecure redirect to non-HTTPS URL.")

    # ---- content-type validation ----
    content_type = response.headers.get("Content-Type", "")
    _validate_content_type(content_type)

    # ---- download with size limit ----
    total_bytes = 0
    chunks = []
    try:
        for chunk in response.iter_content(chunk_size=8192):
            if chunk:
                total_bytes += len(chunk)
                if total_bytes > MAX_CONTENT_LENGTH:
                    raise CSSProcessingError("Content exceeds maximum allowed size.")
                chunks.append(chunk)
    except requests.RequestException as exc:
        raise CSSProcessingError("Error while downloading CSS content.") from exc

    try:
        css_bytes = b"".join(chunks)
        css_text = css_bytes.decode("utf-8")
    except Exception as exc:
        raise CSSProcessingError("Failed to decode CSS content as UTF-8.") from exc

    # ---- regex substitution ----
    _validate_pattern(pattern)
    try:
        modified_text = re.sub(pattern, replacement, css_text)
    except re.error as exc:  # should not occur after validation
        raise CSSProcessingError("Regex substitution failed.") from exc

    # ---- write to temporary file & compute hash ----
    sha256_hash = hashlib.sha256(modified_text.encode("utf-8")).hexdigest()
    try:
        with tempfile.NamedTemporaryFile(
            mode="w",
            suffix=".css",
            encoding="utf-8",
            delete=True,
        ) as tmp:
            tmp.write(modified_text)
    except Exception as exc:
        raise CSSProcessingError("Failed during write of temporary file.") from exc

    return sha256_hash

import json
import logging
import os
