import subprocess
import sys
from contextlib import contextmanager
from pathlib import Path
from typing import Dict, Optional

import shutil

logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s %(levelname)s %(message)s",
    stream=sys.stderr,
)
logger = logging.getLogger(__name__)

# Constants
ALLOWED_EXE_PREFIXES = ("/usr", "/usr/local", "/bin")
MAX_JSON_SIZE_BYTES = 5 * 1024 * 1024  # 5 MiB
BASE_CONFIG_DIR = Path.home() / ".javatest"


class InputValidationError(Exception):
    """Raised when external input validation fails."""


class EnvironmentSetupError(Exception):
    """Raised when setting up the test environment fails."""


class ExpectationLoadError(Exception):
    """Raised when loading expectations from file fails."""


def _is_executable_in_allowed_path(path: Path, name: str) -> None:
    """Validate that the executable path is absolute, has the expected name,
    is executable, and resides in an allowed location."""
    if not path.is_absolute():
        raise EnvironmentSetupError(f"Executable path is not absolute: {path}")
    if path.name != name:
        raise EnvironmentSetupError(f"Executable name mismatch: expected {name}, got {path.name}")
    if not path.is_file() or not os.access(path, os.X_OK):
        raise EnvironmentSetupError(f"Executable not found or not executable: {path}")
    if not any(str(path).startswith(prefix) for prefix in ALLOWED_EXE_PREFIXES):
        raise EnvironmentSetupError(f"Executable path {path} is not in an allowed directory")


def _get_executable_path(name: str) -> Path:
    """Resolve the executable name to an absolute path and validate it."""
    resolved = shutil.which(name)
    if resolved is None:
        raise EnvironmentSetupError(f"Required executable not found: {name}")
    exe_path = Path(resolved).resolve(strict=True)
    _is_executable_in_allowed_path(exe_path, name)
    return exe_path


class JavaTestEnvironment:
    """Sets up a test environment for Java tests, including a Xvfb desktop
    and loading test expectations from a JSON file.
    """

    def __init__(
        self,
        expectations_path: str,
        xvfb_display: Optional[int] = None,
        xvfb_executable: str = "Xvfb",
        max_windows: int = 200,
    ) -> None:
        # Ensure expectations file is within the allowed base directory
        path = Path(expectations_path).expanduser().resolve()
        if not any(str(path).startswith(str(BASE_CONFIG_DIR)) for _ in [None]):
            raise InputValidationError(
                f"Expectation file must be under the allowed configuration directory: {BASE_CONFIG_DIR}"
            )
        self.expectations_path = path
        self._validate_expectations_file()

        self.xvfb_display = xvfb_display or self._find_free_display()
        self.max_windows = max_windows

        self.xvfb_executable = _get_executable_path(xvfb_executable)

        self._xvfb_process: Optional[subprocess.Popen] = None

    # ------------------------------------------------------------------ #
    # Validation and helper methods
    # ------------------------------------------------------------------ #

    def _validate_expectations_file(self) -> None:
        if not self.expectations_path.is_file():
            raise InputValidationError(
                f"Expectation file does not exist or is not a file: {self.expectations_path}"
            )
        if self.expectations_path.suffix.lower() != ".json":
            raise InputValidationError(
                f"Unsupported file type for expectations: {self.expectations_path.suffix}"
            )
        try:
            # Quick readability check
            with self.expectations_path.open("rb") as f:
                _ = f.read(1)
        except OSError as exc:
            raise InputValidationError(
                f"Unable to read expectation file: {self.expectations_path}"
            ) from exc

    @staticmethod
    def _find_free_display() -> int:
        pgrep_path = _get_executable_path("pgrep")

        try:
            result = subprocess.run(
                [pgrep_path, "Xvfb"],
                capture_output=True,
                text=True,
                check=False,
            )
        except (OSError, subprocess.SubprocessError) as exc:
            raise EnvironmentSetupError(
                "Unable to execute pgrep for Xvfb display detection"
            ) from exc

        used_displays = set()
        for line in result.stdout.splitlines():
            try:
                used_displays.add(int(line.split()[0]))
            except ValueError:
                continue

        for display in range(1, 9999):
            if display not in used_displays:
                return display
        raise EnvironmentSetupError("No free Xvfb display found")

    # ------------------------------------------------------------------ #
    # Desktop lifecycle
    # ------------------------------------------------------------------ #

    def start_desktop(self) -> None:
        if self._xvfb_process is not None:
            return
        try:
            env = os.environ.copy()
            env["DISPLAY"] = f":{self.xvfb_display}"
            self._xvfb_process = subprocess.Popen(
                [
                    self.xvfb_executable,
                    f":{self.xvfb_display}",
                    "-screen",
                    "0",
                    "1920x1080x24",
                    "-maxwindows",
                    str(self.max_windows),
                ],
                env=env,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                preexec_fn=os.setpgrp,
            )
            if self._xvfb_process.poll() is not None:
                raise EnvironmentSetupError("Failed to start Xvfb")
        except OSError as exc:
            raise EnvironmentSetupError(
                "Could not start desktop environment"
            ) from exc

    def stop_desktop(self) -> None:
        process = self._xvfb_process
        if not process:
            return

        try:
            os.killpg(os.getpgid(process.pid), signal.SIGTERM)
            process.wait(timeout=5)
        except (OSError, subprocess.TimeoutExpired) as exc:
            logger.warning("Graceful shutdown of Xvfb failed: %s", exc)
            try:
                process.kill()
                process.wait(timeout=5)
            except (OSError, subprocess.TimeoutExpired) as kill_exc:
                logger.warning("Force kill of Xvfb failed: %s", kill_exc)
        finally:
            self._xvfb_process = None

    # ------------------------------------------------------------------ #
    # Expectation loading
    # ------------------------------------------------------------------ #

    def load_expectations(self) -> Dict:
        try:
            file_size = os.path.getsize(self.expectations_path)
            if file_size > MAX_JSON_SIZE_BYTES:
                raise ExpectationLoadError(
                    f"Expectation file exceeds maximum allowed size ({MAX_JSON_SIZE_BYTES} bytes)"
                )
            with self.expectations_path.open("r", encoding="utf-8") as f:
                data = json.load(f)
            if not isinstance(data, dict):
                raise ExpectationLoadError("Expectations file must contain a JSON object")
            return data
        except (OSError, json.JSONDecodeError) as exc:
            raise ExpectationLoadError(
                f"Failed to load expectations from {self.expectations_path}"
            ) from exc

    # ------------------------------------------------------------------ #
    # Context manager
    # ------------------------------------------------------------------ #

    @contextmanager
    def __call__(self):
        try:
            self.start_desktop()
            yield self
        finally:
            self.stop_desktop()


if __name__ == "__main__":
    try:
        env = JavaTestEnvironment("expectations.json")
        with env() as e:
            expectations = e.load_expectations()
            print("Loaded expectations:", expectations)
    except Exception as exc:
        logging.error("Error: %s", exc)
        sys.exit(1)

