logging.basicConfig(level=logging.INFO)
_logger = logging.getLogger(__name__)

_ALLOWED_PATHS = "/usr/bin:/usr/local/bin:/bin"


def _sanitize_path(input_path: str) -> pathlib.Path:
    if not isinstance(input_path, str) or not input_path.strip():
        raise ValueError("Invalid file path provided.")
    path = pathlib.Path(input_path).expanduser().resolve()
    script_dir = pathlib.Path(__file__).parent.resolve()
    try:
        path.relative_to(script_dir)
    except ValueError:
        raise ValueError("Path is outside the allowed directory.")
    if not path.is_file():
        raise ValueError(f"File does not exist: {path}")
    return path


def _read_file_contents(file_path: pathlib.Path) -> bytes:
    try:
        return file_path.read_bytes()
    except OSError as exc:
        raise ValueError("Unable to read file contents.") from exc


def _compute_hash(content: bytes) -> str:
    hasher = hashlib.sha256()
    hasher.update(content)
    return hasher.hexdigest()


def _find_audio_player() -> Optional[pathlib.Path]:
    candidates = [
        ("ffplay", ["-autoexit", "-nodisp"]),
        ("afplay", []),
        ("mpg123", []),
        ("cvlc", ["--play-and-exit"]),
    ]
    for player, _ in candidates:
        exec_path = shutil.which(player, path=_ALLOWED_PATHS)
        if exec_path:
            abs_path = pathlib.Path(exec_path).resolve(strict=True)
            if any(str(abs_path).startswith(dir_path) for dir_path in _ALLOWED_PATHS.split(":")):
                return abs_path
    return None


def _play_audio(file_path: pathlib.Path) -> None:
    if file_path.suffix.lower() not in {".mp3", ".wav", ".ogg", ".aac"}:
        return

    player_path = _find_audio_player()
    if not player_path:
        return

    cmd = [str(player_path)]
    if player_path.name == "ffplay":
        cmd.extend(["-autoexit", "-nodisp"])
    elif player_path.name == "cvlc":
        cmd.append("--play-and-exit")

    if file_path.name.startswith("-"):
        cmd.append("--")

    cmd.append(str(file_path))

    safe_env = {**os.environ, "PATH": _ALLOWED_PATHS}
    try:
        subprocess.run(
            cmd,
            check=False,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            shell=False,
            env=safe_env,
        )
    except (OSError, subprocess.SubprocessError) as exc:
        _logger.debug("Audio playback failed: %s", exc)


def read_and_hash_and_play(file_path: str) -> Tuple[str, str]:
    path = _sanitize_path(file_path)
    raw_content = _read_file_contents(path)
    hash_hex = _compute_hash(raw_content)
    _play_audio(path)
    try:
        decoded = raw_content.decode("utf-8", errors="replace")
    except Exception:
        decoded = ""
    return decoded, hash_hex


