import mysql.connector
from mysql.connector import errorcode
from mysql.connector.pooling import MySQLConnectionPool
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.exceptions import InvalidTag

# Ensure required environment variables are set
REQUIRED_VARS = ["DB_USER", "DB_PASSWORD", "DB_HOST", "DB_NAME"]
missing = [var for var in REQUIRED_VARS if not os.environ.get(var)]
if missing:
    raise EnvironmentError(f"Missing required DB environment variables: {', '.join(missing)}")

# Configure logging
logging.basicConfig(level=logging.WARNING, format='%(asctime)s %(levelname)s %(message)s')

# Database configuration with TLS enforcement
_DB_CONFIG: Dict[str, Any] = {
    "user": os.environ["DB_USER"],
    "password": os.environ["DB_PASSWORD"],
    "host": os.environ["DB_HOST"],
    "database": os.environ["DB_NAME"],
    "raise_on_warnings": True,
    "ssl_disabled": False,  # Enforce TLS
}

# Optional TLS certificates
for env_var, cfg_key in (("DB_SSL_CA", "ssl_ca"), ("DB_SSL_CERT", "ssl_cert"), ("DB_SSL_KEY", "ssl_key")):
    if os.environ.get(env_var):
        _DB_CONFIG[cfg_key] = os.environ[env_var]

# Connection pool for reuse
_POOL_NAME = "secure_pool"
_POOL_SIZE = int(os.getenv("DB_POOL_SIZE", "5"))
_CONNECTION_POOL = MySQLConnectionPool(pool_name=_POOL_NAME, pool_size=_POOL_SIZE, **_DB_CONFIG)


def _validate_record_id(record_id: int) -> None:
    if not isinstance(record_id, int) or record_id <= 0:
        raise ValueError("record_id must be a positive integer")


def _get_connection() -> mysql.connector.connection_cext.CMySQLConnection:
    try:
        return _CONNECTION_POOL.get_connection()
    except mysql.connector.Error as err:
        if err.errno == errorcode.ER_ACCESS_DENIED_ERROR:
            logging.error("Authentication failed for user.")
        elif err.errno == errorcode.ER_BAD_DB_ERROR:
            logging.error("Database does not exist.")
        else:
            logging.error("Database connection error: %s", err)
        raise


def _decrypt_aes_gcm(encrypted_b64: str, key: bytes) -> str:
    try:
        encrypted_bytes = base64.b64decode(encrypted_b64, validate=True)
    except (binascii.Error, ValueError) as exc:
        raise ValueError("Invalid base64 encoding") from exc

    if len(encrypted_bytes) < 28:  # 12-byte nonce + 16-byte tag
        raise ValueError("Encrypted data too short")

    nonce = encrypted_bytes[:12]
    tag = encrypted_bytes[-16:]
    ciphertext = encrypted_bytes[12:-16]

    try:
        aesgcm = AESGCM(key)
    except Exception as exc:
        raise ValueError("Invalid AES key") from exc

    try:
        decrypted = aesgcm.decrypt(nonce, ciphertext + tag, None)
    except InvalidTag as exc:
        raise ValueError("Decryption failed: invalid authentication tag") from exc
    except Exception:
        raise ValueError("Decryption failed")

    return decrypted.decode("utf-8")


def get_decrypted_record(record_id: int, aes_key: bytes) -> Dict[str, Any]:
    """
    Retrieve a record by its ID, decrypt the 'encrypted_data' column using AESGCM,
    and return the decrypted data as a dictionary.
    """
    _validate_record_id(record_id)

    if not isinstance(aes_key, bytes) or len(aes_key) not in (16, 24, 32):
        raise ValueError("AES key must be 16, 24, or 32 bytes long")

    conn = _get_connection()
    cursor = None
    try:
        cursor = conn.cursor(dictionary=True)
        query = "SELECT encrypted_data FROM records WHERE id = %s"
        cursor.execute(query, (record_id,))
        row = cursor.fetchone()
        if row is None:
            raise KeyError(f"Record with id {record_id} not found")

        encrypted_b64 = row["encrypted_data"]
        decrypted_json = _decrypt_aes_gcm(encrypted_b64, aes_key)

        if len(decrypted_json) > 10000:
            raise ValueError("Decrypted content exceeds size limit")

        data = json.loads(decrypted_json)
        if not isinstance(data, dict):
            raise ValueError("Decrypted JSON must be an object")

        return data
    except KeyError as ke:
        logging.warning("%s", ke)
        raise
    except mysql.connector.Error as db_err:
        logging.error("Database query error: %s", db_err)
        raise
    except json.JSONDecodeError as json_err:
        logging.error("JSON decode error: %s", json_err)
        raise
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()

