import importlib.util
import hashlib
import logging
import os
import re
import sys
from pathlib import Path
from typing import Any, Optional

logging.basicConfig(level=logging.WARNING)
logger = logging.getLogger(__name__)

_MAX_FILENAME_LENGTH = 255
_FILENAME_PATTERN = re.compile(r"^[\w.-]+$")  # printable characters allowed

def _sanitize_path(root_dir: Path, target_path: Path) -> Optional[Path]:
    try:
        resolved = target_path.resolve(strict=True)
        if not resolved.is_file() or resolved.suffix.lower() != ".py":
            return None
        if resolved.is_symlink():
            return None
        if not resolved.is_relative_to(root_dir):
            return None
        if resolved.stat().st_uid != os.getuid():
            return None
        return resolved
    except Exception:
        return None

def _deterministic_module_name(ext_path: Path) -> str:
    hash_digest = hashlib.sha256(ext_path.as_posix().encode()).hexdigest()[:12]
    return f"_env_ext_{ext_path.stem}_{hash_digest}"

def _load_source(path: Path) -> Optional[str]:
    try:
        return path.read_text(encoding="utf-8")
    except Exception as exc:
        logger.warning("Unable to read extension file %s: %s", path.name, exc)
        return None

def _load_module_from_path(module_name: str, file_path: Path) -> Optional[Any]:
    try:
        spec = importlib.util.spec_from_file_location(module_name, str(file_path))
        if spec is None or spec.loader is None:
            logger.warning("Could not create import spec for %s", file_path.name)
            return None
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)  # type: ignore[attr-defined]
        return module
    except Exception as exc:
        logger.warning("Failed to load extension module '%s': %s", file_path.name, exc)
        return None

def load_and_extend_python_path(
    extension_file: str,
    base_py_path: Any,
    root_directory: str,
) -> Any:
    root_dir = Path(root_directory).expanduser().resolve()
    if not root_dir.is_dir():
        logger.warning("Root directory does not exist: %s", root_dir.name)
        return base_py_path

    ext_candidate = Path(extension_file).expanduser()
    if ext_candidate.name.lower().startswith("."):
        logger.warning("Extension file '%s' is hidden", ext_candidate.name)
        return base_py_path
    if len(ext_candidate.name) > _MAX_FILENAME_LENGTH or not _FILENAME_PATTERN.match(ext_candidate.name):
        logger.warning("Extension file name '%s' is invalid", ext_candidate.name)
        return base_py_path

    ext_path = _sanitize_path(root_dir, ext_candidate)
    if ext_path is None:
        logger.warning("Extension file '%s' is not a valid, trusted Python source", ext_candidate.name)
        return base_py_path

    source_code = _load_source(ext_path)
    if source_code is None:
        return base_py_path

    module_name = _deterministic_module_name(ext_path)
    module = _load_module_from_path(module_name, ext_path)
    if module is None:
        return base_py_path

    extend_func = getattr(module, "Extend", None)
    if not callable(extend_func):
        logger.warning("Extension module '%s' lacks a callable 'Extend' function", ext_path.name)
        return base_py_path

    try:
        new_py_path = extend_func(base_py_path, root_dir)
    except Exception as exc:
        logger.warning(
            "Extend function raised an exception for '%s': %s",
            ext_path.name,
            exc.__class__.__name__,
        )
        return base_py_path

    if new_py_path is None:
        logger.warning("Extend function returned None for '%s'.", ext_path.name)
        return base_py_path

    return new_py_path

if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Load and extend Python path")
    parser.add_argument("extension_file", help="Path to extension .py file")
    parser.add_argument("root_directory", help="Root directory for extensions")
    args = parser.parse_args()

    result = load_and_extend_python_path(
        args.extension_file, sys.modules[__name__], args.root_directory
    )
    print(result)

import json
from typing import Any, Dict, List, Tuple


MAX_JSON_SIZE = 10 * 1024 * 1024  # 10 MB limit


def safe_json_deserialize(
    json_string: str,
    decode_non_string_keys: bool = False,
) -> Any:
    """
    Deserialize a JSON-formatted string into a Python object safely.

    Parameters:
        json_string: JSON string to deserialize. Must be a non-empty string.
        decode_non_string_keys: If True, attempts to parse dictionary keys that
            represent JSON primitives into their Python types.

    Returns:
        The deserialized Python object.

    Raises:
        ValueError: If input is invalid or JSON parsing fails.
    """
    if not isinstance(json_string, str):
        raise ValueError("Input must be a string.")
    if not json_string:
        raise ValueError("Input JSON string is empty.")
    if len(json_string) > MAX_JSON_SIZE:
        raise ValueError("Input JSON string exceeds maximum allowed size.")
    if not isinstance(decode_non_string_keys, bool):
        raise ValueError("decode_non_string_keys must be a boolean.")

    def _decode_key_pairs(pairs: List[Tuple[Any, Any]]) -> Dict[Any, Any]:
        decoded: Dict[Any, Any] = {}
        for original_key, value in pairs:
            key = original_key
            try:
                parsed_key = json.loads(original_key)
                if isinstance(parsed_key, (str, int, float, bool)):
                    key = parsed_key
            except json.JSONDecodeError:
                pass
            decoded[key] = value
        return decoded

    try:
        if decode_non_string_keys:
            return json.loads(
                json_string,
                object_pairs_hook=_decode_key_pairs,
                strict=True,
            )
        return json.loads(json_string, strict=True)
    except json.JSONDecodeError as e:
        raise ValueError("Invalid JSON input.") from e
    except Exception as e:  # pragma: no cover
        raise ValueError("Failed to deserialize JSON.") from e

