import sqlite3
import subprocess
import threading
import time
import logging
import shutil
import hashlib
from pathlib import Path

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[logging.StreamHandler()],
)

DB_PATH = "audiobook.db"
TABLE_INIT = """
CREATE TABLE IF NOT EXISTS progress (
    book_id TEXT PRIMARY KEY,
    position INTEGER
);
"""

AUDIO_DIR = Path("/home/pi/audiobooks").resolve()
RFID_TO_BOOK = {
    "123ABC": AUDIO_DIR / "book1.mp3",
    "456DEF": AUDIO_DIR / "book2.mp3",
}

TAG_REGEX = re.compile(r"^[A-Za-z0-9]+$")

TRUSTED_MPG123_PATH = Path("/usr/bin/mpg123")
MPG123_HASH = "eadf5bb1a57e80a1f8c88806d0eb9f5d"  # example SHA-256; update if required

class AudiobookPlayer:
    def __init__(self, db_path: str = DB_PATH):
        self.db_path = Path(db_path).resolve()
        self._init_db()
        self._mpg123_path = self._validate_mpg123_path()
        if not self._mpg123_path:
            logging.error("Insecure or missing mpg123 binary; aborting.")
            raise RuntimeError("mpg123 binary verification failed.")
        self._current_process: subprocess.Popen | None = None
        self._current_book_id: str | None = None
        self._lock = threading.Lock()

    def _init_db(self) -> None:
        try:
            with sqlite3.connect(str(self.db_path)) as conn:
                conn.execute(TABLE_INIT)
                conn.commit()
        except sqlite3.Error as e:
            logging.error("Database initialization failed: %s", e)

    def _validate_tag(self, tag: str) -> str | None:
        if TAG_REGEX.match(tag):
            return tag
        logging.warning("Invalid RFID tag detected")
        return None

    def _stop_current_book(self) -> None:
        with self._lock:
            proc = self._current_process
            if proc and proc.poll() is None:
                logging.info("Stopping current book")
                try:
                    proc.terminate()
                    proc.wait(timeout=5)
                except subprocess.TimeoutExpired:
                    proc.kill()
                    proc.wait()
            self._current_process = None
            self._current_book_id = None

    def _delete_progress(self, book_id: str) -> None:
        try:
            with sqlite3.connect(str(self.db_path)) as conn:
                cur = conn.execute(
                    "DELETE FROM progress WHERE book_id = ?", (book_id,)
                )
                conn.commit()
                if cur.rowcount > 0:
                    logging.info("Deleted progress for an unknown book")
        except sqlite3.Error as e:
            logging.error("Failed to delete progress: %s", e)

    def _validate_file_within_audio_dir(self, file_path: Path) -> Path | None:
        try:
            resolved = file_path.resolve(strict=True)
        except FileNotFoundError:
            logging.error("Book file does not exist")
            return None
        if not resolved.is_relative_to(AUDIO_DIR):
            logging.error("Attempted to play file outside authorized directory")
            return None
        if not resolved.is_file():
            logging.error("File is not a regular file")
            return None
        return resolved

    def _validate_mpg123_path(self) -> str | None:
        path = TRUSTED_MPG123_PATH
        if not path.is_file():
            return None
        if path.is_symlink():
            return None
        mode = path.stat().st_mode
        if mode & 0o2777 != 0:
            return None
        try:
            with open(path, "rb") as f:
                sha256 = hashlib.sha256(f.read()).hexdigest()
            if sha256 != MPG123_HASH:
                return None
        except Exception:
            return None
        return str(path)

    def play_book(self, book_id: str, file_path: Path) -> None:
        validated_path = self._validate_file_within_audio_dir(file_path)
        if validated_path is None:
            return
        logging.info("Playing book")
        with self._lock:
            self._stop_current_book()
            try:
                self._current_book_id = book_id
                self._current_process = subprocess.Popen(
                    [self._mpg123_path, "--no-loop", str(validated_path)],
                    stdout=subprocess.DEVNULL,
                    stderr=subprocess.DEVNULL,
                    text=True,
                )
            except Exception as e:
                logging.error("Failed to start playback")
                self._current_process = None
                self._current_book_id = None

    def monitor_playback(self) -> None:
        with self._lock:
            proc = self._current_process
            if proc is None:
                return
            ret = proc.poll()
            if ret is not None:
                logging.info("Book finished")
                if self._current_book_id:
                    self._delete_progress(self._current_book_id)
                self._current_process = None
                self._current_book_id = None

    def run(self) -> None:
        while True:
            try:
                raw_tag = self._simulate_rfid_read()
                if raw_tag is None:
                    time.sleep(1)
                    continue
                tag = self._validate_tag(raw_tag)
                if not tag:
                    continue
                if tag not in RFID_TO_BOOK:
                    logging.warning("Unknown tag detected")
                    continue
                book_path = RFID_TO_BOOK[tag]
                if not book_path.is_file():
                    logging.error("Book file not found")
                    continue
                if self._current_book_id == tag:
                    continue
                self._stop_current_book()
                self.play_book(tag, book_path)
            except Exception:
                logging.exception("Unexpected error:")
            finally:
                self.monitor_playback()
                time.sleep(0.5)

    @staticmethod
    def _simulate_rfid_read() -> str | None:
        return None

if __name__ == "__main__":
    player = AudiobookPlayer()
    try:
        player.run()
    except KeyboardInterrupt:
        logging.info("Shutting down")
        player._stop_current_book()
        exit(0)

