import pathlib
import types
import warnings
import stat
from typing import Any

CONFIG_BASE = pathlib.Path(__file__).resolve().parent / "config"


def _is_within_config_base(path: pathlib.Path) -> bool:
    try:
        path.relative_to(CONFIG_BASE)
        return True
    except ValueError:
        # Fallback compatibility for older Python versions
        try:
            common = os.path.commonpath([CONFIG_BASE, path])
            return common == str(CONFIG_BASE)
        except Exception:
            return False


def _is_trusted_file(path: pathlib.Path) -> bool:
    try:
        st = path.stat()
    except OSError:
        return False

    # File must be owned by the current effective user
    if getattr(os, "geteuid", None):
        uid = os.geteuid()
    else:
        uid = os.getuid()
    if st.st_uid != uid:
        return False

    # File must not be group/world writable or executable
    bad_modes = stat.S_IWGRP | stat.S_IWOTH | stat.S_IXGRP | stat.S_IXOTH
    if st.st_mode & bad_modes:
        return False

    return True


def load_config(path: str, silent: bool = False) -> bool:
    if not isinstance(path, str) or not path.strip():
        return False

    try:
        abs_path = pathlib.Path(path).expanduser().resolve(strict=True)
    except Exception:
        return False

    if not _is_within_config_base(abs_path):
        return False

    if not abs_path.is_file() or abs_path.suffix.lower() != ".json":
        return False

    if not _is_trusted_file(abs_path):
        return False

    try:
        with abs_path.open("r", encoding="utf-8") as fp:
            data = json.load(fp)
    except Exception as e:
        if not silent:
            warnings.warn(f"Unable to load config file {abs_path!s}: {e}")
        return False

    if not isinstance(data, dict):
        if not silent:
            warnings.warn(f"Config file {abs_path!s} does not contain a JSON object.")
        return False

    config_module = types.ModuleType("config")
    for key, value in data.items():
        if (
            not isinstance(key, str)
            or not key.isidentifier()
            or key.startswith("_")
        ):
            continue
        setattr(config_module, key, value)

    import sys

    sys.modules["config"] = config_module

    return True

