SNIPPET_DIR = pathlib.Path(__file__).parent / "snippets"
ALLOWED_SNIPPET_REGEX = re.compile(r"^[A-Za-z0-9_]+$")
MAX_SNIPPET_SIZE = 1_048_576  # 1 MiB


def load_snippet(snippet_name: str) -> pathlib.Path:
    if not ALLOWED_SNIPPET_REGEX.fullmatch(snippet_name):
        raise ValueError("Invalid snippet name")

    snippet_path = SNIPPET_DIR / f"{snippet_name}.py"
    resolved = snippet_path.resolve()

    if not resolved.is_file():
        raise FileNotFoundError(f"Snippet '{snippet_name}' not found")
    if not resolved.is_relative_to(SNIPPET_DIR.resolve()):
        raise ValueError("Snippet path outside of allowed directory")

    size = resolved.stat().st_size
    if size > MAX_SNIPPET_SIZE:
        raise ValueError("Snippet file exceeds maximum allowed size")

    return resolved


def _validate_code(code: str) -> None:
    tree = ast.parse(code, mode="exec")
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            raise ValueError("Import statements are not allowed")
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id == "__import__":
                raise ValueError("Dynamic import is prohibited")
        if isinstance(node, ast.Attribute):
            raise ValueError("Attribute access is prohibited")


SAFE_BUILTINS = {
    "print": print,
    "range": range,
    "len": len,
    "sum": sum,
    "max": max,
    "min": min,
    "abs": abs,
    "bool": bool,
    "int": int,
    "float": float,
    "str": str,
    "dict": dict,
    "list": list,
    "tuple": tuple,
    "set": set,
    "enumerate": enumerate,
    "zip": zip,
    "map": map,
    "filter": filter,
    "any": any,
    "all": all,
}


def safe_exec(code: str,
              globals_dict: Dict[str, object] | None = None,
              locals_dict: Dict[str, object] | None = None) -> None:
    _validate_code(code)

    # Prepare globals for the snippet
    if globals_dict is None:
        globals_dict = {"__builtins__": SAFE_BUILTINS}
    else:
        globals_dict = {"__builtins__": SAFE_BUILTINS, **globals_dict}

    if locals_dict is None:
        locals_dict = {}

    # Execute the code in a separate Python process to contain any side effects.
    try:
        # Build a wrapper script that sets up the safe builtins
        builtin_definitions = ", ".join(
            f"'{name}': {name}" for name in SAFE_BUILTINS
        )
        wrapper_script = (
            f"import builtins, sys
"
            f"builtins.__dict__.update({{ {builtin_definitions} }})
"
            "exec(sys.stdin.read(), globals(), locals())
"
        )
        result = subprocess.run(
            [sys.executable, "-S", "-u", "-c", wrapper_script],
            input=code,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=os.environ.copy(),
            check=True,
        )
        if result.stdout:
            sys.stdout.buffer.write(result.stdout)
        if result.stderr:
            sys.stderr.buffer.write(result.stderr)
    except subprocess.CalledProcessError as exc:
        logging.error("Error executing snippet: %s", exc)
        raise


def _log_dev_envvars() -> None:
    for key, value in os.environ.items():
        if key.startswith("DEV_"):
            logging.debug("%s = %s", key, "<masked>")


def main() -> None:
    snippet_name = os.getenv("SNIPPET_NAME", "default")
    dev_mode = os.getenv("DEV_MODE", "false").strip().lower() in {"1", "true", "yes"}

    try:
        snippet_path = load_snippet(snippet_name)
        code = snippet_path.read_text(encoding="utf-8")
        safe_exec(code)
