import os
import pathlib
import yaml
import uuid
import tempfile

BASE_DIR = pathlib.Path("/etc/myapp").resolve()


def load_modify_save_yaml(config_path: str, updates: dict) -> None:
    if not isinstance(config_path, str) or not config_path:
        raise ValueError("config_path must be a non-empty string")
    if not isinstance(updates, dict):
        raise ValueError("updates must be a dictionary")

    raw_path = pathlib.Path(config_path).expanduser()
    if not raw_path.is_absolute():
        raise ValueError("config_path must be an absolute path")
    if any(part == ".." for part in raw_path.parts):
        raise ValueError("config_path must not contain '..' components")
    if raw_path.is_symlink():
        raise ValueError("config_path must not be a symlink")

    full_path = raw_path.resolve()
    if not full_path.is_relative_to(BASE_DIR):
        raise ValueError(f"config_path must be within {BASE_DIR}")
    if full_path.is_symlink():
        raise ValueError("config_path resolved to a symlink")

    try:
        st_orig = os.stat(str(full_path), follow_symlinks=False)
    except OSError as err:
        raise ValueError("Unable to stat the configuration file") from err

    if not os.path.isfile(str(full_path)):
        raise ValueError("config_path must be a regular file")

    # Read the existing YAML file atomically with O_NOFOLLOW
    try:
        fd_read = os.open(str(full_path), os.O_RDONLY | os.O_NOFOLLOW)
        data_bytes = bytearray()
        while True:
            chunk = os.read(fd_read, 65536)
            if not chunk:
                break
            data_bytes.extend(chunk)
    except OSError as err:
        raise ValueError("Unable to read the configuration file") from err
    finally:
        if 'fd_read' in locals():
            os.close(fd_read)

    try:
        data_str = data_bytes.decode("utf-8")
    except Exception as err:
        raise ValueError("Configuration file is not valid UTF-8") from err

    try:
        data = yaml.safe_load(data_str) or {}
    except yaml.YAMLError as err:
        raise ValueError("YAML parsing error") from err

    if not isinstance(data, dict):
        raise ValueError("The configuration file does not contain a top-level mapping")

    def _deep_merge(orig, upd):
        for key, value in upd.items():
            if (
                key in orig
                and isinstance(orig[key], dict)
                and isinstance(value, dict)
            ):
                _deep_merge(orig[key], value)
            else:
                orig[key] = value

    _deep_merge(data, updates)

    tmp_dir = full_path.parent
    if tmp_dir.is_symlink():
        raise ValueError("Parent directory is invalid or insecure")

    unique_name = f".{full_path.name}-{uuid.uuid4().hex}"
    tmp_path = tmp_dir / unique_name

    # Create temporary file with secure permissions
    old_umask = os.umask(0)
    try:
        fd_tmp = os.open(str(tmp_path), os.O_RDWR | os.O_CREAT | os.O_EXCL, 0o600)
    finally:
        os.umask(old_umask)

    try:
        with os.fdopen(fd_tmp, "w", encoding="utf-8", closefd=False) as tmp_fp:
            yaml.safe_dump(
                data,
                tmp_fp,
                default_flow_style=False,
                sort_keys=False,
            )
            tmp_fp.flush()
            os.fsync(tmp_fp.fileno())
        os.fsync(fd_tmp)
    except Exception as err:
        raise ValueError("Unable to write the temporary configuration file") from err
    finally:
        os.close(fd_tmp)

    # Re-validate that the original file has not changed
    try:
        fd_verify = os.open(str(full_path), os.O_RDONLY | os.O_NOFOLLOW)
        st_verify = os.fstat(fd_verify)
    except OSError as err:
        raise ValueError("Unable to verify configuration file before write") from err
    finally:
        if 'fd_verify' in locals():
            os.close(fd_verify)

    if (st_orig.st_ino != st_verify.st_ino) or (st_orig.st_dev != st_verify.st_dev):
        raise ValueError("Configuration file changed during update")

    # Atomically replace the original file with the temporary file
    try:
        os.replace(str(tmp_path), str(full_path))
    except OSError as err:
        raise ValueError("Unable to write the updated configuration file") from err

    return None

