from collections import OrderedDict as _OrderedDict

_HASH_CACHE_MAXSIZE = 128
_hash_cache = _OrderedDict()
_cache_lock = threading.Lock()

def compute_file_hash(file_path: pathlib.Path | str) -> pathlib.Path:
    if not isinstance(file_path, (str, pathlib.Path)):
        raise TypeError("file_path must be a string or pathlib.Path instance")

    path_obj = pathlib.Path(file_path)

    try:
        fd = os.open(str(path_obj), os.O_RDONLY | os.O_NOFOLLOW)
    except FileNotFoundError:
        raise FileNotFoundError("Specified file does not exist")
    except PermissionError:
        raise PermissionError("Insufficient permissions to read the file")
    except OSError:
        raise IOError("Failed to open the file for reading")

    try:
        stat = os.fstat(fd)
        if not os.path.isfile(path_obj):
            raise FileNotFoundError("Specified path is not a regular file")
    finally:
        os.close(fd)

    key = (stat.st_dev, stat.st_ino)

    with _cache_lock:
        cached_hash = _hash_cache.get(key)
    if cached_hash is not None:
        file_hash = cached_hash
    else:
        sha256 = hashlib.sha256()
        try:
            with os.fdopen(os.open(str(path_obj), os.O_RDONLY | os.O_NOFOLLOW), "rb") as f:
                for chunk in iter(lambda: f.read(8192), b""):
                    sha256.update(chunk)
            file_hash = sha256.hexdigest()
        except Exception:
            raise IOError("Error reading the file")
        with _cache_lock:
            _hash_cache[key] = file_hash
            if len(_hash_cache) > _HASH_CACHE_MAXSIZE:
                _hash_cache.popitem(last=False)

    try:
        fd_tmp, tmp_path = tempfile.mkstemp(
            prefix="hash_",
