import re
from urllib.parse import urlparse
from typing import Optional

ALLOWED_URL_SCHEMES = {"http", "https"}
ISO8601_TZ_REGEX = re.compile(
    r"^\d{4}-\d{2}-\d{2}T"
    r"\d{2}:\d{2}:\d{2}"
    r"(?:\.\d+)?"
    r"(?:Z|[+-]\d{2}:\d{2})$",
    re.IGNORECASE,
)


def _validate_website(website: str) -> str:
    if not isinstance(website, str):
        raise ValueError("Website must be a string")
    website = website.strip()
    if not website:
        raise ValueError("Website cannot be empty")
    parsed = urlparse(website)
    if not parsed.scheme or not parsed.netloc:
        raise ValueError("Invalid website URL")
    if parsed.scheme.lower() not in ALLOWED_URL_SCHEMES:
        raise ValueError("Unsupported URL scheme")
    return website.lower()


def _validate_timestamp(timestamp: str) -> str:
    if not isinstance(timestamp, str):
        raise ValueError("Timestamp must be a string")
    timestamp = timestamp.strip()
    if not timestamp:
        raise ValueError("Timestamp cannot be empty")
    if not ISO8601_TZ_REGEX.match(timestamp):
        raise ValueError("Timestamp must be a timezoneâaware ISO 8601 string")
    return timestamp


def generate_identifier(
    website: str, timestamp: str, secret_key: Optional[bytes] = None
) -> str:
    clean_website = _validate_website(website)
    clean_timestamp = _validate_timestamp(timestamp)
    combined = f"{clean_website}|{clean_timestamp}".encode("utf-8")

    if secret_key is not None:
        if not isinstance(secret_key, (bytes, bytearray)):
            raise ValueError("Secret key must be bytes")
        digest = hmac.new(secret_key, combined, hashlib.sha256).hexdigest()
    else:
        digest = hashlib.sha256(combined).hexdigest()
    return digest

