import argparse
import json
import logging
import os
import shutil
import ssl
import sys
import tarfile
import urllib.parse
import urllib.request
import zipfile
from pathlib import Path
from typing import Dict, List

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    stream=sys.stderr,
)

MAX_DOWNLOAD_SIZE = 50 * 1024 * 1024  # 50MB
MAX_EXTRACT_LIMIT = 20000
MAX_SIZE_LIMIT = 5 * MAX_DOWNLOAD_SIZE
MAX_PRODUCT_NAME_LENGTH = 255

def is_valid_product_name(name: str) -> bool:
    if not name or len(name) > MAX_PRODUCT_NAME_LENGTH:
        return False
    if name in {".", ".."}:
        return False
    return name.replace("-", "").replace("_", "").isalnum()

def is_valid_url(url: str) -> bool:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() != "https" or not parsed.netloc:
        return False
    if parsed.username or parsed.password:
        return False
    return True

def safe_extract_tar(tar: tarfile.TarFile, path: Path) -> None:
    base = path.resolve()
    safe_members: List[tarfile.TarInfo] = []

    for member in tar.getmembers():
        # Skip device files
        if member.isdev() or member.ischar() or member.isblock() or member.isfifo():
            continue
        # Validate symlinks and hardlinks
        if member.issym() or member.islnk():
            link_target = Path(member.linkname)
            link_resolved = (
                link_target.resolve()
                if link_target.is_absolute()
                else (path / link_target).resolve()
            )
            if not link_resolved.is_relative_to(base):
                raise RuntimeError(f"Symlink or hardlink points outside extraction dir: {member.name}")
        # Validate regular file paths
        member_path = (path / member.name).resolve()
        if not member_path.is_relative_to(base):
            raise RuntimeError(f"Attempted Path Traversal in tar file: {member.name}")
        safe_members.append(member)

    try:
        tar.extractall(path=str(path), members=safe_members, filter="data")
    except TypeError:
        for m in safe_members:
            tar.extract(m, path=str(path))

    total_size = 0
    total_files = 0
    for file in path.rglob("*"):
        if file.is_file():
            total_size += file.stat().st_size
            total_files += 1
            if total_size > MAX_SIZE_LIMIT or total_files > MAX_EXTRACT_LIMIT:
                raise RuntimeError("Extraction exceeds size or entry count limits")

def safe_extract_zip(zf: zipfile.ZipFile, path: Path) -> None:
    base = path.resolve()
    members_to_extract: List[zipfile.ZipInfo] = []

    for zi in zf.infolist():
        unix_mode = zi.external_attr >> 16
        if unix_mode & 0o120000 == 0o120000:
            continue
        member_path = (path / zi.filename).resolve()
        if not member_path.is_relative_to(base):
            raise RuntimeError(f"Attempted Path Traversal in zip file: {zi.filename}")
        members_to_extract.append(zi)

    try:
        zf.extractall(path=str(path), members=members_to_extract)
    except TypeError:
        for zi in members_to_extract:
            zf.extract(zi, path=str(path))

    total_size = 0
    total_files = 0
    for file in path.rglob("*"):
        if file.is_file():
            total_size += file.stat().st_size
            total_files += 1
            if total_size > MAX_SIZE_LIMIT or total_files > MAX_EXTRACT_LIMIT:
                raise RuntimeError("ZIP extraction exceeds size or entry count limits")

def download_file(url: str, dest: Path) -> None:
    if not is_valid_url(url):
        raise ValueError(f"Invalid URL: {url}")
    logging.info(f"Downloading {url} to {dest}")
    context = ssl.create_default_context()
    try:
        with urllib.request.urlopen(url, timeout=30, context=context) as response:
            final_url = response.geturl()
            final_parsed = urllib.parse.urlparse(final_url)
            if final_parsed.scheme.lower() != "https":
                raise RuntimeError(f"Redirected to non-HTTPS URL: {final_url}")
            if urllib.parse.urlparse(url).netloc.lower() != final_parsed.netloc.lower():
                raise RuntimeError(f"Redirected to unexpected host: {final_url}")
            content_length = response.getheader("Content-Length")
            if content_length and int(content_length) > MAX_DOWNLOAD_SIZE:
                raise RuntimeError(f"Content length {content_length} exceeds maximum allowed {MAX_DOWNLOAD_SIZE} bytes")
            total = 0
            with dest.open("wb") as out_file:
                while True:
                    chunk = response.read(8192)
                    if not chunk:
                        break
                    total += len(chunk)
                    if total > MAX_DOWNLOAD_SIZE:
                        raise RuntimeError(f"Downloaded file size exceeds maximum allowed {MAX_DOWNLOAD_SIZE} bytes")
                    out_file.write(chunk)
    except Exception as exc:
        raise RuntimeError(f"Failed to download {url}: {exc}") from exc

def process_product(product_name: str, packages: List[str], build_dir: Path) -> None:
    logging.info(f"Processing product: {product_name}")
    staging_dir = build_dir / product_name / "staging"
    final_dir = build_dir / product_name / "final"
    staging_dir.mkdir(parents=True, exist_ok=True)
    final_dir.mkdir(parents=True, exist_ok=True)

    for pkg_url in packages:
        if not is_valid_url(pkg_url):
            raise ValueError(f"Invalid URL: {pkg_url}")
        pkg_name = Path(urllib.parse.urlparse(pkg_url).path).name
        if pkg_name in {".", ".."} or not pkg_name:
            raise ValueError(f"Invalid package filename derived from URL: {pkg_url}")
        pkg_path = staging_dir / pkg_name
        download_file(pkg_url, pkg_path)

        if pkg_path.suffix in {".gz", ".tgz"} and pkg_path.stem.endswith(".tar"):
            with tarfile.open(pkg_path, "r:gz") as tar:
                safe_extract_tar(tar, staging_dir)
        elif pkg_path.suffix == ".tar":
            with tarfile.open(pkg_path, "r:") as tar:
                safe_extract_tar(tar, staging_dir)
        elif pkg_path.suffix == ".zip":
            with zipfile.ZipFile(pkg_path, "r") as zf:
                safe_extract_zip(zf, staging_dir)
        else:
            raise RuntimeError(f"Unsupported package format: {pkg_path}")

    for item in staging_dir.iterdir():
        dest = final_dir / item.name
        if dest.exists():
            if dest.is_dir():
                shutil.rmtree(dest)
            else:
                dest.unlink()
        shutil.move(str(item), str(dest))

    zip_path = build_dir / product_name / f"{product_name}.zip"
    with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zf:
        for root, _, files in os.walk(final_dir):
            for file in files:
                file_path = Path(root) / file
                archive_name = file_path.relative_to(final_dir)
                zf.write(file_path, archive_name)
    logging.info(f"Created archive: {zip_path}")

def main() -> None:
    parser = argparse.ArgumentParser(description="Package extractor")
    parser.add_argument(
        "--products",
        type=str,
        required=True,
        help="JSON string mapping product names to list of HTTPS package URLs",
    )
    parser.add_argument(
        "--build-dir",
        type=Path,
        required=True,
        help="Path to the build directory",
    )
    args = parser.parse_args()

    try:
        products_dict: Dict[str, List[str]] = json.loads(args.products)
    except json.JSONDecodeError as exc:
        logging.error(f"Invalid JSON for products: {exc}")
        sys.exit(1)

    if not isinstance(products_dict, dict):
        logging.error("Products JSON must be an object mapping product names to URL lists")
        sys.exit(1)

    for product_name, pkg_list in products_dict.items():
        if not is_valid_product_name(product_name):
            logging.error(f"Invalid product name: {product_name}")
            sys.exit(1)
        if not isinstance(pkg_list, list) or not all(isinstance(u, str) for u in pkg_list):
            logging.error(f"Package list must be a list of URLs for product {product_name}")
            sys.exit(1)

    build_dir = args.build_dir.expanduser().resolve(strict=True)
    home_dir = Path.home().resolve()
    if not build_dir.is_relative_to(home_dir):
        logging.error(f"Build directory {build_dir} must be within the home directory {home_dir}")
        sys.exit(1)

    if not build_dir.is_dir():
        try:
            build_dir.mkdir(parents=True, exist_ok=True)
        except Exception as exc:
            logging.error(f"Could not create build directory '{build_dir}': {exc}")
            sys.exit(1)

    for product, packages in products_dict.items():
        try:
            process_product(product, packages, build_dir)
        except Exception as exc:
            logging.error(f"Error processing product '{product}': {exc}")
            sys.exit(1)

    logging.info("All products processed successfully.")

if __name__ == "__main__":
    main()

