#!/usr/bin/env python3
import os
import sys
import json
import re
import shlex
import argparse
import subprocess
from typing import List, Dict

# ANSI color codes
try:
    from colorama import init as colorama_init
    colorama_init()
    COLOR_RESET = "[0m"
    COLOR_GREEN = "[32m"
    COLOR_BLUE = "[34m"
    COLOR_CYAN = "[36m"
    COLOR_RED = "[31m"
except Exception:
    COLOR_RESET = ""
    COLOR_GREEN = ""
    COLOR_BLUE = ""
    COLOR_CYAN = ""
    COLOR_RED = ""

# Base directory for file operations
BASE_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "sandbox"))
os.makedirs(BASE_DIR, exist_ok=True)

# Whitelisted safe commands
WHITELIST = {
    "echo", "ls", "cat", "date", "whoami", "uptime", "df",
    "free", "ps", "head", "tail", "sort", "uniq"
}

# Allowed pattern for tokens
TOKEN_REGEX = re.compile(r"^[A-Za-z0-9_.\/-]+$")

# Maximum lengths
MAX_TOKEN_LENGTH = 256
MAX_COMMAND_LENGTH = 1024

# Commands that operate on files/directories
FILE_COMMANDS = {"cat", "ls", "head", "tail", "sort", "uniq"}

def get_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Secure JSON command executor")
    parser.add_argument("json_file", help="Path to JSON file containing command instructions.")
    return parser.parse_args()

def load_json(path: str) -> Dict:
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("JSON root must be an object")
        return data
    except (IOError, json.JSONDecodeError, ValueError) as e:
        print(f"{COLOR_RED}Error loading JSON: {e}{COLOR_RESET}")
        sys.exit(1)

def validate_path(token: str) -> None:
    if ".." in token or token.startswith("./") or token.startswith("../"):
        raise ValueError(f"Relative or traversal path detected: '{token}'")
    if not os.path.isabs(token):
        raise ValueError(f"Non-absolute path: '{token}'")
    real_path = os.path.realpath(token)
    if not real_path.startswith(BASE_DIR):
        raise ValueError(f"Path '{token}' resolves outside allowed base directory")
    return

def validate_command(cmd: str) -> List[str]:
    try:
        tokens = shlex.split(cmd)
    except ValueError as e:
        raise ValueError(f"Failed to parse command: {e}")

    if not tokens:
        raise ValueError("Empty command")

    if len(tokens[0]) > MAX_TOKEN_LENGTH:
        raise ValueError("Command name too long")

    cmd_name = tokens[0]
    if cmd_name not in WHITELIST:
        raise ValueError(f"Command '{cmd_name}' is not whitelisted")

    if sum(len(t) for t in tokens) > MAX_COMMAND_LENGTH:
        raise ValueError("Command exceeds maximum allowed length")

    for token in tokens[1:]:
        if len(token) > MAX_TOKEN_LENGTH:
            raise ValueError(f"Token too long: '{token}'")
        if not TOKEN_REGEX.match(token):
            raise ValueError(f"Unsafe token in command: '{token}'")
        if cmd_name in FILE_COMMANDS and token.startswith("/") and not token.startswith("-"):
            validate_path(token)

    return tokens

def execute_command(tokens: List[str]) -> str:
    try:
        result = subprocess.run(
            tokens,
            capture_output=True,
            text=True,
            shell=False,
            env={"PATH": "/usr/bin:/bin", "LANG": "C"}
        )
        return result.stdout + result.stderr
    except OSError as e:
        return f"Execution error: {e}"

def safe_display(inp: str) -> str:
    return "".join(
        c if 32 <= ord(c) <= 126 else f"\x{ord(c):02x}"
        for c in inp
    )

def main() -> None:
    args = get_args()
    data = load_json(args.json_file)

    instructions = data.get("instructions", [])
    if not isinstance(instructions, list):
        print(f"{COLOR_RED}Invalid 'instructions' format: expected a list{COLOR_RESET}")
        sys.exit(1)

    results: Dict[str, str] = {}
    for idx, instr in enumerate(instructions, 1):
        if not isinstance(instr, dict):
            print(f"{COLOR_RED}Instruction {idx} is not a dictionary. Skipping.{COLOR_RESET}")
            continue
        raw_cmd = instr.get("command")
        if not isinstance(raw_cmd, str):
            print(f"{COLOR_RED}Instruction {idx} missing 'command' string. Skipping.{COLOR_RESET}")
            continue

        try:
            tokens = validate_command(raw_cmd)
        except ValueError as e:
            print(f"{COLOR_RED}Validation failed for instruction {idx}: {e}{COLOR_RESET}")
            continue

        cmd_display = " ".join(shlex.quote(t) for t in tokens)
        print(f"{COLOR_GREEN}Command {idx}:{COLOR_RESET} {COLOR_CYAN}{cmd_display}{COLOR_RESET}")

        inp = instr.get("input")
        if isinstance(inp, str):
            print(f"{COLOR_BLUE}Input:{COLOR_RESET} {safe_display(inp)}")

        output = execute_command(tokens)
        results[raw_cmd] = output

        print(f"{COLOR_CYAN}Output:{COLOR_RESET}")
        print(output)

        try:
            input(f"{COLOR_RED}Press Enter to continue...{COLOR_RESET}")
        except EOFError:
            pass

    print("
Summary of executed commands:")
    for c, o in results.items():
        print(f"{COLOR_GREEN}{c}:{COLOR_RESET}")
        print(o)
        print("-" * 40)

if __name__ == "__main__":
    os.environ.update({"PATH": "/usr/bin:/bin", "LANG": "C"})
    main()

