def _sanitize_command(cmd: str) -> list[str]:
    if not isinstance(cmd, str) or not cmd.strip():
        raise ValueError("Command must be a non-empty string.")
    parts = shlex.split(cmd, posix=True)
    if not parts:
        raise ValueError("Command parsing failed.")
    cmd_name = parts[0]
    if cmd_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Disallowed command: {cmd_name!r}")
    # Ensure command exists in the minimal PATH
    if shutil.which(cmd_name, path="/usr/bin:/bin") is None:
        raise ValueError(f"Command not found: {cmd_name!r}")
    disallowed_chars = {"&&", "||", ";", "|", "$", "&", "`", ">", "<", ">>"}
    for arg in parts[1:]:
        if any(ch in arg for ch in disallowed_chars):
            raise ValueError(f"Argument {arg!r} contains disallowed shell metacharacters.")
        if arg.startswith(('/', '~')) or '..' in arg.split('/'):
            raise ValueError(f"Argument {arg!r} contains disallowed path.")
        if arg.startswith('-i'):
            raise ValueError(f"Argument {arg!r} modifies files in place.")
