    except subprocess.SubprocessError as e:
        _alert_user(f"Command execution failed: {e}")
        raise RuntimeError(f"Command execution failed: {e}") from None
    except Exception as e:
        _alert_user(f"Unexpected error during command execution: {type(e).__name__}")
        raise RuntimeError(f"Unexpected error: {type(e).__name__}") from None
