        os.chmod(script_file, stat.S_IRUSR | stat.S_IWUSR)
    except Exception as e:
        _alert_user(f"Failed to write script file: {e}")
        raise RuntimeError(f"Failed to write script file: {e}") from None
    logger.info("Command output written to secure script file.")

