import java.util.Collections;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.Properties;
import java.util.regex.Pattern;

public class AntlrRunner {

    private static final Set<String> ALLOWED_JAR_PATTERNS = Set.of(
            "^antlr-\d+(?:\.\d+)+-complete\.jar$",
            "^antlr-\d+(?:\.\d+)+-runtime\.jar$"
    );

    private static final Set<String> ALLOWED_OPTIONS = Set.of(
            "-o", "-lib", "-atn", "-debug", "-g", "-tokenVocab"
    );

    private static final Set<String> OPTIONS_REQUIRING_ARGUMENT = new HashSet<>(Set.of(
            "-o", "-lib", "-g", "-tokenVocab"
    ));

    private static final Set<String> ALLOWED_D_PROPERTIES = Set.of(); // Add allowed -D properties if needed

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <directory> <file> [options...]");
            System.exit(1);
        }

        final Path dirPath = resolveDirectory(args[0]);
        final Path filePath = resolveFile(dirPath, args[1]);

        final Path jarPath = resolveJarFromConfig(dirPath);

        final List<String> filteredOptions = filterOptions(
                args.length > 2 ? List.of(args).subList(2, args.length) : List.of()
        );

        final List<String> command = buildCommand(jarPath, filePath, filteredOptions);

        final ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(dirPath.toFile());
        pb.redirectErrorStream(true);

        try {
            // Final raceâcondition free worldâwritable checks before execution
            if (isWorldWritable(jarPath)) {
                System.err.println("Error: ANTLR jar is world-writable: " + jarPath);
                System.exit(1);
            }
            if (isWorldWritable(filePath)) {
                System.err.println("Error: Input file is world-writable: " + filePath);
                System.exit(1);
            }

            final Process process = pb.start();
            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
                 BufferedWriter out = new BufferedWriter(new OutputStreamWriter(System.out))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    out.write(line);
                    out.newLine();
                    out.flush();
                }
            } catch (IOException e) {
                System.err.println("Error: IO exception while reading ANTLR output.");
                System.exit(1);
            }

            final int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("ANTLR tool exited with error code: " + exitCode);
                System.exit(exitCode);
            }
        } catch (IOException | InterruptedException e) {
            System.err.println("Error: Failed to start or run ANTLR process.");
            System.exit(1);
        }
    }

    private static Path resolveDirectory(String dirArg) {
        try {
            Path path = Paths.get(dirArg).toRealPath();
            if (!Files.isDirectory(path)) {
                System.err.println("Error: Directory does not exist: " + path);
                System.exit(1);
            }
            return path;
        } catch (IOException e) {
            System.err.println("Error: Unable to resolve directory: " + dirArg);
            System.exit(1);
            return null;
        }
    }

    private static Path resolveFile(Path dirPath, String fileArg) {
        Path file = dirPath.resolve(fileArg);
        try {
            file = file.toRealPath();
            Path dirCanonical = dirPath.toRealPath();
            if (!Files.isRegularFile(file) || !file.startsWith(dirCanonical)) {
                System.err.println("Error: Invalid file path: " + file);
                System.exit(1);
            }
            if (isWorldWritable(file)) {
                System.err.println("Error: File is world-writable: " + file);
                System.exit(1);
            }
            return file;
        } catch (IOException e) {
            System.err.println("Error: Unable to resolve file: " + fileArg);
            System.exit(1);
            return null;
        }
    }

    private static Path resolveJarFromConfig(Path dirPath) {
        Path configPath = dirPath.resolve("antlr-runner.properties");
        if (!Files.exists(configPath) || !Files.isRegularFile(configPath)) {
            System.err.println("Error: Configuration file not found: " + configPath);
            System.exit(1);
        }
        if (isWorldWritable(configPath)) {
            System.err.println("Error: Configuration file is world-writable: " + configPath);
            System.exit(1);
        }

        Properties props = new Properties();
        try (InputStream in = Files.newInputStream(configPath)) {
            props.load(in);
        } catch (IOException e) {
            System.err.println("Error: Unable to read configuration file: " + configPath);
            System.exit(1);
        }

        String jarStr = props.getProperty("antlr.jar");
        if (jarStr == null || jarStr.isEmpty()) {
            System.err.println("Error: 'antlr.jar' property not defined in configuration.");
            System.exit(1);
        }

        String expectedHash = props.getProperty("antlr.jar.sha256");

        Path jarPath = Paths.get(jarStr);
        if (!jarPath.isAbsolute()) {
            jarPath = configPath.getParent().resolve(jarPath);
        }

        try {
            jarPath = jarPath.toRealPath();
        } catch (IOException e) {
            System.err.println("Error: Unable to resolve ANTLR jar path: " + jarStr);
            System.exit(1);
        }

        if (!Files.isRegularFile(jarPath)) {
            System.err.println("Error: ANTLR jar not found: " + jarPath);
            System.exit(1);
        }

        if (!isJarAllowed(jarPath)) {
            System.err.println("Error: Unapproved ANTLR jar: " + jarPath);
            System.exit(1);
        }

        if (expectedHash != null && !expectedHash.isEmpty()) {
            try {
                String actualHash = sha256Hex(jarPath);
                if (!actualHash.equalsIgnoreCase(expectedHash)) {
                    System.err.println("Error: ANTLR jar checksum mismatch. Expected: " + expectedHash + ", Actual: " + actualHash);
                    System.exit(1);
                }
            } catch (Exception e) {
                System.err.println("Error: Unable to compute checksum for ANTLR jar.");
                System.exit(1);
            }
        }

        return jarPath;
    }

    private static boolean isJarAllowed(Path jarPath) {
        String jarName = jarPath.getFileName().toString();
        for (String pattern : ALLOWED_JAR_PATTERNS) {
            if (Pattern.compile(pattern).matcher(jarName).matches()) {
                return true;
            }
        }
        return false;
    }

    private static boolean isWorldWritable(Path path) {
        try {
            Set<PosixFilePermission> perms = Files.getPosixFilePermissions(path);
            return perms.contains(PosixFilePermission.GROUP_WRITE) || perms.contains(PosixFilePermission.OTHERS_WRITE);
        } catch (UnsupportedOperationException | IOException e) {
            try {
                AclFileAttributeView view = Files.getFileAttributeView(path, AclFileAttributeView.class);
                if (view != null) {
                    List<AclEntry> entries = view.getAcl();
                    for (AclEntry entry : entries) {
                        String name = entry.principal().getName();
                        if (name != null && (
                                name.equalsIgnoreCase("Everyone") || name.equalsIgnoreCase("Authenticated Users")
                                        || name.equalsIgnoreCase("ANONYMOUS LOGON"))) {
                            if (entry.permissions().contains(AclEntryPermission.WRITE_DATA) ||
                                    entry.permissions().contains(AclEntryPermission.APPEND_DATA)) {
                                return true;
                            }
                        }
                    }
                }
            } catch (Exception ignored) {
            }
            return path.toFile().canWrite();
        }
    }

    private static List<String> filterOptions(List<String> options) {
        if (options.isEmpty()) {
            return Collections.emptyList();
        }
        List<String> filtered = new ArrayList<>();
        for (int i = 0; i < options.size(); i++) {
            String opt = options.get(i);
            if (ALLOWED_OPTIONS.contains(opt)) {
                if (OPTIONS_REQUIRING_ARGUMENT.contains(opt)) {
                    if (i + 1 >= options.size() || options.get(i + 1).startsWith("-")) {
                        System.err.println("Error: Option " + opt + " requires an argument.");
                        System.exit(1);
                    }
                    filtered.add(opt);
                    filtered.add(options.get(i + 1));
                    i++;
                } else {
                    filtered.add(opt);
                }
            } else if (opt.startsWith("-D")) {
                String property = opt.substring(2);
                String name = property.contains("=") ? property.substring(0, property.indexOf('=')) : property;
                if (ALLOWED_D_PROPERTIES.contains(name)) {
                    filtered.add(opt);
                } else {
                    System.err.println("Warning: Disallowed -D property ignored: " + name);
                }
            } else {
                System.err.println("Warning: Unaccepted option ignored: " + opt);
            }
        }
        return filtered;
    }

    private static List<String> buildCommand(Path jarPath, Path filePath, List<String> options) {
        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-jar");
        command.add(jarPath.toString());
        command.add(filePath.toString());
        command.addAll(options);
        return command;
    }

    private static String sha256Hex(Path path) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        try (InputStream in = Files.newInputStream(path)) {
            byte[] buffer = new byte[8192];
            int read;
            while ((read = in.read(buffer)) != -1) {
                digest.update(buffer, 0, read);
            }
        }
        byte[] hash = digest.digest();
        StringBuilder sb = new StringBuilder();
        for (byte b : hash) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}

