import os
import re
import shutil
import subprocess
import stat
from typing import Dict, List

ALLOWED_HG_DIRS = {"/usr/bin", "/usr/local/bin", "/opt/bin"}
ALLOWED_REPO_BASES = {"/srv/repos", "/opt/mercurial"}

class MercurialError(Exception):
    """Custom exception for Mercurial-related errors."""
    pass

def _validate_hg_executable() -> str:
    """Find and validate the hg executable."""
    hg_path = shutil.which("hg")
    if hg_path is None:
        raise MercurialError("Mercurial executable 'hg' not found")

    try:
        st = os.stat(hg_path)
    except OSError as exc:
        raise MercurialError(f"Unable to stat Mercurial executable: {exc}")

    if not stat.S_ISREG(st.st_mode):
        raise MercurialError("Mercurial executable is not a regular file")
    if not os.access(hg_path, os.X_OK):
        raise MercurialError("Mercurial executable is not executable")
    if (st.st_mode & (stat.S_ISUID | stat.S_ISGID)) != 0:
        raise MercurialError("Mercurial executable must not have setuid or setgid bits")
    if st.st_uid != 0:
        raise MercurialError("Mercurial executable must be owned by root")

    hg_dir = os.path.dirname(os.path.realpath(hg_path))
    if hg_dir not in ALLOWED_HG_DIRS:
        raise MercurialError(f"Mercurial executable located in untrusted directory: {hg_dir}")

    return os.path.realpath(hg_path)

def _validate_repo_path(repo_path: str) -> str:
    """Validate and normalize the repository path."""
    if not os.path.isabs(repo_path):
        raise MercurialError("Repository path must be absolute")
    norm_path = os.path.normpath(repo_path)
    try:
        real_path = os.path.realpath(norm_path)
    except OSError as exc:
        raise MercurialError(f"Unable to resolve repository path: {exc}")

    if real_path != norm_path:
        raise MercurialError("Repository path must not contain symbolic links")
    if not os.path.isdir(real_path):
        raise MercurialError("Repository path does not exist or is not a directory")
    if not any(
        real_path == base or real_path.startswith(base + os.sep) for base in ALLOWED_REPO_BASES
    ):
        raise MercurialError("Repository path is outside allowed base directories")
    if not os.path.isdir(os.path.join(real_path, ".hg")):
        raise MercurialError("Directory does not contain a Mercurial repository (.hg missing)")
    return real_path

def _validate_rev(rev: str) -> None:
    """Validate the revision identifier."""
    if not re.fullmatch(r"(?:[0-9a-fA-F]+|[0-9]+)", rev):
        raise MercurialError("Invalid revision identifier")
    if len(rev) > 64:
        raise MercurialError("Revision identifier too long")

def get_changeset_info(repo_path: str, rev: str) -> Dict[str, object]:
    real_repo_path = _validate_repo_path(repo_path)
    _validate_rev(rev)

    hg_path = _validate_hg_executable()

    template = (
        "{tags}
"
        "{date|isodate}
"
        "{author}
"
        "{parents}
"
        "{desc}"
    )
    cmd = [hg_path, "log", "-r", rev, "--template", template]

    try:
        result = subprocess.run(
            cmd,
            cwd=real_repo_path,
            capture_output=True,
            text=True,
            check=True,
            shell=False,
            timeout=10,
        )
    except subprocess.TimeoutExpired:
        raise MercurialError("Mercurial command timed out")
    except subprocess.CalledProcessError as exc:
        raise MercurialError(f"Failed to retrieve changeset information: {exc}")

    output_lines = result.stdout.splitlines()
    if len(output_lines) < 5:
        raise MercurialError("Incomplete changeset data received")

    tags_line, date_line, author_line, parents_line = output_lines[:4]
    comment_lines = output_lines[4:]

    tags: List[str] = [t for t in tags_line.strip().split() if t]
    parents: List[str] = [p for p in parents_line.strip().split() if p]
    comment = "
".join(comment_lines).strip()

    return {
        "tags": tags,
        "date": date_line.strip(),
        "author": author_line.strip(),
        "parents": parents,
        "comment": comment,
    }

import os
import json
import re
from typing import Optional
from urllib.parse import urlparse, parse_qs, urlencode
from urllib.request import Request, urlopen
from urllib.error import URLError, HTTPError


_video_id_regex = re.compile(r'^[A-Za-z0-9_-]{11}$')


def _is_valid_video_id(video_id: str) -> bool:
    return bool(_video_id_regex.fullmatch(video_id))


def _extract_video_id(parsed: urlparse) -> Optional[str]:
    netloc = parsed.netloc.lower()
    path = parsed.path
    query = parse_qs(parsed.query)

    if netloc in {"youtu.be", "www.youtu.be"}:
        video_id = path.lstrip("/")
    elif "youtube.com" in netloc:
        if path.startswith("/watch"):
            video_id = query.get("v", [None])[0]
        elif path.startswith(("/embed/", "/v/", "/shorts/")):
            video_id = path.split("/", 2)[-1]
        else:
            video_id = None
    elif parsed.scheme == "youtube":
        video_id = parsed.netloc or parsed.path
    else:
        video_id = None

    if video_id and _is_valid_video_id(video_id):
        return video_id
    return None


def _get_video_id_from_api(query: str, api_key: str, logger) -> Optional[str]:
    if not query or len(query) > 200:
        logger.debug("Invalid query for API request")
        return None

    base_url = "https://www.googleapis.com/youtube/v3/search"
    params = {
        "part": "id",
        "type": "video",
        "maxResults": "1",
        "q": query,
        "key": api_key,
    }
    req_url = f"{base_url}?{urlencode(params)}"
    logger.debug("Calling YouTube API search with query '%s'", query)

    parsed_req = urlparse(req_url)
    if parsed_req.scheme != "https" or parsed_req.netloc != "www.googleapis.com":
        logger.debug("API request URL does not use a permitted HTTPS endpoint")
        return None

    req = Request(req_url, headers={"User-Agent": "SecureYouTubeResolver/1.0", "Accept": "application/json"})
    try:
        with urlopen(req, timeout=10) as resp:
            final_url = resp.geturl()
            parsed_final = urlparse(final_url)
            if parsed_final.scheme != "https" or parsed_final.netloc != "www.googleapis.com":
                logger.debug("Redirected to disallowed URL %s", final_url)
                return None
            if resp.status != 200:
                logger.debug("YouTube API returned unexpected status %s", resp.status)
                return None
            data = json.loads(resp.read().decode("utf-8"))
            items = data.get("items")
            if not items:
                logger.debug("No search results found for query '%s'", query)
                return None
            video_id = items[0]["id"].get("videoId")
            if video_id and _is_valid_video_id(video_id):
                return video_id
            logger.debug("Returned video ID '%s' is invalid", video_id)
            return None
    except (URLError, HTTPError, json.JSONDecodeError) as exc:
        logger.debug("Error during YouTube API call: %s", exc)
        return None


def get_resolved_youtube_url(track_name: str, logger) -> Optional[str]:
    if not isinstance(track_name, str):
