package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"syscall"
	"time"
)

const (
	validatorBinary = "/usr/local/bin/validator"
	maxFileSize      = 10 << 20
	timeoutDuration  = 60 * time.Second
	safeDir          = "/tmp/validator_input"
)

var expectedValidatorChecksum = "PLACEHOLDER_HASH"

func die(format string, a ...interface{}) {
	fmt.Fprintf(os.Stderr, format+"
", a...)
	os.Exit(1)
}

func checkSafeDir() {
	info, err := os.Stat(safeDir)
	if err != nil {
		die("Cannot access safe directory: %v", err)
	}
	if !info.IsDir() {
		die("Safe location is not a directory")
	}
	stat, ok := info.Sys().(*syscall.Stat_t)
	if !ok {
		die("Cannot get file status for safe directory")
	}
	if stat.Uid != 0 || (stat.Mode&0777) != 0700 {
		die("Safe directory must be owned by root with 0700 permissions")
	}
}

func checkValidatorBinary() {
	info, err := os.Lstat(validatorBinary)
	if err != nil {
		die("Validator binary not found: %v", err)
	}
	if info.Mode()&os.ModeSymlink != 0 {
		die("Validator binary must not be a symlink")
	}
	if !info.Mode().IsRegular() {
		die("Validator binary must be a regular file")
	}
	if info.Mode().Perm() != 0755 {
		die("Validator binary must have 0755 permissions")
	}
	stat, ok := info.Sys().(*syscall.Stat_t)
	if !ok {
		die("Cannot get file status for validator binary")
	}
	if stat.Uid != 0 {
		die("Validator binary must be owned by root")
	}
	sum, err := computeChecksum(validatorBinary)
	if err != nil {
		die("Cannot compute checksum of validator binary: %v", err)
	}
	if sum != expectedValidatorChecksum {
		die("Validator binary checksum does not match expected value")
	}
}

func computeChecksum(path string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f.Close()
	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return "", err
	}
	return hex.EncodeToString(h.Sum(nil)), nil
}

func main() {
	if len(os.Args) != 2 {
		fmt.Fprintln(os.Stderr, "Usage: program <file_path>")
		os.Exit(2)
	}

	rawPath := os.Args[1]
	clean := filepath.Clean(rawPath)
	if filepath.IsAbs(clean) || strings.ContainsAny(clean, `/\`) || strings.Contains(clean, "..") || clean == "." {
		die("Invalid file path.")
	}

	filePath := filepath.Join(safeDir, clean)

	checkSafeDir()
	checkValidatorBinary()

	src, err := os.Open(filePath)
	if err != nil {
		die("Cannot open source file: %v", err)
	}
	defer src.Close()

	info, err := src.Stat()
	if err != nil {
		die("Cannot stat source file: %v", err)
	}
	if !info.Mode().IsRegular() {
		die("Specified path is not a regular file.")
	}
	if info.Size() > maxFileSize {
		die("File too large to validate.")
	}

	data, err := io.ReadAll(src)
	if err != nil {
		die("Failed to read file: %v", err)
	}

	tempFile, err := os.CreateTemp(os.TempDir(), "validator_input_*")
	if err != nil {
		die("Failed to create temporary file: %v", err)
	}
	tempFileName := tempFile.Name()
	if err := tempFile.Chmod(0600); err != nil {
		tempFile.Close()
		os.Remove(tempFileName)
		die("Failed to set permissions on temporary file: %v", err)
	}
	if _, err := tempFile.Write(data); err != nil {
		tempFile.Close()
		os.Remove(tempFileName)
		die("Failed to write to temporary file: %v", err)
	}
	tempFile.Close()
	defer os.Remove(tempFileName)

	ctx, cancel := context.WithTimeout(context.Background(), timeoutDuration)
	defer cancel()

	cmd := exec.CommandContext(ctx, validatorBinary, tempFileName)
	_, err = cmd.CombinedOutput()
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			die("Validation timed out.")
		}
		if _, ok := err.(*exec.Error); ok {
			die("Validation tool not found.")
		}
		if exitErr, ok := err.(*exec.ExitError); ok && exitErr.ExitCode() != 0 {
			die("Syntax validation failed.")
		}
		die("Failed to execute validation tool: %v", err)
	}

	os.Exit(0)
}

import json
import urllib.parse
import socket
import ipaddress
import requests
from typing import Dict, Any

MAX_PAYLOAD_SIZE = 1 * 1024 * 1024  # 1 MiB
MAX_PAYLOAD_DEPTH = 20
ALLOWED_HOSTS = set()  # If empty, any nonâprivate host is allowed


def _is_private_ip(hostname: str) -> bool:
    try:
        ip = ipaddress.ip_address(hostname)
    except ValueError:
        return False
    return (
        ip.is_private
        or ip.is_loopback
        or ip.is_link_local
        or ip.is_multicast
        or ip.is_reserved
        or ip.is_unspecified
    )


def _is_allowed_host(parsed_url: urllib.parse.ParseResult) -> bool:
    host = parsed_url.hostname or ""
    if ALLOWED_HOSTS and host not in ALLOWED_HOSTS:
        return False
    if _is_private_ip(host):
        return False
    if host.lower() in ("localhost", "127.0.0.1"):
        return False
    return True


def _validate_payload_depth(obj: Any, depth: int = 0):
    if depth > MAX_PAYLOAD_DEPTH:
        raise ValueError(f"Payload depth exceeds {MAX_PAYLOAD_DEPTH}")
    if isinstance(obj, dict):
        for value in obj.values():
            _validate_payload_depth(value, depth + 1)
    elif isinstance(obj, list):
        for item in obj:
            _validate_payload_depth(item, depth + 1)


def post_json(
    url: str,
    payload: Dict[str, Any],
    access_token: str,
    timeout: float = 10.0,
) -> requests.Response:
    # Validate URL to prevent SSRF
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https") or not parsed.netloc:
        raise ValueError("Invalid URL")
    if not _is_allowed_host(parsed):
        raise ValueError("URL host is not allowed")

    if not isinstance(payload, dict):
        raise TypeError("Payload must be a dictionary")
    _validate_payload_depth(payload)

    if not isinstance(access_token, str) or not access_token:
        raise TypeError("Access token must be a nonâempty string")

    try:
        json_payload = json.dumps(payload, separators=(",", ":"))
    except (TypeError, ValueError) as exc:
        raise TypeError("Payload is not JSON serializable") from exc

    if len(json_payload.encode("utf-8")) > MAX_PAYLOAD_SIZE:
        raise ValueError("Payload size exceeds maximum allowed")

    headers = {"Authorization": f"Bearer {access_token}"}

    try:
        response = requests.post(
            url,
            headers=headers,
            json=payload,
            timeout=timeout,
            allow_redirects=False,
        )
        response.raise_for_status()
    except requests.exceptions.HTTPError as exc:
        raise RuntimeError("HTTP error occurred during request") from exc
    except requests.exceptions.RequestException as exc:
        raise RuntimeError("Request failed") from exc

    return response

