import requests
from typing import Dict, Set

logger = logging.getLogger(__name__)

class AssetUpdateError(Exception):
    """Base exception for asset update failures."""

class AssetNotFoundError(AssetUpdateError):
    """Raised when the specified asset type does not exist."""


def _validate_base_url(url: str) -> Dict[str, object]:
    parsed = urllib.parse.urlparse(url)

    if parsed.scheme != "https":
        raise ValueError("base_url must use HTTPS")

    if not parsed.hostname:
        raise ValueError("base_url must contain a hostname")

    # Reject URLs that include a nonâempty path or query
    if parsed.path and parsed.path not in ("", "/"):
        raise ValueError("base_url must not contain a path")
    if parsed.query:
        raise ValueError("base_url must not contain a query")

    bad_hostnames = {"localhost", "127.0.0.1", "0.0.0.0", "::1", "fe80::1"}
    if parsed.hostname.lower() in bad_hostnames:
        raise ValueError("base_url cannot target localhost")

    try:
        addrinfos = socket.getaddrinfo(
            parsed.hostname, None, family=socket.AF_UNSPEC, type=socket.SOCK_STREAM
        )
    except socket.gaierror as exc:
        raise ValueError(f"Hostname resolution failed: {exc}") from None

    valid_ip_set: Set[str] = set()
    for _, _, _, _, sockaddr in addrinfos:
        ip_str = sockaddr[0]
        try:
            ip_obj = ipaddress.ip_address(ip_str)
        except ValueError:
            continue
        if ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_link_local:
            raise ValueError("base_url resolves to a private IP address")
        valid_ip_set.add(ip_str)

    if not valid_ip_set:
        raise ValueError("base_url resolution yielded no valid IP addresses")

    # Canonicalize base URL (no trailing slash, include port if nonâdefault)
    netloc = parsed.hostname
    if parsed.port and parsed.port != 443:
        netloc = f"{parsed.hostname}:{parsed.port}"
    base_url = f"{parsed.scheme}://{netloc}"

    return {"base_url": base_url, "resolved_ips": valid_ip_set}


ALLOWED_ASSET_FIELDS = {"description", "category", "metadata"}


def update_asset_type(
    asset_type_id: int,
    new_name: str,
    base_url: str | None = None,
    api_token: str | None = None,
) -> dict:
    if not isinstance(asset_type_id, int) or asset_type_id <= 0:
        raise ValueError("asset_type_id must be a positive integer")
    if not isinstance(new_name, str) or not new_name.strip():
        raise ValueError("new_name must be a non-empty string")
    if len(new_name) > 255:
        raise ValueError("new_name must not exceed 255 characters")
    if not re.fullmatch(r"^[\w\s-]+$", new_name):
        raise ValueError("new_name contains invalid characters")

    base_url = base_url or os.getenv("BASE_URL")
    if not base_url:
        raise AssetUpdateError(
            "Base URL must be provided or set in BASE_URL environment variable"
        )

    validated = _validate_base_url(base_url.rstrip("/"))
    base_url = validated["base_url"]
    expected_ips = validated["resolved_ips"]
    hostname = urllib.parse.urlparse(base_url).hostname

    def _ensure_dns_unchanged():
        try:
            new_addrinfos = socket.getaddrinfo(
                hostname, None, family=socket.AF_UNSPEC, type=socket.SOCK_STREAM
            )
        except socket.gaierror as exc:
            raise AssetUpdateError(f"DNS resolution failed during request: {exc}") from None

        new_ip_set: Set[str] = set()
        for _, _, _, _, sockaddr in new_addrinfos:
            ip_str = sockaddr[0]
            try:
                ip_obj = ipaddress.ip_address(ip_str)
            except ValueError:
                continue
            if ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_link_local:
                continue
            new_ip_set.add(ip_str)

        if new_ip_set != expected_ips:
            raise AssetUpdateError("DNS rebinding detected: IP address changed during request")

    with requests.Session() as session:
        session.trust_env = False

        context = ssl.create_default_context()
        context.minimum_version = ssl.TLSVersion.TLSv1_2
        context.options |= (
            ssl.OP_NO_SSLv2
            | ssl.OP_NO_SSLv3
            | ssl.OP_NO_TLSv1
            | ssl.OP_NO_TLSv1_1
        )
        session.mount("https://", requests.adapters.HTTPAdapter(ssl_context=context))

        headers = {"Accept": "application/json", "Content-Type": "application/json"}
        if api_token and api_token.strip():
            headers["Authorization"] = f"Bearer {api_token}"
        session.headers.update(headers)

        # Fetch current asset type
        _ensure_dns_unchanged()
        get_url = f"{base_url}/assettypes/{asset_type_id}"
        try:
            get_resp = session.get(get_url, timeout=10, verify=True)
            get_resp.raise_for_status()
        except requests.HTTPError as err:
            if err.response and err.response.status_code == 404:
                raise AssetNotFoundError(f"Asset type {asset_type_id} not found") from None
            logger.exception("HTTP error during asset fetch", exc_info=err)
            raise AssetUpdateError("Failed to fetch asset type") from None
        except requests.RequestException as err:
            logger.exception("Network error while fetching asset type", exc_info=err)
            raise AssetUpdateError("Network error while fetching asset type") from None

        try:
            current_asset = get_resp.json()
        except ValueError:
            logger.exception("Invalid JSON response when fetching asset type")
            raise AssetUpdateError("Invalid JSON response when fetching asset type") from None

        new_payload = {k: v for k, v in current_asset.items() if k in ALLOWED_ASSET_FIELDS}
        new_payload["name"] = new_name

        # Create new asset type
        _ensure_dns_unchanged()
        post_url = f"{base_url}/assettypes"
        try:
            post_resp = session.post(
                post_url, json=new_payload, timeout=10, verify=True
            )
            post_resp.raise_for_status()
        except requests.HTTPError as err:
            logger.exception("HTTP error during asset creation", exc_info=err)
            raise AssetUpdateError("Failed to create new asset type") from None
        except requests.RequestException as err:
            logger.exception("Network error while creating new asset type", exc_info=err)
            raise AssetUpdateError("Network error while creating new asset type") from None

        try:
            new_asset = post_resp.json()
        except ValueError:
            logger.exception("Invalid JSON response when creating asset type")
            raise AssetUpdateError("Invalid JSON response when creating asset type") from None

        new_asset_id = new_asset.get("id")
        if not new_asset_id:
            raise AssetUpdateError("New asset type creation did not return an ID")

        # Delete old asset type
        _ensure_dns_unchanged()
        delete_url = f"{base_url}/assettypes/{asset_type_id}"
        try:
            del_resp = session.delete(delete_url, timeout=10, verify=True)
            del_resp.raise_for_status()
        except requests.HTTPError as err:
            logger.exception("HTTP error during asset deletion", exc_info=err)
            raise AssetUpdateError("Failed to delete old asset type") from None
        except requests.RequestException as err:
            logger.exception("Network error while deleting old asset type", exc_info=err)
            raise AssetUpdateError("Network error while deleting old asset type") from None

        return new_asset

import json
from typing import List, Dict, Any
import urllib.parse
import requests


class ValidationError(Exception):
    """Raised when input data fails validation checks."""
    pass


class FetchError(Exception):
    """Raised when fetching data from the API fails."""
    pass


def _validate_url(url: str) -> str:
    """
    Allow only HTTPS URLs whose hostname is in a whitelist.
    Returns the validated URL if it passes all checks.
    """
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme != "https":
        raise ValidationError("URL must use HTTPS")
    if not parsed.hostname:
        raise ValidationError("URL missing hostname")
    allowed_hosts = {"api.example.com", "data.service.local"}
    if parsed.hostname not in allowed_hosts:
        raise ValidationError(
            f"Hostname '{parsed.hostname}' not allowed"
        )
    return url


def _validate_object(item: Dict[str, Any]) -> None:
    """
    Validate that a dictionary has the required structure.
    """
    required_keys = {"id", "name", "value"}
    if not isinstance(item, dict):
        raise ValidationError("List element is not a JSON object")
    if set(item.keys()) != required_keys:
        raise ValidationError(f"Object keys mismatch: {item.keys()}")
    if not isinstance(item["id"], int):
        raise ValidationError("Field 'id' must be an integer")
    if not isinstance(item["name"], str):
        raise ValidationError("Field 'name' must be a string")
    if not isinstance(item["value"], (int, float)):
        raise ValidationError("Field 'value' must be numeric")


def fetch_and_validate(url: str) -> List[Dict[str, Any]]:
    """
    Fetch JSON data from a RESTful API and validate that it is a list
    of objects with keys 'id', 'name', and 'value'.
    """
    try:
        safe_url = _validate_url(url)
        response = requests.get(
            safe_url,
            timeout=10,
            verify=True,
            headers={"Accept": "application/json"},
        )
        response.raise_for_status()
    except requests.exceptions.RequestException as exc:
        raise FetchError("Failed to fetch data from the API") from exc

    try:
        data = response.json()
    except json.JSONDecodeError as exc:
        raise ValidationError("Response is not valid JSON") from exc

    if not isinstance(data, list):
        raise ValidationError("Response JSON is not a list")

    for item in data:
        _validate_object(item)

    return data


if __name__ == "__main__":
    test_url = "https://api.example.com/data"
    try:
        result = fetch_and_validate(test_url)
        print("Fetched and validated data:", result)
    except (ValidationError, FetchError) as e:
        print("Error:", str(e))

import datetime
import hashlib
from typing import Any, Dict, List, Optional
from urllib.parse import urlparse

import defusedxml.ElementTree as ET

_rss_cache: Optional[Dict[str, Any]] = None

# Maximum lengths for safety
_MAX_TITLE_LEN = 512
_MAX_LINK_LEN = 2048
_MAX_DESC_LEN = 2048
_MAX_ITEM_TITLE_LEN = 512
_MAX_ITEM_DESC_LEN = 4096

def _validate_length(value: str, max_len: int, field_name: str) -> str:
    if len(value) > max_len:
        raise ValueError(f"'{field_name}' exceeds maximum length of {max_len} characters.")
    return value

def _validate_url(url: str) -> str:
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("URL must use http or https scheme.")
    if not parsed.netloc:
        raise ValueError("URL must have a host component.")
    return url

def _parse_last_build_date(value: Any) -> datetime.datetime:
    if isinstance(value, (int, float)):
        try:
            dt = datetime.datetime.utcfromtimestamp(value).replace(tzinfo=datetime.timezone.utc)
        except (OverflowError, ValueError) as exc:
            raise ValueError("Invalid timestamp for 'last_build_date'.") from exc
        return dt
    if isinstance(value, str):
        parsed = None
        for fmt in ("%a, %d %b %Y %H:%M:%S %z", "%Y-%m-%dT%H:%M:%SZ"):
            try:
                parsed = datetime.datetime.strptime(value, fmt)
                break
            except ValueError:
                continue
        if parsed is None:
            raise ValueError(
                "The 'last_build_date' must be a valid RFC 2822 or ISO 8601 datetime string."
            )
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=datetime.timezone.utc)
        return parsed
    raise ValueError("The 'last_build_date' must be a timestamp or datetime string.")

def generate_rss_feed(data: Dict[str, Any]) -> str:
    required_top_keys = ("title", "link", "description", "last_build_date", "items")

    if not isinstance(data, dict):
        raise ValueError("Input data must be a dictionary.")
    for key in required_top_keys:
        if key not in data:
            raise ValueError(f"Missing required key: {key}")

    title = _validate_length(str(data["title"]).strip(), _MAX_TITLE_LEN, "title")
    link = _validate_url(str(data["link"]).strip())
    description = _validate_length(str(data["description"]).strip(), _MAX_DESC_LEN, "description")

    last_build_dt = _parse_last_build_date(data["last_build_date"])

    rss = ET.Element("rss", version="2.0")
    channel = ET.SubElement(rss, "channel")

    ET.SubElement(channel, "title").text = title
    ET.SubElement(channel, "link").text = link
    ET.SubElement(channel, "description").text = description
    ET.SubElement(channel, "lastBuildDate").text = (
        last_build_dt.strftime("%a, %d %b %Y %H:%M:%S %z")
    )

    items = data.get("items")
    if not isinstance(items, list):
        raise ValueError("The 'items' field must be a list.")
    for itm in items:
        if not isinstance(itm, dict):
            continue
        item_el = ET.SubElement(channel, "item")
        for field in ("title", "link", "description", "pubDate", "guid"):
            if field not in itm:
                continue
            val = str(itm[field]).strip()
            if field == "link":
                try:
                    val = _validate_url(val)
                except ValueError:
                    continue
            if field == "title":
                val = _validate_length(val, _MAX_ITEM_TITLE_LEN, "item title")
            if field == "description":
                val = _validate_length(val, _MAX_ITEM_DESC_LEN, "item description")
            ET.SubElement(item_el, field).text = val

    feed_xml = ET.tostring(rss, encoding="utf-8", xml_declaration=True).decode("utf-8")

    etag = hashlib.sha256(feed_xml.encode("utf-8")).hexdigest()

    global _rss_cache
    _rss_cache = {
        "content": feed_xml,
        "etag": etag,
        "last_modified": datetime.datetime.utcnow().replace(tzinfo=datetime.timezone.utc),
    }

    return feed_xml

def get_rss_cache() -> Dict[str, Any]:
    return globals().get("_rss_cache", {}) or {}

from typing import Tuple
from urllib.parse import quote_plus, urlparse
from urllib.request import Request, build_opener, HTTPRedirectHandler
from urllib.error import URLError, HTTPError
import json
import ssl

_ALLOWED_HOST = "nominatim.openstreetmap.org"
_MAX_RESPONSE_SIZE = 1 << 20  # 1 MiB limit for security

class NoRedirectHandler(HTTPRedirectHandler):
    def http_error_301(self, req, fp, code, msg, headers):
        return fp
    http_error_302 = http_error_307 = http_error_301
    http_error_308 = http_error_301

_opener = build_opener(NoRedirectHandler())

def get_coordinates(location: str) -> Tuple[float, float]:
    if not isinstance(location, str):
        raise TypeError("location must be a string")
    trimmed = location.strip()
    if not trimmed:
        raise ValueError("location cannot be empty")
    if len(trimmed) > 256:
        raise ValueError("location too long")

    query = quote_plus(trimmed)
    url = f"https://{_ALLOWED_HOST}/search?q={query}&format=json&limit=1"
    parsed = urlparse(url)
    if parsed.scheme != "https" or parsed.hostname != _ALLOWED_HOST:
        raise ValueError("Invalid URL scheme or host")

    headers = {
        "User-Agent": "SecureGeoClient/1.0",
        "Accept": "application/json",
    }
    req = Request(url, headers=headers, method="GET")

    context = ssl.create_default_context()
    context.check_hostname = True
    context.verify_mode = ssl.CERT_REQUIRED

    try:
        with _opener.open(req, timeout=10, context=context) as response:
            if response.status != 200:
                raise RuntimeError(f"HTTP error {response.status}")
            try:
                data_bytes = response.read(_MAX_RESPONSE_SIZE + 1)
            except Exception as exc:
                raise RuntimeError(f"Error reading response: {exc}") from exc
            if len(data_bytes) > _MAX_RESPONSE_SIZE:
                raise RuntimeError("Response too large")
    except HTTPError as e:
        raise RuntimeError(f"HTTP error {e.code}: {e.reason}") from e
    except URLError as e:
        raise RuntimeError(f"Unable to retrieve coordinates: {e}") from e
    except Exception as e:
        raise RuntimeError(f"Unexpected error during request: {e}") from e

    try:
        data_str = data_bytes.decode("utf-8")
    except UnicodeDecodeError as e:
        raise RuntimeError(f"Decoding error: {e}") from e

    try:
        json_data = json.loads(data_str)
    except json.JSONDecodeError as e:
        raise RuntimeError(f"Invalid JSON response: {e}") from e

    if not isinstance(json_data, list) or not json_data:
        raise RuntimeError("Location not found")

    place = json_data[0]
    if not isinstance(place, dict):
        raise RuntimeError("Unexpected response format")
    try:
        lat = float(place["lat"])
        lon = float(place["lon"])
    except (KeyError, ValueError, TypeError) as e:
        raise RuntimeError(f"Missing or invalid coordinate data: {e}") from e

    return lat, lon

import json
import logging
import http.client
import urllib.parse
from typing import Any, Dict, Optional

ALLOWED_HOSTS = {"api.example.com"}
MAX_RESPONSE_BYTES = 1_048_576  # 1 MB


def validate_url(url: str) -> urllib.parse.ParseResult:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in {"http", "https"}:
        raise ValueError("URL scheme must be http or https")
    if not parsed.netloc:
        raise ValueError("URL must have a network location")
    host = parsed.hostname
    if host not in ALLOWED_HOSTS:
        raise ValueError(f"Host {host} is not allowed")
    return parsed


def validate_resource_id(resource_id: str) -> str:
    if not isinstance(resource_id, str) or not resource_id:
        raise ValueError("resource_id must be a non-empty string")
    if not resource_id.isalnum():
        raise ValueError("resource_id must be alphanumeric")
    return resource_id


def _redact_sensitive(data: Dict[str, Any]) -> Dict[str, Any]:
    sensitive_keys = {"token", "auth", "password"}
    return {
        k: (v if k.lower() not in sensitive_keys else "***REDACTED***")
        for k, v in data.items()
    }


def _log_response(logger: logging.Logger, url: str, data: Optional[Dict[str, Any]]) -> None:
    logger.info("POST request sent to URL: %s", url)
    if data is None:
        logger.info("Response data: None")
        return
    safe_data = _redact_sensitive(data)
    logger.info("Response data: %s", safe_data)
    message = data.get("message")
    logger.info("Extracted message: %s", message)


def send_post_and_delete(
    url: str,
    resource_id: str,
    expected_message: str,
    logger: logging.Logger,
) -> None:
    try:
        parsed_url = validate_url(url)
        validate_resource_id(resource_id)

        host = parsed_url.hostname
        port = parsed_url.port or (443 if parsed_url.scheme == "https" else 80)

        conn = (
            http.client.HTTPSConnection(host, port=port, timeout=10)
            if parsed_url.scheme == "https"
            else http.client.HTTPConnection(host, port=port, timeout=10)
        )
        try:
            payload = json.dumps({"delete": resource_id}).encode("utf-8")
            headers = {
                "Content-Type": "application/json",
                "Accept": "application/json",
                "Content-Length": str(len(payload)),
            }
            path = parsed_url.path or "/"
            if parsed_url.query:
                path += f"?{parsed_url.query}"

            conn.request("POST", path, body=payload, headers=headers)
            response = conn.getresponse()
            content = response.read(MAX_RESPONSE_BYTES)
            try:
                response_data: Optional[Dict[str, Any]] = json.loads(content.decode("utf-8"))
            except json.JSONDecodeError:
                response_data = None

            _log_response(logger, url, response_data)

            if response_data is None:
                raise ValueError("Response JSON is missing")
            if not isinstance(response_data, dict):
                raise ValueError("Response JSON is not a dictionary")
            actual_message = response_data.get("message")
            if actual_message != expected_message:
                raise ValueError(
                    f"Message '{actual_message}' does not match expected '{expected_message}'"
                )
            if not (200 <= response.status < 300):
                raise ValueError(f"Unexpected HTTP status: {response.status}")
        finally:
            conn.close()
    except ValueError as ve:
        logger.error("Invalid input: %s", ve)
        raise
    except Exception as exc:
        logger.error("An unexpected error occurred: %s", exc)
        raise

import json
import logging
import re
import ipaddress
from typing import Any, Dict
from urllib.parse import urlparse

import requests
from requests.exceptions import HTTPError, Timeout, ConnectionError, TooManyRedirects, RequestException

logger = logging.getLogger(__name__)


def _sanitize_string(value: str) -> str:
    return value.strip()


def _validate_asset_id(asset_id: Any) -> int:
    if isinstance(asset_id, int):
        return asset_id
    if isinstance(asset_id, str) and re.fullmatch(r"\d+", asset_id):
        return int(asset_id)
    raise ValueError("Invalid asset_id; must be an integer or numeric string.")


def _validate_asset_data(asset_data: Any) -> Dict[str, Any]:
    if not isinstance(asset_data, dict):
        raise ValueError("asset_data must be a dictionary.")
    sanitized = {}
    for key, value in asset_data.items():
        if not isinstance(key, str):
            raise ValueError("Asset data keys must be strings.")
        if isinstance(value, str):
            sanitized[key] = _sanitize_string(value)
        else:
            sanitized[key] = value
    return sanitized


def _validate_auth_token(token: Any) -> str:
    if not isinstance(token, str) or not token:
        raise ValueError("auth_token must be a non-empty string.")
    return token.strip()


def _validate_base_url(base_url: Any) -> str:
    if not isinstance(base_url, str) or not base_url:
        raise ValueError("base_url must be a non-empty string.")
    parsed = urlparse(base_url.rstrip("/"))
    if parsed.scheme != "https":
        raise ValueError("base_url must use HTTPS.")
    host = parsed.hostname or ""
    if not host:
        raise ValueError("base_url must contain a host.")
    if host in ("localhost", "127.0.0.1", "::1"):
        raise ValueError("base_url host is disallowed.")
    try:
        ip = ipaddress.ip_address(host)
        if ip.is_private or ip.is_loopback or ip.is_link_local:
            raise ValueError("base_url host IP is disallowed.")
    except ValueError:
        if host.endswith(".local"):
            raise ValueError("base_url host is disallowed.")
        if not re.fullmatch(r"[a-zA-Z0-9.-]+", host):
            raise ValueError("base_url host contains invalid characters.")
    return f"{parsed.scheme}://{parsed.netloc}/"


def _validate_response(content: Dict[str, Any]) -> None:
    if not isinstance(content, dict):
        raise RuntimeError("API response is not JSON.")
    if "message" not in content or not isinstance(content["message"], str):
        raise RuntimeError("API response missing message field.")
    if "success" not in content or not isinstance(content["success"], bool):
        raise RuntimeError("API response missing success field.")
    if not content["success"]:
        logger.warning("Update failed: %s", content.get("message"))
        raise RuntimeError("Update failed.")


def update_asset_type(
    base_url: str,
    asset_id: Any,
    asset_data: Any,
    auth_token: Any,
    *,
    timeout: int = 10,
) -> Dict[str, Any]:
    if not 1 <= timeout <= 30:
        timeout = 10
    try:
        asset_id = _validate_asset_id(asset_id)
        asset_data = _validate_asset_data(asset_data)
        auth_token = _validate_auth_token(auth_token)
        base_url = _validate_base_url(base_url)

        url = f"{base_url}asset-types/{asset_id}"
        headers = {
            "Accept": "application/json",
            "Content-Type": "application/json",
            "Authorization": f"Bearer {auth_token}",
        }

        session = requests.Session()
        try:
            response = session.put(
                url,
                headers=headers,
                json=asset_data,
                timeout=timeout,
                verify=True,
            )
            if len(response.content) > 1_048_576:
                raise RuntimeError("Response too large.")
            response.raise_for_status()
        finally:
            session.close()

        try:
            content = response.json()
        except ValueError:
            raise RuntimeError("API response is not valid JSON.")

        _validate_response(content)
        return content
    except (HTTPError, Timeout, ConnectionError, TooManyRedirects) as exc:
        logger.exception("Network error occurred: %s", exc)
        raise RuntimeError("Communication with the API failed.") from exc
    except RequestException as exc:
        logger.exception("Request failed: %s", exc)
        raise RuntimeError("Communication with the API failed.") from exc
    except ValueError as exc:
        raise ValueError(f"Input validation error: {exc}") from exc
    except RuntimeError as exc:
        raise RuntimeError(f"API error: {exc}") from exc
